def get_football_method_modules(sport_key=None):
    sport_key = str(sport_key or '').strip().lower()
    modules = [dict(item) for item in FOOTBALL_METHOD_MODULES]
    if sport_key == 'ncaaf':
        for item in modules:
            key = str(item.get('key', '')).strip().lower()
            if key == 'game_lines':
                item['summary'] = 'This is the main college-football read. Start with the spread and moneyline, then let totals and matchup context tighten the board before you even think about props.'
                item['best_use'] = 'Best on full Saturday slates when you can compare multiple side profiles instead of forcing action into isolated games.'
            elif key == 'totals':
                item['summary'] = 'Totals are a primary college-football weapon. Use them to capture tempo, explosiveness, and mismatch-driven environments when player props are thin or unavailable.'
                item['best_use'] = 'Strong when offensive pace, defensive leak points, or mismatch scoring environments are clearer than the side.'
            elif key == 'trends':
                item['summary'] = 'In college football, trends should lean more on team ATS and O/U behavior than on broad prop chasing. Use them to confirm the environment, not to invent it.'
                item['best_use'] = 'Best when recent team form, conference context, and side/total behavior all point the same way.'
            elif key == 'props':
                item['title'] = 'Optional Props'
                item['summary'] = 'Props are optional support on the college side. Some books or states may offer them lightly, but they should not drive the CFB product or the weekly card.'
                item['best_use'] = 'Only use when a reliable market actually exists and the line clearly agrees with the side, total, and matchup script already on the board.'
            elif key == 'parlay_structure':
                item['title'] = 'Slate Structure'
                item['summary'] = 'College football slates work best when you build around spreads, totals, and a few clean matchup environments instead of stuffing too many niche legs together.'
                item['best_use'] = 'Use big Saturday slates to compare boards, avoid weak one-game reach, and structure tickets around the best environments first.'
    return modules


def get_football_method_config(method_key):
    method_key = str(method_key or '').strip().lower()
    for item in get_football_method_modules():
        if str(item.get('key', '')).strip().lower() == method_key:
            return item
    return FOOTBALL_METHOD_MODULES[0]

