# DATA LOADING
# =============================================================================
def _load_cached_csv(path, transform=None, default=None):
    path = Path(path)
    if not path.exists():
        return default.copy() if isinstance(default, pd.DataFrame) else (pd.DataFrame() if default is None else default)

    mtime = path.stat().st_mtime
    cache_key = (str(path.resolve()), transform.__name__ if transform else None)
    cached = DATAFRAME_CACHE.get(cache_key)
    if cached and cached['mtime'] == mtime:
        return cached['df'].copy()

    try:
        df = pd.read_csv(path, low_memory=False)
    except pd.errors.EmptyDataError:
        df = default.copy() if isinstance(default, pd.DataFrame) else (pd.DataFrame() if default is None else default)
        if not isinstance(df, pd.DataFrame):
            df = pd.DataFrame()
    if transform:
        df = transform(df)
    DATAFRAME_CACHE[cache_key] = {'mtime': mtime, 'df': df.copy()}
    return df.copy()


def _load_cached_json_records(path, default=None):
    path = Path(path)
    if not path.exists():
        return default.copy() if isinstance(default, pd.DataFrame) else (pd.DataFrame() if default is None else default)

    mtime = path.stat().st_mtime
    cache_key = str(path.resolve())
    cached = JSON_CACHE.get(cache_key)
    if cached and cached['mtime'] == mtime:
        return cached['df'].copy()

    import json
    records = json.loads(path.read_text(encoding='utf-8'))
    df = pd.DataFrame(records if isinstance(records, list) else [])
    JSON_CACHE[cache_key] = {'mtime': mtime, 'df': df.copy()}
    return df.copy()


