def normalize_combined_prop_key(stat_name):
    text = str(stat_name or '').strip().upper()
    text = re.sub(r'\s+', ' ', text)
    compact = text.replace(' ', '')
    return COMBINED_PROP_ALIASES.get(text) or COMBINED_PROP_ALIASES.get(compact) or text


def _add_component_sum_columns(df, sport_key):
    sport_key = str(sport_key or '').strip().upper()
    specs = COMBINED_PROP_COMPONENTS.get(sport_key, {})
    if not specs:
        return df
    working = df.copy()
    for output_col, components in specs.items():
        if output_col in working.columns:
            continue
        if all(component in working.columns for component in components):
            total = pd.Series(0, index=working.index, dtype='float64')
            for component in components:
                total = total + pd.to_numeric(working[component], errors='coerce').fillna(0)
            working[output_col] = total
    return working


def _format_gamelogs(df):
    df = df.copy()
    if 'Date' in df.columns:
        try:
            parsed_dates = pd.to_datetime(df['Date'], errors='coerce', format='mixed')
        except TypeError:
            parsed_dates = pd.to_datetime(df['Date'], errors='coerce')
        df['Date'] = parsed_dates.dt.strftime('%Y-%m-%d')
    if 'Matchup' in df.columns:
        matchup_series = df['Matchup'].astype(str).fillna('').str.strip()
        if 'Team' not in df.columns:
            df['Team'] = ''
        if 'Opp' not in df.columns:
            df['Opp'] = ''
        df['Team'] = df['Team'].astype(object)
        df['Opp'] = df['Opp'].astype(object)

        missing_team = df['Team'].isna() | (df['Team'].astype(str).str.strip() == '')
        missing_opp = df['Opp'].isna() | (df['Opp'].astype(str).str.strip() == '')

        def _team_from_matchup(matchup):
            if ' vs. ' in matchup:
                return matchup.split(' vs. ', 1)[0].strip().upper()
            if ' @ ' in matchup:
                return matchup.split(' @ ', 1)[0].strip().upper()
            return ''

        def _opp_from_matchup(matchup):
            if ' vs. ' in matchup:
                return matchup.split(' vs. ', 1)[1].strip().upper()
            if ' @ ' in matchup:
                return matchup.split(' @ ', 1)[1].strip().upper()
            return ''

        if missing_team.any():
            df.loc[missing_team, 'Team'] = matchup_series[missing_team].apply(_team_from_matchup)
        if missing_opp.any():
            df.loc[missing_opp, 'Opp'] = matchup_series[missing_opp].apply(_opp_from_matchup)
    df = _add_component_sum_columns(df, 'NBA')
    return df


def _format_mlb_gamelogs(df):
    df = _format_gamelogs(df)
    for col in ['H', '1B', '2B', '3B', 'R', 'RBI', 'HR']:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors='coerce').fillna(0)
    if '1B' not in df.columns and {'H', '2B', '3B', 'HR'}.issubset(df.columns):
        df['1B'] = (df['H'] - df['2B'] - df['3B'] - df['HR']).clip(lower=0)
    if {'H', 'R', 'RBI'}.issubset(df.columns):
        df['HRR'] = df['H'] + df['R'] + df['RBI']
    if {'2B', '3B', 'HR'}.issubset(df.columns):
        df['XBH'] = df['2B'] + df['3B'] + df['HR']
    df = _add_component_sum_columns(df, 'MLB')
    return df


def _format_schedule(df):
    df = df.copy()
    if 'Date' in df.columns:
        df['Date'] = pd.to_datetime(df['Date'], errors='coerce')
        df = df.dropna(subset=['Date'])
        df['Date'] = df['Date'].dt.strftime('%Y-%m-%d')
    if 'Away' in df.columns and 'Home' in df.columns:
        df = df.dropna(subset=['Away', 'Home'])
        df['Away'] = df['Away'].astype(str).str.strip()
        df['Home'] = df['Home'].astype(str).str.strip()
        df = df[(df['Away'] != 'nan') & (df['Home'] != 'nan') & (df['Away'] != '') & (df['Home'] != '')]
    return df


def _format_playoff_results(df):
    df = df.copy()
    if 'Date' in df.columns:
        df['Date'] = pd.to_datetime(df['Date'], errors='coerce')
        df = df.dropna(subset=['Date'])
        df['Date'] = df['Date'].dt.strftime('%Y-%m-%d')
    for column in ['Away', 'Home']:
        if column in df.columns:
            df[column] = df[column].astype(str).str.strip()
    return df


def _format_current_team_overrides(df):
    roster = df.copy()
    if {'Player', 'CurrentTeam'}.issubset(roster.columns):
        roster['Team'] = roster['CurrentTeam'].map(TEAM_NAME_TO_ABBR).fillna(roster['CurrentTeam'])
        roster['Note'] = 'Roster document import'
        return roster[['Player', 'Team', 'Note']]
    return roster


def _format_props(df):
    if not df.empty and len(df) > 1:
        return normalize_props_market_data(df.copy())
    return pd.DataFrame()


