def _format_ncaaf_transfer_portal(df):
    portal = df.copy()
    if 'Player' not in portal.columns:
        first = portal['firstName'].fillna('').astype(str).str.strip() if 'firstName' in portal.columns else pd.Series('', index=portal.index)
        last = portal['lastName'].fillna('').astype(str).str.strip() if 'lastName' in portal.columns else pd.Series('', index=portal.index)
        portal['Player'] = (first + ' ' + last).str.strip()
    rename_map = {}
    for col in portal.columns:
        key = ''.join(ch.lower() for ch in str(col).strip() if ch.isalnum() or ch == '_')
        mapped = {
            'year': 'Year',
            'season': 'Year',
            'id': 'PlayerID',
            'playerid': 'PlayerID',
            'athleteid': 'PlayerID',
            'player': 'Player',
            'name': 'Player',
            'fullname': 'Player',
            'position': 'Position',
            'origin': 'OriginTeam',
            'originschool': 'OriginTeam',
            'source': 'OriginTeam',
            'destination': 'DestinationTeam',
            'destinationschool': 'DestinationTeam',
            'transferdate': 'TransferDate',
            'date': 'TransferDate',
            'rating': 'Rating',
            'stars': 'Stars',
            'eligibility': 'Eligibility',
        }.get(key)
        if mapped:
            rename_map[col] = mapped
    portal = portal.rename(columns=rename_map).copy()
    for col in ['PlayerID', 'Player', 'Position', 'OriginTeam', 'DestinationTeam', 'Eligibility']:
        if col not in portal.columns:
            portal[col] = ''
        portal[col] = portal[col].fillna('').astype(str).str.strip()
    portal['OriginTeam'] = portal['OriginTeam'].apply(normalize_ncaaf_team_name)
    portal['DestinationTeam'] = portal['DestinationTeam'].apply(normalize_ncaaf_team_name)
    for col in ['Year', 'Rating', 'Stars']:
        if col not in portal.columns:
            portal[col] = np.nan
        portal[col] = pd.to_numeric(portal[col], errors='coerce')
    if 'TransferDate' not in portal.columns:
        portal['TransferDate'] = pd.NaT
    portal['TransferDate'] = pd.to_datetime(portal['TransferDate'], errors='coerce')
    return portal[['Year', 'PlayerID', 'Player', 'Position', 'OriginTeam', 'DestinationTeam', 'TransferDate', 'Rating', 'Stars', 'Eligibility']]


def _format_football_game_lines_history(df):
    history = df.copy()
    if 'Date' in history.columns:
        history['Date'] = pd.to_datetime(history['Date'], errors='coerce')
    for col in [
        'Week', 'Spread', 'Total', 'AwayScore', 'HomeScore',
        'HomeSpread', 'AwaySpread', 'OpenHomeSpread', 'OpenAwaySpread',
        'OpenTotal', 'CloseTotal', 'HomeCloseML', 'AwayCloseML'
    ]:
        if col in history.columns:
            history[col] = pd.to_numeric(history[col], errors='coerce')
    for col in ['Away', 'Home', 'Season']:
        if col in history.columns:
            history[col] = history[col].fillna('').astype(str).str.strip()
    if 'Away' in history.columns:
        history['Away'] = history['Away'].apply(normalize_nfl_historical_team_name)
    if 'Home' in history.columns:
        history['Home'] = history['Home'].apply(normalize_nfl_historical_team_name)
    if 'Away' in history.columns and 'Home' in history.columns:
        history = history[(history['Away'] != '') & (history['Home'] != '')].copy()
    if 'HomeSpread' not in history.columns and 'Spread' in history.columns:
        history['HomeSpread'] = pd.to_numeric(history['Spread'], errors='coerce')
    if 'AwaySpread' not in history.columns and 'HomeSpread' in history.columns:
        history['AwaySpread'] = -pd.to_numeric(history['HomeSpread'], errors='coerce')
    if 'CloseTotal' not in history.columns and 'Total' in history.columns:
        history['CloseTotal'] = pd.to_numeric(history['Total'], errors='coerce')
    return history


def _format_ncaaf_game_lines_history(df):
    history = _format_football_game_lines_history(df)
    if history.empty:
        return history
    if 'Away' in history.columns:
        history['Away'] = history['Away'].apply(normalize_ncaaf_team_name)
    if 'Home' in history.columns:
        history['Home'] = history['Home'].apply(normalize_ncaaf_team_name)
    if 'Away' in history.columns and 'Home' in history.columns:
        history = history[(history['Away'] != '') & (history['Home'] != '')].copy()
    return history


