def load_nfl_game_lines_history():
    path = DATA_DIR / 'historical' / 'NFL_GameLines_History.csv'
    if path.exists():
        df = _load_cached_csv(path, transform=_format_football_game_lines_history, default=pd.DataFrame())
        if not df.empty:
            return df
    frames = []
    sbr_path = DATA_DIR / 'historical' / 'NFL_Archive_10Y_SBR.json'
    if sbr_path.exists():
        raw = _load_cached_json_records(sbr_path, default=pd.DataFrame())
        if not raw.empty:
            working = raw.rename(columns={
                'date': 'Date',
                'season': 'Season',
                'away_team': 'Away',
                'home_team': 'Home',
                'away_final': 'AwayScore',
                'home_final': 'HomeScore',
                'home_open_spread': 'OpenHomeSpread',
                'away_open_spread': 'OpenAwaySpread',
                'home_close_spread': 'HomeSpread',
                'away_close_spread': 'AwaySpread',
                'open_over_under': 'OpenTotal',
                'close_over_under': 'CloseTotal',
                'home_close_ml': 'HomeCloseML',
                'away_close_ml': 'AwayCloseML',
            }).copy()
            if 'Date' in working.columns:
                working['Date'] = pd.to_datetime(working['Date'].astype(str).str.replace(r'\.0$', '', regex=True), format='%Y%m%d', errors='coerce')
            if 'CloseTotal' in working.columns and 'Total' not in working.columns:
                working['Total'] = pd.to_numeric(working['CloseTotal'], errors='coerce')
            working['Source'] = 'sbr'
            formatted = _format_football_game_lines_history(working)
            if not formatted.empty:
                frames.append(formatted)
    vegas_path = DATA_DIR / 'historical' / 'NFL_Lines_09_19.csv'
    if not frames and vegas_path.exists():
        raw = _load_cached_csv(vegas_path, default=pd.DataFrame())
        if not raw.empty:
            working = raw.rename(columns={
                'date': 'Date',
                'season': 'Season',
                'type': 'WeekLabel',
                'away.team': 'Away',
                'home.team': 'Home',
                'home.line': 'HomeSpread',
                'total': 'Total',
                'away.score': 'AwayScore',
                'home.score': 'HomeScore',
            }).copy()
            if 'HomeSpread' in working.columns and 'AwaySpread' not in working.columns:
                working['AwaySpread'] = -pd.to_numeric(working['HomeSpread'], errors='coerce')
            if 'WeekLabel' in working.columns and 'Week' not in working.columns:
                working['Week'] = working['WeekLabel'].astype(str).str.extract(r'(\d+)')
            working['Source'] = 'vegaslines'
            formatted = _format_football_game_lines_history(working)
            if not formatted.empty:
                frames.append(formatted)
    nfldata_path = DATA_DIR / 'historical' / 'NFL_Games_nfldata.csv'
    if nfldata_path.exists():
        raw = _load_cached_csv(nfldata_path, default=pd.DataFrame())
        if not raw.empty:
            working = raw.rename(columns={
                'gameday': 'Date',
                'season': 'Season',
                'week': 'Week',
                'away_team': 'Away',
                'home_team': 'Home',
                'spread_line': 'AwaySpread',
                'total_line': 'Total',
                'away_score': 'AwayScore',
                'home_score': 'HomeScore',
            }).copy()
            if 'AwaySpread' in working.columns and 'HomeSpread' not in working.columns:
                working['HomeSpread'] = -pd.to_numeric(working['AwaySpread'], errors='coerce')
            if 'Total' in working.columns and 'CloseTotal' not in working.columns:
                working['CloseTotal'] = pd.to_numeric(working['Total'], errors='coerce')
            if 'game_type' in raw.columns:
                working['GameType'] = raw['game_type']
            working['Source'] = 'nfldata'
            formatted = _format_football_game_lines_history(working)
            if not formatted.empty:
                if 'GameType' in formatted.columns:
                    formatted = formatted[formatted['GameType'].isin(['REG', 'POST', 'WC', 'DIV', 'CON', 'SB'])].copy()
                formatted = formatted.dropna(subset=['AwayScore', 'HomeScore'])
                if frames:
                    max_existing_season = pd.to_numeric(pd.concat(frames, ignore_index=True).get('Season'), errors='coerce').max()
                    if pd.notna(max_existing_season):
                        formatted = formatted[pd.to_numeric(formatted['Season'], errors='coerce') > max_existing_season].copy()
                if not formatted.empty:
                    frames.append(formatted)
    if not frames:
        return pd.DataFrame()
    combined = pd.concat(frames, ignore_index=True, sort=False)
    if {'Date', 'Away', 'Home'}.issubset(combined.columns):
        combined = combined.sort_values(['Date', 'Away', 'Home']).drop_duplicates(subset=['Date', 'Away', 'Home'], keep='first')
    return combined.reset_index(drop=True)


