def load_nfl_player_stats_history():
    frames = []
    for season in range(2020, 2025):
        path = DATA_DIR / 'historical' / f'NFL_PlayerStats_{season}.csv'
        if not path.exists():
            continue
        df = _load_cached_csv(path, default=pd.DataFrame())
        if df is None or df.empty:
            continue
        working = df.copy()
        numeric_cols = [
            'season', 'week', 'passing_yards', 'passing_tds', 'passing_interceptions',
            'rushing_yards', 'rushing_tds', 'receptions', 'targets',
            'receiving_yards', 'receiving_tds', 'fantasy_points', 'fantasy_points_ppr',
        ]
        for col in numeric_cols:
            if col in working.columns:
                working[col] = pd.to_numeric(working[col], errors='coerce')
        for col in ['player_display_name', 'position', 'position_group', 'team', 'opponent_team', 'season_type']:
            if col in working.columns:
                working[col] = working[col].fillna('').astype(str).str.strip()
        frames.append(working)

    if not frames:
        return pd.DataFrame()

    combined = pd.concat(frames, ignore_index=True, sort=False)
    if 'season_type' in combined.columns:
        combined = combined[combined['season_type'].isin(['REG', 'POST'])].copy()
    if 'player_display_name' in combined.columns:
        combined = combined[combined['player_display_name'] != ''].copy()
    return combined


def get_props_refresh_meta(props_df, max_age_hours=6):
    if props_df is None or props_df.empty:
        return {
            'last_updated': 'Unknown',
            'age_hours': None,
            'book_count': 0,
            'books': [],
            'row_count': 0,
            'has_live_props': False,
            'is_stale': False,
            'status': 'unavailable',
            'warning': 'Live props feed is unavailable. Verify the Odds API key or subscription before trusting board lines.',
        }

    books = []
    if 'Book' in props_df.columns:
        books = sorted([str(book).strip() for book in props_df['Book'].dropna().unique().tolist() if str(book).strip()])

    last_updated = 'Unknown'
    age_hours = None
    if 'LastUpdated' in props_df.columns:
        parsed = pd.to_datetime(props_df['LastUpdated'], errors='coerce')
        parsed = parsed.dropna()
        if not parsed.empty:
            now_ts = pd.Timestamp.now(tz=getattr(parsed.dt, 'tz', None)) if hasattr(parsed, 'dt') and getattr(parsed.dt, 'tz', None) is not None else pd.Timestamp.now()
            valid_parsed = parsed[parsed <= (now_ts + pd.Timedelta(minutes=5))]
            freshest = valid_parsed.max() if not valid_parsed.empty else parsed.max()
            last_updated = freshest.strftime('%b %d, %Y %I:%M %p')
            try:
                age_hours = round(float((pd.Timestamp.now(tz=freshest.tz) if getattr(freshest, 'tzinfo', None) else pd.Timestamp.now()) - freshest).total_seconds() / 3600.0, 2)
            except Exception:
                age_hours = None

    is_stale = bool(age_hours is not None and max_age_hours is not None and age_hours > max_age_hours)
    status = 'stale' if is_stale else 'live'
    warning = ''
    if is_stale:
        warning = f"Live props feed is {age_hours:.1f}h old. Refresh lines before trusting scored props or market overlays."

    return {
        'last_updated': last_updated,
        'age_hours': age_hours,
        'book_count': len(books),
        'books': books,
        'row_count': int(len(props_df)),
        'has_live_props': True,
        'is_stale': is_stale,
        'status': status,
        'warning': warning,
    }


def load_live_props_feed(max_age_hours=6, require_fresh=False):
    props_df = load_props()
    refresh_meta = get_props_refresh_meta(props_df, max_age_hours=max_age_hours)
    if require_fresh and refresh_meta.get('is_stale'):
        empty_columns = list(props_df.columns) if props_df is not None and not props_df.empty else []
        return pd.DataFrame(columns=empty_columns), refresh_meta
    return props_df, refresh_meta


