def load_nfl_floor_play_preview():
    workbook_path = BASE_DIR / 'NFL_Floor_Plays_01032026.xlsx'
    preview = {
        'available': False,
        'title': '',
        'parameters': [],
        'top_plays': [],
        'games': [],
    }
    if load_workbook is None or not workbook_path.exists():
        return preview

    try:
        wb = load_workbook(workbook_path, read_only=True, data_only=True)
    except Exception:
        return preview

    preview['available'] = True
    preview['title'] = workbook_path.name
    sheet_names = wb.sheetnames
    preview['games'] = [name for name in sheet_names if name != 'SUMMARY']

    if 'SUMMARY' not in sheet_names:
        return preview

    ws = wb['SUMMARY']
    rows = [list(row) for row in ws.iter_rows(values_only=True)]

    for row in rows[:20]:
        first = row[0]
        if isinstance(first, str) and 'NFL FLOOR PLAY HEAT MAP' in first.upper():
            preview['title'] = first.strip()
            break

    in_parameters = False
    in_top_plays = False
    for row in rows:
        first = row[0]
        if isinstance(first, str):
            label = first.strip()
            upper = label.upper()
            if upper.startswith('PARAMETERS'):
                in_parameters = True
                in_top_plays = False
                continue
            if upper.startswith(' TOP FLOOR PLAYS') or upper.startswith('TOP FLOOR PLAYS'):
                in_top_plays = True
                in_parameters = False
                continue
            if label == 'Player':
                continue

            if in_parameters and label:
                preview['parameters'].append(label)
                continue

        if in_top_plays:
            player = row[0]
            if not player or player == 'Player':
                continue
            hit_pct = row[6]
            streak = row[7]
            preview['top_plays'].append({
                'player': player,
                'team': row[1],
                'stat': row[2],
                'line': row[3],
                'floor': row[4],
                'avg': row[5],
                'hit_pct': hit_pct,
                'streak': streak,
            })
            if len(preview['top_plays']) >= 12:
                break

    return preview


