def build_wnba_board_status(schedule_df, odds_df, props_df, upcoming):
    books = []
    if not props_df.empty and 'Book' in props_df.columns:
        books.extend(
            str(book).strip()
            for book in props_df['Book'].dropna().unique().tolist()
            if str(book).strip()
        )
    if not odds_df.empty and 'Book' in odds_df.columns:
        books.extend(
            str(book).strip()
            for book in odds_df['Book'].dropna().unique().tolist()
            if str(book).strip()
        )
    books = sorted({book for book in books if book})

    has_schedule = not schedule_df.empty
    has_odds = not odds_df.empty
    has_props = not props_df.empty
    coverage = []
    if has_schedule:
        coverage.append('Schedule')
    if has_odds:
        coverage.append('Game Lines')
    if has_props:
        coverage.append('Props')

    if has_schedule and has_odds and has_props:
        stage = 'Board Ready'
        next_layer = 'Next step is cloning the NBA board structure for live WNBA props, matchup views, and parlay planning.'
    elif has_schedule and has_odds:
        stage = 'Lines Ready'
        next_layer = 'Game markets are present. The next job is building the NBA-style prop board once WNBA props are loaded.'
    elif has_schedule and has_props:
        stage = 'Props Ready'
        next_layer = 'Props are present. The next job is connecting game-line context and matchup pages so the board behaves like NBA.'
    elif has_schedule:
        stage = 'Schedule Only'
        next_layer = 'The slate is visible. The next job is pulling WNBA game lines and player props into the same board.'
    elif has_odds or has_props:
        stage = 'Partial Feed'
        next_layer = 'Some WNBA data exists, but the slate is incomplete. The next job is syncing schedule, lines, and props together.'
    else:
        stage = 'Waiting On Feed'
        next_layer = 'No WNBA files are loaded yet. Run the WNBA refresh scripts to start the board.'

    return {
        'schedule_games': len(schedule_df),
        'today_games': len(upcoming.get('today', [])),
        'tomorrow_games': len(upcoming.get('tomorrow', [])),
        'props_rows': int(len(props_df)),
        'odds_rows': int(len(odds_df)),
        'books': books,
        'available': has_schedule or has_odds or has_props,
        'has_schedule': has_schedule,
        'has_odds': has_odds,
        'has_props': has_props,
        'coverage': coverage,
        'stage': stage,
        'next_layer': next_layer,
    }


def build_mlb_board_status(schedule_df, odds_df, props_df, gamelogs_df, upcoming):
    books = []
    if not props_df.empty and 'Book' in props_df.columns:
        books.extend(
            str(book).strip()
            for book in props_df['Book'].dropna().unique().tolist()
            if str(book).strip()
        )
    if not odds_df.empty and 'Book' in odds_df.columns:
        books.extend(
            str(book).strip()
            for book in odds_df['Book'].dropna().unique().tolist()
            if str(book).strip()
        )
    books = sorted({book for book in books if book})

    has_schedule = not schedule_df.empty
    has_odds = not odds_df.empty
    has_props = not props_df.empty
    has_logs = not gamelogs_df.empty
    coverage = []
    if has_schedule:
        coverage.append('Schedule')
    if has_odds:
        coverage.append('Game Lines')
    if has_props:
        coverage.append('Props')
    if has_logs:
        coverage.append('Game Logs')

    if has_schedule and has_odds and has_props and has_logs:
        stage = 'Live'
        next_layer = 'MLB is live: use the slate, game-line context, prop board, reliability labels, and matchup reads together the same way the NBA and WNBA boards work.'
    elif has_schedule and (has_odds or has_props):
        stage = 'Partial Feed'
        next_layer = 'Baseball data has started landing. The next job is syncing schedules, lines, props, and logs into one daily board.'
    elif has_schedule:
        stage = 'Schedule Only'
        next_layer = 'The slate is visible. The next job is pulling MLB odds, props, and logs into the same workflow.'
    elif has_odds or has_props or has_logs:
        stage = 'Raw Data Only'
        next_layer = 'Some baseball files exist, but the slate is not connected yet. The next step is harmonizing the inputs.'
    else:
        stage = 'Waiting On Feed'
        next_layer = 'No MLB source files are loaded yet. Add schedule, odds, props, and game logs before the prop engine begins.'

    latest_schedule_date = ''
    loaded_slate_games = 0
    if not schedule_df.empty and 'Date' in schedule_df.columns:
        parsed_dates = pd.to_datetime(schedule_df['Date'], errors='coerce')
        if parsed_dates.notna().any():
            latest_date = parsed_dates.max().normalize()
            latest_schedule_date = latest_date.strftime('%Y-%m-%d')
            loaded_slate_games = int((parsed_dates.dt.normalize() == latest_date).sum())

    return {
        'schedule_games': len(schedule_df),
        'today_games': len(upcoming.get('today', [])),
        'tomorrow_games': len(upcoming.get('tomorrow', [])),
        'loaded_slate_games': loaded_slate_games,
        'latest_schedule_date': latest_schedule_date,
        'props_rows': int(len(props_df)),
        'odds_rows': int(len(odds_df)),
        'gamelog_rows': int(len(gamelogs_df)),
        'books': books,
        'coverage': coverage,
        'stage': stage,
        'next_layer': next_layer,
        'available': has_schedule or has_odds or has_props or has_logs,
    }


def build_wnba_game_environment_note(total, spread, stat, direction):
    stat = str(stat or '').upper()
    note_bits = []
    if total is not None and not pd.isna(total):
        total = float(total)
        if total >= 170:
            if stat in {'PTS', 'AST', '3PM'}:
                note_bits.append('This is a high-total game, which usually helps scoring and playmaking volume hold up.')
            elif stat == 'REB':
                note_bits.append('This is a high-total game, so there should be plenty of possessions to create rebound chances.')
        elif total <= 160:
            if stat in {'PTS', 'AST', '3PM'}:
                note_bits.append('This is a lower-total game, so raw scoring volume is less forgiving than usual.')
            elif stat == 'REB':
                note_bits.append('This is a lower-total game, which can trim the overall possession count a bit.')

    if spread is not None and not pd.isna(spread):
        spread = abs(float(spread))
        if spread <= 4:
            note_bits.append('The spread is tight, which is a good sign for starters keeping their full workload.')
        elif spread >= 8:
            if direction == 'UNDER':
                note_bits.append('The spread is wide enough to create some blowout risk if one side pulls away early.')
            else:
                note_bits.append('The spread is wide, so make sure the player can still get enough work if the game gets lopsided.')

    if not note_bits:
        return 'The game environment looks fairly neutral, so the price itself is doing most of the talking here.'
    return ' '.join(note_bits[:2])


def classify_prop_game_environment(total=None, spread=None, sport='NBA'):
    sport_key = str(sport or '').upper()
    total_value = pd.to_numeric(pd.Series([total]), errors='coerce').iloc[0]
    spread_value = pd.to_numeric(pd.Series([spread]), errors='coerce').iloc[0]

    if pd.isna(total_value):
        label = 'NO TOTAL'
    elif sport_key == 'MLB':
        if float(total_value) <= 7.5:
            label = 'PITCHER FRIENDLY'
        elif float(total_value) >= 9.0:
            label = 'HITTER FRIENDLY'
        else:
            label = 'NEUTRAL'
    elif sport_key == 'WNBA':
        if float(total_value) >= 170:
            label = 'SCORING ENV'
        elif float(total_value) <= 160:
            label = 'UNDER ENV'
        else:
            label = 'NEUTRAL'
    else:
        if float(total_value) >= 226:
            label = 'SCORING ENV'
        elif float(total_value) <= 218:
            label = 'UNDER ENV'
        else:
            label = 'NEUTRAL'

    tags = []
    if not pd.isna(total_value):
        tags.append(f"Total {float(total_value):g}")
    if not pd.isna(spread_value):
        tags.append(f"Spread {float(spread_value):+g}")
        if abs(float(spread_value)) >= (8 if sport_key == 'WNBA' else 9):
            tags.append('Blowout risk')
        elif abs(float(spread_value)) <= 4:
            tags.append('Close spread')
    return {
        'label': label,
        'tags': tags,
        'summary': ' | '.join(tags),
    }


def enrich_rows_with_game_environment(rows, sport='NBA', odds_df=None):
    if not rows:
        return rows
    sport_key = str(sport or '').upper()
    lookup = {}
    if odds_df is not None and not odds_df.empty:
        for _, market in odds_df.iterrows():
            away = str(market.get('AwayFull') or market.get('Away') or '').strip()
            home = str(market.get('HomeFull') or market.get('Home') or '').strip()
            if not away or not home:
                continue
            payload = {
                'total': market.get('Total'),
                'spread': market.get('Spread'),
            }
            for key in {
                _mlb_prop_game_key(f'{away} @ {home}'),
                _mlb_prop_game_key(f'{away}@{home}'),
                _mlb_prop_game_key(f'{away} vs {home}'),
                build_matchup_slug(away, home),
            }:
                lookup[key] = payload

    enriched = []
    for row in rows:
        item = dict(row)
        market = (
            lookup.get(_mlb_prop_game_key(item.get('game')))
            or lookup.get(_mlb_prop_game_key(item.get('matchup')))
            or lookup.get(str(item.get('matchup_slug') or '').strip())
            or {}
        )
        total = item.get('total', item.get('game_total', market.get('total')))
        spread = item.get('spread', item.get('team_spread', market.get('spread')))
        context = classify_prop_game_environment(total, spread, sport=sport_key)
        item.setdefault('game_environment_label', context.get('label'))
        if not item.get('game_environment_label'):
            item['game_environment_label'] = context.get('label')
        if not item.get('game_environment_summary'):
            item['game_environment_summary'] = context.get('summary')
        enriched.append(item)
    return enriched


def _team_strength_prior_key(value):
    return ' '.join(str(value or '').strip().upper().split())


def load_team_strength_prior_lookup():
    path = DATA_DIR / 'tracking' / 'Team_Strength_Priors.csv'
    cache_key = 'team_strength_prior_lookup'
    cache_version = _build_file_token(path)
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry and cached_entry.get('version') == cache_version:
        return cached_entry['value']

    lookup = {}
    if path.exists():
        try:
            df = pd.read_csv(path)
        except Exception:
            df = pd.DataFrame()
        if not df.empty:
            working = df.copy()
            working['Sport'] = working.get('Sport', '').fillna('').astype(str).str.strip().str.upper()
            working['Team'] = working.get('Team', '').fillna('').astype(str).str.strip()
            working['TeamKey'] = working['Team'].apply(_team_strength_prior_key)
            for _, row in working.iterrows():
                sport = str(row.get('Sport') or '').strip().upper()
                team_key = str(row.get('TeamKey') or '').strip().upper()
                if not sport or not team_key:
                    continue
                lookup[(sport, team_key)] = row.to_dict()

    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': lookup,
        'version': cache_version,
    }
    return lookup


def attach_team_strength_priors_to_rows(rows, sport='NBA'):
    if not rows:
        return rows
    sport_key = str(sport or '').strip().upper()
    lookup = load_team_strength_prior_lookup()
    if not lookup:
        return rows

    enriched = []
    for row in rows:
        item = dict(row)
        team_candidates = [
            item.get('team'),
            item.get('Team'),
            item.get('team_name'),
            item.get('team_abbr'),
            item.get('player_team'),
        ]
        prior = None
        for candidate in team_candidates:
            key = _team_strength_prior_key(candidate)
            if not key:
                continue
            prior = lookup.get((sport_key, key))
            if prior:
                break
        if not prior:
            enriched.append(item)
            continue

        score = _safe_float(prior.get('TeamPriorScore'))
        market_prob = _safe_float(prior.get('MarketWinProb'))
        avg_spread = _safe_float(prior.get('AvgSpread'))
        label = str(prior.get('PriorLabel') or '').strip()
        source = str(prior.get('Source') or '').strip()
        item['team_prior_team'] = str(prior.get('Team') or '').strip()
        item['team_prior_score'] = round(score, 1) if score is not None else None
        item['team_prior_label'] = label
        item['team_prior_source'] = source
        item['team_market_win_prob'] = round(market_prob, 1) if market_prob is not None else None
        item['team_prior_spread'] = round(avg_spread, 1) if avg_spread is not None else None
        detail_bits = []
        if item.get('team_prior_score') is not None:
            detail_bits.append(f"Prior {item['team_prior_score']}")
        if label:
            detail_bits.append(label.title())
        if item.get('team_market_win_prob') is not None:
            detail_bits.append(f"market {item['team_market_win_prob']}%")
        item['team_prior_note'] = ' | '.join(detail_bits)
        if source:
            item['team_prior_note'] = f"{item['team_prior_note']} via {source}" if item['team_prior_note'] else f"via {source}"
        enriched.append(item)
    return enriched


def build_board_intelligence_summary(rows):
    rows = rows or []
    prior_rows = [row for row in rows if _safe_float(row.get('team_prior_score')) is not None]
    sim_rows = [row for row in rows if _safe_float(row.get('calibrated_sim_hit_probability')) is not None]
    prior_counts = {}
    for row in prior_rows:
        label = str(row.get('team_prior_label') or 'UNKNOWN').strip().upper() or 'UNKNOWN'
        prior_counts[label] = prior_counts.get(label, 0) + 1
    top_priors = sorted(
        prior_rows,
        key=lambda row: _safe_float(row.get('team_prior_score')) or 0,
        reverse=True,
    )[:3]
    top_sims = sorted(
        sim_rows,
        key=lambda row: _safe_float(row.get('calibrated_sim_hit_probability')) or 0,
        reverse=True,
    )[:3]
    return {
        'row_count': len(rows),
        'prior_count': len(prior_rows),
        'sim_count': len(sim_rows),
        'prior_counts': prior_counts,
        'top_priors': top_priors,
        'top_sims': top_sims,
        'live_sim_count': sum(1 for row in sim_rows if str(row.get('simulation_authority') or '').upper() == 'LIVE_AUTHORITY'),
        'watch_sim_count': sum(1 for row in sim_rows if str(row.get('simulation_authority') or '').upper() == 'WATCH'),
    }


def build_wnba_recent_form_note(player_name, stat, line, gamelogs, sample_size=5):
    if gamelogs is None or gamelogs.empty or stat not in gamelogs.columns or 'Player' not in gamelogs.columns:
        return ''

    player_logs = gamelogs[gamelogs['Player'] == player_name].copy()
    if player_logs.empty:
        return ''
    if 'Date' in player_logs.columns:
        player_logs = player_logs.sort_values('Date', ascending=False)
    recent = player_logs.head(sample_size).copy()
    if recent.empty:
        return ''

    values = pd.to_numeric(recent[stat], errors='coerce').dropna()
    if values.empty:
        return ''

    avg = round(float(values.mean()), 1)
    hits_over = int((values > float(line)).sum())
    hits_under = int((values < float(line)).sum())
    actual_n = int(len(values))
    stat_label = STAT_LABELS.get(stat, stat)

    if hits_over == actual_n:
        return f'Cleared {line:g} in all of the last {actual_n} games, averaging {avg} {stat_label.lower()}.'
    if hits_under == actual_n:
        return f'Stayed below {line:g} in all of the last {actual_n} games, averaging {avg} {stat_label.lower()}.'
    if hits_over > hits_under:
        return f'Averaging {avg} {stat_label.lower()} over the last {actual_n} games and clearing {line:g} in {hits_over} of them.'
    if hits_under > hits_over:
        return f'Averaging {avg} {stat_label.lower()} over the last {actual_n} games and staying below {line:g} in {hits_under} of them.'
    return f'Averaging {avg} {stat_label.lower()} over the last {actual_n} games with a mixed hit profile around {line:g}.'


