def load_mlb_all_prop_results():
    path = DATA_DIR / 'tracking' / 'MLB_AllPropResults.csv'
    if path.exists():
        return _load_cached_csv(path, default=pd.DataFrame())
    fallback = DATA_DIR / 'tracking' / 'MLB_FeaturedResults.csv'
    if fallback.exists():
        return _load_cached_csv(fallback, default=pd.DataFrame())
    return pd.DataFrame()


def calculate_mlb_launch_reliability(resolved_count, hit_rate):
    resolved_count = int(resolved_count or 0)
    hit_rate = float(hit_rate or 0)
    if resolved_count < 10:
        return 'SMALL SAMPLE'
    if resolved_count >= 20 and hit_rate >= 0.65:
        return 'ANCHOR'
    if resolved_count >= 10 and hit_rate >= 0.60:
        return 'WATCH'
    if resolved_count >= 10 and hit_rate < 0.52:
        return 'AVOID'
    return 'DEVELOPING'


def build_mlb_reliability_tables(results_df=None):
    if results_df is None:
        cache_key = 'mlb_reliability_tables'
        cache_version = _build_file_token(DATA_DIR / 'tracking' / 'MLB_AllPropResults.csv')
        cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
        if cached_entry:
            cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
            if cached_age <= 600 and cached_entry.get('version') == cache_version:
                return cached_entry['value']
        disk_hit, disk_payload = _read_disk_ttl_cached_value(f'disk::{cache_key}', version=cache_version)
        if disk_hit:
            RUNTIME_TTL_CACHE[cache_key] = {
                'created_at': datetime.now(timezone.utc),
                'value': disk_payload,
                'version': cache_version,
            }
            return disk_payload
        disk_hit, disk_payload = _read_disk_ttl_cached_value(f'disk::{cache_key}', version=cache_version)
        if disk_hit:
            RUNTIME_TTL_CACHE[cache_key] = {
                'created_at': datetime.now(timezone.utc),
                'value': disk_payload,
                'version': cache_version,
            }
            return disk_payload

    results = load_mlb_all_prop_results() if results_df is None else results_df
    empty = {
        'bucket_rows': [],
        'player_rows': [],
        'bucket_lookup': {},
        'player_lookup': {},
        'totals': {'resolved': 0, 'pending': 0, 'hits': 0, 'misses': 0, 'hit_rate': None},
    }
    if results is None or results.empty or 'OutcomeState' not in results.columns:
        return empty

    df = results.copy()
    for col in ['Player', 'Stat', 'Direction', 'Method']:
        if col in df.columns:
            df[col] = df[col].fillna('').astype(str).str.strip()
    df['OutcomeState'] = df['OutcomeState'].fillna('').astype(str).str.strip()
    resolved = df[df['OutcomeState'].isin(['Hit', 'Miss'])].copy()
    if resolved.empty:
        pending = int((df['OutcomeState'] == 'Pending').sum())
        empty['totals']['pending'] = pending
        return empty

    resolved['Hit_Binary'] = (resolved['OutcomeState'] == 'Hit').astype(int)
    if 'Confidence' in resolved.columns:
        resolved['Confidence'] = pd.to_numeric(resolved['Confidence'], errors='coerce')
    hits = int(resolved['Hit_Binary'].sum())
    misses = int(len(resolved) - hits)
    totals = {
        'resolved': int(len(resolved)),
        'pending': int((df['OutcomeState'] == 'Pending').sum()),
        'hits': hits,
        'misses': misses,
        'hit_rate': round(float(resolved['Hit_Binary'].mean() * 100), 1),
    }

    bucket_lookup = {}
    bucket_rows = []
    if {'Stat', 'Direction'}.issubset(resolved.columns):
        grouped = resolved.groupby(['Stat', 'Direction'], dropna=False).agg(
            resolved=('Hit_Binary', 'count'),
            hits=('Hit_Binary', 'sum'),
            hit_rate=('Hit_Binary', 'mean'),
        ).reset_index()
        for _, row in grouped.iterrows():
            stat = str(row.get('Stat') or '').strip()
            direction = str(row.get('Direction') or '').strip().upper()
            if not stat or not direction:
                continue
            resolved_count = int(row['resolved'])
            hit_rate = float(row['hit_rate'])
            pending_count = int(len(df[
                (df.get('Stat', '').fillna('').astype(str).str.strip() == stat) &
                (df.get('Direction', '').fillna('').astype(str).str.upper() == direction) &
                (df['OutcomeState'] == 'Pending')
            ]))
            reliability = calculate_mlb_launch_reliability(resolved_count, hit_rate)
            payload = {
                'stat': stat,
                'direction': direction,
                'resolved': resolved_count,
                'hits': int(row['hits']),
                'misses': resolved_count - int(row['hits']),
                'hit_rate': round(hit_rate * 100, 1),
                'pending': pending_count,
                'reliability': reliability,
            }
            bucket_rows.append(payload)
            bucket_lookup[(stat.upper(), direction)] = payload
    bucket_order = {'ANCHOR': 0, 'WATCH': 1, 'DEVELOPING': 2, 'SMALL SAMPLE': 3, 'AVOID': 4}
    bucket_rows = sorted(
        bucket_rows,
        key=lambda item: (bucket_order.get(item['reliability'], 9), -item['hit_rate'], -item['resolved'], item['stat']),
    )

    player_lookup = {}
    player_rows = []
    if {'Player', 'Stat', 'Direction'}.issubset(resolved.columns):
        grouped = resolved.groupby(['Player', 'Stat', 'Direction'], dropna=False).agg(
            resolved=('Hit_Binary', 'count'),
            hits=('Hit_Binary', 'sum'),
            hit_rate=('Hit_Binary', 'mean'),
            avg_conf=('Confidence', 'mean') if 'Confidence' in resolved.columns else ('Hit_Binary', 'mean'),
        ).reset_index()
        for _, row in grouped.iterrows():
            player = str(row.get('Player') or '').strip()
            stat = str(row.get('Stat') or '').strip()
            direction = str(row.get('Direction') or '').strip().upper()
            if not player or not stat or not direction:
                continue
            resolved_count = int(row['resolved'])
            hit_rate = float(row['hit_rate'])
            reliability = calculate_mlb_launch_reliability(resolved_count, hit_rate)
            avg_conf = pd.to_numeric(row.get('avg_conf'), errors='coerce')
            model_flag = 'CALIBRATED'
            if pd.notna(avg_conf) and float(avg_conf) >= 70 and hit_rate < 0.52 and resolved_count >= 5:
                model_flag = 'OVERVALUED'
            elif pd.notna(avg_conf) and float(avg_conf) <= 62 and hit_rate >= 0.70 and resolved_count >= 5:
                model_flag = 'UNDERVALUED'
            payload = {
                'player': player,
                'stat': stat,
                'direction': direction,
                'resolved': resolved_count,
                'hits': int(row['hits']),
                'misses': resolved_count - int(row['hits']),
                'hit_rate': round(hit_rate * 100, 1),
                'reliability': reliability,
                'model_flag': model_flag,
                'avg_conf': round(float(avg_conf), 1) if pd.notna(avg_conf) else None,
            }
            player_rows.append(payload)
            player_lookup[(player.upper(), stat.upper(), direction)] = payload
    player_rows = sorted(
        player_rows,
        key=lambda item: (bucket_order.get(item['reliability'], 9), -item['hit_rate'], -item['resolved'], item['player']),
    )

    payload = {
        'bucket_rows': bucket_rows,
        'player_rows': player_rows,
        'bucket_lookup': bucket_lookup,
        'player_lookup': player_lookup,
        'totals': totals,
    }
    if results_df is None:
        RUNTIME_TTL_CACHE[cache_key] = {
            'created_at': datetime.now(timezone.utc),
            'value': payload,
            'version': cache_version,
        }
        _write_disk_ttl_cached_value(f'disk::{cache_key}', 43200, payload, version=cache_version)
    return payload


def build_mlb_launch_lab(results_df=None, gamelogs_df=None):
    if results_df is None and gamelogs_df is None:
        cache_key = 'mlb_launch_lab'
        cache_version = _build_file_token(
            DATA_DIR / 'tracking' / 'MLB_AllPropResults.csv',
            DATA_DIR / 'gamelogs' / 'MLB_GameLogs.csv',
            DATA_DIR / 'tracking' / 'Floor_Play_Index.csv',
        )
        cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
        if cached_entry:
            cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
            if cached_age <= 600 and cached_entry.get('version') == cache_version:
                return cached_entry['value']

    reliability_tables = build_mlb_reliability_tables(results_df)
    bucket_rows = reliability_tables.get('bucket_rows', [])
    totals = reliability_tables.get('totals', {})
    anchors = [row for row in bucket_rows if row.get('reliability') == 'ANCHOR']
    avoids = [row for row in bucket_rows if row.get('reliability') == 'AVOID']
    best = bucket_rows[0] if bucket_rows else {}

    cards = [
        {
            'label': 'Resolved MLB',
            'value': totals.get('resolved', 0),
            'note': f"{totals.get('hits', 0)} hits / {totals.get('misses', 0)} misses"
        },
        {
            'label': 'Current Hit Rate',
            'value': f"{totals.get('hit_rate')}%" if totals.get('hit_rate') is not None else '-',
            'note': f"{totals.get('pending', 0)} pending rows still waiting to grade"
        },
        {
            'label': 'Best Bucket',
            'value': f"{best.get('stat', '-')} {best.get('direction', '')}".strip(),
            'note': f"{best.get('hit_rate', '-')}% over {best.get('resolved', 0)} resolved" if best else 'Need resolved rows'
        },
    ]

    watch_cards = []
    for row in anchors[:4]:
        watch_cards.append({
            'type': 'ANCHOR',
            'title': f"{row['stat']} {row['direction']}",
            'detail': f"{row['hits']}-{row['misses']} ({row['hit_rate']}%) with {row['pending']} pending. This can stabilize MLB/WNBA parlay mixes."
        })
    for row in avoids[:4]:
        watch_cards.append({
            'type': 'AVOID',
            'title': f"{row['stat']} {row['direction']}",
            'detail': f"{row['hits']}-{row['misses']} ({row['hit_rate']}%). Do not let this bucket become a launch anchor yet."
        })

    pitcher_rows = []
    hitter_rows = []
    logs = load_mlb_gamelogs() if gamelogs_df is None else gamelogs_df
    if logs is not None and not logs.empty:
        gl = logs.copy()
        for col in ['IP', 'P_SO', 'P_H', 'P_BB', 'P_OUTS', 'P_PITCHES', 'AB', 'H', 'TB', 'HR', 'SO']:
            if col in gl.columns:
                gl[col] = pd.to_numeric(gl[col], errors='coerce').fillna(0)
        if {'Player', 'Team', 'IP', 'P_SO', 'P_H', 'P_BB', 'P_OUTS'}.issubset(gl.columns):
            pitchers = gl[gl['P_OUTS'] > 0].copy()
            if not pitchers.empty:
                grouped = pitchers.groupby(['Player', 'Team'], dropna=False).agg(
                    games=('GameID', 'nunique') if 'GameID' in pitchers.columns else ('Player', 'count'),
                    ip=('IP', 'sum'),
                    strikeouts=('P_SO', 'sum'),
                    hits_allowed=('P_H', 'sum'),
                    walks=('P_BB', 'sum'),
                    outs_avg=('P_OUTS', 'mean'),
                    pitches_avg=('P_PITCHES', 'mean') if 'P_PITCHES' in pitchers.columns else ('P_OUTS', 'mean'),
                ).reset_index()
                grouped = grouped[grouped['ip'] >= 20].copy()
                grouped['k_per_9'] = np.where(grouped['ip'] > 0, grouped['strikeouts'] / grouped['ip'] * 9, np.nan)
                grouped['h_per_9'] = np.where(grouped['ip'] > 0, grouped['hits_allowed'] / grouped['ip'] * 9, np.nan)
                grouped['whip'] = np.where(grouped['ip'] > 0, (grouped['hits_allowed'] + grouped['walks']) / grouped['ip'], np.nan)
                grouped['pitcher_tag'] = np.where(grouped['k_per_9'] <= 7.0, 'K UNDER WATCH',
                                           np.where(grouped['whip'] <= 1.10, 'HITS ALLOWED UNDER WATCH',
                                           np.where(grouped['outs_avg'] >= 17, 'OUTS OVER WATCH', 'DEVELOPING')))
                for _, row in grouped.sort_values(['k_per_9', 'whip'], ascending=[True, True]).head(10).iterrows():
                    pitcher_rows.append({
                        'player': str(row['Player']),
                        'team': str(row['Team']),
                        'games': int(row['games']),
                        'ip': round(float(row['ip']), 1),
                        'k_per_9': round(float(row['k_per_9']), 1) if pd.notna(row['k_per_9']) else None,
                        'h_per_9': round(float(row['h_per_9']), 1) if pd.notna(row['h_per_9']) else None,
                        'whip': round(float(row['whip']), 2) if pd.notna(row['whip']) else None,
                        'outs_avg': round(float(row['outs_avg']), 1) if pd.notna(row['outs_avg']) else None,
                        'tag': str(row['pitcher_tag']),
                    })
        if {'Player', 'Team', 'AB', 'H', 'TB', 'HR', 'SO'}.issubset(gl.columns):
            hitters = gl[(gl['AB'] > 0) & (gl.get('Position', '').fillna('').astype(str) != 'P')].copy()
            if not hitters.empty:
                grouped = hitters.groupby(['Player', 'Team'], dropna=False).agg(
                    games=('GameID', 'nunique') if 'GameID' in hitters.columns else ('Player', 'count'),
                    ab=('AB', 'sum'),
                    hits=('H', 'sum'),
                    tb=('TB', 'sum'),
                    hr=('HR', 'sum'),
                    so=('SO', 'sum'),
                ).reset_index()
                grouped = grouped[grouped['ab'] >= 50].copy()
                grouped['avg'] = np.where(grouped['ab'] > 0, grouped['hits'] / grouped['ab'], np.nan)
                grouped['tb_per_game'] = np.where(grouped['games'] > 0, grouped['tb'] / grouped['games'], np.nan)
                grouped['k_rate'] = np.where(grouped['ab'] > 0, grouped['so'] / grouped['ab'], np.nan)
                grouped['hr_rate'] = np.where(grouped['ab'] > 0, grouped['hr'] / grouped['ab'], np.nan)
                grouped['hitter_tag'] = np.where((grouped['tb_per_game'] <= 1.2) & (grouped['k_rate'] >= 0.25), 'TOTAL BASES UNDER WATCH',
                                          np.where(grouped['hr_rate'] <= 0.02, 'HR SUPPRESSION WATCH', 'DEVELOPING'))
                for _, row in grouped.sort_values(['tb_per_game', 'k_rate'], ascending=[True, False]).head(10).iterrows():
                    hitter_rows.append({
                        'player': str(row['Player']),
                        'team': str(row['Team']),
                        'games': int(row['games']),
                        'avg': round(float(row['avg']), 3) if pd.notna(row['avg']) else None,
                        'tb_per_game': round(float(row['tb_per_game']), 2) if pd.notna(row['tb_per_game']) else None,
                        'k_rate': round(float(row['k_rate'] * 100), 1) if pd.notna(row['k_rate']) else None,
                        'hr_rate': round(float(row['hr_rate'] * 100), 1) if pd.notna(row['hr_rate']) else None,
                        'tag': str(row['hitter_tag']),
                    })

    summer_mix = []
    floor_path = DATA_DIR / 'tracking' / 'Floor_Play_Index.csv'
    if floor_path.exists():
        try:
            floor_df = _load_cached_csv(floor_path, default=pd.DataFrame())
        except Exception:
            floor_df = pd.DataFrame()
        if floor_df is not None and not floor_df.empty and {'Sport', 'OutcomeState', 'Stat', 'Direction'}.issubset(floor_df.columns):
            floor = floor_df.copy()
            for col in ['Sport', 'OutcomeState', 'Stat', 'Direction', 'Method']:
                floor[col] = floor[col].fillna('').astype(str).str.strip()
            if 'IsFloorPlay' in floor.columns:
                mask = floor['IsFloorPlay'].astype(str).str.lower().isin(['true', '1', 'yes'])
                floor = floor[mask | floor['Method'].str.upper().eq('FLOOR PLAYS')].copy()
            else:
                floor = floor[floor['Method'].str.upper().eq('FLOOR PLAYS')].copy()
            resolved_floor = floor[floor['OutcomeState'].isin(['Hit', 'Miss'])].copy()
            if not resolved_floor.empty:
                resolved_floor['Hit_Binary'] = (resolved_floor['OutcomeState'] == 'Hit').astype(int)
                grouped = resolved_floor[resolved_floor['Sport'].isin(['MLB', 'WNBA'])].groupby(['Sport', 'Stat', 'Direction'], dropna=False).agg(
                    resolved=('Hit_Binary', 'count'),
                    hits=('Hit_Binary', 'sum'),
                    hit_rate=('Hit_Binary', 'mean'),
                ).reset_index()
                for _, row in grouped.iterrows():
                    resolved_count = int(row['resolved'])
                    hit_rate = float(row['hit_rate'])
                    mix_reliability = calculate_mlb_launch_reliability(resolved_count, hit_rate)
                    if mix_reliability in {'ANCHOR', 'WATCH'}:
                        summer_mix.append({
                            'sport': str(row['Sport']),
                            'bucket': f"{row['Stat']} {row['Direction']}",
                            'resolved': resolved_count,
                            'hits': int(row['hits']),
                            'misses': resolved_count - int(row['hits']),
                            'hit_rate': round(hit_rate * 100, 1),
                            'reliability': mix_reliability,
                        })
                summer_mix = sorted(
                    summer_mix,
                    key=lambda item: ({'ANCHOR': 0, 'WATCH': 1}.get(item['reliability'], 9), -item['hit_rate'], -item['resolved']),
                )[:8]

    payload = {
        'cards': cards,
        'bucket_rows': bucket_rows[:12],
        'player_rows': reliability_tables.get('player_rows', [])[:12],
        'watch_cards': watch_cards,
        'pitcher_rows': pitcher_rows,
        'hitter_rows': hitter_rows,
        'summer_mix': summer_mix,
    }
    if results_df is None and gamelogs_df is None:
        RUNTIME_TTL_CACHE[cache_key] = {
            'created_at': datetime.now(timezone.utc),
            'value': payload,
            'version': cache_version,
        }
        _write_disk_ttl_cached_value(f'disk::{cache_key}', 43200, payload, version=cache_version)
    return payload


def annotate_mlb_rows_with_reliability(rows):
    rows = list(rows or [])
    if not rows:
        return rows
    reliability_tables = build_mlb_reliability_tables()
    bucket_lookup = reliability_tables.get('bucket_lookup', {})
    player_lookup = reliability_tables.get('player_lookup', {})
    annotated = []
    for row in rows:
        item = dict(row)
        player = str(item.get('player') or item.get('Player') or '').strip()
        stat = str(item.get('stat') or item.get('Stat') or '').strip()
        direction = str(item.get('direction') or item.get('Direction') or '').strip().upper()
        player_payload = player_lookup.get((player.upper(), stat.upper(), direction), {}) if player and stat and direction else {}
        bucket_payload = bucket_lookup.get((stat.upper(), direction), {}) if stat and direction else {}
        source_payload = player_payload or bucket_payload
        if source_payload:
            item.setdefault('historical_reliability', source_payload.get('reliability'))
            item.setdefault('historical_hit_rate', source_payload.get('hit_rate'))
            item.setdefault('historical_resolved', source_payload.get('resolved'))
            item.setdefault('historical_source', 'Player' if player_payload else 'Bucket')
            if player_payload:
                item.setdefault('player_model_flag', player_payload.get('model_flag'))
        annotated.append(item)
    return annotated


def build_mlb_slate_intelligence(odds_df, prop_rows):
    rows = []
    odds = odds_df.copy() if isinstance(odds_df, pd.DataFrame) else pd.DataFrame()
    props = list(prop_rows or [])
    prop_lookup = {}
    for prop in props:
        matchup = str(prop.get('matchup') or '').strip()
        if not matchup:
            continue
        item = prop_lookup.setdefault(matchup, {
            'props': 0,
            'anchors': 0,
            'watch': 0,
            'avoid': 0,
            'best_anchor': None,
        })
        item['props'] += 1
        reliability = str(prop.get('historical_reliability') or '').strip().upper()
        if reliability == 'ANCHOR':
            item['anchors'] += 1
            candidate = {
                'player': prop.get('player'),
                'stat': prop.get('stat'),
                'direction': prop.get('direction'),
                'hit_rate': prop.get('historical_hit_rate'),
                'resolved': prop.get('historical_resolved'),
            }
            current_best = item.get('best_anchor') or {}
            if not current_best or float(candidate.get('hit_rate') or 0) > float(current_best.get('hit_rate') or 0):
                item['best_anchor'] = candidate
        elif reliability == 'WATCH':
            item['watch'] += 1
        elif reliability == 'AVOID':
            item['avoid'] += 1

    has_team_columns = ({'AwayFull', 'HomeFull'}.issubset(odds.columns) or {'Away', 'Home'}.issubset(odds.columns))
    if odds is None or odds.empty or not has_team_columns:
        for matchup, meta in sorted(prop_lookup.items(), key=lambda kv: (-kv[1]['anchors'], -kv[1]['props'], kv[0]))[:12]:
            away, home = split_game_label(matchup)
            rows.append({
                'matchup': matchup,
                'slug': build_matchup_slug(away, home),
                'date': '',
                'time': '',
                'books': '-',
                'total': '-',
                'total_range': '-',
                'runline_range': '-',
                'environment': 'PROP ONLY',
                'props': meta['props'],
                'anchors': meta['anchors'],
                'watch': meta['watch'],
                'avoid': meta['avoid'],
                'best_anchor': meta.get('best_anchor'),
                'note': 'No game-line row matched this prop group yet.',
            })
        return rows

    working = odds.copy()
    for col in ['Total', 'Spread']:
        if col in working.columns:
            working[col] = pd.to_numeric(working[col], errors='coerce')
    away_col = 'AwayFull' if 'AwayFull' in working.columns else 'Away'
    home_col = 'HomeFull' if 'HomeFull' in working.columns else 'Home'
    group_cols = [col for col in ['Date', 'Time', away_col, home_col] if col in working.columns]
    if len(group_cols) < 2:
        return rows

    for keys, group in working.groupby(group_cols, dropna=False):
        key_map = dict(zip(group_cols, keys if isinstance(keys, tuple) else (keys,)))
        away = str(key_map.get(away_col) or group.iloc[0].get('Away') or '').strip()
        home = str(key_map.get(home_col) or group.iloc[0].get('Home') or '').strip()
        if not away or not home:
            continue
        matchup = f'{away} @ {home}'
        reverse_matchup = f'{home} @ {away}'
        meta = prop_lookup.get(matchup) or prop_lookup.get(reverse_matchup) or {'props': 0, 'anchors': 0, 'watch': 0, 'avoid': 0, 'best_anchor': None}
        totals = pd.to_numeric(group.get('Total', pd.Series(dtype=float)), errors='coerce').dropna()
        spreads = pd.to_numeric(group.get('Spread', pd.Series(dtype=float)), errors='coerce').dropna()
        total_avg = round(float(totals.mean()), 1) if not totals.empty else None
        total_range = round(float(totals.max() - totals.min()), 1) if len(totals) > 1 else 0 if not totals.empty else None
        spread_range = round(float(spreads.max() - spreads.min()), 1) if len(spreads) > 1 else 0 if not spreads.empty else None
        books = sorted({str(book).strip() for book in group.get('Book', pd.Series(dtype=str)).dropna().tolist() if str(book).strip()})
        if total_avg is None:
            environment = 'NO TOTAL'
            note = 'No game total loaded yet, so prop context is coming from market and trend data.'
        elif total_avg >= 9:
            environment = 'HITTER FRIENDLY'
            note = 'High total supports hitter volume, but pitcher overs need extra proof.'
        elif total_avg <= 7.5:
            environment = 'PITCHER FRIENDLY'
            note = 'Low total supports hitter unders and cleaner pitcher-out/K contexts.'
        else:
            environment = 'NEUTRAL'
            note = 'Total is neutral, so book split and player reliability matter more.'
        if total_range is not None and total_range >= 0.5:
            note = f'{note} Books differ by {total_range:g} runs on the total.'
        if meta.get('avoid', 0):
            note = f"{note} {meta['avoid']} current props sit in historical avoid buckets."
        rows.append({
            'matchup': matchup,
            'slug': build_matchup_slug(away, home),
            'date': str(key_map.get('Date') or '').strip(),
            'time': str(key_map.get('Time') or '').strip(),
            'books': ', '.join(books[:4]) if books else '-',
            'total': f'{total_avg:g}' if total_avg is not None else '-',
            'total_range': f'{total_range:g}' if total_range is not None else '-',
            'runline_range': f'{spread_range:g}' if spread_range is not None else '-',
            'environment': environment,
            'props': int(meta.get('props', 0)),
            'anchors': int(meta.get('anchors', 0)),
            'watch': int(meta.get('watch', 0)),
            'avoid': int(meta.get('avoid', 0)),
            'best_anchor': meta.get('best_anchor'),
            'note': note,
        })

    rows.sort(key=lambda item: (-item['anchors'], -item['watch'], -item['props'], item['matchup']))
    return rows[:12]


def _normalize_mlb_team_key(team):
    return re.sub(r'[^a-z0-9]+', '', str(team or '').strip().lower())


def build_mlb_odds_lookup(odds_df, schedule_df):
    lookup = {}
    frames = [df for df in [odds_df, schedule_df] if df is not None and not df.empty]
    if not frames:
        return lookup

    merged = pd.concat(frames, ignore_index=True, sort=False)
    dedupe_cols = [col for col in ['Away', 'Home', 'Date', 'Time', 'Book'] if col in merged.columns]
    if dedupe_cols:
        merged = merged.drop_duplicates(subset=dedupe_cols, keep='first')

    for _, row in merged.iterrows():
        away = str(row.get('AwayFull') or row.get('Away') or '').strip()
        home = str(row.get('HomeFull') or row.get('Home') or '').strip()
        if not away or not home or away.lower() in {'nan', 'none', 'null'} or home.lower() in {'nan', 'none', 'null'}:
            continue
        game_key = f'{away}@{home}'
        slug = build_matchup_slug(away, home)
        payload = {
            'away': away,
            'home': home,
            'away_abbr': MLB_TEAM_NAME_TO_ABBR.get(away, str(row.get('Away') or '').strip()),
            'home_abbr': MLB_TEAM_NAME_TO_ABBR.get(home, str(row.get('Home') or '').strip()),
            'date': str(row.get('Date') or '').strip(),
            'time': str(row.get('Time') or '').strip(),
            'book': str(row.get('Book') or '').strip(),
            'away_ml': row.get('AwayML'),
            'home_ml': row.get('HomeML'),
            'spread': row.get('Spread'),
            'spread_odds': row.get('SpreadOdds'),
            'total': row.get('Total'),
            'over_odds': row.get('OverOdds'),
            'under_odds': row.get('UnderOdds'),
            'slug': slug,
        }
        lookup[game_key] = payload
        lookup[slug] = payload
    return lookup


def build_mlb_market_note(direction, over_rate, under_rate, is_one_sided=False):
    if is_one_sided:
        return 'One-sided market: books are posting the yes/over side only, so this is not a normal two-way O/U price.'
    if over_rate is None or under_rate is None:
        return 'Market split unavailable for this prop right now.'
    edge = abs(float(over_rate) - float(under_rate))
    if edge < 2:
        return 'This baseball prop is priced close to a coin flip.'
    if direction == 'OVER':
        if edge >= 10:
            return 'Books are clearly leaning over on this number.'
        if edge >= 5:
            return 'The market has a measurable over lean here.'
        return 'There is only a light over lean in the current prices.'
    if edge >= 10:
        return 'Books are clearly leaning under on this number.'
    if edge >= 5:
        return 'The market has a measurable under lean here.'
    return 'There is only a light under lean in the current prices.'


def build_mlb_book_comparison_note(dk_line, vegas_line, line_low, line_high, direction, best_book):
    notes = []
    if dk_line is not None and vegas_line is not None:
        try:
            delta = round(float(dk_line) - float(vegas_line), 1)
        except Exception:
            delta = 0
        if abs(delta) >= 0.5:
            if delta > 0:
                notes.append(f'DraftKings is {abs(delta):g} higher than Caesars on this line.')
            else:
                notes.append(f'Caesars is {abs(delta):g} higher than DraftKings on this line.')
        else:
            notes.append('DraftKings and Caesars are dealing basically the same line.')
    elif vegas_line is not None:
        notes.append('Caesars is acting as the Vegas reference for this market.')
    elif dk_line is not None:
        notes.append('DraftKings is loaded, but the Vegas comparison book is missing.')

    if line_low is not None and line_high is not None and line_high != line_low:
        notes.append(f'The live range is {line_low:g} to {line_high:g} across books.')

    if best_book:
        notes.append(f'Best {direction.lower()} price is currently at {best_book}.')
    return ' '.join(notes[:3]).strip()


def build_mlb_game_environment_note(total, stat, direction, context=None):
    stat = str(stat or '').strip()
    note_bits = []
    total_num = pd.to_numeric(total, errors='coerce')
    if pd.notna(total_num):
        total_num = float(total_num)
        if total_num >= 9:
            if stat in {'Hits', 'Total Bases', 'RBIs', 'Runs'} and direction == 'OVER':
                note_bits.append('This is a healthy total for hitter overs, so run environment is supportive.')
            elif stat in {'Pitcher Ks', 'Pitcher Outs'} and direction == 'UNDER':
                note_bits.append('This is a lively run environment, which can pressure pitcher unders into play faster.')
        elif total_num <= 7.5:
            if stat in {'Hits', 'Total Bases', 'RBIs', 'Runs'} and direction == 'UNDER':
                note_bits.append('This is a lower total, which makes hitter unders a little easier to justify.')
            elif stat in {'Pitcher Ks', 'Pitcher Outs'} and direction == 'OVER':
                note_bits.append('This is a lower total, which can help efficient starting-pitcher overs hold together.')

    context = context or {}
    tags = set(context.get('context_tags') or [])
    raw_context = context.get('context') or {}
    if 'WIND OUT' in tags:
        if stat in {'Home Runs', 'Total Bases', 'Hits', 'Runs', 'RBIs'} and direction == 'OVER':
            note_bits.append('Wind context is helping hitter/power overs.')
        elif stat in {'Home Runs', 'Total Bases'} and direction == 'UNDER':
            note_bits.append('Wind context is fighting this power under.')
    if 'WIND IN' in tags:
        if stat in {'Home Runs', 'Total Bases'} and direction == 'UNDER':
            note_bits.append('Wind context supports power suppression.')
        elif stat in {'Home Runs', 'Total Bases'} and direction == 'OVER':
            note_bits.append('Wind context is fighting this power over.')
    if 'WIDE ZONE' in tags and stat in {'Pitcher Ks', 'Pitcher Outs'}:
        note_bits.append('Wide-zone umpire context supports pitcher control/K outcomes.')
    if 'TIGHT ZONE' in tags and stat in {'Pitcher Ks', 'Pitcher Outs'}:
        note_bits.append('Tight-zone umpire context can pressure pitcher overs.')
    if raw_context.get('ballpark'):
        note_bits.append(f"Context source loaded for {raw_context.get('ballpark')}.")

    if not note_bits:
        return 'The game environment looks fairly neutral, so the market split is doing most of the work here.'
    return ' '.join(note_bits[:2])


def build_mlb_recent_form_note(player_name, stat, line, gamelogs, sample_size=5):
    stat_col = MLB_STAT_COLUMN_MAP.get(str(stat or '').strip())
    if not stat_col or gamelogs is None or gamelogs.empty or stat_col not in gamelogs.columns or 'Player' not in gamelogs.columns:
        return ''

    player_logs = gamelogs[gamelogs['Player'] == player_name].copy()
    if player_logs.empty:
        return ''
    if 'Date' in player_logs.columns:
        player_logs['Date'] = pd.to_datetime(player_logs['Date'], errors='coerce')
        player_logs = player_logs.sort_values('Date', ascending=False)
    recent = player_logs.head(sample_size).copy()
    if recent.empty:
        return ''

    values = pd.to_numeric(recent[stat_col], errors='coerce').dropna()
    if values.empty:
        return ''

    line_value = pd.to_numeric(line, errors='coerce')
    if pd.isna(line_value):
        return ''

    avg = round(float(values.mean()), 1)
    hits_over = int((values > float(line_value)).sum())
    hits_under = int((values < float(line_value)).sum())
    actual_n = int(len(values))
    stat_label = str(stat or '').strip().lower()

    if hits_over == actual_n:
        return f'Cleared {line_value:g} in all of the last {actual_n} games, averaging {avg} {stat_label}.'
    if hits_under == actual_n:
        return f'Stayed below {line_value:g} in all of the last {actual_n} games, averaging {avg} {stat_label}.'
    if hits_over > hits_under:
        return f'Averaging {avg} {stat_label} over the last {actual_n} games and clearing {line_value:g} in {hits_over} of them.'
    if hits_under > hits_over:
        return f'Averaging {avg} {stat_label} over the last {actual_n} games and staying below {line_value:g} in {hits_under} of them.'
    return f'Averaging {avg} {stat_label} over the last {actual_n} games with a mixed hit profile around {line_value:g}.'


def build_mlb_recent_form_lookup(gamelogs, sample_size=5):
    if gamelogs is None or gamelogs.empty or 'Player' not in gamelogs.columns:
        return {}
    working = gamelogs.copy()
    if 'Date' in working.columns:
        working['Date'] = pd.to_datetime(working['Date'], errors='coerce')
        working = working.sort_values(['Player', 'Date'], ascending=[True, False])
    lookup = {}
    for player_name, player_logs in working.groupby('Player', sort=False):
        player_key = str(player_name or '').strip()
        if player_key:
            lookup[player_key] = player_logs.head(sample_size).copy()
    return lookup


def build_mlb_recent_form_note_from_lookup(player_name, stat, line, recent_form_lookup, sample_size=5):
    if not recent_form_lookup:
        return ''
    player_logs = recent_form_lookup.get(str(player_name or '').strip())
    if player_logs is None or player_logs.empty:
        return ''
    stat_col = MLB_STAT_COLUMN_MAP.get(str(stat or '').strip())
    if not stat_col or stat_col not in player_logs.columns:
        return ''

    recent = player_logs.head(sample_size).copy()
    values = pd.to_numeric(recent[stat_col], errors='coerce').dropna()
    if values.empty:
        return ''

    line_value = pd.to_numeric(line, errors='coerce')
    if pd.isna(line_value):
        return ''

    avg = round(float(values.mean()), 1)
    hits_over = int((values > float(line_value)).sum())
    hits_under = int((values < float(line_value)).sum())
    actual_n = int(len(values))
    stat_label = str(stat or '').strip().lower()

    if hits_over == actual_n:
        return f'Cleared {line_value:g} in all of the last {actual_n} games, averaging {avg} {stat_label}.'
    if hits_under == actual_n:
        return f'Stayed below {line_value:g} in all of the last {actual_n} games, averaging {avg} {stat_label}.'
    if hits_over > hits_under:
        return f'Averaging {avg} {stat_label} over the last {actual_n} games and clearing {line_value:g} in {hits_over} of them.'
    if hits_under > hits_over:
        return f'Averaging {avg} {stat_label} over the last {actual_n} games and staying below {line_value:g} in {hits_under} of them.'
    return f'Averaging {avg} {stat_label} over the last {actual_n} games with a mixed hit profile around {line_value:g}.'


MLB_BATTER_LINEUP_STATS = {
    'HITS', 'TOTAL BASES', 'RUNS', 'RBIS', 'HOME RUNS', 'DOUBLES', 'TRIPLES',
    'SINGLES', 'STOLEN BASES', 'BATTER WALKS', 'BATTER STRIKEOUTS',
}

MLB_PITCHER_LINEUP_STATS = {
    'PITCHER STRIKEOUTS', 'STRIKEOUTS', 'PITCHER OUTS', 'OUTS RECORDED',
    'EARNED RUNS', 'PITCHER WALKS', 'HITS ALLOWED',
}


def classify_mlb_lineup_gate(stat, source_row=None):
    row = source_row if source_row is not None else {}
    status_fields = [
        'LineupStatus', 'lineup_status', 'ConfirmedLineup', 'confirmed_lineup',
        'StartingStatus', 'starting_status', 'BattingOrder', 'batting_order',
    ]
    raw_status = ''
    for field in status_fields:
        if hasattr(row, 'get'):
            value = row.get(field)
            if value is not None and not pd.isna(value) and str(value).strip():
                raw_status = str(value).strip()
                break

    normalized_status = raw_status.upper()
    stat_key = str(stat or '').strip().upper()
    is_pitcher_market = stat_key in MLB_PITCHER_LINEUP_STATS or 'PITCHER' in stat_key
    is_batter_market = stat_key in MLB_BATTER_LINEUP_STATS or not is_pitcher_market

    if normalized_status in {'CONFIRMED', 'STARTING', 'LOCKED', 'YES', 'TRUE', '1'}:
        return {
            'status': 'CONFIRMED',
            'label': 'LINEUP CONFIRMED',
            'class': 'confirmed',
            'note': 'Starting status is present in the feed.',
            'is_confirmed': True,
        }

    if is_pitcher_market:
        return {
            'status': 'PROBABLE',
            'label': 'PITCHER PROBABLE',
            'class': 'watch',
            'note': 'Pitcher markets can be reviewed before batting orders lock, but confirm starter/news before final ticket build.',
            'is_confirmed': False,
        }

    if is_batter_market:
        return {
            'status': 'PENDING',
            'label': 'LINEUP PENDING',
            'class': 'pending',
            'note': 'Do not treat this batter prop as final until starting lineup and batting order are confirmed.',
            'is_confirmed': False,
        }

    return {
        'status': 'UNKNOWN',
        'label': 'CONFIRM ROLE',
        'class': 'pending',
        'note': 'Starting role was not confirmed by the current feed.',
        'is_confirmed': False,
    }


def build_mlb_prop_board(props_df, odds_df, schedule_df, gamelogs=None, date_filter='today', stat_filter='', direction_filter='all', search_query='', cache_namespace='default', max_groups=None, fast_mode=False):
    cache_key = 'mlb_prop_board::fast_mode_v5::{cache_namespace}::{date_filter}::{stat_filter}::{direction_filter}::{search_query}::{max_groups}::{fast_mode}'.format(
        cache_namespace=str(cache_namespace or 'default'),
        date_filter=str(date_filter or ''),
        stat_filter=str(stat_filter or ''),
        direction_filter=str(direction_filter or ''),
        search_query=str(search_query or '').strip().lower(),
        max_groups=str(max_groups or ''),
        fast_mode=int(bool(fast_mode)),
    )
    cache_version = _build_file_token(
        DATA_DIR / 'props' / 'MLB_Props.csv',
        DATA_DIR / 'props' / 'MLB_Props_Fallback.csv',
        DATA_DIR / 'odds' / 'MLB_Odds.csv',
        DATA_DIR / 'schedules' / 'MLB_Schedule.csv',
        DATA_DIR / 'gamelogs' / 'MLB_GameLogs.csv',
        DATA_DIR / 'injuries' / 'MLB_Injuries.csv',
        DATA_DIR / 'tracking' / 'MLB_Calibration_Report.csv',
        DATA_DIR / 'tracking' / 'MLB_Simulation_Results.csv',
        DATA_DIR / 'tracking' / 'MLB_AllPropResults.csv',
        DATA_DIR / 'tracking' / 'Team_Strength_Priors.csv',
    )
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry:
        cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
        if cached_age <= 43200 and cached_entry.get('version') == cache_version:
            return cached_entry['value']

    disk_cache_key = f'disk::{cache_key}'
    disk_hit, disk_rows = _read_disk_ttl_cached_value(disk_cache_key, version=cache_version)
    if disk_hit:
        RUNTIME_TTL_CACHE[cache_key] = {
            'created_at': datetime.now(timezone.utc),
            'value': disk_rows,
            'version': cache_version,
        }
        return disk_rows

    if props_df is None or props_df.empty:
        return []

    odds_lookup = build_mlb_odds_lookup(odds_df, schedule_df)
    stat_filter = str(stat_filter or '').strip()
    direction_filter = str(direction_filter or 'all').strip().lower() or 'all'
    search_query = str(search_query or '').strip().lower()

    today = sports_today_ts()
    tomorrow = today + pd.Timedelta(days=1)
    if date_filter in {'today', 'tomorrow'} and 'Game' in props_df.columns:
        target_day = today if date_filter == 'today' else tomorrow
        allowed_games = set()
        for key, market in odds_lookup.items():
            if '-' in str(key or ''):
                continue
            parsed_date = pd.to_datetime(str(market.get('date') or '').strip(), errors='coerce')
            if pd.notna(parsed_date) and parsed_date.normalize() == target_day:
                allowed_games.add(_mlb_prop_game_key(key))
        if allowed_games:
            props_df = props_df[props_df['Game'].astype(str).map(_mlb_prop_game_key).isin(allowed_games)].copy()
        else:
            props_df = props_df.iloc[0:0].copy()
    if props_df.empty:
        return []

    if stat_filter and 'Stat' in props_df.columns:
        props_df = props_df[props_df['Stat'].astype(str).str.strip() == stat_filter].copy()
    if search_query:
        search_cols = [col for col in ['Player', 'Stat', 'Game', 'Team', 'Book'] if col in props_df.columns]
        if search_cols:
            haystack = props_df[search_cols].astype(str).agg(' '.join, axis=1).str.lower()
            props_df = props_df[haystack.str.contains(re.escape(search_query), na=False)].copy()
    if props_df.empty:
        return []

    reliability_tables = build_mlb_reliability_tables()
    bucket_reliability_lookup = reliability_tables.get('bucket_lookup', {})
    player_reliability_lookup = reliability_tables.get('player_lookup', {})
    latest_team_map = {}
    environment_lookup = build_mlb_game_environment_lookup()
    recent_form_lookup = build_mlb_recent_form_lookup(gamelogs)
    if gamelogs is not None and not gamelogs.empty and {'Player', 'Team', 'Date'}.issubset(gamelogs.columns):
        latest_logs = gamelogs.copy()
        latest_logs['Date'] = pd.to_datetime(latest_logs['Date'], errors='coerce')
        latest_logs = latest_logs.sort_values('Date', ascending=False)
        latest_team_map = (
            latest_logs.dropna(subset=['Player'])
            .drop_duplicates(subset=['Player'], keep='first')
            .set_index('Player')['Team']
            .astype(str)
            .str.strip()
            .to_dict()
        )

    rows = []
    group_cols = [col for col in ['Player', 'Stat', 'Game'] if col in props_df.columns]
    if len(group_cols) < 3:
        return []

    grouped = props_df.groupby(group_cols, dropna=False, sort=False)

    for (player, stat, game), market_rows in grouped:
        if max_groups is not None and len(rows) >= int(max_groups):
            break
        player = str(player or '').strip()
        stat = str(stat or '').strip()
        game = str(game or '').strip()
        if not player or not stat or not game:
            continue

        market = odds_lookup.get(game, {})
        away = market.get('away')
        home = market.get('home')
        if not away or not home:
            away, home = split_market_game_label(game)
        if not away or not home:
            continue

        market_rows = market_rows.copy()
        for col in ['CurrentLine', 'Line', 'OverOdds', 'UnderOdds']:
            if col in market_rows.columns:
                market_rows[col] = pd.to_numeric(market_rows[col], errors='coerce')

        if stat_filter and stat != stat_filter:
            continue

        game_date = str(market.get('date') or '').strip()
        game_time = str(market.get('time') or '').strip()
        game_day = None
        if game_date:
            parsed_date = pd.to_datetime(game_date, errors='coerce')
            if pd.notna(parsed_date):
                game_day = parsed_date.normalize()

        if date_filter == 'today' and game_day is not None and game_day != today:
            continue
        if date_filter == 'tomorrow' and game_day is not None and game_day != tomorrow:
            continue

        dk_rows = market_rows[market_rows.get('Book', '').astype(str).str.lower() == 'draftkings'] if 'Book' in market_rows.columns else pd.DataFrame()
        vegas_rows = market_rows[market_rows.get('Book', '').astype(str).str.lower() == 'caesars'] if 'Book' in market_rows.columns else pd.DataFrame()
        primary_row = dk_rows.iloc[0] if not dk_rows.empty else market_rows.iloc[0]
        vegas_row = vegas_rows.iloc[0] if not vegas_rows.empty else None

        line = primary_row.get('CurrentLine')
        if pd.isna(line):
            line = primary_row.get('Line')
        if pd.isna(line):
            numeric_lines = pd.to_numeric(market_rows.get('CurrentLine', market_rows.get('Line')), errors='coerce').dropna()
            line = numeric_lines.median() if not numeric_lines.empty else np.nan
        if pd.isna(line):
            continue

        book_probs = []
        one_sided_books = []
        for book_row in market_rows.to_dict('records'):
            over_prob = american_odds_to_implied_prob(book_row.get('OverOdds'))
            under_prob = american_odds_to_implied_prob(book_row.get('UnderOdds'))
            total_prob = (over_prob or 0) + (under_prob or 0)
            if total_prob > 0 and over_prob is not None and under_prob is not None:
                book_probs.append({
                    'book': str(book_row.get('Book') or '').strip(),
                    'over_rate': (over_prob / total_prob) * 100,
                    'under_rate': (under_prob / total_prob) * 100,
                    'line': book_row.get('CurrentLine') if pd.notna(book_row.get('CurrentLine')) else book_row.get('Line'),
                    'over_odds': book_row.get('OverOdds'),
                    'under_odds': book_row.get('UnderOdds'),
                })
            elif over_prob is not None and under_prob is None:
                one_sided_books.append({
                    'book': str(book_row.get('Book') or '').strip(),
                    'over_rate': over_prob * 100,
                    'under_rate': None,
                    'line': book_row.get('CurrentLine') if pd.notna(book_row.get('CurrentLine')) else book_row.get('Line'),
                    'over_odds': book_row.get('OverOdds'),
                    'under_odds': None,
                })

        is_one_sided = False
        if not book_probs and one_sided_books:
            book_probs = one_sided_books
            is_one_sided = True

        if not book_probs:
            continue

        over_rate = round(float(np.mean([item['over_rate'] for item in book_probs])), 1)
        if is_one_sided:
            under_rate = None
            direction = 'OVER'
            lean_prob = over_rate
            lean_gap = None
        else:
            under_rate = round(float(np.mean([item['under_rate'] for item in book_probs])), 1)
            direction = 'OVER' if over_rate >= under_rate else 'UNDER'
            lean_prob = over_rate if direction == 'OVER' else under_rate
            lean_gap = round(abs(over_rate - under_rate), 1)

        if direction_filter in {'over', 'under'} and direction.lower() != direction_filter:
            continue

        matchup_text = f'{away} @ {home}'
        if search_query and search_query not in ' '.join([player, stat, matchup_text]).lower():
            continue
        environment_payload = environment_lookup.get(_mlb_prop_game_key(game)) or environment_lookup.get(_mlb_prop_game_key(matchup_text)) or {}
        environment_context = classify_prop_game_environment(market.get('total'), market.get('spread'), sport='MLB')
        game_environment_label = environment_payload.get('environment') or environment_context.get('label') or 'NO TOTAL'
        game_environment_summary = environment_payload.get('summary') or environment_context.get('summary') or ''

        stat_key = stat.upper()
        direction_key = direction.upper()
        player_reliability = player_reliability_lookup.get((player.upper(), stat_key, direction_key), {})
        bucket_reliability = bucket_reliability_lookup.get((stat_key, direction_key), {})
        reliability_label = player_reliability.get('reliability') or bucket_reliability.get('reliability') or 'UNPROVEN'
        reliability_hit_rate = player_reliability.get('hit_rate') if player_reliability else bucket_reliability.get('hit_rate')
        reliability_resolved = player_reliability.get('resolved') if player_reliability else bucket_reliability.get('resolved')
        reliability_source = 'Player' if player_reliability else 'Bucket' if bucket_reliability else 'Pending'

        priced_books = [
            item for item in book_probs
            if item.get('over_odds' if direction == 'OVER' else 'under_odds') is not None
            and not pd.isna(item.get('over_odds' if direction == 'OVER' else 'under_odds'))
        ]
        best_row = max(priced_books, key=lambda item: float(item['over_odds'] if direction == 'OVER' else item['under_odds'])) if priced_books else None
        market_price = best_row['over_odds'] if direction == 'OVER' else best_row['under_odds'] if best_row else None
        best_book = best_row['book'] if best_row else str(primary_row.get('Book') or '').strip()

        numeric_lines = []
        for candidate in pd.concat([market_rows['CurrentLine'], market_rows['Line']], axis=0).dropna().tolist():
            try:
                numeric_lines.append(float(candidate))
            except Exception:
                continue
        line_low = min(numeric_lines) if numeric_lines else None
        line_high = max(numeric_lines) if numeric_lines else None
        range_span = abs(float(line_high) - float(line_low)) if line_low is not None and line_high is not None else 0.0
        dk_line = primary_row.get('CurrentLine') if pd.notna(primary_row.get('CurrentLine')) else primary_row.get('Line')
        vegas_line = vegas_row.get('CurrentLine') if vegas_row is not None and pd.notna(vegas_row.get('CurrentLine')) else vegas_row.get('Line') if vegas_row is not None else None

        primary_team_value = primary_row.get('Team')
        if primary_team_value is None or pd.isna(primary_team_value) or not str(primary_team_value).strip():
            primary_team_value = latest_team_map.get(player, '')
        player_team_abbr = str(primary_team_value or '').strip().upper()
        away_abbr = str(market.get('away_abbr') or MLB_TEAM_NAME_TO_ABBR.get(away, '')).strip().upper()
        home_abbr = str(market.get('home_abbr') or MLB_TEAM_NAME_TO_ABBR.get(home, '')).strip().upper()
        if player_team_abbr == away_abbr and away_abbr:
            team_name = away
            opponent_name = home
        elif player_team_abbr == home_abbr and home_abbr:
            team_name = home
            opponent_name = away
        else:
            team_name = MLB_TEAM_ABBR_TO_NAME.get(player_team_abbr, away)
            opponent_name = home if _normalize_mlb_team_key(team_name) == _normalize_mlb_team_key(away) else away

        play_verdict = 'PLAY'
        verdict_note = ''
        guardrail_tags = []
        if is_one_sided:
            play_verdict = 'CONFLICTED'
            verdict_note = 'One-sided yes market only. Treat this as price discovery and matchup intelligence until a no/under price is available.'
            guardrail_tags.extend(['ONE SIDED', 'NO UNDER PRICE'])
        elif float(line) == 0.5 and direction == 'UNDER' and stat in {'Hits', 'RBIs', 'Runs'}:
            play_verdict = 'CONFLICTED'
            verdict_note = 'Zero-required under: one event kills this ticket, so it is more fragile than a normal under.'
            guardrail_tags.extend(['ZERO REQUIRED', 'FRAGILE UNDER'])
        elif market_rows['Book'].dropna().nunique() < 2:
            play_verdict = 'CONFLICTED'
            verdict_note = 'Single-book confirmation only. This needs wider market support before it should be trusted as a clean play.'
            guardrail_tags.append('SINGLE BOOK')
        elif range_span >= 1.0:
            play_verdict = 'CONFLICTED'
            verdict_note = 'Books are dealing a wide line range here, so the market is not speaking with one voice yet.'
            guardrail_tags.append('WIDE RANGE')
        elif lean_gap < 4:
            play_verdict = 'CONFLICTED'
            verdict_note = 'The market lean is still light here, so this reads more like a lean than a true play.'
            guardrail_tags.append('LIGHT EDGE')

        lineup_gate = classify_mlb_lineup_gate(stat, primary_row)
        if lineup_gate.get('status') == 'PENDING':
            if play_verdict == 'PLAY':
                play_verdict = 'CONFLICTED'
                verdict_note = lineup_gate.get('note') or verdict_note
            guardrail_tags.append('LINEUP PENDING')
        elif lineup_gate.get('status') == 'PROBABLE':
            guardrail_tags.append('CONFIRM STARTER')

        statcast_signal = build_statcast_prop_signal(player, stat, direction)
        statcast_delta = float(statcast_signal.get('score_delta') or 0.0) if statcast_signal.get('available') else 0.0
        statcast_note = str(statcast_signal.get('note') or '').strip() if statcast_signal.get('available') else ''
        for tag in statcast_signal.get('tags') or []:
            if tag and tag not in guardrail_tags:
                guardrail_tags.append(tag)

        rows.append({
            'player': player,
            'team': team_name,
            'opponent': opponent_name,
            'stat': stat,
            'line': round(float(line), 1),
            'game': game,
            'matchup': matchup_text,
            'away': away,
            'home': home,
            'game_date': game_date,
            'game_time': game_time,
            'matchup_slug': build_matchup_slug(away, home),
            'direction': direction,
            'over_rate': over_rate,
            'under_rate': under_rate,
            'market_prob': round(float(lean_prob), 1),
            'market_confidence': round(max(50.0, min(normalize_confidence_rate(lean_prob) + statcast_delta, 99.0)), 1),
            'raw_market_confidence': normalize_confidence_rate(lean_prob),
            'lean_gap': lean_gap,
            'lean_strength': 'One-sided' if is_one_sided else 'Strong' if lean_gap >= 10 else 'Medium' if lean_gap >= 5 else 'Light',
            'market_price': int(market_price) if market_price is not None and not pd.isna(market_price) else None,
            'fair_price': prob_to_american_odds((lean_prob / 100) if lean_prob is not None else None),
            'book': str(primary_row.get('Book') or market.get('book') or '').strip(),
            'book_count': int(market_rows['Book'].dropna().nunique()) if 'Book' in market_rows.columns else 1,
            'books': sorted([str(book).strip() for book in market_rows['Book'].dropna().unique().tolist() if str(book).strip()]) if 'Book' in market_rows.columns else [],
            'draftkings_line': round(float(dk_line), 1) if dk_line is not None and not pd.isna(dk_line) else None,
            'vegas_line': round(float(vegas_line), 1) if vegas_line is not None and not pd.isna(vegas_line) else None,
            'line_low': round(float(line_low), 1) if line_low is not None else None,
            'line_high': round(float(line_high), 1) if line_high is not None else None,
            'best_book': best_book,
            'is_one_sided': is_one_sided,
            'market_type': 'ONE_SIDED_YES' if is_one_sided else 'TWO_WAY_TOTAL',
            'market_note': build_mlb_market_note(direction, over_rate, under_rate, is_one_sided=is_one_sided),
            'book_comparison_note': build_mlb_book_comparison_note(dk_line, vegas_line, line_low, line_high, direction, best_book),
            'environment_note': build_mlb_game_environment_note(market.get('total'), stat, direction, context=environment_payload),
            'environment_tags': environment_payload.get('context_tags', []),
            'game_environment_label': game_environment_label,
            'game_environment_summary': game_environment_summary,
            'trend_note': build_mlb_recent_form_note_from_lookup(player, stat, line, recent_form_lookup),
            'historical_reliability': reliability_label,
            'historical_hit_rate': reliability_hit_rate,
            'historical_resolved': reliability_resolved,
            'historical_source': reliability_source,
            'player_model_flag': player_reliability.get('model_flag') if player_reliability else '',
            'total': market.get('total'),
            'spread': market.get('spread'),
            'away_ml': market.get('away_ml'),
            'home_ml': market.get('home_ml'),
            'last_updated': str(primary_row.get('LastUpdated') or '').strip(),
            'play_verdict': play_verdict,
            'play_verdict_note': verdict_note,
            'guardrail_tags': guardrail_tags,
            'guardrail_note': verdict_note,
            'statcast_signal': statcast_signal,
            'statcast_score_delta': statcast_delta,
            'statcast_note': statcast_note,
            'lineup_gate_status': lineup_gate.get('status'),
            'lineup_gate_label': lineup_gate.get('label'),
            'lineup_gate_class': lineup_gate.get('class'),
            'lineup_gate_note': lineup_gate.get('note'),
            'lineup_confirmed': bool(lineup_gate.get('is_confirmed')),
        })

    verdict_rank = {'PLAY': 2, 'CONFLICTED': 1, 'PASS': 0}
    rows.sort(
        key=lambda item: (
            -verdict_rank.get(str(item.get('play_verdict') or 'PLAY').upper(), 1),
            -float(item.get('lean_gap') or 0),
            -float(item.get('market_prob') or 0),
            item.get('player', ''),
            item.get('stat', ''),
        )
    )
    rows = annotate_prop_rows_with_injuries(rows, load_sport_injuries('mlb'))
    rows = apply_mlb_contradiction_guardrails(rows, featured_top_n=0)
    if not fast_mode:
        rows = apply_live_calibration_adjustments(rows, 'MLB', score_field='market_confidence')
    rows = attach_promotion_signals_to_props(rows, sport='MLB', score_fields=('market_confidence',))
    if not fast_mode:
        rows = attach_active_simulation_insights_to_rows(rows, sport='MLB')
    rows = attach_team_strength_priors_to_rows(rows, sport='MLB')
    rows = apply_mlb_contradiction_guardrails(rows, featured_top_n=0)
    rows.sort(
        key=lambda item: (
            -_mlb_verdict_sort_rank(item),
            -float(item.get('promotion_boost') or 0),
            -float(item.get('lean_gap') or 0),
            -float(item.get('market_prob') or 0),
            item.get('player', ''),
            item.get('stat', ''),
        )
    )
    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': rows,
        'version': cache_version,
    }
    _write_disk_ttl_cached_value(disk_cache_key, 43200, rows, version=cache_version)
    return rows


def build_mlb_method_board(method_key, props_df, odds_df, schedule_df, gamelogs=None, date_filter='today', stat_filter='', direction_filter='all', search_query='', featured_top_n=12, max_groups=None, fast_mode=False):
    method_key = str(method_key or 'market_edge').strip().lower()
    cache_key = 'mlb_method_board::fast_mode_v3::{method_key}::{date_filter}::{stat_filter}::{direction_filter}::{search_query}::{featured_top_n}::{max_groups}::{fast_mode}'.format(
        method_key=method_key,
        date_filter=str(date_filter or ''),
        stat_filter=str(stat_filter or ''),
        direction_filter=str(direction_filter or ''),
        search_query=str(search_query or '').strip().lower(),
        featured_top_n=int(featured_top_n or 0),
        max_groups=str(max_groups or ''),
        fast_mode=int(bool(fast_mode)),
    )
    cache_version = _build_file_token(
        DATA_DIR / 'props' / 'MLB_Props.csv',
        DATA_DIR / 'props' / 'MLB_Props_Fallback.csv',
        DATA_DIR / 'odds' / 'MLB_Odds.csv',
        DATA_DIR / 'schedules' / 'MLB_Schedule.csv',
        DATA_DIR / 'gamelogs' / 'MLB_GameLogs.csv',
        DATA_DIR / 'injuries' / 'MLB_Injuries.csv',
        DATA_DIR / 'tracking' / 'MLB_Calibration_Report.csv',
    )
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry:
        cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
        if cached_age <= 43200 and cached_entry.get('version') == cache_version:
            return cached_entry['value']

    def _build_enriched_method_board():
        base_rows = build_mlb_prop_board(
            props_df,
            odds_df,
            schedule_df,
            gamelogs=gamelogs,
            date_filter=date_filter,
            stat_filter=stat_filter,
            direction_filter=direction_filter,
            search_query=search_query,
            max_groups=max_groups,
            fast_mode=fast_mode,
        )
        enriched_rows = []
        for row in base_rows:
            market_prob = pd.to_numeric(row.get('market_prob'), errors='coerce')
            market_conf = pd.to_numeric(row.get('market_confidence'), errors='coerce')
            lean_gap = pd.to_numeric(row.get('lean_gap'), errors='coerce')
            book_count = pd.to_numeric(row.get('book_count'), errors='coerce')
            line_low = pd.to_numeric(row.get('line_low'), errors='coerce')
            line_high = pd.to_numeric(row.get('line_high'), errors='coerce')
            range_span = abs(float(line_high) - float(line_low)) if pd.notna(line_low) and pd.notna(line_high) else 0.0
            trend_ready = bool(str(row.get('trend_note') or '').strip())
            historical_reliability = str(row.get('historical_reliability') or '').strip().upper()
            score = float(market_conf) if pd.notna(market_conf) else float(market_prob) if pd.notna(market_prob) else 50.0
            tags = []
            note = str(row.get('market_note') or '').strip()
            if historical_reliability == 'ANCHOR':
                score += 8.0
                tags.append('MLB ANCHOR')
            elif historical_reliability == 'WATCH':
                score += 4.0
                tags.append('MLB WATCH')
            elif historical_reliability == 'AVOID':
                score -= 10.0
                tags.append('MLB AVOID')

            if method_key == 'props':
                score += min((float(lean_gap) if pd.notna(lean_gap) else 0.0) * 0.35, 6.0)
                if pd.notna(book_count) and float(book_count) >= 2:
                    tags.append('MULTI-BOOK')
                if trend_ready:
                    tags.append('TREND READY')
                note = str(row.get('environment_note') or row.get('market_note') or row.get('trend_note') or '').strip()
            elif method_key == 'market_edge':
                score += min(float(lean_gap) if pd.notna(lean_gap) else 0.0, 18.0)
                if pd.notna(book_count) and float(book_count) >= 2:
                    score += 4.0
                    tags.append('MULTI-BOOK')
                if range_span >= 0.5:
                    tags.append('LINE RANGE')
                if row.get('book_comparison_note'):
                    tags.append('PRICE SPLIT')
                note = str(row.get('book_comparison_note') or row.get('market_note') or '').strip()
            elif method_key == 'floor_plays':
                score += 6.0 if pd.notna(book_count) and float(book_count) >= 2 else 0.0
                score += 6.0 if trend_ready else 0.0
                score += 4.0 if range_span <= 0.5 else 0.0
                score -= min(range_span * 4.0, 6.0)
                if trend_ready:
                    tags.append('TREND READY')
                if range_span <= 0.5:
                    tags.append('TIGHT RANGE')
                if pd.notna(book_count) and float(book_count) >= 2:
                    tags.append('CONFIRMED')
                note = str(row.get('trend_note') or row.get('environment_note') or row.get('market_note') or '').strip()
            else:
                score += 10.0 if trend_ready else -8.0
                score += min((float(lean_gap) if pd.notna(lean_gap) else 0.0) * 0.5, 8.0)
                if trend_ready:
                    tags.append('RECENT FORM')
                if pd.notna(market_prob) and float(market_prob) >= 60:
                    tags.append('MARKET AGREES')
                note = str(row.get('trend_note') or row.get('market_note') or row.get('environment_note') or '').strip()

            row_copy = dict(row)
            row_copy['method_score'] = round(max(50.0, min(score, 99.0)), 1)
            row_copy['method_tags'] = tags
            row_copy['method_note'] = note
            enriched_rows.append(row_copy)

        if method_key == 'floor_plays':
            enriched_rows = [row for row in enriched_rows if row.get('method_score', 0) >= 64]
        elif method_key == 'trends':
            enriched_rows = [row for row in enriched_rows if str(row.get('trend_note') or '').strip()]

        verdict_rank = {'PLAY': 2, 'CONFLICTED': 1, 'PASS': 0}
        enriched_rows.sort(
            key=lambda item: (
                -verdict_rank.get(str(item.get('play_verdict') or 'PLAY').upper(), 1),
                -float(item.get('method_score') or 0),
                -float(item.get('market_prob') or 0),
                -float(item.get('lean_gap') or 0),
                item.get('player', ''),
            )
        )
        enriched_rows = apply_mlb_contradiction_guardrails(enriched_rows, featured_top_n=featured_top_n)
        enriched_rows = apply_live_calibration_adjustments(enriched_rows, 'MLB', score_field='method_score')
        enriched_rows = attach_promotion_signals_to_props(enriched_rows, sport='MLB', score_fields=('method_score',))
        enriched_rows = attach_active_simulation_insights_to_rows(enriched_rows, sport='MLB')
        enriched_rows = attach_team_strength_priors_to_rows(enriched_rows, sport='MLB')
        enriched_rows = apply_mlb_contradiction_guardrails(enriched_rows, featured_top_n=featured_top_n)
        enriched_rows.sort(
            key=lambda item: (
                -_mlb_verdict_sort_rank(item),
                -float(item.get('promotion_boost') or 0),
                -float(item.get('method_score') or 0),
                -float(item.get('market_prob') or 0),
                -float(item.get('lean_gap') or 0),
                item.get('player', ''),
            )
        )
        return apply_mlb_contradiction_guardrails(enriched_rows, featured_top_n=featured_top_n)

    enriched = _get_disk_ttl_cached_value(
        f'disk::{cache_key}',
        43200,
        _build_enriched_method_board,
        version=cache_version,
    )
    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': enriched,
        'version': cache_version,
    }
    return enriched


RAW_DATA_STATS = ['PTS', 'REB', 'AST', '3PM', 'STL', 'BLK', 'MIN']


def normalize_stat_filter(stat, available_stats=None, default='PTS'):
    available = [str(item).upper() for item in (available_stats or RAW_DATA_STATS)]
    chosen = str(stat or default).strip().upper()
    if chosen in available:
        return chosen
    return available[0] if available else str(default).upper()


def build_stat_trajectory(logs_df, stat, line=None, max_points=12, overlays=None):
    stat = normalize_stat_filter(stat)
    result = {
        'stat': stat,
        'points': [],
        'svg_points': '',
        'line_y': None,
        'line_value': None,
        'overlay_lines': [],
        'avg': None,
        'recent_avg': None,
        'high': None,
        'low': None,
        'latest': None,
        'delta': None,
        'sample_size': 0,
    }
    if logs_df is None or logs_df.empty or stat not in logs_df.columns:
        return result

    working = logs_df.copy()
    if 'Date' in working.columns:
        working['Date'] = pd.to_datetime(working['Date'], errors='coerce')
        working = working.sort_values('Date', ascending=False)

    valid = working[working[stat].notna()].head(max_points).copy()
    if valid.empty:
        return result

    values = pd.to_numeric(valid[stat], errors='coerce').tolist()
    labels = []
    if 'Date' in valid.columns:
        labels = [
            value.strftime('%m/%d') if pd.notna(value) else f'G{idx + 1}'
            for idx, value in enumerate(valid['Date'])
        ]
    else:
        labels = [f'G{idx + 1}' for idx in range(len(valid))]

    reversed_values = list(reversed(values))
    reversed_labels = list(reversed(labels))
    clean_values = [float(v) for v in reversed_values if pd.notna(v)]
    if not clean_values:
        return result

    line_value = pd.to_numeric(pd.Series([line]), errors='coerce').iloc[0] if line is not None else np.nan
    chart_floor = min(clean_values + ([float(line_value)] if pd.notna(line_value) else []))
    chart_ceiling = max(clean_values + ([float(line_value)] if pd.notna(line_value) else []))
    if chart_floor == chart_ceiling:
        chart_floor = chart_floor - 1
        chart_ceiling = chart_ceiling + 1

    width = 100.0
    height = 100.0
    x_step = width / max(1, len(reversed_values) - 1)

    def scale_y(value):
        return round(height - (((float(value) - chart_floor) / (chart_ceiling - chart_floor)) * height), 2)

    points = []
    svg_points = []
    for idx, value in enumerate(reversed_values):
        x = round(idx * x_step, 2)
        y = scale_y(value)
        point = {
            'label': reversed_labels[idx],
            'value': round(float(value), 1),
            'x': x,
            'y': y,
            'season_type': str(valid.iloc[len(valid) - 1 - idx].get('SeasonType', '') or ''),
            'result': str(valid.iloc[len(valid) - 1 - idx].get('Result', '') or ''),
            'opp': str(valid.iloc[len(valid) - 1 - idx].get('Opp', '') or ''),
        }
        points.append(point)
        svg_points.append(f"{x},{y}")

    recent_window = reversed_values[-5:] if len(reversed_values) >= 5 else reversed_values
    latest = float(reversed_values[-1])
    prior = float(reversed_values[-2]) if len(reversed_values) >= 2 else latest

    overlay_lines = []
    for overlay in overlays or []:
        overlay_value = pd.to_numeric(pd.Series([overlay.get('line')]), errors='coerce').iloc[0]
        if pd.isna(overlay_value):
            continue
        overlay_lines.append({
            'book': str(overlay.get('book', '')).strip(),
            'line': round(float(overlay_value), 1),
            'y': scale_y(overlay_value),
            'color': str(overlay.get('color', '')).strip() or '#84d7d2',
        })

    result.update({
        'points': points,
        'svg_points': ' '.join(svg_points),
        'line_y': scale_y(line_value) if pd.notna(line_value) else None,
        'line_value': round(float(line_value), 1) if pd.notna(line_value) else None,
        'overlay_lines': overlay_lines,
        'avg': round(float(np.mean(reversed_values)), 1),
        'recent_avg': round(float(np.mean(recent_window)), 1),
        'high': round(float(max(reversed_values)), 1),
        'low': round(float(min(reversed_values)), 1),
        'latest': round(latest, 1),
        'delta': round(latest - prior, 1),
        'sample_size': len(reversed_values),
    })
    return result


def split_market_game_label(game_label):
    text = str(game_label or '').strip()
    if '@' in text:
        away, home = text.split('@', 1)
        return away.strip(), home.strip()
    parts = re.split(r'\s+vs\.?\s+', text, maxsplit=1, flags=re.IGNORECASE)
    if len(parts) == 2:
        return parts[0].strip(), parts[1].strip()
    return text, ''


def split_game_label(game_label):
    return split_market_game_label(game_label)


def build_matchup_slug(away, home):
    def _slug_part(value):
        text = str(value or '').strip()
        if not text or text.lower() in {'nan', 'none', 'null'}:
            return ''
        return '-'.join(
            ''.join(ch.lower() if ch.isalnum() else ' ' for ch in text).split()
        )
    away_slug = _slug_part(away)
    home_slug = _slug_part(home)
    if away_slug and home_slug:
        return f'{away_slug}-at-{home_slug}'
    return away_slug or home_slug


def parse_nfl_floor_matchup_teams(sheet_name, matchup_title=''):
    candidates = [str(sheet_name or '').strip(), str(matchup_title or '').strip()]
    patterns = [
        re.compile(r'^\s*([A-Za-z0-9 .&]+?)\s*@\s*([A-Za-z0-9 .&]+?)\s*$'),
        re.compile(r'^\s*([A-Za-z0-9 .&]+?)\s+at\s+([A-Za-z0-9 .&]+?)\s*$', re.IGNORECASE),
        re.compile(r'^\s*([A-Za-z0-9 .&]+?)\s+vs\.?\s+([A-Za-z0-9 .&]+?)\s*$', re.IGNORECASE),
        re.compile(r'^\s*([A-Za-z0-9 .&]+?)\s+v\.?\s+([A-Za-z0-9 .&]+?)\s*$', re.IGNORECASE),
    ]
    for candidate in candidates:
        if not candidate:
            continue
        for pattern in patterns:
            match = pattern.match(candidate)
            if not match:
                continue
            away = normalize_team_abbr(match.group(1))
            home = normalize_team_abbr(match.group(2))
            if away and home:
                return away, home
    return '', ''


def resolve_nfl_floor_matchup(board, key):
    board = board or {}
    lookup_key = str(key or '').strip().lower()
    if not lookup_key:
        return None

    for game in board.get('games', []):
        sheet = str(game.get('sheet', '')).strip()
        title = str(game.get('title', '')).strip()
        slug = str(game.get('matchup_slug', '')).strip().lower()
        away = str(game.get('away_team', '')).strip()
        home = str(game.get('home_team', '')).strip()
        candidates = {sheet.lower(), title.lower(), slug}
        if away and home:
            candidates.add(build_matchup_slug(away, home).lower())
            candidates.add(f'{away.lower()}-at-{home.lower()}')
            candidates.add(f'{away.lower()}@{home.lower()}')
        if lookup_key in candidates:
            return game

    normalized_key = re.sub(r'[^a-z0-9]+', '-', lookup_key).strip('-')
    if not normalized_key:
        return None
    for game in board.get('games', []):
        if normalized_key == str(game.get('matchup_slug', '')).strip().lower():
            return game
    return None


def build_wnba_odds_lookup(odds_df, schedule_df):
    lookup = {}
    frames = [df for df in [odds_df, schedule_df] if df is not None and not df.empty]
    if not frames:
        return lookup

    merged = pd.concat(frames, ignore_index=True, sort=False)
    merged = merged.drop_duplicates(subset=['Away', 'Home', 'Date', 'Time'], keep='first')

    for _, row in merged.iterrows():
        away = str(row.get('AwayFull') or row.get('Away') or '').strip()
        home = str(row.get('HomeFull') or row.get('Home') or '').strip()
        if not away or not home or away.lower() in {'nan', 'none', 'null'} or home.lower() in {'nan', 'none', 'null'}:
            continue
        game_key = f'{away}@{home}'
        slug = build_matchup_slug(away, home)
        lookup[game_key] = {
            'away': away,
            'home': home,
            'date': str(row.get('Date') or '').strip(),
            'time': str(row.get('Time') or '').strip(),
            'book': str(row.get('Book') or '').strip(),
            'away_ml': row.get('AwayML'),
            'home_ml': row.get('HomeML'),
            'spread': row.get('Spread'),
            'spread_odds': row.get('SpreadOdds'),
            'total': row.get('Total'),
            'over_odds': row.get('OverOdds'),
            'under_odds': row.get('UnderOdds'),
            'slug': slug,
        }
        lookup[slug] = lookup[game_key]
    return lookup


def build_wnba_market_note(direction, over_rate, under_rate):
    if over_rate is None or under_rate is None:
        return 'Market note unavailable.'
    edge = abs(float(over_rate) - float(under_rate))
    if edge < 2:
        return 'This prop is priced close to a coin flip right now.'
    if direction == 'OVER':
        if edge >= 10:
            return 'The book is pricing the over clearly stronger than the under.'
        if edge >= 5:
            return 'The market leans over on this number.'
        return 'There is a light market lean to the over.'
    if edge >= 10:
        return 'The book is pricing the under clearly stronger than the over.'
    if edge >= 5:
        return 'The market leans under on this number.'
    return 'There is a light market lean to the under.'


def build_wnba_book_comparison_note(dk_line, vegas_line, line_low, line_high, direction, best_book):
    notes = []
    if dk_line is not None and vegas_line is not None:
        try:
            delta = round(float(dk_line) - float(vegas_line), 1)
        except Exception:
            delta = 0
        if abs(delta) >= 0.5:
            if delta > 0:
                notes.append(f'DraftKings is {abs(delta):g} higher than Caesars on this line.')
            else:
                notes.append(f'Caesars is {abs(delta):g} higher than DraftKings on this line.')
        else:
            notes.append('DraftKings and Caesars are dealing basically the same line.')
    elif vegas_line is not None:
        notes.append('Caesars is loaded as the Vegas reference on this market.')
    elif dk_line is not None:
        notes.append('DraftKings is loaded, but the Caesars reference is not available yet.')

    if line_low is not None and line_high is not None and line_high != line_low:
        notes.append(f'The market range is {line_low:g} to {line_high:g} across books.')

    if best_book:
        notes.append(f'Best {direction.lower()} price is currently at {best_book}.')
    return ' '.join(notes[:3]).strip()


def build_wnba_prop_board(props_df, odds_df, schedule_df, gamelogs=None, date_filter='today', stat_filter='', direction_filter='all', search_query='', featured_top_n=12):
    cache_key = 'wnba_prop_board::{date_filter}::{stat_filter}::{direction_filter}::{search_query}::{featured_top_n}'.format(
        date_filter=str(date_filter or ''),
        stat_filter=str(stat_filter or ''),
        direction_filter=str(direction_filter or ''),
        search_query=str(search_query or '').strip().lower(),
        featured_top_n=int(featured_top_n or 0),
    )
    cache_version = _build_file_token(
        DATA_DIR / 'props' / 'WNBA_Props.csv',
        DATA_DIR / 'odds' / 'WNBA_Odds.csv',
        DATA_DIR / 'schedules' / 'WNBA_Schedule.csv',
        DATA_DIR / 'gamelogs' / 'WNBA_GameLogs.csv',
        DATA_DIR / 'injuries' / 'WNBA_Injuries.csv',
        DATA_DIR / 'tracking' / 'WNBA_Calibration_Report.csv',
        DATA_DIR / 'tracking' / 'WNBA_Simulation_Results.csv',
        DATA_DIR / 'tracking' / 'WNBA_Simulation_Results.csv',
        DATA_DIR / 'tracking' / 'Team_Strength_Priors.csv',
    )
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry:
        cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
        if cached_age <= 43200 and cached_entry.get('version') == cache_version:
            return cached_entry['value']

    if props_df is None or props_df.empty:
        return []

    odds_lookup = build_wnba_odds_lookup(odds_df, schedule_df)
    wnba_team_map = {}
    if gamelogs is not None and not gamelogs.empty and {'Player', 'Team', 'Date'}.issubset(gamelogs.columns):
        latest_logs = gamelogs.copy()
        latest_logs['Date'] = pd.to_datetime(latest_logs['Date'], errors='coerce')
        latest_logs = latest_logs.sort_values('Date', ascending=False)
        wnba_team_map = (
            latest_logs.dropna(subset=['Player'])
            .drop_duplicates(subset=['Player'], keep='first')
            .set_index('Player')['Team']
            .astype(str)
            .str.strip()
            .to_dict()
        )
    rows = []
    today = sports_today_ts()
    tomorrow = today + pd.Timedelta(days=1)
    stat_filter = str(stat_filter or '').strip().upper()
    direction_filter = str(direction_filter or 'all').strip().lower()
    search_query = str(search_query or '').strip().lower()

    group_cols = [col for col in ['Player', 'Stat', 'Game'] if col in props_df.columns]
    if len(group_cols) < 3:
        return []

    grouped = props_df.groupby(group_cols, dropna=False, sort=False)

    for (player, stat, game), market_rows in grouped:
        player = str(player or '').strip()
        stat = str(stat or '').strip()
        game = str(game or '').strip()
        if not player or not stat or not game:
            continue

        market = odds_lookup.get(game, {})
        away = market.get('away')
        home = market.get('home')
        if not away or not home:
            away, home = split_market_game_label(game)
        if not away or not home:
            continue

        market_rows = market_rows.copy()
        for col in ['CurrentLine', 'Line', 'OverOdds', 'UnderOdds']:
            if col in market_rows.columns:
                market_rows[col] = pd.to_numeric(market_rows[col], errors='coerce')

        dk_rows = market_rows[market_rows.get('Book', '').astype(str).str.lower() == 'draftkings'.lower()] if 'Book' in market_rows.columns else pd.DataFrame()
        vegas_rows = market_rows[market_rows.get('Book', '').astype(str).str.lower() == 'caesars'] if 'Book' in market_rows.columns else pd.DataFrame()
        primary_row = dk_rows.iloc[0] if not dk_rows.empty else market_rows.iloc[0]
        vegas_row = vegas_rows.iloc[0] if not vegas_rows.empty else None

        line = primary_row.get('CurrentLine')
        if pd.isna(line):
            line = primary_row.get('Line')
        if pd.isna(line):
            numeric_lines = pd.to_numeric(market_rows.get('CurrentLine', market_rows.get('Line')), errors='coerce').dropna()
            line = numeric_lines.median() if not numeric_lines.empty else np.nan
        if pd.isna(line):
            continue

        book_probs = []
        for _, book_row in market_rows.iterrows():
            over_odds = book_row.get('OverOdds')
            under_odds = book_row.get('UnderOdds')
            over_prob = american_odds_to_implied_prob(over_odds)
            under_prob = american_odds_to_implied_prob(under_odds)
            total_prob = (over_prob or 0) + (under_prob or 0)
            if total_prob > 0 and over_prob is not None and under_prob is not None:
                book_probs.append({
                    'book': str(book_row.get('Book') or '').strip(),
                    'over_rate': (over_prob / total_prob) * 100,
                    'under_rate': (under_prob / total_prob) * 100,
                    'line': book_row.get('CurrentLine') if pd.notna(book_row.get('CurrentLine')) else book_row.get('Line'),
                    'over_odds': over_odds,
                    'under_odds': under_odds,
                })

        if book_probs:
            over_rate = round(float(np.mean([item['over_rate'] for item in book_probs])), 1)
            under_rate = round(float(np.mean([item['under_rate'] for item in book_probs])), 1)
        else:
            over_rate = under_rate = None

        game_date = str(market.get('date') or '').strip()
        game_time = str(market.get('time') or '').strip()
        game_day = None
        if game_date:
            parsed_date = pd.to_datetime(game_date, errors='coerce')
            if pd.notna(parsed_date):
                game_day = parsed_date.normalize()

        if date_filter == 'today' and game_day is not None and game_day != today:
            continue
        if date_filter == 'tomorrow' and game_day is not None and game_day != tomorrow:
            continue
        if stat_filter and stat.upper() != stat_filter:
            continue

        if over_rate is None or under_rate is None:
            direction = 'OVER'
            lean_prob = 50.0
            lean_gap = 0.0
            market_price = primary_row.get('OverOdds') if pd.notna(primary_row.get('OverOdds')) else primary_row.get('UnderOdds')
            best_book = str(primary_row.get('Book') or '').strip()
        else:
            if over_rate >= under_rate:
                direction = 'OVER'
                lean_prob = over_rate
                priced_books = [item for item in book_probs if item.get('over_odds') is not None and not pd.isna(item.get('over_odds'))]
                best_row = max(priced_books, key=lambda item: float(item['over_odds'])) if priced_books else None
                market_price = best_row['over_odds'] if best_row else primary_row.get('OverOdds')
                best_book = best_row['book'] if best_row else str(primary_row.get('Book') or '').strip()
            else:
                direction = 'UNDER'
                lean_prob = under_rate
                priced_books = [item for item in book_probs if item.get('under_odds') is not None and not pd.isna(item.get('under_odds'))]
                best_row = max(priced_books, key=lambda item: float(item['under_odds'])) if priced_books else None
                market_price = best_row['under_odds'] if best_row else primary_row.get('UnderOdds')
                best_book = best_row['book'] if best_row else str(primary_row.get('Book') or '').strip()
            lean_gap = round(abs(over_rate - under_rate), 1)

        if direction_filter in {'over', 'under'} and direction.lower() != direction_filter:
            continue

        matchup_text = f'{away} @ {home}'
        haystack = ' '.join([player, stat, matchup_text]).lower()
        if search_query and search_query not in haystack:
            continue
        environment_context = classify_prop_game_environment(market.get('total'), market.get('spread'), sport='WNBA')

        numeric_lines = []
        for candidate in pd.concat([market_rows['CurrentLine'], market_rows['Line']], axis=0).dropna().tolist():
            try:
                numeric_lines.append(float(candidate))
            except Exception:
                continue
        line_low = min(numeric_lines) if numeric_lines else None
        line_high = max(numeric_lines) if numeric_lines else None
        dk_line = primary_row.get('CurrentLine') if pd.notna(primary_row.get('CurrentLine')) else primary_row.get('Line')
        vegas_line = None
        if vegas_row is not None:
            vegas_line = vegas_row.get('CurrentLine') if pd.notna(vegas_row.get('CurrentLine')) else vegas_row.get('Line')

        team_name = str(primary_row.get('Team') or '').strip()
        if not team_name or team_name.lower() == 'nan':
            team_name = str(wnba_team_map.get(player, '') or '').strip()
        if not team_name or team_name.lower() == 'nan':
            team_name = away
        normalized_team = normalize_team_for_filter(team_name)
        normalized_away = normalize_team_for_filter(away)
        normalized_home = normalize_team_for_filter(home)
        opponent_name = home if normalized_team == normalized_away else away if normalized_team == normalized_home else away

        rows.append({
            'player': player,
            'team': team_name,
            'opponent': opponent_name,
            'stat': stat,
            'line': round(float(line), 1) if pd.notna(line) else line,
            'game': game,
            'matchup': matchup_text,
            'away': away,
            'home': home,
            'game_date': game_date,
            'game_time': game_time,
            'matchup_slug': build_matchup_slug(away, home),
            'direction': direction,
            'over_rate': over_rate,
            'under_rate': under_rate,
            'market_prob': round(float(lean_prob), 1),
            'market_confidence': normalize_confidence_rate(lean_prob),
            'lean_gap': lean_gap,
            'lean_strength': 'Strong' if lean_gap >= 10 else 'Medium' if lean_gap >= 5 else 'Light',
            'market_price': int(market_price) if pd.notna(market_price) else None,
            'fair_price': prob_to_american_odds((lean_prob / 100) if lean_prob is not None else None),
            'book': str(primary_row.get('Book') or market.get('book') or '').strip(),
            'book_count': int(market_rows['Book'].dropna().nunique()) if 'Book' in market_rows.columns else 1,
            'books': sorted([str(book).strip() for book in market_rows['Book'].dropna().unique().tolist() if str(book).strip()]) if 'Book' in market_rows.columns else [],
            'draftkings_line': round(float(dk_line), 1) if dk_line is not None and not pd.isna(dk_line) else None,
            'vegas_line': round(float(vegas_line), 1) if vegas_line is not None and not pd.isna(vegas_line) else None,
            'line_low': round(float(line_low), 1) if line_low is not None else None,
            'line_high': round(float(line_high), 1) if line_high is not None else None,
            'best_book': best_book,
            'market_note': build_wnba_market_note(direction, over_rate, under_rate),
            'book_comparison_note': build_wnba_book_comparison_note(
                dk_line, vegas_line, line_low, line_high, direction, best_book
            ),
            'environment_note': build_wnba_game_environment_note(market.get('total'), market.get('spread'), stat, direction),
            'game_environment_label': environment_context.get('label'),
            'game_environment_summary': environment_context.get('summary'),
            'trend_note': build_wnba_recent_form_note(player, stat, line, gamelogs),
            'total': market.get('total'),
            'spread': market.get('spread'),
            'away_ml': market.get('away_ml'),
            'home_ml': market.get('home_ml'),
            'last_updated': str(primary_row.get('LastUpdated') or '').strip(),
            'play_verdict': 'PLAY',
            'play_verdict_note': '',
            'guardrail_tags': [],
            'guardrail_note': '',
        })

    rows.sort(key=lambda item: (-float(item.get('lean_gap') or 0), -float(item.get('market_prob') or 0), item.get('player', ''), item.get('stat', '')))
    rows = annotate_prop_rows_with_injuries(rows, load_sport_injuries('wnba'))
    rows = apply_wnba_contradiction_guardrails(rows, featured_top_n=featured_top_n)
    rows = apply_live_calibration_adjustments(rows, 'WNBA', score_field='market_confidence')
    rows = attach_promotion_signals_to_props(rows, sport='WNBA', score_fields=('market_confidence',))
    rows = attach_active_simulation_insights_to_rows(rows, sport='WNBA')
    rows = attach_team_strength_priors_to_rows(rows, sport='WNBA')
    rows = sort_wnba_rows_for_promotion(rows, score_field='market_confidence')
    rows = apply_wnba_contradiction_guardrails(rows, featured_top_n=featured_top_n)
    rows = sort_wnba_rows_for_promotion(rows, score_field='market_confidence')
    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': rows,
        'version': cache_version,
    }
    return rows


def build_wnba_matchup_cards(odds_df, schedule_df):
    lookup = build_wnba_odds_lookup(odds_df, schedule_df)
    cards = []
    seen = set()
    for key, market in lookup.items():
        slug = market.get('slug')
        if not slug or slug in seen:
            continue
        seen.add(slug)
        cards.append({
            'slug': slug,
            'away': market.get('away'),
            'home': market.get('home'),
            'date': market.get('date'),
            'time': market.get('time'),
            'spread': market.get('spread'),
            'total': market.get('total'),
            'away_ml': market.get('away_ml'),
            'home_ml': market.get('home_ml'),
            'book': market.get('book'),
        })
    cards.sort(key=lambda item: (item.get('date') or '', item.get('time') or '', item.get('away') or ''))
    return cards


def wnba_snapshot_has_invalid_matchups(payload):
    for card in (payload or {}).get('matchup_cards', []) or []:
        away = str((card or {}).get('away') or '').strip().lower()
        home = str((card or {}).get('home') or '').strip().lower()
        slug = str((card or {}).get('slug') or '').strip().lower()
        if away in {'nan', 'none', 'null'} or home in {'nan', 'none', 'null'} or 'nan' in slug:
            return True
    return False


def build_live_game_lookup(odds_df, schedule_df):
    lookup = {}
    frames = [df for df in [odds_df, schedule_df] if df is not None and not df.empty]
    if not frames:
        return lookup

    merged = pd.concat(frames, ignore_index=True, sort=False)
    dedupe_cols = [col for col in ['Away', 'Home', 'Date', 'Time'] if col in merged.columns]
    if dedupe_cols:
        merged = merged.drop_duplicates(subset=dedupe_cols, keep='first')

    for _, row in merged.iterrows():
        away = str(row.get('AwayFull') or row.get('Away') or '').strip()
        home = str(row.get('HomeFull') or row.get('Home') or '').strip()
        if not away or not home:
            continue
        game_key = f'{away}@{home}'
        slug = build_matchup_slug(away, home)
        lookup[game_key] = {
            'away': away,
            'home': home,
            'date': str(row.get('Date') or '').strip(),
            'time': str(row.get('Time') or '').strip(),
            'book': str(row.get('Book') or '').strip(),
            'away_ml': row.get('AwayML'),
            'home_ml': row.get('HomeML'),
            'spread': row.get('Spread'),
            'spread_odds': row.get('SpreadOdds'),
            'total': row.get('Total'),
            'over_odds': row.get('OverOdds'),
            'under_odds': row.get('UnderOdds'),
            'slug': slug,
        }
        lookup[slug] = lookup[game_key]
    return lookup


def build_football_market_note(direction, over_rate, under_rate):
    if over_rate is None or under_rate is None:
        return 'Market note unavailable.'
    edge = abs(float(over_rate) - float(under_rate))
    if edge < 2:
        return 'Books are pricing this close to a coin flip.'
    if direction == 'OVER':
        if edge >= 10:
            return 'The market is clearly pricing the over stronger than the under.'
        if edge >= 5:
            return 'The market leans over on this number.'
        return 'There is a light lean to the over.'
    if edge >= 10:
        return 'The market is clearly pricing the under stronger than the over.'
    if edge >= 5:
        return 'The market leans under on this number.'
    return 'There is a light lean to the under.'


def build_football_book_comparison_note(dk_line, vegas_line, line_low, line_high, direction, best_book):
    notes = []
    if dk_line is not None and vegas_line is not None:
        try:
            delta = round(float(dk_line) - float(vegas_line), 1)
        except Exception:
            delta = 0
        if abs(delta) >= 0.5:
            if delta > 0:
                notes.append(f'DraftKings is {abs(delta):g} higher than Caesars on this line.')
            else:
                notes.append(f'Caesars is {abs(delta):g} higher than DraftKings on this line.')
        else:
            notes.append('DraftKings and Caesars are dealing basically the same line.')
    elif vegas_line is not None:
        notes.append('Caesars is loaded as the Vegas reference on this market.')
    elif dk_line is not None:
        notes.append('DraftKings is loaded, but the Caesars reference is not available yet.')

    if line_low is not None and line_high is not None and line_high != line_low:
        notes.append(f'The market range is {line_low:g} to {line_high:g} across books.')

    if best_book:
        notes.append(f'Best {direction.lower()} price is currently at {best_book}.')
    return ' '.join(notes[:3]).strip()


def build_football_environment_note(total, spread, stat_family, direction):
    notes = []
    total_num = pd.to_numeric(total, errors='coerce')
    spread_num = pd.to_numeric(spread, errors='coerce')
    family = str(stat_family or '').strip().lower()
    if pd.notna(total_num):
        if total_num >= 49:
            notes.append('High-total game environment.')
        elif total_num <= 41:
            notes.append('Lower-total game environment.')
    if pd.notna(spread_num):
        if abs(float(spread_num)) <= 3:
            notes.append('Tight spread keeps both sides live deeper into the game.')
        elif abs(float(spread_num)) >= 7:
            notes.append('Wider spread can push the script harder than usual.')
    if family == 'passing' and direction == 'OVER':
        notes.append('Passing overs like neutral or fast scripts.')
    elif family in {'rushing', 'rush'} and direction == 'OVER':
        notes.append('Rushing overs improve when the script stays friendly.')
    elif family == 'receiving' and direction == 'OVER':
        notes.append('Receiving overs work best when targets stay concentrated.')
    return ' '.join(notes[:2]).strip()


def get_football_stat_family(stat):
    text = str(stat or '').strip().lower()
    if 'pass' in text:
        return 'Passing'
    if 'rush' in text:
        return 'Rushing'
    if 'rec' in text:
        return 'Receiving'
    if 'td' in text and 'pass' in text:
        return 'Passing'
    if 'td' in text and ('rush' in text or 'anytime' in text):
        return 'Scoring'
    return 'Props'


def build_football_live_games(odds_df, schedule_df, date_filter='all'):
    lookup = build_live_game_lookup(odds_df, schedule_df)
    rows = []
    today = sports_today_ts()
    tomorrow = today + pd.Timedelta(days=1)
    for key, market in lookup.items():
        slug = market.get('slug')
        if key == slug:
            continue
        game_date = str(market.get('date') or '').strip()
        parsed_date = pd.to_datetime(game_date, errors='coerce')
        game_day = parsed_date.normalize() if pd.notna(parsed_date) else None
        if date_filter == 'today' and game_day is not None and game_day != today:
            continue
        if date_filter == 'tomorrow' and game_day is not None and game_day != tomorrow:
            continue
        away = str(market.get('away') or '').strip()
        home = str(market.get('home') or '').strip()
        if not away or not home:
            continue
        rows.append({
            'away': away,
            'home': home,
            'matchup': f'{away} @ {home}',
            'date': game_date,
            'time': str(market.get('time') or '').strip(),
            'spread': market.get('spread'),
            'total': market.get('total'),
            'away_ml': market.get('away_ml'),
            'home_ml': market.get('home_ml'),
            'book': str(market.get('book') or '').strip() or 'DraftKings',
            'slug': market.get('slug'),
            'summary': format_game_market_summary(market, home),
        })
    rows.sort(key=lambda item: (item.get('date') or '', item.get('time') or '', item.get('away') or ''))
    return rows


def build_ncaaf_team_signal_map():
    context = build_ncaaf_current_season_context()
    return build_ncaaf_team_signal_map_service(
        context.get('team_signals') or [],
        normalize_ncaaf_team_name,
    )


def build_ncaaf_matchup_signal_context(away, home, method_key='game_lines', signal_map=None):
    signal_map = signal_map or build_ncaaf_team_signal_map()
    return build_ncaaf_matchup_signal_context_service(
        away,
        home,
        method_key=method_key,
        signal_map=signal_map,
        normalize_team_name=normalize_ncaaf_team_name,
    )


def build_football_live_game_method_board(method_key, odds_df, schedule_df, date_filter='all', search_query='', sport_key=None):
    method_key = str(method_key or 'game_lines').strip().lower()
    sport_key = str(sport_key or '').strip().lower()
    search_query = str(search_query or '').strip().lower()
    base_games = build_football_live_games(odds_df, schedule_df, date_filter=date_filter)
    ncaaf_signal_map = build_ncaaf_team_signal_map() if sport_key == 'ncaaf' else {}
    rows = []
    for game in base_games:
        spread = pd.to_numeric(game.get('spread'), errors='coerce')
        total = pd.to_numeric(game.get('total'), errors='coerce')
        summary = str(game.get('summary') or '').strip()
        matchup = str(game.get('matchup') or '').strip()
        signal_context = build_ncaaf_matchup_signal_context(game.get('away'), game.get('home'), method_key=method_key, signal_map=ncaaf_signal_map) if sport_key == 'ncaaf' else {}
        if search_query and search_query not in matchup.lower():
            continue

        if method_key == 'totals':
            fit_score = 55.0
            tags = []
            if pd.notna(total):
                if float(total) >= 49:
                    fit_score += 16
                    tags.append('HIGH TOTAL')
                elif float(total) >= 45:
                    fit_score += 10
                    tags.append('SOLID TOTAL')
                elif float(total) <= 41:
                    fit_score += 8
                    tags.append('LOW TOTAL')
            if pd.notna(spread) and abs(float(spread)) <= 3:
                fit_score += 8
                tags.append('TIGHT SPREAD')
            note = build_football_environment_note(total, spread, 'passing', 'OVER')
            lean = 'Track totals first'
        else:
            fit_score = 55.0
            tags = []
            if pd.notna(spread):
                if abs(float(spread)) <= 3:
                    fit_score += 14
                    tags.append('ONE-SCORE GAME')
                elif abs(float(spread)) >= 7:
                    fit_score += 8
                    tags.append('CLEAR SCRIPT')
            if pd.notna(total) and float(total) >= 45:
                fit_score += 6
                tags.append('SCORING SUPPORT')
            note = build_football_environment_note(total, spread, 'rushing', 'OVER')
            lean = 'Track sides first'

        signal_tags = []
        signal_summary = ''
        if sport_key == 'ncaaf':
            fit_score += float(signal_context.get('score_delta') or 0)
            away_signal = signal_context.get('away_signal') or {}
            home_signal = signal_context.get('home_signal') or {}
            if away_signal.get('tags'):
                signal_tags.append(f"{signal_context.get('away')}: " + ', '.join(list(away_signal.get('tags') or [])[:2]))
            if home_signal.get('tags'):
                signal_tags.append(f"{signal_context.get('home')}: " + ', '.join(list(home_signal.get('tags') or [])[:2]))
            signal_summary = str(signal_context.get('verdict') or '').strip()
            if signal_summary:
                note = f"{note} {signal_summary}".strip()

        rows.append({
            **game,
            'fit_score': round(max(50.0, min(fit_score, 95.0)), 1),
            'fit_tags': tags,
            'fit_note': note or summary or 'Live football market row.',
            'lean_label': lean,
            'signal_tags': signal_tags,
            'signal_summary': signal_summary,
            'away_signal_tags': list((signal_context.get('away_signal') or {}).get('tags') or []),
            'home_signal_tags': list((signal_context.get('home_signal') or {}).get('tags') or []),
        })

    rows.sort(key=lambda item: (float(item.get('fit_score') or 0), item.get('date') or '', item.get('time') or ''), reverse=True)
    return rows


def _format_signed_line(value):
    num = pd.to_numeric(value, errors='coerce')
    if pd.isna(num):
        return '-'
    return f"{float(num):+g}"


def build_football_script_tags(spread=None, total=None, *, team_side='shared', wind_mph=None):
    tags = []
    spread_num = pd.to_numeric(spread, errors='coerce')
    total_num = pd.to_numeric(total, errors='coerce')
    wind_num = pd.to_numeric(wind_mph, errors='coerce')

    if pd.notna(spread_num):
        abs_spread = abs(float(spread_num))
        if abs_spread <= 3:
            tags.append('PROJECTED_TIGHT_GAME')
        elif team_side == 'favorite':
            tags.append('PROJECTED_BLOWOUT_WIN' if abs_spread >= 10 else 'PROJECTED_CLEAR_WIN')
        elif team_side == 'underdog':
            tags.append('PROJECTED_BLOWOUT_TRAIL' if abs_spread >= 10 else 'PROJECTED_TRAIL')
        elif abs_spread >= 7:
            tags.append('CLEAR_SCRIPT')

    if pd.notna(total_num):
        if float(total_num) >= 49:
            tags.append('HIGH_TOTAL')
        elif float(total_num) <= 42:
            tags.append('LOW_TOTAL')
        else:
            tags.append('MID_TOTAL')

    if pd.notna(wind_num) and float(wind_num) >= 15:
        tags.append('WIND_15_PLUS')

    return tags


def build_game_line_teaching_note(spread=None, total=None, spread_move=None, total_move=None, wind_mph=None):
    notes = []
    spread_num = pd.to_numeric(spread, errors='coerce')
    total_num = pd.to_numeric(total, errors='coerce')
    move_num = pd.to_numeric(spread_move, errors='coerce')
    total_move_num = pd.to_numeric(total_move, errors='coerce')
    wind_num = pd.to_numeric(wind_mph, errors='coerce')

    if pd.notna(spread_num):
        abs_spread = abs(float(spread_num))
        if abs_spread in {3.0, 7.0} or abs(abs_spread - 3.5) < 1e-9 or abs(abs_spread - 7.5) < 1e-9:
            notes.append('Key-number spread. Shopping the half point can turn losses into pushes.')
        elif abs_spread >= 7:
            notes.append('Clear favorite script can pressure late-game passing or rushing volume depending on side.')
        elif abs_spread <= 3:
            notes.append('Tight spread keeps both teams live deeper into the game.')
    if pd.notna(total_num):
        if float(total_num) >= 49:
            notes.append('High total supports volume and scoring props.')
        elif float(total_num) <= 42:
            notes.append('Low total puts pressure on counting-stat overs.')
    if pd.notna(move_num) and abs(float(move_num)) >= 1:
        direction = 'toward the favorite' if float(move_num) < 0 else 'toward the underdog'
        notes.append(f'Spread moved {direction}; compare that against prop direction.')
    if pd.notna(total_move_num) and abs(float(total_move_num)) >= 1:
        direction = 'up' if float(total_move_num) > 0 else 'down'
        notes.append(f'Total moved {direction}; that should feed prop pace assumptions.')
    if pd.notna(wind_num) and float(wind_num) >= 15:
        notes.append('Wind 15+ mph is a passing/receiving over warning.')
    return ' '.join(notes[:3]) or 'Use the best available line before treating this as the market number.'


def build_football_game_line_intelligence(sport_key, method_key, odds_df=None, limit=18):
    sport_key = str(sport_key or '').strip().lower()
    method_key = str(method_key or 'game_lines').strip().lower()
    rows = []
    source_label = 'Historical consensus'
    source_note = 'No live multi-book game-line feed is loaded, so this falls back to archived spreads and totals.'
    middle_alerts = []

    live_df = odds_df.copy() if isinstance(odds_df, pd.DataFrame) else pd.DataFrame()
    if not live_df.empty and {'Away', 'Home', 'Spread', 'Total'}.issubset(live_df.columns):
        source_label = 'Live books'
        source_note = 'Live book rows are grouped by matchup so the page can show best-number range and middle potential.'
        working = live_df.copy()
        for col in ['Spread', 'Total']:
            working[col] = pd.to_numeric(working[col], errors='coerce')
        for key_cols, group in working.groupby(['Date', 'Away', 'Home'], dropna=False):
            date, away, home = key_cols
            away = normalize_team_abbr(away)
            home = normalize_team_abbr(home)
            if not away or not home:
                continue
            group = group.copy()
            group['AwaySpread'] = -group['Spread']
            group['HomeSpread'] = group['Spread']
            best_away = group.loc[group['AwaySpread'].idxmax()] if group['AwaySpread'].notna().any() else None
            best_home = group.loc[group['HomeSpread'].idxmax()] if group['HomeSpread'].notna().any() else None
            best_total = group.loc[group['Total'].idxmax()] if group['Total'].notna().any() else None
            best_home_spread = best_home.get('HomeSpread') if best_home is not None else None
            best_away_spread = best_away.get('AwaySpread') if best_away is not None else None
            best_total_value = best_total.get('Total') if best_total is not None else None
            home_spread = pd.to_numeric(best_home_spread, errors='coerce')
            total = pd.to_numeric(best_total_value, errors='coerce')
            spread_range = None
            if group['HomeSpread'].notna().any():
                spread_range = round(float(group['HomeSpread'].max() - group['HomeSpread'].min()), 2)
            total_range = None
            if group['Total'].notna().any():
                total_range = round(float(group['Total'].max() - group['Total'].min()), 2)
            middle_note = ''
            if spread_range is not None and spread_range >= 0.5:
                middle_note = f'{spread_range:g}-point spread range across books.'
                middle_alerts.append({'matchup': f'{away} @ {home}', 'note': middle_note})
            favorite = home if pd.notna(home_spread) and float(home_spread) < 0 else away if pd.notna(home_spread) and float(home_spread) > 0 else ''
            favorite_spread = home_spread if favorite == home else -home_spread if favorite == away and pd.notna(home_spread) else None
            rows.append({
                'matchup': f'{away} @ {home}',
                'date': str(date or '').strip(),
                'week': '',
                'source': source_label,
                'best_spread': f"{home} {_format_signed_line(best_home_spread)} / {away} {_format_signed_line(best_away_spread)}",
                'spread_book': f"{best_home.get('Book', '-') if best_home is not None else '-'} / {best_away.get('Book', '-') if best_away is not None else '-'}",
                'best_total': f"{float(total):g}" if pd.notna(total) else '-',
                'total_book': str(best_total.get('Book', '-') if best_total is not None else '-'),
                'movement': f"Spread range {spread_range:g}" if spread_range is not None else '-',
                'total_movement': f"Total range {total_range:g}" if total_range is not None else '-',
                'script_tags': build_football_script_tags(favorite_spread, total, team_side='shared'),
                'teaching_note': build_game_line_teaching_note(favorite_spread, total),
                'middle_note': middle_note,
            })

    if not rows:
        lines_history = load_ncaaf_game_lines_history() if sport_key == 'ncaaf' else load_nfl_game_lines_history()
        if lines_history is not None and not lines_history.empty:
            working = lines_history.copy()
            if 'Date' in working.columns:
                working['Date'] = pd.to_datetime(working['Date'], errors='coerce')
            for col in ['AwaySpread', 'HomeSpread', 'Total', 'CloseTotal', 'OpenTotal', 'OpenAwaySpread', 'OpenHomeSpread', 'wind']:
                if col in working.columns:
                    working[col] = pd.to_numeric(working[col], errors='coerce')
            working = working.dropna(subset=['Date', 'Away', 'Home']).sort_values('Date', ascending=False)
            for _, row in working.head(limit).iterrows():
                away = normalize_team_abbr(row.get('Away'))
                home = normalize_team_abbr(row.get('Home'))
                if not away or not home:
                    continue
                home_spread = pd.to_numeric(row.get('HomeSpread'), errors='coerce')
                away_spread = pd.to_numeric(row.get('AwaySpread'), errors='coerce')
                total = pd.to_numeric(row.get('CloseTotal', row.get('Total')), errors='coerce')
                open_total = pd.to_numeric(row.get('OpenTotal'), errors='coerce')
                spread_move = None
                if pd.notna(home_spread) and pd.notna(pd.to_numeric(row.get('OpenHomeSpread'), errors='coerce')):
                    spread_move = round(float(home_spread - pd.to_numeric(row.get('OpenHomeSpread'), errors='coerce')), 2)
                total_move = round(float(total - open_total), 2) if pd.notna(total) and pd.notna(open_total) else None
                favorite = ''
                favorite_spread = None
                if pd.notna(home_spread) and float(home_spread) < 0:
                    favorite = home
                    favorite_spread = home_spread
                elif pd.notna(away_spread) and float(away_spread) < 0:
                    favorite = away
                    favorite_spread = away_spread
                wind_mph = row.get('wind')
                rows.append({
                    'matchup': f'{away} @ {home}',
                    'date': row['Date'].strftime('%Y-%m-%d') if pd.notna(row.get('Date')) else '',
                    'week': int(row.get('Week')) if pd.notna(pd.to_numeric(row.get('Week'), errors='coerce')) else '',
                    'source': str(row.get('Source') or source_label),
                    'best_spread': f"{favorite} {_format_signed_line(favorite_spread)}" if favorite else f"{home} {_format_signed_line(home_spread)}",
                    'spread_book': 'Consensus',
                    'best_total': f"{float(total):g}" if pd.notna(total) else '-',
                    'total_book': 'Consensus',
                    'movement': f"{spread_move:+g}" if spread_move is not None else 'No open line',
                    'total_movement': f"{total_move:+g}" if total_move is not None else 'No open total',
                    'script_tags': build_football_script_tags(favorite_spread, total, team_side='shared', wind_mph=wind_mph),
                    'teaching_note': build_game_line_teaching_note(favorite_spread, total, spread_move=spread_move, total_move=total_move, wind_mph=wind_mph),
                    'middle_note': '',
                })

    if method_key == 'totals':
        rows = sorted(rows, key=lambda item: pd.to_numeric(item.get('best_total'), errors='coerce') if item.get('best_total') != '-' else -999, reverse=True)

    return {
        'rows': rows[:limit],
        'source_label': source_label,
        'note': source_note,
        'middle_alerts': middle_alerts[:5],
    }


def build_nfl_game_script_lookup():
    lines_history = load_nfl_game_lines_history()
    lookup = {}
    if lines_history is None or lines_history.empty:
        return lookup
    history = lines_history.copy()
    if 'Date' in history.columns:
        history['Date'] = pd.to_datetime(history['Date'], errors='coerce')
    for col in ['AwaySpread', 'HomeSpread', 'CloseTotal', 'Total', 'wind']:
        if col in history.columns:
            history[col] = pd.to_numeric(history[col], errors='coerce')
    history = history.dropna(subset=['Date', 'Away', 'Home']).sort_values('Date')
    for _, row in history.iterrows():
        away = normalize_team_abbr(row.get('Away'))
        home = normalize_team_abbr(row.get('Home'))
        if not away or not home:
            continue
        total = row.get('CloseTotal', row.get('Total'))
        wind_mph = row.get('wind')
        away_spread = pd.to_numeric(row.get('AwaySpread'), errors='coerce')
        home_spread = pd.to_numeric(row.get('HomeSpread'), errors='coerce')
        shared_tags = build_football_script_tags(None, total, team_side='shared', wind_mph=wind_mph)
        if pd.notna(away_spread):
            away_side = 'favorite' if float(away_spread) < 0 else 'underdog' if float(away_spread) > 0 else 'shared'
            away_tags = build_football_script_tags(away_spread, total, team_side=away_side, wind_mph=wind_mph)
        else:
            away_tags = shared_tags
        if pd.notna(home_spread):
            home_side = 'favorite' if float(home_spread) < 0 else 'underdog' if float(home_spread) > 0 else 'shared'
            home_tags = build_football_script_tags(home_spread, total, team_side=home_side, wind_mph=wind_mph)
        else:
            home_tags = shared_tags
        payload = {
            'date': row['Date'].strftime('%Y-%m-%d') if pd.notna(row.get('Date')) else '',
            'away': away,
            'home': home,
            'total': float(total) if pd.notna(pd.to_numeric(total, errors='coerce')) else None,
            'away_spread': float(away_spread) if pd.notna(away_spread) else None,
            'home_spread': float(home_spread) if pd.notna(home_spread) else None,
            'away_tags': list(dict.fromkeys(away_tags)),
            'home_tags': list(dict.fromkeys(home_tags)),
        }
        lookup[(away, home)] = payload
        lookup[(home, away)] = payload
        lookup[away] = {'team_tags': payload['away_tags'], **payload}
        lookup[home] = {'team_tags': payload['home_tags'], **payload}
    return lookup


def attach_nfl_game_script_to_board(board):
    if not isinstance(board, dict) or not board.get('available'):
        return board
    lookup = build_nfl_game_script_lookup()
    if not lookup:
        return board

    updated = dict(board)

    def _with_tags(play, game=None):
        play = dict(play)
        team = normalize_team_abbr(play.get('team'))
        tags = []
        context = {}
        if game:
            away = normalize_team_abbr(game.get('away_team'))
            home = normalize_team_abbr(game.get('home_team'))
            context = lookup.get((away, home)) or lookup.get((home, away)) or {}
            if team and context:
                if team == context.get('away'):
                    tags = list(context.get('away_tags') or [])
                elif team == context.get('home'):
                    tags = list(context.get('home_tags') or [])
        if not tags and team:
            context = lookup.get(team) or {}
            tags = list(context.get('team_tags') or [])
        if tags:
            play['game_script_tags'] = list(dict.fromkeys(tags))
            play['game_script_note'] = ', '.join(play['game_script_tags'][:4])
        return play

    updated['top_plays'] = [_with_tags(play) for play in updated.get('top_plays', [])]
    games = []
    for game in updated.get('games', []):
        game = dict(game)
        away = normalize_team_abbr(game.get('away_team'))
        home = normalize_team_abbr(game.get('home_team'))
        context = lookup.get((away, home)) or lookup.get((home, away)) or {}
        if context:
            game['game_script_context'] = context
        game['plays'] = [_with_tags(play, game) for play in game.get('plays', [])]
        game['best_plays'] = game['plays'][:6]
        games.append(game)
    updated['games'] = games
    return updated


def summarize_football_hot_hand(props_history):
    summary = {
        'ready': False,
        'rows': 0,
        'players': 0,
        'seasons': 0,
        'follow_3_rate': None,
        'follow_5_rate': None,
        'over_follow_3_rate': None,
        'under_follow_3_rate': None,
        'top_stats': [],
    }
    if props_history is None or props_history.empty:
        return summary
    required = {'Player', 'Stat', 'Line', 'Actual', 'Date'}
    if not required.issubset(props_history.columns):
        return summary

    history = props_history.dropna(subset=['Player', 'Stat', 'Line', 'Actual', 'Date']).copy()
    if history.empty:
        return summary
    history = history.sort_values(['Player', 'Stat', 'Date'])
    history['OverHit'] = history['Actual'] > history['Line']
    history['UnderHit'] = history['Actual'] < history['Line']

    opportunities = []
    stat_buckets = {}
    for (_, stat), group in history.groupby(['Player', 'Stat'], dropna=False):
        over_run = 0
        under_run = 0
        for _, row in group.iterrows():
            if over_run >= 3:
                opportunities.append({'Stat': stat, 'Side': 'OVER', 'Threshold': 3, 'Continued': bool(row['OverHit'])})
            if over_run >= 5:
                opportunities.append({'Stat': stat, 'Side': 'OVER', 'Threshold': 5, 'Continued': bool(row['OverHit'])})
            if under_run >= 3:
                opportunities.append({'Stat': stat, 'Side': 'UNDER', 'Threshold': 3, 'Continued': bool(row['UnderHit'])})
            if under_run >= 5:
                opportunities.append({'Stat': stat, 'Side': 'UNDER', 'Threshold': 5, 'Continued': bool(row['UnderHit'])})

            over_hit = bool(row['OverHit'])
            under_hit = bool(row['UnderHit'])
            over_run = over_run + 1 if over_hit else 0
            under_run = under_run + 1 if under_hit else 0

    opp_df = pd.DataFrame(opportunities)
    if opp_df.empty:
        summary.update({
            'ready': True,
            'rows': int(len(history)),
            'players': int(history['Player'].nunique()),
            'seasons': int(history['Season'].nunique()) if 'Season' in history.columns else 0,
        })
        return summary

    def _rate(frame):
        if frame.empty:
            return None
        return round(float(frame['Continued'].mean() * 100), 1)

    stat_rows = []
    for stat, frame in opp_df.groupby('Stat'):
        total = len(frame)
        follow3 = _rate(frame[frame['Threshold'] == 3])
        follow5 = _rate(frame[frame['Threshold'] == 5])
        if total:
            stat_rows.append({
                'stat': str(stat),
                'opportunities': int(total),
                'follow_3_rate': follow3,
                'follow_5_rate': follow5,
            })
    stat_rows = sorted(
        stat_rows,
        key=lambda item: ((item.get('follow_5_rate') or item.get('follow_3_rate') or 0), item.get('opportunities') or 0),
        reverse=True
    )[:6]

    summary.update({
        'ready': True,
        'rows': int(len(history)),
        'players': int(history['Player'].nunique()),
        'seasons': int(history['Season'].nunique()) if 'Season' in history.columns else 0,
        'follow_3_rate': _rate(opp_df[opp_df['Threshold'] == 3]),
        'follow_5_rate': _rate(opp_df[opp_df['Threshold'] == 5]),
        'over_follow_3_rate': _rate(opp_df[(opp_df['Threshold'] == 3) & (opp_df['Side'] == 'OVER')]),
        'under_follow_3_rate': _rate(opp_df[(opp_df['Threshold'] == 3) & (opp_df['Side'] == 'UNDER')]),
        'top_stats': stat_rows,
    })
    return summary


def build_football_prop_review_lab(props_history):
    review = {
        'ready': False,
        'totals': {
            'rows': 0,
            'resolved': 0,
            'hits': 0,
            'misses': 0,
            'pushes': 0,
            'hit_rate': None,
        },
        'coverage_by_stat': [],
        'coverage_note': '',
        'by_stat': [],
        'by_threshold': [],
        'by_side': [],
        'best_patterns': [],
    }
    if props_history is None or props_history.empty:
        return review
    required = {'Player', 'Stat', 'Line', 'Actual'}
    if not required.issubset(props_history.columns):
        return review

    history = props_history.dropna(subset=['Player', 'Stat', 'Line', 'Actual']).copy()
    if history.empty:
        return review

    history['Line'] = pd.to_numeric(history['Line'], errors='coerce')
    history['Actual'] = pd.to_numeric(history['Actual'], errors='coerce')
    history = history.dropna(subset=['Line', 'Actual']).copy()
    if history.empty:
        return review

    history = history.sort_values(['Player', 'Stat', 'Season', 'Week', 'CommenceTime', 'SnapshotDate'])
    history['OverHit'] = history['Actual'] > history['Line']
    history['UnderHit'] = history['Actual'] < history['Line']
    history['Push'] = history['Actual'] == history['Line']

    opportunities = []
    for (_, stat), group in history.groupby(['Player', 'Stat'], dropna=False):
        over_run = 0
        under_run = 0
        for _, row in group.iterrows():
            if over_run >= 3:
                opportunities.append({'Stat': stat, 'Side': 'OVER', 'Threshold': 3, 'Continued': bool(row['OverHit']), 'Push': bool(row['Push'])})
            if over_run >= 5:
                opportunities.append({'Stat': stat, 'Side': 'OVER', 'Threshold': 5, 'Continued': bool(row['OverHit']), 'Push': bool(row['Push'])})
            if under_run >= 3:
                opportunities.append({'Stat': stat, 'Side': 'UNDER', 'Threshold': 3, 'Continued': bool(row['UnderHit']), 'Push': bool(row['Push'])})
            if under_run >= 5:
                opportunities.append({'Stat': stat, 'Side': 'UNDER', 'Threshold': 5, 'Continued': bool(row['UnderHit']), 'Push': bool(row['Push'])})

            if bool(row['Push']):
                over_run = 0
                under_run = 0
                continue

            over_run = over_run + 1 if bool(row['OverHit']) else 0
            under_run = under_run + 1 if bool(row['UnderHit']) else 0

    opp_df = pd.DataFrame(opportunities)
    if opp_df.empty:
        review['ready'] = True
        review['totals']['rows'] = int(len(history))
        return review

    resolved = opp_df[~opp_df['Push']].copy()
    hits = int(resolved['Continued'].sum()) if not resolved.empty else 0
    misses = int((~resolved['Continued']).sum()) if not resolved.empty else 0
    pushes = int(opp_df['Push'].sum()) if 'Push' in opp_df.columns else 0
    hit_rate = round(float(resolved['Continued'].mean() * 100), 1) if not resolved.empty else None

    review['ready'] = True
    review['totals'] = {
        'rows': int(len(history)),
        'resolved': int(len(resolved)),
        'hits': hits,
        'misses': misses,
        'pushes': pushes,
        'hit_rate': hit_rate,
    }

    if 'Week' in history.columns:
        coverage_rows = []
        for stat, group in history.groupby('Stat', dropna=False):
            weeks = sorted(pd.to_numeric(group['Week'], errors='coerce').dropna().astype(int).unique().tolist())
            coverage_rows.append({
                'stat': str(stat),
                'weeks_loaded': int(len(weeks)),
                'week_span': f"{weeks[0]}-{weeks[-1]}" if weeks else '-',
                'missing_weeks': [w for w in range(1, 19) if w not in weeks],
            })
        coverage_rows.sort(key=lambda item: (item.get('weeks_loaded') or 0, item.get('stat') or ''), reverse=True)
        review['coverage_by_stat'] = coverage_rows
        partial = [row for row in coverage_rows if (row.get('weeks_loaded') or 0) < 18]
        if partial:
            review['coverage_note'] = 'Some NFL prop categories are still partial because the historical API run hit an authorization limit before every week could be completed.'

    def _summary_rows(frame, key_name):
        rows = []
        for key, group in frame.groupby(key_name, dropna=False):
            resolved_group = group[~group['Push']].copy()
            if resolved_group.empty:
                continue
            row = {
                key_name.lower(): str(key),
                'opportunities': int(len(group)),
                'resolved': int(len(resolved_group)),
                'hits': int(resolved_group['Continued'].sum()),
                'misses': int((~resolved_group['Continued']).sum()),
                'pushes': int(group['Push'].sum()),
                'hit_rate': round(float(resolved_group['Continued'].mean() * 100), 1),
            }
            rows.append(row)
        return rows

    by_stat = _summary_rows(opp_df, 'Stat')
    by_stat.sort(key=lambda item: (float(item.get('hit_rate') or 0), item.get('resolved') or 0), reverse=True)
    review['by_stat'] = by_stat[:8]

    threshold_rows = []
    for threshold, group in opp_df.groupby('Threshold', dropna=False):
        resolved_group = group[~group['Push']].copy()
        if resolved_group.empty:
            continue
        threshold_rows.append({
            'threshold': f'{int(threshold)}+',
            'opportunities': int(len(group)),
            'resolved': int(len(resolved_group)),
            'hits': int(resolved_group['Continued'].sum()),
            'misses': int((~resolved_group['Continued']).sum()),
            'pushes': int(group['Push'].sum()),
            'hit_rate': round(float(resolved_group['Continued'].mean() * 100), 1),
        })
    threshold_rows.sort(key=lambda item: int(str(item.get('threshold', '0')).replace('+', '')))
    review['by_threshold'] = threshold_rows

    side_rows = []
    for side, group in opp_df.groupby('Side', dropna=False):
        resolved_group = group[~group['Push']].copy()
        if resolved_group.empty:
            continue
        side_rows.append({
            'side': str(side),
            'opportunities': int(len(group)),
            'resolved': int(len(resolved_group)),
            'hits': int(resolved_group['Continued'].sum()),
            'misses': int((~resolved_group['Continued']).sum()),
            'pushes': int(group['Push'].sum()),
            'hit_rate': round(float(resolved_group['Continued'].mean() * 100), 1),
        })
    side_rows.sort(key=lambda item: (float(item.get('hit_rate') or 0), item.get('resolved') or 0), reverse=True)
    review['by_side'] = side_rows

    pattern_rows = []
    for (stat, side, threshold), group in opp_df.groupby(['Stat', 'Side', 'Threshold'], dropna=False):
        resolved_group = group[~group['Push']].copy()
        if len(resolved_group) < 8:
            continue
        pattern_rows.append({
            'stat': str(stat),
            'side': str(side),
            'threshold': f'{int(threshold)}+',
            'resolved': int(len(resolved_group)),
            'hits': int(resolved_group['Continued'].sum()),
            'hit_rate': round(float(resolved_group['Continued'].mean() * 100), 1),
            'label': f"{stat} {side} {int(threshold)}+",
            'note': f"{int(resolved_group['Continued'].sum())} hits in {int(len(resolved_group))} resolved follow spots.",
        })
    pattern_rows.sort(key=lambda item: (float(item.get('hit_rate') or 0), item.get('resolved') or 0), reverse=True)
    review['best_patterns'] = pattern_rows[:8]

    return review


def summarize_football_game_line_patterns(lines_history):
    summary = {
        'ready': False,
        'rows': 0,
        'seasons': 0,
        'ats_follow_3_rate': None,
        'ou_follow_3_rate': None,
        'ats_follow_5_rate': None,
        'ou_follow_5_rate': None,
        'team_patterns': [],
    }
    if lines_history is None or lines_history.empty:
        return summary
    required = {'Away', 'Home', 'AwayScore', 'HomeScore', 'Date'}
    if not required.issubset(lines_history.columns):
        return summary

    history = lines_history.dropna(subset=['Away', 'Home', 'AwayScore', 'HomeScore', 'Date']).copy()
    if history.empty:
        return summary
    history = history.sort_values('Date')

    team_rows = []
    for _, row in history.iterrows():
        away = str(row['Away']).strip()
        home = str(row['Home']).strip()
        away_score = float(row['AwayScore'])
        home_score = float(row['HomeScore'])
        away_spread = pd.to_numeric(row.get('AwaySpread'), errors='coerce')
        home_spread = pd.to_numeric(row.get('HomeSpread'), errors='coerce')
        total = pd.to_numeric(row.get('CloseTotal', row.get('Total')), errors='coerce')
        total_points = away_score + home_score
        away_ats_result = 'PUSH'
        home_ats_result = 'PUSH'
        if pd.notna(away_spread):
            away_margin_vs_line = away_score + float(away_spread) - home_score
            away_ats_result = 'COVER' if away_margin_vs_line > 0 else 'PUSH' if abs(away_margin_vs_line) < 1e-9 else 'MISS'
        if pd.notna(home_spread):
            home_margin_vs_line = home_score + float(home_spread) - away_score
            home_ats_result = 'COVER' if home_margin_vs_line > 0 else 'PUSH' if abs(home_margin_vs_line) < 1e-9 else 'MISS'
        ou_side = 'PUSH'
        if pd.notna(total):
            ou_side = 'OVER' if total_points > float(total) else 'UNDER' if total_points < float(total) else 'PUSH'
        team_rows.append({'Team': away, 'Date': row['Date'], 'ATS': away_ats_result, 'OU': ou_side})
        team_rows.append({'Team': home, 'Date': row['Date'], 'ATS': home_ats_result, 'OU': ou_side})

    team_df = pd.DataFrame(team_rows).sort_values(['Team', 'Date'])
    ats_opps = []
    ou_opps = []
    for _, group in team_df.groupby('Team'):
        ats_run = 0
        ou_run = {'OVER': 0, 'UNDER': 0}
        for _, row in group.iterrows():
            if ats_run >= 3:
                ats_opps.append({'Team': row['Team'], 'Threshold': 3, 'Continued': row['ATS'] == 'COVER'})
            if ats_run >= 5:
                ats_opps.append({'Team': row['Team'], 'Threshold': 5, 'Continued': row['ATS'] == 'COVER'})

            for side in ['OVER', 'UNDER']:
                if ou_run[side] >= 3:
                    ou_opps.append({'Team': row['Team'], 'Side': side, 'Threshold': 3, 'Continued': row['OU'] == side})
                if ou_run[side] >= 5:
                    ou_opps.append({'Team': row['Team'], 'Side': side, 'Threshold': 5, 'Continued': row['OU'] == side})

            ats_run = ats_run + 1 if row['ATS'] == 'COVER' else 0
            current_ou = row['OU']
            if current_ou == 'OVER':
                ou_run['OVER'] += 1
                ou_run['UNDER'] = 0
            elif current_ou == 'UNDER':
                ou_run['UNDER'] += 1
                ou_run['OVER'] = 0
            else:
                ou_run['OVER'] = 0
                ou_run['UNDER'] = 0

    ats_df = pd.DataFrame(ats_opps)
    ou_df = pd.DataFrame(ou_opps)

    def _rate(frame):
        if frame.empty:
            return None
        return round(float(frame['Continued'].mean() * 100), 1)

    team_patterns = []
    for team, group in team_df.groupby('Team'):
        team_patterns.append({
            'team': team,
            'games': int(len(group)),
            'cover_rate': round(float((group['ATS'] == 'COVER').mean() * 100), 1),
            'over_rate': round(float((group['OU'] == 'OVER').mean() * 100), 1),
        })
    team_patterns = sorted(team_patterns, key=lambda item: (item['cover_rate'], item['games']), reverse=True)[:8]

    summary.update({
        'ready': True,
        'rows': int(len(history)),
        'seasons': int(history['Season'].nunique()) if 'Season' in history.columns else 0,
        'ats_follow_3_rate': _rate(ats_df[ats_df['Threshold'] == 3]) if not ats_df.empty else None,
        'ats_follow_5_rate': _rate(ats_df[ats_df['Threshold'] == 5]) if not ats_df.empty else None,
        'ou_follow_3_rate': _rate(ou_df[ou_df['Threshold'] == 3]) if not ou_df.empty else None,
        'ou_follow_5_rate': _rate(ou_df[ou_df['Threshold'] == 5]) if not ou_df.empty else None,
        'team_patterns': team_patterns,
    })
    return summary


def build_football_history_lab(sport_key):
    sport_key = str(sport_key or 'nfl').strip().lower()
    if sport_key == 'ncaaf':
        label = 'College Football'
        required_files = [
            'data/historical/NCAAF_Props_History.csv',
            'data/historical/NCAAF_GameLines_History.csv',
        ]
        props_loader = load_ncaaf_props_history
        lines_loader = load_ncaaf_game_lines_history
        token_paths = [
            DATA_DIR / 'historical' / 'NCAAF_Props_History.csv',
            DATA_DIR / 'historical' / 'NCAAF_GameLines_History.csv',
        ]
    else:
        label = 'NFL'
        required_files = [
            'data/historical/NFL_Props_History.csv',
            'data/historical/NFL_GameLines_History.csv',
        ]
        props_loader = load_nfl_props_history
        lines_loader = load_nfl_game_lines_history
        token_paths = [
            DATA_DIR / 'historical' / 'NFL_Props_History.csv',
            DATA_DIR / 'historical' / 'NFL_GameLines_History.csv',
        ]

    def _build_history_lab():
        props_history = props_loader()
        lines_history = lines_loader()
        hot_hand = summarize_football_hot_hand(props_history)
        if sport_key == 'nfl' and not hot_hand.get('ready'):
            hot_hand = summarize_nfl_player_hot_hand()
        prop_review = build_football_prop_review_lab(props_history)
        line_patterns = summarize_football_game_line_patterns(lines_history)
        return {
            'sport_key': sport_key,
            'label': label,
            'props_history_rows': int(len(props_history)) if props_history is not None and not props_history.empty else 0,
            'game_line_history_rows': int(len(lines_history)) if lines_history is not None and not lines_history.empty else 0,
            'hot_hand': hot_hand,
            'prop_review': prop_review,
            'line_patterns': line_patterns,
            'required_files': required_files,
            'ready': hot_hand.get('ready') or line_patterns.get('ready') or prop_review.get('ready'),
        }

    return _get_disk_ttl_cached_value(
        f'football_history_lab::{sport_key}',
        43200,
        _build_history_lab,
        version=_build_file_token(*token_paths),
    )


def build_football_history_status(history_lab):
    history_lab = history_lab or {}
    sport_key = str(history_lab.get('sport_key') or '').lower()
    props_rows = int(history_lab.get('props_history_rows') or 0)
    line_rows = int(history_lab.get('game_line_history_rows') or 0)
    hot_hand = history_lab.get('hot_hand') or {}
    prop_review = history_lab.get('prop_review') or {}
    line_patterns = history_lab.get('line_patterns') or {}

    cards = []
    if sport_key == 'nfl':
        coverage_rows = prop_review.get('coverage_by_stat') or []
        complete = sum(1 for row in coverage_rows if int(row.get('weeks_loaded') or 0) >= 18)
        partial = sum(1 for row in coverage_rows if 0 < int(row.get('weeks_loaded') or 0) < 18)
        top_stat = coverage_rows[0].get('stat') if coverage_rows else '-'
        cards = [
            {
                'label': 'Prop Archive',
                'value': f"{props_rows:,}" if props_rows else '0',
                'note': 'historical NFL prop rows loaded from archived book lines',
            },
            {
                'label': 'Game-Line History',
                'value': f"{line_rows:,}" if line_rows else '0',
                'note': 'historical NFL side/total rows available for team pattern work',
            },
            {
                'label': 'Coverage',
                'value': f"{complete} full / {partial} partial",
                'note': f"top visible stat coverage: {top_stat}",
            },
        ]
        state = 'ready'
        note = prop_review.get('coverage_note') or 'NFL historical lines and prop review are live; incomplete categories are flagged on-page.'
    else:
        required_files = history_lab.get('required_files') or []
        cards = [
            {
                'label': 'Prop Archive',
                'value': f"{props_rows:,}" if props_rows else '0',
                'note': 'college-football prop history rows currently loaded',
            },
            {
                'label': 'Game-Line History',
                'value': f"{line_rows:,}" if line_rows else '0',
                'note': 'college-football side/total history rows currently loaded',
            },
            {
                'label': 'Required Files',
                'value': len(required_files),
                'note': ', '.join(required_files[-2:]) if required_files else 'No file list attached',
            },
        ]
        state = 'empty' if not history_lab.get('ready') else 'partial'
        note = 'CFB structure is live, but the historical datasets are still empty, so this page is ready for data rather than fully powered by it yet.'

    return {
        'cards': cards,
        'state': state,
        'note': note,
    }


def build_nfl_prop_stat_governance(prop_review):
    prop_review = prop_review or {}
    review_rows = prop_review.get('by_stat') or []
    coverage_rows = prop_review.get('coverage_by_stat') or []
    coverage_map = {
        str(row.get('stat') or '').strip(): row
        for row in coverage_rows
        if str(row.get('stat') or '').strip()
    }
    governance = {}
    for row in review_rows:
        stat = str(row.get('stat') or '').strip()
        if not stat:
            continue
        resolved = int(row.get('resolved') or 0)
        hit_rate = pd.to_numeric(row.get('hit_rate'), errors='coerce')
        coverage = coverage_map.get(stat, {})
        weeks_loaded = int(coverage.get('weeks_loaded') or 0)

        tier = 'watch'
        badge = 'REVIEW OK'
        note = 'Usable, but this stat family still needs context support.'
        adjustment = 0

        if resolved < 25 or weeks_loaded < 8:
            tier = 'partial'
            badge = 'PARTIAL'
            note = 'Historical coverage is still thin, so this bucket should not lead the handicap.'
            adjustment = -8
        elif pd.notna(hit_rate) and hit_rate <= 46:
            tier = 'fade'
            badge = 'REVIEW FADE'
            note = 'Historical streak follow-through has been weak here. Treat this bucket cautiously.'
            adjustment = -10
        elif pd.notna(hit_rate) and hit_rate <= 49:
            tier = 'tight'
            badge = 'REVIEW TIGHT'
            note = 'This stat family has been close to coin-flip on follow spots.'
            adjustment = -4
        elif pd.notna(hit_rate) and hit_rate >= 53 and resolved >= 40 and weeks_loaded >= 18:
            tier = 'trusted'
            badge = 'REVIEW+'
            note = 'This stat family has the cleanest historical follow-through and full archive coverage.'
            adjustment = 5
        elif pd.notna(hit_rate) and hit_rate >= 50 and resolved >= 40:
            tier = 'supported'
            badge = 'REVIEW OK'
            note = 'This stat family is supported historically, but it still should confirm the broader script.'
            adjustment = 2

        governance[stat] = {
            'stat': stat,
            'resolved': resolved,
            'hit_rate': round(float(hit_rate), 1) if pd.notna(hit_rate) else None,
            'weeks_loaded': weeks_loaded,
            'tier': tier,
            'badge': badge,
            'note': note,
            'adjustment': adjustment,
        }
    return governance


def annotate_nfl_workbook_play_with_governance(play, governance_map):
    play = dict(play or {})
    stat = str(play.get('stat') or '').strip()
    governance = dict((governance_map or {}).get(stat) or {})
    if not governance:
        governance = {
            'stat': stat,
            'resolved': 0,
            'hit_rate': None,
            'weeks_loaded': 0,
            'tier': 'watch',
            'badge': 'REVIEW WATCH',
            'note': 'This stat family has not been reviewed deeply enough yet, so the streak should stay secondary to the game script.',
            'adjustment': -2,
        }

    tier = str(governance.get('tier') or 'watch').strip().lower()
    ceilings = {
        'trusted': 95.0,
        'supported': 90.0,
        'watch': 86.0,
        'tight': 82.0,
        'partial': 76.0,
        'fade': 72.0,
    }
    tier_weights = {
        'trusted': 1.0,
        'supported': 0.96,
        'watch': 0.91,
        'tight': 0.86,
        'partial': 0.79,
        'fade': 0.70,
    }
    trust_titles = {
        'trusted': 'Trusted support bucket',
        'supported': 'Supported support bucket',
        'watch': 'Watch-list support bucket',
        'tight': 'Tight support bucket',
        'partial': 'Partial support bucket',
        'fade': 'Fade-risk support bucket',
    }
    trust_verdicts = {
        'trusted': 'Historical review supports letting this streak confirm the matchup.',
        'supported': 'Historical review supports this as secondary confirmation, not the whole handicap.',
        'watch': 'The streak is usable, but the stat family still needs stronger review support.',
        'tight': 'The streak is real, but this stat family has been close to coin-flip on follow-through.',
        'partial': 'Archive coverage is still thin here, so do not let this streak lead the bet.',
        'fade': 'Historical review pushes against blindly following this streak.',
    }

    hit_pct_value = _safe_pct(play.get('hit_pct')) or 0.0
    streak_value = float(_safe_int(play.get('streak')) or 0)
    avg_value = _safe_float(play.get('avg'))
    line_value = _safe_float(play.get('line'))
    edge_bonus = 0.0
    if avg_value is not None and line_value is not None:
        edge_bonus = max(min(avg_value - line_value, 6.0), -6.0) * 2.0

    base_score = (hit_pct_value * 0.68) + (streak_value * 5.0) + edge_bonus + float(governance.get('adjustment') or 0)
    weighted_score = base_score * float(tier_weights.get(tier, 0.9))
    trust_score = round(max(50.0, min(weighted_score, ceilings.get(tier, 84.0))), 1)

    play['governance_tier'] = tier
    play['governance_badge'] = governance.get('badge') or 'REVIEW WATCH'
    play['governance_note'] = governance.get('note') or ''
    play['governance_resolved'] = governance.get('resolved')
    play['governance_hit_rate'] = governance.get('hit_rate')
    play['governance_weeks_loaded'] = governance.get('weeks_loaded')
    play['trust_label'] = trust_titles.get(tier, 'Watch-list support bucket')
    play['trust_score'] = trust_score
    play['trust_summary'] = (
        f"{play['trust_label']}. "
        f"{play['governance_badge']} across {play['governance_resolved'] or 0} resolved spots"
        + (f" at {play['governance_hit_rate']}%." if play.get('governance_hit_rate') is not None else '.')
    )
    play['trust_verdict'] = trust_verdicts.get(tier, 'The streak should stay secondary to the broader game read.')
    note = str(play.get('note') or '').strip()
    if play['governance_note']:
        play['note'] = f"{note} {play['governance_note']}".strip() if note else play['governance_note']
    return play


def apply_nfl_workbook_governance(board):
    if not isinstance(board, dict) or not board.get('available'):
        return board

    history_lab = build_football_history_lab('nfl')
    governance_map = build_nfl_prop_stat_governance((history_lab or {}).get('prop_review') or {})

    def _sort_key(play):
        return (
            float(play.get('trust_score') or 0),
            float(play.get('hit_pct_value') or 0),
            float(play.get('streak_value') or 0),
            float(play.get('avg_value') or 0),
        )

    board['top_plays'] = [
        annotate_nfl_workbook_play_with_governance(play, governance_map)
        for play in list(board.get('top_plays') or [])
    ]
    board['top_plays'].sort(key=_sort_key, reverse=True)

    updated_games = []
    for game in list(board.get('games') or []):
        game = dict(game)
        plays = [
            annotate_nfl_workbook_play_with_governance(play, governance_map)
            for play in list(game.get('plays') or [])
        ]
        plays.sort(key=_sort_key, reverse=True)
        game['plays'] = plays
        game['best_plays'] = plays[:6]
        updated_games.append(game)
    board['games'] = updated_games
    return board


def apply_nfl_contradiction_guardrails(plays, *, featured=False):
    plays = list(plays or [])
    if not plays:
        return []

    runtime = {
        'warning_history_map': build_warning_history_map('nfl_contradictions'),
    }
    guarded = []
    for play in plays:
        candidate = dict(play)
        candidate['_is_featured'] = bool(featured)
        audit = audit_nfl_plays([candidate], runtime=runtime)
        failures = audit.get('failures', []) or []
        warnings = audit.get('warnings', []) or []
        updated = dict(play)
        updated['contradiction_warning_rules'] = [str(item.rule).strip() for item in warnings if str(item.rule).strip()]
        updated['contradiction_warning_note'] = " | ".join(str(item.message).strip() for item in warnings if str(item.message).strip())
        if not failures:
            guarded.append(updated)
            continue

        failure_rules = [str(item.rule).strip() for item in failures if str(item.rule).strip()]
        failure_messages = [str(item.message).strip() for item in failures if str(item.message).strip()]
        fail_note = "Contradiction QC: " + " | ".join(failure_messages[:3])
        updated['contradiction_fail_rules'] = failure_rules
        updated['contradiction_fail_note'] = fail_note
        updated['trust_verdict'] = fail_note
        updated['trust_summary'] = fail_note
        updated['governance_badge'] = 'QC BLOCKED'
        updated['governance_note'] = fail_note
        updated['trust_score'] = min(float(updated.get('trust_score', 0) or 0), 59.9)
        updated['is_contradiction_blocked'] = True
        guarded.append(updated)
    return guarded


def apply_nfl_board_contradictions(board):
    if not isinstance(board, dict) or not board.get('available'):
        return board

    board = dict(board)
    top_plays = apply_nfl_contradiction_guardrails(board.get('top_plays', []), featured=True)
    board['top_plays'] = [
        play for play in top_plays
        if not bool(play.get('is_contradiction_blocked'))
    ]

    updated_games = []
    for game in list(board.get('games') or []):
        game = dict(game)
        game['plays'] = apply_nfl_contradiction_guardrails(game.get('plays', []), featured=False)
        game['best_plays'] = [
            play for play in game.get('plays', [])
            if not bool(play.get('is_contradiction_blocked'))
        ][:6]
        updated_games.append(game)
    board['games'] = updated_games
    return board


