def get_current_user():
    user_id = str(session.get('user_id', '') or '').strip()
    user_email = str(session.get('user_email', '') or '').strip().lower()
    if not user_id and not user_email:
        return None

    users = load_users()
    if users.empty:
        return None

    match = pd.DataFrame()
    if user_id:
        match = users[users['UserId'].astype(str) == user_id]
    if match.empty and user_email:
        match = users[users['Email'].str.lower() == user_email]
    if match.empty:
        return None

    row = match.iloc[0].to_dict()
    return {
        'user_id': row.get('UserId', ''),
        'display_name': row.get('DisplayName', ''),
        'email': row.get('Email', ''),
        'plan': row.get('Plan', 'free'),
        'billing_cycle': row.get('BillingCycle', 'monthly'),
        'plan_status': row.get('PlanStatus', 'active'),
        'role': row.get('Role', ''),
        'is_admin': str(row.get('IsAdmin', '')).strip().lower() in {'1', '1.0', 'true', 'yes'},
    }


def login_user(user):
    session['user_id'] = str(user.get('user_id') or user.get('UserId') or '')
    session['user_email'] = str(user.get('email') or user.get('Email') or '').lower()
    session['display_name'] = str(user.get('display_name') or user.get('DisplayName') or '')


def logout_user():
    session.pop('user_id', None)
    session.pop('user_email', None)
    session.pop('display_name', None)


def _resolve_post_auth_target(user, raw_next=''):
    """Where to send a user after sign-in / sign-up.

    Free (non-paying) users land on the free surface (/free) instead of the Pro-gated
    dashboard. A specific `next` (e.g. a destination saved by an access gate) is honored;
    the generic /dashboard default is replaced with the plan-appropriate landing. Pass a
    get_current_user()-shaped dict so normalize_user_plan reads the plan correctly.
    """
    raw_next = str(raw_next or '').strip()
    if raw_next and raw_next not in {'/dashboard', '/dashboard?postseason=1', '/dashboard?postseason=0'}:
        return raw_next
    paid = bool(user) and (is_owner_user(user) or get_plan_rank(normalize_user_plan(user)) >= get_plan_rank('pro'))
    return '/dashboard?postseason=1' if paid else '/free'


@app.before_request
def enforce_access_gate():
    endpoint = str(request.endpoint or '').strip()
    if not endpoint or endpoint in PUBLIC_ENDPOINTS or endpoint in FREE_ENDPOINTS or endpoint.startswith('static'):
        return None

    required_plan = get_required_plan_for_endpoint(endpoint)
    if not required_plan:
        return None

    current_user = get_current_user()
    requested_path = build_requested_path()
    sport_access_key = get_sport_key_for_access_path(request.path)
    gate_required_plan = (
        get_sport_pass_plan_for_sport(sport_access_key)
        if sport_access_key and required_plan in ('pro', 'sharp')
        else required_plan
    )

    if not current_user:
        if request.method != 'GET':
            return jsonify({
                'ok': False,
                'error': 'login_required',
                'required_plan': gate_required_plan,
                'login_url': url_for('login', next=requested_path, gate='login_required', required=gate_required_plan),
            }), 401
        return render_access_gate_response(gate_required_plan, requested_path, current_user=None)

    if is_owner_user(current_user):
        return None

    current_plan = normalize_user_plan(current_user)
    if sport_access_key and required_plan in ('pro', 'sharp') and user_has_sport_access(current_user, sport_access_key):
        return None
    if get_plan_rank(current_plan) >= get_plan_rank(required_plan):
        return None

    if request.method != 'GET':
        return jsonify({
            'ok': False,
            'error': 'upgrade_required',
            'required_plan': gate_required_plan,
            'pricing_url': url_for('pricing', next=requested_path, gate='upgrade_required', required=gate_required_plan),
        }), 403
    return render_access_gate_response(gate_required_plan, requested_path, current_user=current_user)


def filter_saved_parlays_for_user(df, user=None):
    if df.empty:
        return df
    if user is None:
        return pd.DataFrame(columns=df.columns)

    user_id = str(user.get('user_id', '')).strip()
    user_email = str(user.get('email', '')).strip().lower()
    mask = pd.Series(False, index=df.index)

    if 'UserId' in df.columns and user_id:
        mask = mask | (df['UserId'].astype(str) == user_id)
    if 'UserEmail' in df.columns and user_email:
        mask = mask | (df['UserEmail'].astype(str).str.lower() == user_email)

    return df[mask].copy()


