def _latest_file_mtime(path):
    try:
        if not path.exists():
            return None
        return datetime.fromtimestamp(path.stat().st_mtime)
    except Exception:
        return None


def _latest_glob_mtime(pattern):
    matches = list(Path(pattern.parent).glob(pattern.name))
    latest = None
    for candidate in matches:
        mtime = _latest_file_mtime(candidate)
        if mtime and (latest is None or mtime > latest):
            latest = mtime
    return latest


def _latest_any_log_mtime(*patterns):
    latest = None
    for pattern in patterns:
        mtime = _latest_glob_mtime(pattern)
        if mtime and (latest is None or mtime > latest):
            latest = mtime
    return latest


def _latest_qc_scope_entry(scope):
    qc_log = load_qc_run_log()
    if qc_log.empty or 'Scope' not in qc_log.columns:
        return {}
    scoped = qc_log[qc_log['Scope'].astype(str).str.strip() == str(scope or '').strip()]
    if scoped.empty:
        return {}
    if 'CheckedAt' in scoped.columns:
        scoped = scoped.copy()
        scoped['CheckedAtParsed'] = pd.to_datetime(scoped['CheckedAt'], errors='coerce', format='mixed')
        scoped = scoped.sort_values('CheckedAtParsed')
    row = scoped.iloc[-1].to_dict()
    return row


def _format_elapsed_label(dt_value):
    if not dt_value:
        return 'never'
    delta = datetime.now() - dt_value
    hours = delta.total_seconds() / 3600.0
    if hours < 1:
        minutes = max(int(delta.total_seconds() // 60), 0)
        return f'{minutes}m ago'
    if hours < 24:
        return f'{hours:.1f}h ago'
    days = hours / 24.0
    return f'{days:.1f}d ago'


def _classify_ops_freshness(dt_value, good_hours=24, watch_hours=48):
    if not dt_value:
        return 'missing'
    age_hours = (datetime.now() - dt_value).total_seconds() / 3600.0
    if age_hours <= good_hours:
        return 'good'
    if age_hours <= watch_hours:
        return 'watch'
    return 'stale'


def _load_sport_scorecard_summary(sport_key):
    sport = str(sport_key or '').strip().upper()
    if not sport:
        return {}

    scorecard_path = DATA_DIR / 'tracking' / f'{sport}_99_Scorecard.csv'
    featured_results_path = DATA_DIR / 'tracking' / f'{sport}_FeaturedResults.csv'
    scorecard_mtime = _latest_file_mtime(scorecard_path)

    status = 'missing'
    decision = 'No scorecard'
    pass_count = watch_count = fail_count = 0

    if scorecard_path.exists():
        try:
            df = _load_cached_csv(scorecard_path, default=pd.DataFrame())
        except Exception:
            df = pd.DataFrame()
        if not df.empty and {'Section', 'Status'}.issubset(df.columns):
            statuses = df['Status'].fillna('').astype(str).str.upper()
            pass_count = int((statuses == 'PASS').sum())
            watch_count = int((statuses == 'WATCH').sum())
            fail_count = int((statuses == 'FAIL').sum())
            decision = f'{sport} 99% READY' if fail_count == 0 and watch_count <= 2 else 'NOT 99% YET'
            if fail_count > 0:
                status = 'stale'
            elif watch_count <= 2:
                status = 'good'
            else:
                status = 'watch'
        else:
            status = 'missing'

    resolved = 0
    pending = 0
    if featured_results_path.exists():
        try:
            featured = _load_cached_csv(featured_results_path, default=pd.DataFrame())
        except Exception:
            featured = pd.DataFrame()
        if not featured.empty and 'OutcomeState' in featured.columns:
            outcomes = featured['OutcomeState'].fillna('').astype(str)
            resolved = int(outcomes.isin(['Hit', 'Miss', 'Push']).sum())
            pending = int(outcomes.eq('Pending').sum())

    return {
        'label': sport,
        'status': status,
        'status_label': 'Ready' if status == 'good' else 'Watch' if status == 'watch' else 'Attention' if status == 'stale' else 'Missing',
        'decision': decision,
        'last_run': _format_elapsed_label(scorecard_mtime),
        'detail': f'{decision} | PASS {pass_count} | WATCH {watch_count} | FAIL {fail_count}',
        'resolved': resolved,
        'pending': pending,
        'meta': f'R{resolved}/P{pending}',
    }


def _detect_series_mapping_alerts():
    """Owner-facing alert: playoff matchups missing from SERIES_CONFIG.

    A definite GAP is a playoff RESULT for an unmapped team pair — that series
    will render 0-0 on the dashboard (exactly what happened with the Finals).
    In postseason mode we also surface upcoming scheduled matchups that aren't
    mapped yet, so a new round gets configured before its games are played.
    """
    alerts = []
    try:
        configured = {frozenset(cfg['teams']) for cfg in SERIES_CONFIG.values()}
    except Exception:
        return alerts
    seen = set()
    try:
        results = load_playoff_results()
        if results is not None and not results.empty and {'Away', 'Home'}.issubset(results.columns):
            for _, row in results.iterrows():
                away = normalize_team_for_filter(row.get('Away'))
                home = normalize_team_for_filter(row.get('Home'))
                if not away or not home:
                    continue
                pair = frozenset({away, home})
                if pair not in configured and pair not in seen:
                    seen.add(pair)
                    alerts.append({
                        'severity': 'fail',
                        'message': f"{' vs '.join(sorted(pair))} has playoff results but no SERIES_CONFIG entry — that series will show 0-0.",
                    })
    except Exception:
        pass
    try:
        if postseason_only_enabled():
            schedule = load_schedule()
            if schedule is not None and not schedule.empty and {'Away', 'Home'}.issubset(schedule.columns):
                for _, row in schedule.iterrows():
                    away = normalize_team_for_filter(row.get('Away'))
                    home = normalize_team_for_filter(row.get('Home'))
                    if not away or not home:
                        continue
                    pair = frozenset({away, home})
                    if pair not in configured and pair not in seen:
                        seen.add(pair)
                        alerts.append({
                            'severity': 'warn',
                            'message': f"Upcoming {' vs '.join(sorted(pair))} is not in SERIES_CONFIG — add it before tip-off.",
                        })
    except Exception:
        pass
    return alerts


def build_ops_status_strip():
    cache_key = 'ops_status_strip'
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry:
        cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
        if cached_age <= 90:
            return cached_entry['value']

    logs_dir = BASE_DIR / 'logs'
    tasks = [
        {
            'label': 'Football',
            'kind': 'task',
            'mtime': _latest_any_log_mtime(
                logs_dir / 'refresh_football*.log',
                logs_dir / 'refresh_everything_*_football.log',
                logs_dir / 'manual_football_refresh_*.log',
            ),
            'good_hours': 30,
            'watch_hours': 54,
            'detail': 'NFL/CFB data refresh',
        },
        {
            'label': 'NBA',
            'kind': 'task',
            'mtime': _latest_any_log_mtime(
                logs_dir / 'refresh_nba_daily*.log',
                logs_dir / 'refresh_everything_*_nba.log',
                logs_dir / 'manual_nba_refresh_*.log',
                logs_dir / 'manual_nba_playerlog_retry_*.log',
            ),
            'good_hours': 30,
            'watch_hours': 54,
            'detail': 'NBA daily refresh',
        },
        {
            'label': 'WNBA',
            'kind': 'task',
            'mtime': _latest_any_log_mtime(
                logs_dir / 'refresh_wnba*.log',
                logs_dir / 'refresh_everything_*_wnba.log',
                logs_dir / 'manual_wnba_refresh_*.log',
            ),
            'good_hours': 30,
            'watch_hours': 54,
            'detail': 'WNBA data refresh',
        },
        {
            'label': 'MLB',
            'kind': 'task',
            'mtime': _latest_any_log_mtime(
                logs_dir / 'refresh_mlb*.log',
                logs_dir / 'refresh_everything_*_mlb.log',
                logs_dir / 'manual_mlb_refresh_*.log',
            ),
            'good_hours': 30,
            'watch_hours': 54,
            'detail': 'MLB data refresh',
        },
        {
            'label': 'Injuries',
            'kind': 'task',
            'mtime': _latest_glob_mtime(logs_dir / 'injuries_all_sports_*.log'),
            'good_hours': 8,
            'watch_hours': 18,
            'detail': 'All-sport injury refresh',
        },
        {
            'label': 'Scorecard',
            'kind': 'task',
            'mtime': _latest_any_log_mtime(
                logs_dir / 'prelaunch_scorecard*.log',
                DATA_DIR / 'tracking' / 'Prelaunch_Scorecard.csv',
            ),
            'good_hours': 30,
            'watch_hours': 54,
            'detail': 'Prelaunch scorecard run',
        },
    ]

    items = []
    for task in tasks:
        status = _classify_ops_freshness(task['mtime'], task['good_hours'], task['watch_hours'])
        items.append({
            'label': task['label'],
            'status': status,
            'status_label': {
                'good': 'Fresh',
                'watch': 'Aging',
                'stale': 'Stale',
                'missing': 'Missing',
            }.get(status, 'Unknown'),
            'last_run': _format_elapsed_label(task['mtime']),
            'detail': task['detail'],
        })

    scorecard_entry = _latest_qc_scope_entry('prelaunch_scorecard')
    scorecard_note = str(scorecard_entry.get('Notes', '') or '').strip()
    scorecard_decision = 'Unknown'
    if scorecard_note:
        parts = scorecard_note.split('|', 1)
        if parts:
            scorecard_decision = parts[0].replace('Prelaunch decision:', '').strip() or 'Unknown'

    series_alerts = _detect_series_mapping_alerts()

    overall = 'good'
    if any(item['status'] in {'stale', 'missing'} for item in items):
        overall = 'stale'
    elif any(item['status'] == 'watch' for item in items):
        overall = 'watch'
    # A playoff series with no config is an attention-level problem (wrong score
    # shown to users); an unmapped upcoming matchup is at least a watch.
    if any(a['severity'] == 'fail' for a in series_alerts):
        overall = 'stale'
    elif series_alerts and overall == 'good':
        overall = 'watch'

    sport_scorecards = [
        _load_sport_scorecard_summary('NBA'),
        _load_sport_scorecard_summary('WNBA'),
        _load_sport_scorecard_summary('MLB'),
        _load_sport_scorecard_summary('NFL'),
    ]

    strip = {
        'overall': overall,
        'overall_label': {
            'good': 'Ops Healthy',
            'watch': 'Ops Watch',
            'stale': 'Ops Attention',
        }.get(overall, 'Ops Status'),
        'items': items,
        'sport_scorecards': sport_scorecards,
        'scorecard_decision': scorecard_decision,
        'scorecard_note': scorecard_note or 'No scorecard note available yet.',
        'series_alerts': series_alerts,
    }
    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': strip,
        'version': None,
    }
    return strip


def _safe_int(value, default=0):
    try:
        if value is None or str(value).strip() == '':
            return default
        return int(float(value))
    except Exception:
        return default


def _build_qc_scope_summary(scope, label):
    entry = _latest_qc_scope_entry(scope)
    if not entry:
        return {
            'scope': scope,
            'label': label,
            'status': 'missing',
            'status_label': 'Missing',
            'last_run': 'never',
            'pass_count': 0,
            'warning_count': 0,
            'failure_count': 0,
            'detail': 'No QC run logged yet.',
            'notes': '',
        }

    checked_at = pd.to_datetime(entry.get('CheckedAt'), errors='coerce')
    clean = str(entry.get('Clean', '')).strip() == '1'
    warning_count = _safe_int(entry.get('WarningCount'))
    failure_count = _safe_int(entry.get('FailureCount'))
    pass_count = _safe_int(entry.get('PassCount'))
    if failure_count > 0 or not clean:
        status = 'stale'
    elif warning_count > 0:
        status = 'watch'
    else:
        status = 'good'

    notes = str(entry.get('Notes', '') or '').strip()
    if notes.lower() in {'nan', 'none', 'null'}:
        notes = ''
    detail_bits = [f'PASS {pass_count}', f'WARN {warning_count}', f'FAIL {failure_count}']
    if notes:
        detail_bits.append(notes)

    return {
        'scope': scope,
        'label': label,
        'status': status,
        'status_label': {
            'good': 'Clean',
            'watch': 'Watch',
            'stale': 'Attention',
            'missing': 'Missing',
        }.get(status, 'Unknown'),
        'last_run': _format_elapsed_label(checked_at.to_pydatetime() if not pd.isna(checked_at) else None),
        'pass_count': pass_count,
        'warning_count': warning_count,
        'failure_count': failure_count,
        'detail': ' | '.join(detail_bits),
        'notes': notes,
    }


def _load_calibration_report_summary(sport_key):
    sport = str(sport_key or '').strip().upper()
    path = DATA_DIR / 'tracking' / f'{sport}_Calibration_Report.csv'
    mtime = _latest_file_mtime(path)
    if not path.exists():
        return {
            'label': f'{sport} Calibration',
            'status': 'missing',
            'status_label': 'Missing',
            'last_run': 'never',
            'resolved_rows': 0,
            'bucket_rows': 0,
            'lying_count': 0,
            'strong_count': 0,
            'watch_count': 0,
            'note': 'No calibration report file yet.',
            'top_buckets': [],
        }

    try:
        df = _load_cached_csv(path, default=pd.DataFrame())
    except Exception:
        df = pd.DataFrame()

    if df.empty or 'Classification' not in df.columns:
        return {
            'label': f'{sport} Calibration',
            'status': 'watch',
            'status_label': 'Waiting',
            'last_run': _format_elapsed_label(mtime),
            'resolved_rows': 0,
            'bucket_rows': 0,
            'lying_count': 0,
            'strong_count': 0,
            'watch_count': 0,
            'note': 'No resolved rows yet, so calibration is not meaningful.',
            'top_buckets': [],
        }

    classifications = df['Classification'].fillna('').astype(str).str.upper()
    lying_count = int((classifications == 'LYING').sum())
    strong_count = int((classifications == 'STRONG').sum())
    watch_count = int((classifications == 'WATCH').sum())
    sample_sizes = pd.to_numeric(df.get('SampleSize'), errors='coerce').fillna(0)
    resolved_rows = int(sample_sizes.max()) if not sample_sizes.empty else 0
    top_buckets = []
    if {'BucketLabel', 'Classification', 'Recommendation'}.issubset(df.columns):
        ranked = df[df['Classification'].astype(str).isin(['LYING', 'STRONG', 'WATCH'])].copy()
        if not ranked.empty:
            ranked['SampleSize'] = pd.to_numeric(ranked.get('SampleSize'), errors='coerce').fillna(0)
            ranked = ranked.sort_values(['Classification', 'SampleSize'], ascending=[True, False])
            for _, row in ranked.head(4).iterrows():
                top_buckets.append({
                    'label': str(row.get('BucketLabel', '') or '').strip(),
                    'classification': str(row.get('Classification', '') or '').strip().upper(),
                    'sample_size': _safe_int(row.get('SampleSize')),
                    'recommendation': str(row.get('Recommendation', '') or '').strip(),
                })

    if lying_count > 0:
        status = 'watch'
        note = f'{lying_count} lying bucket(s) flagged for review.'
    elif strong_count > 0:
        status = 'good'
        note = f'{strong_count} strong bucket(s) logged with no lying buckets.'
    else:
        status = 'watch'
        note = 'Calibration ran, but there is not enough resolved signal to make changes yet.'

    return {
        'label': f'{sport} Calibration',
        'status': status,
        'status_label': 'Healthy' if status == 'good' else 'Watch',
        'last_run': _format_elapsed_label(mtime),
        'resolved_rows': resolved_rows,
        'bucket_rows': int(len(df)),
        'lying_count': lying_count,
        'strong_count': strong_count,
        'watch_count': watch_count,
        'note': note,
        'top_buckets': top_buckets,
    }


def build_ops_dashboard_context():
    sport_definitions = [
        {
            'key': 'NBA',
            'checks': [
                ('nba_contradictions', 'Contradictions'),
                ('nba_injuries', 'Injuries'),
                ('nba_board', 'Board'),
                ('nba_visual_trust', 'Visual Trust'),
                ('nba_featured_results', 'Featured Results'),
            ],
        },
        {
            'key': 'WNBA',
            'checks': [
                ('wnba_contradictions', 'Contradictions'),
                ('wnba_injuries', 'Injuries'),
                ('wnba_readiness', 'Readiness'),
                ('wnba_visual_trust', 'Visual Trust'),
                ('wnba_featured_results', 'Featured Results'),
            ],
        },
        {
            'key': 'MLB',
            'checks': [
                ('mlb_contradictions', 'Contradictions'),
                ('mlb_injuries', 'Injuries'),
                ('mlb_readiness', 'Readiness'),
                ('mlb_visual_trust', 'Visual Trust'),
                ('mlb_featured_results', 'Featured Results'),
            ],
        },
        {
            'key': 'NFL',
            'checks': [
                ('nfl_contradictions', 'Contradictions'),
                ('nfl_injuries', 'Injuries'),
                ('nfl_board', 'Board'),
                ('nfl_visual_trust', 'Visual Trust'),
                ('nfl_featured_results', 'Featured Results'),
            ],
        },
    ]

    global_checks = [
        _build_qc_scope_summary('platform_routes_fast', 'Platform Routes (Fast)'),
        _build_qc_scope_summary('prelaunch_scorecard', 'Prelaunch Scorecard'),
        _build_qc_scope_summary('checkout_readiness', 'Checkout Readiness'),
    ]

    sports = []
    for definition in sport_definitions:
        sport_key = definition['key']
        scorecard = _load_sport_scorecard_summary(sport_key)
        calibration = _load_calibration_report_summary(sport_key)
        checks = [_build_qc_scope_summary(scope, label) for scope, label in definition['checks']]
        sports.append({
            'key': sport_key,
            'scorecard': scorecard,
            'calibration': calibration,
            'checks': checks,
        })

    return {
        'ops_status': build_ops_status_strip(),
        'global_checks': global_checks,
        'sports': sports,
        'generated_at': datetime.now().strftime('%Y-%m-%d %I:%M %p'),
    }


