def get_player_snapshot_row(player_snapshot, player_name, team=''):
    if player_snapshot is None or player_snapshot.empty or 'player_name' not in player_snapshot.columns:
        return None

    snapshot = player_snapshot[player_snapshot['player_name'] == player_name]
    if team and 'last_team_abbrev' in snapshot.columns:
        team_match = snapshot[snapshot['last_team_abbrev'] == team]
        if not team_match.empty:
            snapshot = team_match
    if snapshot.empty:
        return None
    return snapshot.iloc[0]


def get_snapshot_stat_key(stat):
    return {'PTS': 'pts', 'REB': 'reb', 'AST': 'ast', '3PM': '3pt'}.get(stat, stat.lower())


def normalize_player_lookup_name(name):
    raw = str(name or '').strip()
    if not raw:
        return ''
    cleaned = re.sub(r"[.,'`']", '', raw).strip().lower()
    cleaned = re.sub(r'\s+', ' ', cleaned)
    cleaned = re.sub(r'\b(jr|sr|ii|iii|iv|v)\b$', '', cleaned).strip()
    return cleaned


def build_current_team_map(gamelogs, player_snapshot=None, current_team_overrides=None):
    current_map = {}
    if gamelogs is not None and not gamelogs.empty and {'Player', 'Team'}.issubset(gamelogs.columns):
        logs = gamelogs.copy()
        if 'Date' in logs.columns:
            logs['DateParsed'] = pd.to_datetime(logs['Date'], errors='coerce')
            logs = logs.sort_values('DateParsed')
        latest = logs.dropna(subset=['Player', 'Team']).groupby('Player').tail(1)
        current_map.update(dict(zip(latest['Player'], latest['Team'])))

    if player_snapshot is not None and not player_snapshot.empty and {'player_name', 'last_team_abbrev'}.issubset(player_snapshot.columns):
        snapshot_latest = (
            player_snapshot.dropna(subset=['player_name', 'last_team_abbrev'])
            .drop_duplicates(subset=['player_name'], keep='last')
        )
        for _, row in snapshot_latest.iterrows():
            current_map.setdefault(str(row['player_name']), str(row['last_team_abbrev']))

    if current_team_overrides is not None and not current_team_overrides.empty and {'Player', 'Team'}.issubset(current_team_overrides.columns):
        override_map = (
            current_team_overrides.dropna(subset=['Player', 'Team'])
            .drop_duplicates(subset=['Player'], keep='last')
        )
        for _, row in override_map.iterrows():
            current_map[str(row['Player'])] = str(row['Team'])

    return current_map


def parse_game_matchup_to_abbrs(game):
    if pd.isna(game):
        return (None, None)
    game = str(game)
    if '@' not in game:
        return (None, None)
    away_name, home_name = [part.strip() for part in game.split('@', 1)]
    return TEAM_NAME_TO_ABBR.get(away_name), TEAM_NAME_TO_ABBR.get(home_name)


def apply_current_team_context(props_df, gamelogs, player_snapshot=None, current_team_overrides=None):
    if props_df is None or props_df.empty:
        return props_df
    props = props_df.copy()
    current_map = build_current_team_map(gamelogs, player_snapshot, current_team_overrides)
    normalized_current_map = {
        normalize_player_lookup_name(player): team
        for player, team in current_map.items()
        if normalize_player_lookup_name(player)
    }

    if 'Team' not in props.columns:
        props['Team'] = np.nan

    resolved_teams = []
    for _, row in props.iterrows():
        player = row.get('Player', '')
        current_team = current_map.get(player) or normalized_current_map.get(normalize_player_lookup_name(player))
        away_abbr, home_abbr = parse_game_matchup_to_abbrs(row.get('Game', ''))
        prop_team = row.get('Team')
        if pd.notna(prop_team) and str(prop_team).strip():
            resolved = str(prop_team).strip()
        elif current_team and current_team in {away_abbr, home_abbr}:
            resolved = current_team
        else:
            resolved = current_team or ''
        resolved_teams.append(resolved)
    props['Team'] = resolved_teams
    return props


def filter_props_to_active_slate(props_df, team_game_lookup):
    if props_df is None or props_df.empty or not team_game_lookup:
        return props_df

    filtered_rows = []
    for _, row in props_df.iterrows():
        team = normalize_team_for_filter(row.get('Team'))
        scheduled_game = team_game_lookup.get(team) if team else None
        if not scheduled_game:
            filtered_rows.append(row.to_dict())
            continue

        scheduled_matchup = str(scheduled_game.get('matchup') or '')
        scheduled_away, scheduled_home = parse_game_matchup_to_abbrs(scheduled_matchup.replace(' @ ', '@'))
        prop_away, prop_home = parse_game_matchup_to_abbrs(row.get('Game', ''))

        if scheduled_away and scheduled_home and prop_away and prop_home:
            if {scheduled_away, scheduled_home} != {prop_away, prop_home}:
                continue

        filtered_rows.append(row.to_dict())

    if not filtered_rows:
        return pd.DataFrame(columns=props_df.columns)
    return pd.DataFrame(filtered_rows)


def get_player_analysis_logs(player_name, gamelogs, current_team_map=None, sample_mode='full', postseason_logs=None, postseason_only=False):
    source_logs = gamelogs
    if postseason_only and postseason_logs is not None and not postseason_logs.empty and 'Player' in postseason_logs.columns:
        postseason_player_logs = postseason_logs[postseason_logs['Player'] == player_name].copy()
        if not postseason_player_logs.empty:
            source_logs = postseason_logs

    player_logs = source_logs[source_logs['Player'] == player_name].copy() if not source_logs.empty and 'Player' in source_logs.columns else pd.DataFrame()
    if player_logs.empty:
        return player_logs, {
            'current_team': current_team_map.get(player_name) if current_team_map else None,
            'teams': [],
            'team_count': 0,
            'is_multi_team': False,
            'sample_mode': sample_mode,
            'sample_label': 'Full Season',
            'used_current_sample': False,
            'current_team_games': 0
        }

    if 'Date' in player_logs.columns:
        player_logs['Date'] = pd.to_datetime(player_logs['Date'], errors='coerce')
        player_logs = player_logs.sort_values('Date', ascending=False)

    teams = [team for team in player_logs['Team'].dropna().astype(str).unique().tolist()] if 'Team' in player_logs.columns else []
    current_team = current_team_map.get(player_name) if current_team_map else (teams[0] if teams else None)
    current_team_logs = player_logs[player_logs['Team'] == current_team].copy() if current_team and 'Team' in player_logs.columns else pd.DataFrame()
    use_current_sample = sample_mode == 'current' and len(current_team_logs) >= 5
    active_logs = current_team_logs if use_current_sample else player_logs

    return active_logs, {
        'current_team': current_team,
        'teams': teams,
        'team_count': len(teams),
        'is_multi_team': len(teams) > 1,
        'sample_mode': sample_mode,
        'sample_label': 'Current Team Sample' if use_current_sample else 'Full Season Sample',
        'used_current_sample': use_current_sample,
        'current_team_games': len(current_team_logs)
    }


def build_player_playoff_summary(player_name, current_team, playoff_logs, schedule):
    summary = {
        'has_playoff_data': False,
        'team': current_team,
        'opponent': None,
        'series_label': '',
        'games': 0,
        'wins': 0,
        'losses': 0,
        'pts': 0,
        'reb': 0,
        'ast': 0,
        'threes': 0,
        'min': 0,
        'recent_games': []
    }

    if playoff_logs is None or playoff_logs.empty or 'Player' not in playoff_logs.columns:
        return summary

    player_playoff_logs = playoff_logs[playoff_logs['Player'] == player_name].copy()
    if player_playoff_logs.empty:
        return summary

    if current_team and 'Team' in player_playoff_logs.columns:
        filtered = player_playoff_logs[player_playoff_logs['Team'] == current_team].copy()
        if not filtered.empty:
            player_playoff_logs = filtered

    if 'Date' in player_playoff_logs.columns:
        player_playoff_logs['Date'] = pd.to_datetime(player_playoff_logs['Date'], errors='coerce')
        player_playoff_logs = player_playoff_logs.sort_values('Date', ascending=False)

    opponent = None
    if schedule is not None and not schedule.empty and current_team:
        upcoming_games = get_upcoming_games(schedule, days=10)
        for bucket in ['today', 'tomorrow', 'upcoming']:
            for game in upcoming_games.get(bucket, []):
                if game.get('Away') == current_team:
                    opponent = game.get('Home')
                    break
                if game.get('Home') == current_team:
                    opponent = game.get('Away')
                    break
            if opponent:
                break

    if not opponent and 'Opp' in player_playoff_logs.columns:
        opp_mode = player_playoff_logs['Opp'].dropna().astype(str).mode()
        if not opp_mode.empty:
            opponent = opp_mode.iloc[0]

    if opponent and 'Opp' in player_playoff_logs.columns:
        series_logs = player_playoff_logs[player_playoff_logs['Opp'] == opponent].copy()
        if series_logs.empty:
            series_logs = player_playoff_logs.copy()
    else:
        series_logs = player_playoff_logs.copy()

    series_label, _ = get_series_label(current_team, opponent) if current_team and opponent else ('Current Playoff Run', '')

    summary.update({
        'has_playoff_data': True,
        'team': current_team,
        'opponent': opponent,
        'series_label': series_label or 'Current Playoff Run',
        'games': int(len(series_logs)),
        'wins': int((series_logs['Result'] == 'W').sum()) if 'Result' in series_logs.columns else 0,
        'losses': int((series_logs['Result'] == 'L').sum()) if 'Result' in series_logs.columns else 0,
        'pts': round(float(series_logs['PTS'].mean()), 1) if 'PTS' in series_logs.columns else 0,
        'reb': round(float(series_logs['REB'].mean()), 1) if 'REB' in series_logs.columns else 0,
        'ast': round(float(series_logs['AST'].mean()), 1) if 'AST' in series_logs.columns else 0,
        'threes': round(float(series_logs['3PM'].mean()), 1) if '3PM' in series_logs.columns else 0,
        'min': round(float(series_logs['MIN'].mean()), 1) if 'MIN' in series_logs.columns else 0,
        'recent_games': series_logs.head(5).to_dict('records')
    })
    return summary


