def _split_camel_stem(stem):
    parts = re.findall(r'[A-Z]?[a-z]+|[A-Z]+(?![a-z])|\d+', str(stem or ''))
    return parts or [str(stem or '')]


def _stem_to_display_name(stem):
    parts = _split_camel_stem(stem)
    pretty = []
    for part in parts:
        token = str(part or '').strip()
        if not token:
            continue
        lowered = token.lower()
        pretty.append(CFB_TOKEN_DISPLAY.get(lowered, token[0].upper() + token[1:]))
    return ' '.join(pretty).strip()


