def normalize_nfl_historical_team_name(value):
    if value is None or pd.isna(value):
        return ''
    cleaned = str(value).strip()
    if not cleaned or cleaned == '0':
        return ''
    alias = NFL_HISTORICAL_TEAM_ALIASES.get(cleaned.replace(' ', '').upper())
    if alias:
        return alias
    return cleaned


def normalize_ncaaf_team_name(value):
    if value is None or pd.isna(value):
        return ''
    cleaned = str(value).strip()
    if not cleaned or cleaned == '0':
        return ''
    normalized = _normalize_logo_key(cleaned)
    alias = CFB_TEAM_ALIASES.get(normalized)
    if alias:
        return alias
    logo_name = CFB_LOGO_NAME_INDEX.get(normalized)
    if logo_name:
        return logo_name
    return cleaned


def team_logo_url(value, sport_key=None):
    sport_key = str(sport_key or '').strip().lower()
    if sport_key in {'nfl', 'ncaaf'}:
        football_logo = football_logo_url(value, sport_key=sport_key)
        if football_logo:
            return football_logo
    abbr = normalize_team_abbr(value)
    if not abbr:
        return ''
    # Prefer curated local assets first so we control quality and avoid
    # mismatched remote logos. Fall back to the remote map only if a local
    # file is missing.
    for extension in ('webp', 'png'):
        clean_candidate = STATIC_DIR / 'logos' / 'nba_clean' / f'{abbr}.{extension}'
        if clean_candidate.exists():
            return f'/static/logos/nba_clean/{abbr}.{extension}'
    for extension in ('svg', 'webp', 'png', 'jpg', 'jpeg'):
        candidate = STATIC_DIR / 'logos' / 'nba' / f'{abbr}.{extension}'
        if candidate.exists():
            return f'/static/logos/nba/{abbr}.{extension}'
    if abbr in TEAM_ABBR_TO_LOGO_URL:
        return TEAM_ABBR_TO_LOGO_URL[abbr]
    football_logo = football_logo_url(value, sport_key=sport_key)
    if football_logo:
        return football_logo
    return ''


def team_display_name(value, sport_key=None):
    sport_key = str(sport_key or '').strip().lower()
    cleaned = str(value or '').strip()
    if sport_key in {'nfl', 'ncaaf'} and cleaned:
        pretty = FOOTBALL_DISPLAY_NAMES.get(cleaned.upper())
        if pretty:
            return pretty
    abbr = normalize_team_abbr(value)
    if abbr in TEAM_ABBR_TO_NAME:
        return TEAM_ABBR_TO_NAME[abbr]
    return cleaned


def render_team_mark(value, size='sm', show_name=True, extra_class='', sport_key=None):
    abbr = normalize_team_abbr(value)
    if not abbr:
        return Markup(escape(str(value or '')))

    display_name = team_display_name(value, sport_key=sport_key)
    label = escape(abbr if len(abbr) <= 4 and display_name == str(value or '').strip() else display_name)
    logo = team_logo_url(value, sport_key=sport_key)
    title = escape(display_name)
    classes = f'team-mark team-mark-{escape(size)}'
    if extra_class:
        classes += f' {escape(extra_class)}'

    image_html = ''
    if logo:
        image_html = f'<img src="{escape(logo)}" alt="{title}" class="team-mark-logo">'
    if show_name:
        return Markup(f'<span class="{classes}">{image_html}<span class="team-mark-text">{label}</span></span>')
    if image_html:
        return Markup(f'<span class="{classes}">{image_html}</span>')
    return Markup(f'<span class="{classes}"><span class="team-mark-text">{label}</span></span>')


def render_matchup_mark(away, home, separator='@', size='sm', extra_class='', sport_key=None):
    away_html = render_team_mark(away, size=size, show_name=True, sport_key=sport_key)
    home_html = render_team_mark(home, size=size, show_name=True, sport_key=sport_key)
    classes = f'matchup-mark matchup-mark-{escape(size)}'
    if extra_class:
        classes += f' {escape(extra_class)}'
    sep = escape(separator)
    return Markup(
        f'<span class="{classes}">{away_html}<span class="matchup-mark-sep">{sep}</span>{home_html}</span>'
    )


def glossary_href(section_id, postseason=None):
    postseason_flag = 1 if postseason_only_enabled() else 0 if postseason is None else int(bool(postseason))
    return f"/glossary?postseason={postseason_flag}#{escape(section_id)}"


def render_glossary_hint(label, section_id, show_icon=True, variant='default', title=None):
    safe_label = escape(label)
    safe_title = escape(title or f"Open glossary for {label}")
    href = glossary_href(section_id)
    link_class = 'glossary-term-link'
    if variant == 'quiet':
        link_class += ' glossary-term-link-quiet'
    elif variant == 'muted':
        link_class += ' glossary-term-link-muted'

    label_html = f'<a href="{href}" class="{link_class}" title="{safe_title}">{safe_label}</a>'
    if not show_icon:
        return Markup(label_html)

    icon_html = (
        f'<a href="{href}" class="glossary-info-link" title="{safe_title}" '
        f'aria-label="{safe_title}">i</a>'
    )
    return Markup(f'<span class="glossary-inline-help">{label_html}{icon_html}</span>')


def ou_rate_color(value):
    try:
        numeric = float(value)
    except Exception:
        return 'var(--text-muted)'
    if numeric >= 50:
        return 'var(--accent)'
    return '#FF6B6B'


def _format_game_market_odds(df):
    working = df.copy()
    rename_map = {}
    if 'ML_Home' in working.columns:
        rename_map['ML_Home'] = 'HomeML'
    if 'ML_Away' in working.columns:
        rename_map['ML_Away'] = 'AwayML'
    working = working.rename(columns=rename_map)

    if 'Away' in working.columns:
        working['Away'] = working['Away'].apply(normalize_team_abbr)
    elif 'AwayFull' in working.columns:
        working['Away'] = working['AwayFull'].apply(normalize_team_abbr)

    if 'Home' in working.columns:
        working['Home'] = working['Home'].apply(normalize_team_abbr)
    elif 'HomeFull' in working.columns:
        working['Home'] = working['HomeFull'].apply(normalize_team_abbr)

    for col in ['Spread', 'SpreadOdds', 'Total', 'OverOdds', 'UnderOdds', 'AwayML', 'HomeML']:
        if col in working.columns:
            working[col] = pd.to_numeric(working[col], errors='coerce')

    if 'Date' in working.columns:
        working['Date'] = pd.to_datetime(working['Date'], errors='coerce').dt.strftime('%Y-%m-%d')

    if 'Book' not in working.columns:
        working['Book'] = 'DraftKings'

    keep_cols = [col for col in ['Date', 'Time', 'Away', 'Home', 'AwayML', 'HomeML', 'Spread', 'SpreadOdds', 'Total', 'OverOdds', 'UnderOdds', 'Book', 'GameID'] if col in working.columns]
    return working[keep_cols].dropna(subset=[col for col in ['Date', 'Away', 'Home'] if col in working.columns])


