def build_game_market_lookup(odds_df):
    lookup = {}
    if odds_df.empty:
        return lookup
    for _, row in odds_df.iterrows():
        away = normalize_team_abbr(row.get('Away', '') or row.get('AwayFull', ''))
        home = normalize_team_abbr(row.get('Home', '') or row.get('HomeFull', ''))
        date = str(row.get('Date', '')).strip()
        if not away or not home:
            continue
        payload = {
            'away_ml': row.get('AwayML'),
            'home_ml': row.get('HomeML'),
            'spread': row.get('Spread'),
            'spread_odds': row.get('SpreadOdds'),
            'total': row.get('Total'),
            'over_odds': row.get('OverOdds'),
            'under_odds': row.get('UnderOdds'),
            'book': row.get('Book', 'DraftKings'),
            'time': row.get('Time', ''),
            'last_updated': row.get('LastUpdated', '')
        }
        lookup[(date, away, home)] = payload
        lookup[('any', away, home)] = payload
    return lookup


def attach_market_to_games(games, market_lookup):
    annotated = []
    for game in games:
        date = str(game.get('Date', '')).strip()
        away = normalize_team_abbr(game.get('Away', ''))
        home = normalize_team_abbr(game.get('Home', ''))
        market = market_lookup.get((date, away, home)) or market_lookup.get(('any', away, home)) or {}
        enriched = dict(game)
        enriched['market'] = market
        enriched['market_total'] = market.get('total')
        enriched['market_spread'] = market.get('spread')
        enriched['market_book'] = market.get('book')
        enriched['market_summary'] = format_game_market_summary(market, home)
        annotated.append(enriched)
    return annotated


def get_single_game_market(odds_df, away, home):
    lookup = build_game_market_lookup(odds_df)
    return lookup.get(('any', normalize_team_abbr(away), normalize_team_abbr(home)), {})


def format_game_market_summary(market, home_team=None):
    if not market:
        return ''
    bits = []
    spread = market.get('spread')
    total = market.get('total')
    home_ml = market.get('home_ml')
    away_ml = market.get('away_ml')
    if spread is not None and not pd.isna(spread) and home_team:
        bits.append(f"{home_team} {float(spread):+g}")
    if total is not None and not pd.isna(total):
        bits.append(f"O/U {float(total):g}")
    if home_ml is not None and away_ml is not None and not pd.isna(home_ml) and not pd.isna(away_ml):
        bits.append(f"ML {int(away_ml):+d}/{int(home_ml):+d}")
    return ' | '.join(bits)


def build_compact_prop_market_summary(draftkings_line=None, vegas_line=None, line_low=None, line_high=None, best_book='', book_count=0, current_line=None):
    bits = []
    if draftkings_line is not None and not pd.isna(draftkings_line):
        bits.append(f"DK {float(draftkings_line):g}")
    if best_book and current_line is not None and not pd.isna(current_line) and str(best_book).strip().lower() != 'draftkings':
        bits.append(f"{str(best_book).strip()} {float(current_line):g}")
    elif vegas_line is not None and not pd.isna(vegas_line) and (draftkings_line is None or pd.isna(draftkings_line) or float(vegas_line) != float(draftkings_line)):
        bits.append(f"Vegas {float(vegas_line):g}")
    if line_low is not None and line_high is not None and not pd.isna(line_low) and not pd.isna(line_high) and float(line_low) != float(line_high):
        bits.append(f"Range {float(line_low):g}-{float(line_high):g}")
    if book_count and int(book_count) > 1:
        bits.append(f"{int(book_count)} books")
    return " | ".join(dict.fromkeys([bit for bit in bits if bit]))


def build_season_review(gamelogs, player_advanced):
    review = {
        'snapshot': {},
        'playoff_edges': [],
        'playoff_team_profiles': [],
        'all_team_profiles': [],
        'quarter_trend_leaders': [],
        'playoff_history': [],
        'formula_backtest': {},
        'stable_leaders': {stat: [] for stat in ['PTS', 'REB', 'AST', '3PM']},
        'role_risers': [],
        'defense_trends': {stat: [] for stat in ['PTS', 'REB', 'AST', '3PM']},
        'insights': []
    }
    if gamelogs.empty:
        return review

    logs = gamelogs.copy()
    for col in ['PTS', 'REB', 'AST', '3PM', 'MIN']:
        if col in logs.columns:
            logs[col] = pd.to_numeric(logs[col], errors='coerce')
    if 'Date' in logs.columns:
        logs['Date'] = pd.to_datetime(logs['Date'], errors='coerce')

    team_games = (
        logs.groupby(['Game_ID', 'Team'], as_index=False)
        .agg({
            'Date': 'first',
            'Opp': 'first',
            'Matchup': 'first',
            'Result': 'first',
            'PTS': 'sum',
            'REB': 'sum',
            'AST': 'sum',
            '3PM': 'sum'
        })
    )
    team_games['site'] = np.where(
        team_games['Matchup'].astype(str).str.contains('vs.', regex=False, na=False),
        'home',
        'away'
    )
    team_games['won'] = team_games['Result'].astype(str).str.startswith('W')

    game_pairs = (
        team_games.pivot_table(index='Game_ID', columns='site', values='PTS', aggfunc='first')
        .reset_index()
        .rename(columns={'home': 'home_points', 'away': 'away_points'})
    )
    if not game_pairs.empty:
        game_pairs['total_points'] = game_pairs[['home_points', 'away_points']].sum(axis=1)
        home_win_rate = round((game_pairs['home_points'] > game_pairs['away_points']).mean() * 100, 1)
        avg_total_points = round(game_pairs['total_points'].mean(), 1)
        avg_home_points = round(game_pairs['home_points'].mean(), 1)
        avg_away_points = round(game_pairs['away_points'].mean(), 1)
    else:
        home_win_rate = avg_total_points = avg_home_points = avg_away_points = 0

    review['snapshot'] = {
        'games': int(logs['Game_ID'].nunique()) if 'Game_ID' in logs.columns else 0,
        'players': int(logs['Player'].nunique()) if 'Player' in logs.columns else 0,
        'teams': int(logs['Team'].nunique()) if 'Team' in logs.columns else 0,
        'home_win_rate': home_win_rate,
        'avg_total_points': avg_total_points,
        'avg_home_points': avg_home_points,
        'avg_away_points': avg_away_points,
    }

    all_profile_rows = []
    for team in sorted(logs['Team'].dropna().unique()):
        team_logs = logs[logs['Team'] == team].copy()
        if team_logs.empty:
            continue
        record = get_team_record(logs, team)
        team_logs = team_logs.sort_values('Date')
        player_pts = (
            team_logs.groupby('Player', as_index=False)
            .agg(
                games=('Game_ID', 'nunique'),
                ppg=('PTS', 'mean'),
                mpg=('MIN', 'mean')
            )
            .sort_values(['ppg', 'mpg'], ascending=False)
        )
        top_scorer = player_pts.iloc[0]['Player'] if not player_pts.empty else ''
        top_scorer_ppg = round(float(player_pts.iloc[0]['ppg']), 1) if not player_pts.empty else 0
        team_game_level = (
            team_logs.groupby('Game_ID', as_index=False)
            .agg({'Date': 'first', 'PTS': 'sum', 'Result': 'first'})
            .sort_values('Date')
            .reset_index(drop=True)
        )
        last10_games = team_logs['Game_ID'].dropna().drop_duplicates().tolist()[-10:]
        last10_logs = team_logs[team_logs['Game_ID'].isin(last10_games)] if last10_games else team_logs.head(0)
        last10_ppg = round(
            last10_logs.groupby('Game_ID')['PTS'].sum().mean(), 1
        ) if not last10_logs.empty else 0

        quarter_ppg = []
        quarter_win_pct = []
        if not team_game_level.empty:
            for quarter_slice in np.array_split(team_game_level.index.to_numpy(), 4):
                quarter_games = team_game_level.loc[quarter_slice] if len(quarter_slice) else team_game_level.head(0)
                quarter_ppg.append(round(float(quarter_games['PTS'].mean()), 1) if not quarter_games.empty else 0)
                quarter_win_pct.append(round(float(quarter_games['Result'].astype(str).str.startswith('W').mean() * 100), 1) if not quarter_games.empty else 0)
        else:
            quarter_ppg = [0, 0, 0, 0]
            quarter_win_pct = [0, 0, 0, 0]

        all_profile_rows.append({
            'team': team,
            'wins': record['wins'],
            'losses': record['losses'],
            'win_pct': round(record['win_pct'] * 100, 1),
            'home_record': f"{record['home_wins']}-{record['home_losses']}",
            'away_record': f"{record['away_wins']}-{record['away_losses']}",
            'last_5': f"{record['last_5_wins']}-" + str(max(0, 5 - record['last_5_wins'])),
            'home_ppg': record['home_ppg'],
            'away_ppg': record['away_ppg'],
            'ppg_split': round(record['home_ppg'] - record['away_ppg'], 1),
            'top_scorer': top_scorer,
            'top_scorer_ppg': top_scorer_ppg,
            'last10_ppg': last10_ppg,
            'q1_ppg': quarter_ppg[0],
            'q2_ppg': quarter_ppg[1],
            'q3_ppg': quarter_ppg[2],
            'q4_ppg': quarter_ppg[3],
            'q1_win_pct': quarter_win_pct[0],
            'q4_win_pct': quarter_win_pct[3],
            'trend_ppg': round(quarter_ppg[3] - quarter_ppg[0], 1),
            'trend_win_pct': round(quarter_win_pct[3] - quarter_win_pct[0], 1),
            'is_playoff_team': team in POSTSEASON_TEAMS
        })

    review['all_team_profiles'] = sorted(all_profile_rows, key=lambda x: (x['win_pct'], x['wins']), reverse=True)
    review['playoff_team_profiles'] = [row for row in review['all_team_profiles'] if row['is_playoff_team']]
    review['quarter_trend_leaders'] = {
        'surging': sorted(review['all_team_profiles'], key=lambda x: (x['trend_ppg'], x['trend_win_pct']), reverse=True)[:6],
        'slipping': sorted(review['all_team_profiles'], key=lambda x: (x['trend_ppg'], x['trend_win_pct']))[:6]
    }

    playoff_history = load_playoff_history()
    if not playoff_history.empty and 'Team' in playoff_history.columns:
        history_rows = []
        profile_lookup = {row['team']: row for row in review['all_team_profiles']}
        for _, row in playoff_history.iterrows():
            team = str(row.get('Team', '')).strip().upper()
            if not team:
                continue
            profile = profile_lookup.get(team, {})
            history_rows.append({
                'team': team,
                'playoff_apps': int(pd.to_numeric(row.get('PlayoffApps', 0), errors='coerce') or 0),
                'playoff_wins': int(pd.to_numeric(row.get('PlayoffWins', 0), errors='coerce') or 0),
                'playoff_losses': int(pd.to_numeric(row.get('PlayoffLosses', 0), errors='coerce') or 0),
                'finals_apps': int(pd.to_numeric(row.get('FinalsApps', 0), errors='coerce') or 0),
                'titles': int(pd.to_numeric(row.get('Titles', 0), errors='coerce') or 0),
                'last_title': str(row.get('LastTitle', '') or '-'),
                'is_playoff_team': team in POSTSEASON_TEAMS,
                'win_pct': profile.get('win_pct', 0)
            })
        review['playoff_history'] = sorted(history_rows, key=lambda x: (x['titles'], x['playoff_apps'], x['playoff_wins']), reverse=True)

    playoff_games = team_games[team_games['Team'].isin(POSTSEASON_TEAMS)].copy()
    if not playoff_games.empty:
        team_summary = (
            playoff_games.groupby('Team', as_index=False)
            .agg(
                games=('Game_ID', 'nunique'),
                wins=('won', 'sum'),
                ppg=('PTS', 'mean')
            )
        )
        home_summary = (
            playoff_games[playoff_games['site'] == 'home']
            .groupby('Team', as_index=False)
            .agg(home_games=('Game_ID', 'nunique'), home_wins=('won', 'sum'), home_ppg=('PTS', 'mean'))
        )
        away_summary = (
            playoff_games[playoff_games['site'] == 'away']
            .groupby('Team', as_index=False)
            .agg(away_games=('Game_ID', 'nunique'), away_wins=('won', 'sum'), away_ppg=('PTS', 'mean'))
        )
        playoff_edges = team_summary.merge(home_summary, on='Team', how='left').merge(away_summary, on='Team', how='left').fillna(0)
        playoff_edges['home_win_pct'] = np.where(playoff_edges['home_games'] > 0, playoff_edges['home_wins'] / playoff_edges['home_games'] * 100, 0)
        playoff_edges['away_win_pct'] = np.where(playoff_edges['away_games'] > 0, playoff_edges['away_wins'] / playoff_edges['away_games'] * 100, 0)
        playoff_edges['home_edge'] = playoff_edges['home_win_pct'] - playoff_edges['away_win_pct']
        playoff_edges['ppg_split'] = playoff_edges['home_ppg'] - playoff_edges['away_ppg']
        review['playoff_edges'] = playoff_edges.sort_values(['home_edge', 'home_win_pct'], ascending=False).head(8).to_dict('records')
    stat_thresholds = {'PTS': 12, 'REB': 5, 'AST': 4, '3PM': 1.5}
    adv_lookup = {}
    if not player_advanced.empty and 'Player' in player_advanced.columns:
        adv_lookup = player_advanced.set_index('Player').to_dict('index')

    playoff_logs = logs[logs['Team'].isin(POSTSEASON_TEAMS)].copy()
    for stat in ['PTS', 'REB', 'AST', '3PM']:
        stat_rows = []
        if stat not in playoff_logs.columns:
            continue
        for (player, team), player_logs in playoff_logs.groupby(['Player', 'Team']):
            valid = player_logs[player_logs[stat].notna()].sort_values('Date')
            if len(valid) < 25:
                continue
            avg = float(valid[stat].mean())
            if avg < stat_thresholds[stat]:
                continue
            floor_line = avg * 0.8
            hit_rate = (valid[stat] >= floor_line).mean() * 100
            last10 = valid.tail(10)[stat].mean() if len(valid) >= 10 else valid[stat].mean()
            stat_rows.append({
                'player': player,
                'team': team,
                'avg': round(avg, 1),
                'floor_line': round(floor_line, 1),
                'hit_rate': round(hit_rate, 1),
                'games': int(len(valid)),
                'last10': round(last10, 1)
            })
        review['stable_leaders'][stat] = sorted(stat_rows, key=lambda x: (x['hit_rate'], x['avg']), reverse=True)[:6]

    role_risers = []
    if 'MIN' in playoff_logs.columns:
        for (player, team), player_logs in playoff_logs.groupby(['Player', 'Team']):
            valid = player_logs[player_logs['MIN'].notna()].sort_values('Date')
            if len(valid) < 15:
                continue
            season_min = float(valid['MIN'].mean())
            last10_min = float(valid.tail(10)['MIN'].mean()) if len(valid) >= 10 else season_min
            min_jump = last10_min - season_min
            if min_jump < 2.5:
                continue
            season_pts = float(valid['PTS'].mean()) if 'PTS' in valid.columns else 0
            last10_pts = float(valid.tail(10)['PTS'].mean()) if 'PTS' in valid.columns and len(valid) >= 10 else season_pts
            advanced = adv_lookup.get(player, {})
            role_risers.append({
                'player': player,
                'team': team,
                'season_min': round(season_min, 1),
                'last10_min': round(last10_min, 1),
                'min_jump': round(min_jump, 1),
                'season_pts': round(season_pts, 1),
                'last10_pts': round(last10_pts, 1),
                'usg_pct': round(float(advanced.get('USG_PCT', 0)) * 100, 1) if advanced.get('USG_PCT') is not None else None,
                'net_rating': round(float(advanced.get('NET_RATING', 0)), 1) if advanced.get('NET_RATING') is not None else None
            })
    review['role_risers'] = sorted(role_risers, key=lambda x: (x['min_jump'], x['last10_pts']), reverse=True)[:10]

    opponent_totals = team_games.rename(columns={
        'Team': 'defense_team',
        'Opp': 'offense_team',
        'PTS': 'points_scored',
        'REB': 'reb_scored',
        'AST': 'ast_scored',
        '3PM': 'threes_scored'
    })
    defense_matchups = team_games[['Game_ID', 'Team']].merge(opponent_totals, left_on=['Game_ID', 'Team'], right_on=['Game_ID', 'offense_team'], how='left')
    defense_matchups = defense_matchups[defense_matchups['defense_team'].isin(POSTSEASON_TEAMS)]
    for stat, source_col in [('PTS', 'points_scored'), ('REB', 'reb_scored'), ('AST', 'ast_scored'), ('3PM', 'threes_scored')]:
        if source_col not in defense_matchups.columns:
            continue
        summary = (
            defense_matchups.groupby('defense_team', as_index=False)
            .agg(games=('Game_ID', 'nunique'), allowed=(source_col, 'mean'))
            .rename(columns={'defense_team': 'team'})
            .sort_values('allowed')
            .head(6)
        )
        review['defense_trends'][stat] = [
            {'team': row['team'], 'allowed': round(row['allowed'], 1), 'games': int(row['games'])}
            for _, row in summary.iterrows()
        ]

    insights = []
    snapshot = review['snapshot']
    if snapshot.get('home_win_rate'):
        insights.append(f"Home teams won {snapshot['home_win_rate']}% of games, so venue should stay in the playoff model.")
    if review['playoff_edges']:
        top_home = review['playoff_edges'][0]
        insights.append(f"{top_home['Team']} had the strongest home-court edge among playoff teams at +{top_home['home_edge']:.1f} win-rate points.")
    if review['stable_leaders']['PTS']:
        top_floor = review['stable_leaders']['PTS'][0]
        insights.append(f"{top_floor['player']} ({top_floor['team']}) delivered the steadiest points floor, clearing 80% of his average in {top_floor['hit_rate']}% of games.")
    if review['role_risers']:
        top_riser = review['role_risers'][0]
        insights.append(f"{top_riser['player']} closed the season with a {top_riser['min_jump']}-minute role jump, the kind of signal worth carrying into playoff props and next year.")
    if review['defense_trends']['3PM']:
        threes_def = review['defense_trends']['3PM'][0]
        insights.append(f"{threes_def['team']} were the stingiest playoff-team defense against 3PM, allowing only {threes_def['allowed']} makes per game.")
    review['insights'] = insights
    return review


def build_team_season_review(team, gamelogs, player_advanced, current_team_map=None):
    if gamelogs.empty or 'Team' not in gamelogs.columns:
        return None
    team_logs = gamelogs[gamelogs['Team'] == team].copy()
    if team_logs.empty:
        return None

    for col in ['PTS', 'REB', 'AST', '3PM', 'MIN']:
        if col in team_logs.columns:
            team_logs[col] = pd.to_numeric(team_logs[col], errors='coerce')
    if 'Date' in team_logs.columns:
        team_logs['Date'] = pd.to_datetime(team_logs['Date'], errors='coerce')
        team_logs = team_logs.sort_values('Date')

    record = get_team_record(gamelogs, team)
    game_level = (
        team_logs.groupby('Game_ID', as_index=False)
        .agg({
            'Date': 'first',
            'Opp': 'first',
            'Matchup': 'first',
            'Result': 'first',
            'PTS': 'sum',
            'REB': 'sum',
            'AST': 'sum',
            '3PM': 'sum'
        })
        .sort_values('Date')
    )
    game_level['site'] = np.where(
        game_level['Matchup'].astype(str).str.contains('vs.', regex=False, na=False),
        'home',
        'away'
    )

    season_averages = {
        'PTS': round(game_level['PTS'].mean(), 1) if 'PTS' in game_level.columns else 0,
        'REB': round(game_level['REB'].mean(), 1) if 'REB' in game_level.columns else 0,
        'AST': round(game_level['AST'].mean(), 1) if 'AST' in game_level.columns else 0,
        '3PM': round(game_level['3PM'].mean(), 1) if '3PM' in game_level.columns else 0,
    }

    last10_games = game_level.tail(10)
    recent_averages = {
        'PTS': round(last10_games['PTS'].mean(), 1) if not last10_games.empty else 0,
        'REB': round(last10_games['REB'].mean(), 1) if not last10_games.empty else 0,
        'AST': round(last10_games['AST'].mean(), 1) if not last10_games.empty else 0,
        '3PM': round(last10_games['3PM'].mean(), 1) if not last10_games.empty else 0,
    }

    home_games = game_level[game_level['site'] == 'home']
    away_games = game_level[game_level['site'] == 'away']
    split_summary = {
        'home_ppg': round(home_games['PTS'].mean(), 1) if not home_games.empty else 0,
        'away_ppg': round(away_games['PTS'].mean(), 1) if not away_games.empty else 0,
        'home_reb': round(home_games['REB'].mean(), 1) if not home_games.empty else 0,
        'away_reb': round(away_games['REB'].mean(), 1) if not away_games.empty else 0,
        'home_ast': round(home_games['AST'].mean(), 1) if not home_games.empty else 0,
        'away_ast': round(away_games['AST'].mean(), 1) if not away_games.empty else 0,
    }

    adv_lookup = {}
    if not player_advanced.empty and 'Player' in player_advanced.columns:
        adv_lookup = player_advanced.set_index('Player').to_dict('index')

    core_rotation = []
    stable_floor = []
    role_risers = []
    team_angles = []
    roster_logs = team_logs
    if current_team_map:
        current_players = [player for player, current_team in current_team_map.items() if current_team == team]
        if current_players:
            roster_logs = gamelogs[gamelogs['Player'].isin(current_players)].copy()
            if 'Date' in roster_logs.columns:
                roster_logs['Date'] = pd.to_datetime(roster_logs['Date'], errors='coerce')
    for player, player_logs in roster_logs.groupby('Player'):
        player_logs = player_logs.sort_values('Date')
        games = len(player_logs)
        if games < 8:
            continue
        avg_min = round(float(player_logs['MIN'].mean()), 1) if 'MIN' in player_logs.columns else 0
        avg_pts = round(float(player_logs['PTS'].mean()), 1) if 'PTS' in player_logs.columns else 0
        avg_reb = round(float(player_logs['REB'].mean()), 1) if 'REB' in player_logs.columns else 0
        avg_ast = round(float(player_logs['AST'].mean()), 1) if 'AST' in player_logs.columns else 0
        avg_3pm = round(float(player_logs['3PM'].mean()), 1) if '3PM' in player_logs.columns else 0
        advanced = adv_lookup.get(player, {})
        core_rotation.append({
            'player': player,
            'games': games,
            'min': avg_min,
            'pts': avg_pts,
            'reb': avg_reb,
            'ast': avg_ast,
            '3pm': avg_3pm,
            'usg_pct': round(float(advanced.get('USG_PCT', 0)) * 100, 1) if advanced.get('USG_PCT') is not None else None
        })

        if games >= 15:
            for stat, min_avg in [('PTS', 8), ('REB', 4), ('AST', 3), ('3PM', 1.2)]:
                if stat not in player_logs.columns:
                    continue
                avg = float(player_logs[stat].mean())
                if avg < min_avg:
                    continue
                floor_line = avg * 0.8
                hit_rate = (player_logs[stat] >= floor_line).mean() * 100
                stable_floor.append({
                    'player': player,
                    'stat': stat,
                    'avg': round(avg, 1),
                    'floor_line': round(floor_line, 1),
                    'hit_rate': round(hit_rate, 1)
                })
                if hit_rate >= 74:
                    last10_avg = float(player_logs.tail(10)[stat].mean()) if len(player_logs) >= 10 else avg
                    team_angles.append({
                        'player': player,
                        'stat': stat,
                        'angle': f"{player} {stat} floor",
                        'hit_rate': round(hit_rate, 1),
                        'floor_line': round(floor_line, 1),
                        'avg': round(avg, 1),
                        'trend_delta': round(last10_avg - avg, 1),
                        'label': 'Hot floor' if last10_avg >= avg else 'Stable floor'
                    })

        if games >= 15 and 'MIN' in player_logs.columns:
            season_min = float(player_logs['MIN'].mean())
            last10_min = float(player_logs.tail(10)['MIN'].mean())
            min_jump = last10_min - season_min
            if min_jump >= 2:
                role_risers.append({
                    'player': player,
                    'season_min': round(season_min, 1),
                    'last10_min': round(last10_min, 1),
                    'min_jump': round(min_jump, 1),
                    'last10_pts': round(float(player_logs.tail(10)['PTS'].mean()), 1) if 'PTS' in player_logs.columns else 0
                })

    core_rotation = sorted(core_rotation, key=lambda x: (x['min'], x['pts']), reverse=True)[:10]
    stable_floor = sorted(stable_floor, key=lambda x: (x['hit_rate'], x['avg']), reverse=True)[:12]
    role_risers = sorted(role_risers, key=lambda x: (x['min_jump'], x['last10_pts']), reverse=True)[:6]
    team_angles = sorted(team_angles, key=lambda x: (x['hit_rate'], x['trend_delta'], x['avg']), reverse=True)[:8]

    best_offense = []
    for stat in ['PTS', 'REB', 'AST', '3PM']:
        leader = max(core_rotation, key=lambda x: x[stat.lower() if stat != 'PTS' else 'pts'], default=None)
        if leader:
            best_offense.append({
                'stat': stat,
                'player': leader['player'],
                'value': leader[stat.lower() if stat != 'PTS' else 'pts']
            })

    return {
        'team': team,
        'record': record,
        'season_averages': season_averages,
        'recent_averages': recent_averages,
        'split_summary': split_summary,
        'game_log_tail': game_level.sort_values('Date', ascending=False).head(10).to_dict('records'),
        'core_rotation': core_rotation,
        'stable_floor': stable_floor,
        'team_angles': team_angles,
        'role_risers': role_risers,
        'best_offense': best_offense
    }


def build_formula_backtest(gamelogs, player_snapshot=None, max_slates=None):
    summary = {
        'tested_slates': 0,
        'candidate_props': 0,
        'tier1_props': 0,
        'tier1_win_rate': 0,
        'anchor_slates': 0,
        'anchor_hits': 0,
        'anchor_hit_rate': 0,
        'rr_pair_legs': 0,
        'rr_pair_hits': 0,
        'rr_pair_hit_rate': 0,
        'best_stat': None,
        'worst_stat': None,
        'baseline': {},
        'snapshot_model': {},
        'lift': {},
        'stat_comparison': [],
        'team_comparison': []
    }
    if gamelogs.empty or 'Date' not in gamelogs.columns or 'Player' not in gamelogs.columns:
        return summary

    logs = gamelogs.copy()
    logs['Date'] = pd.to_datetime(logs['Date'], errors='coerce')
    logs = logs.dropna(subset=['Date']).sort_values('Date')
    for col in ['PTS', 'REB', 'AST', '3PM', 'MIN']:
        if col in logs.columns:
            logs[col] = pd.to_numeric(logs[col], errors='coerce')

    stat_results = {
        'baseline': {stat: {'wins': 0, 'total': 0} for stat in ['PTS', 'REB', 'AST', '3PM']},
        'snapshot': {stat: {'wins': 0, 'total': 0} for stat in ['PTS', 'REB', 'AST', '3PM']}
    }
    team_results = {'baseline': {}, 'snapshot': {}}
    slate_dates = sorted(logs['Date'].dt.normalize().unique())
    if max_slates:
        slate_dates = slate_dates[-max(int(max_slates), 1):]
    baseline_slates = []
    snapshot_slates = []

    def summarize_slates(tested_slates, stat_bucket):
        result = {
            'tested_slates': len(tested_slates),
            'candidate_props': sum(len(slate['ranked']) for slate in tested_slates),
            'tier1_props': 0,
            'tier1_win_rate': 0,
            'anchor_slates': 0,
            'anchor_hits': 0,
            'anchor_hit_rate': 0,
            'rr_pair_legs': 0,
            'rr_pair_hits': 0,
            'rr_pair_hit_rate': 0,
            'best_stat': None,
            'worst_stat': None
        }
        tier1_props = [prop for slate in tested_slates for prop in slate['ranked'] if prop['tier'] == 'Tier 1']
        result['tier1_props'] = len(tier1_props)
        if tier1_props:
            result['tier1_win_rate'] = round(sum(1 for prop in tier1_props if prop['hit']) / len(tier1_props) * 100, 1)

        anchor_slates = [slate for slate in tested_slates if len(slate['anchor']) >= 4]
        result['anchor_slates'] = len(anchor_slates)
        if anchor_slates:
            anchor_hits = sum(1 for slate in anchor_slates if all(prop['hit'] for prop in slate['anchor'][:4]))
            result['anchor_hits'] = anchor_hits
            result['anchor_hit_rate'] = round(anchor_hits / len(anchor_slates) * 100, 1)

        rr_pair_results = []
        for slate in tested_slates:
            pool = slate['rr_pool'][:5]
            for i in range(len(pool)):
                for j in range(i + 1, len(pool)):
                    rr_pair_results.append(pool[i]['hit'] and pool[j]['hit'])
        result['rr_pair_legs'] = len(rr_pair_results)
        result['rr_pair_hits'] = int(sum(rr_pair_results))
        if rr_pair_results:
            result['rr_pair_hit_rate'] = round(sum(rr_pair_results) / len(rr_pair_results) * 100, 1)

        stat_rates = []
        for stat, stat_result in stat_bucket.items():
            if stat_result['total'] > 0:
                stat_rates.append({
                    'stat': stat,
                    'hit_rate': round(stat_result['wins'] / stat_result['total'] * 100, 1),
                    'total': stat_result['total']
                })
        if stat_rates:
            result['best_stat'] = max(stat_rates, key=lambda x: x['hit_rate'])
            result['worst_stat'] = min(stat_rates, key=lambda x: x['hit_rate'])
        return result

    def update_bucket(bucket, key, hit):
        if key not in bucket:
            bucket[key] = {'wins': 0, 'total': 0}
        bucket[key]['total'] += 1
        if hit:
            bucket[key]['wins'] += 1

    def compare_buckets(base_bucket, snapshot_bucket, min_total=1):
        comparison = []
        keys = sorted(set(base_bucket.keys()) | set(snapshot_bucket.keys()))
        for key in keys:
            base_total = base_bucket.get(key, {}).get('total', 0)
            snap_total = snapshot_bucket.get(key, {}).get('total', 0)
            if max(base_total, snap_total) < min_total:
                continue
            base_hit_rate = round(base_bucket.get(key, {}).get('wins', 0) / base_total * 100, 1) if base_total else 0
            snap_hit_rate = round(snapshot_bucket.get(key, {}).get('wins', 0) / snap_total * 100, 1) if snap_total else 0
            comparison.append({
                'key': key,
                'baseline_total': base_total,
                'snapshot_total': snap_total,
                'baseline_hit_rate': base_hit_rate,
                'snapshot_hit_rate': snap_hit_rate,
                'lift': round(snap_hit_rate - base_hit_rate, 1)
            })
        return comparison

    for slate_date in slate_dates:
        slate_logs = logs[logs['Date'].dt.normalize() == slate_date]
        if slate_logs.empty:
            continue
        baseline_available = []
        snapshot_available = []
        for _, game_row in slate_logs.iterrows():
            player = game_row.get('Player')
            team = game_row.get('Team')
            opponent = game_row.get('Opp')
            if not player or not team:
                continue
            player_history = logs[(logs['Player'] == player) & (logs['Date'] < slate_date)].copy()
            if len(player_history) < 10:
                continue
            player_history = player_history.sort_values('Date', ascending=False)
            pressure = get_player_pressure_profile(player_history)
            for stat in ['PTS', 'REB', 'AST', '3PM']:
                if stat not in player_history.columns or stat not in slate_logs.columns:
                    continue
                valid = player_history[player_history[stat].notna()].sort_values('Date', ascending=False)
                if len(valid) < 10:
                    continue
                avg = float(valid[stat].mean())
                if avg < MIN_AVG_FOR_PROPS.get(stat, 1):
                    continue
                line = round(avg * FLOOR_MULTIPLIERS.get(stat, 0.75) * 2) / 2
                ou_rates = calculate_over_under_rates(valid, stat, line)
                result_value = pd.to_numeric(game_row.get(stat), errors='coerce')
                if pd.isna(result_value):
                    continue
                hit = bool(result_value > line)
                base_best_play = get_best_play(ou_rates['over'], ou_rates['under'], 0, 0, line, avg)
                if base_best_play['direction'] == 'OVER' and base_best_play['confidence'] >= 68:
                    projected_minutes = round(float(valid['MIN'].head(10).mean()), 1) if 'MIN' in valid.columns else 0
                    base_prop = {
                        'player': player,
                        'team': team,
                        'stat': stat,
                        'line': line,
                        'avg': round(avg, 1),
                        'direction': 'OVER',
                        'confidence': base_best_play['confidence'],
                        'weighted_over_rate': ou_rates['over'],
                        'weighted_under_rate': ou_rates['under'],
                        'over_rate': ou_rates['over'],
                        'under_rate': ou_rates['under'],
                        'projected_minutes': projected_minutes,
                        'situations': pressure['tags'],
                        'edge_pct': round(max(0, ou_rates['over'] - 50), 1),
                        'ev_pct': round(max(0, ou_rates['over'] - 52) * 0.5, 1),
                        'matchup': f"{team} vs {opponent}" if opponent else team,
                        'hit': hit
                    }
                    base_prop['strategy_score'] = score_floor_parlay_candidate(base_prop)
                    base_prop['tier'] = classify_floor_parlay_tier(base_prop)
                    baseline_available.append(base_prop)
                    stat_results['baseline'][stat]['total'] += 1
                    update_bucket(team_results['baseline'], team, hit)
                    if hit:
                        stat_results['baseline'][stat]['wins'] += 1

                projection_context = get_player_projection_context(
                    player, team, stat, valid, pd.DataFrame(), None, player_snapshot
                )
                projection_adjustments = get_projection_adjustments(projection_context, stat)
                snapshot_best_play = get_best_play(
                    ou_rates['over'],
                    ou_rates['under'],
                    projection_adjustments['under_boost'],
                    projection_adjustments['over_boost'],
                    line,
                    avg
                )
                if snapshot_best_play['direction'] != 'OVER' or snapshot_best_play['confidence'] < 68:
                    continue
                snapshot_prop = {
                    'player': player,
                    'team': team,
                    'stat': stat,
                    'line': line,
                    'avg': round(avg, 1),
                    'direction': 'OVER',
                    'confidence': snapshot_best_play['confidence'],
                    'weighted_over_rate': ou_rates['over'],
                    'weighted_under_rate': ou_rates['under'],
                    'over_rate': ou_rates['over'],
                    'under_rate': ou_rates['under'],
                    'projected_minutes': projection_context.get('projected_minutes') or round(float(valid['MIN'].head(10).mean()), 1) if 'MIN' in valid.columns else 0,
                    'situations': list(dict.fromkeys(pressure['tags'] + projection_adjustments['tags'])),
                    'edge_pct': round(max(0, ou_rates['over'] - 50) + max(0, projection_adjustments['over_boost'] - projection_adjustments['under_boost']) * 0.8, 1),
                    'ev_pct': round(max(0, ou_rates['over'] - 52) * 0.5 + max(0, projection_adjustments['over_boost'] - projection_adjustments['under_boost']) * 0.35, 1),
                    'matchup': f"{team} vs {opponent}" if opponent else team,
                    'hit': hit,
                    'snapshot_consistency': projection_context.get('snapshot_consistency'),
                    'snapshot_tier': projection_context.get('snapshot_tier'),
                    'snapshot_load_label': projection_context.get('snapshot_load_label'),
                    'snapshot_signal': projection_context.get('snapshot_signal'),
                    'snapshot_stat_trend': projection_context.get('snapshot_stat_trend')
                }
                snapshot_prop['strategy_score'] = score_floor_parlay_candidate(snapshot_prop)
                snapshot_prop['tier'] = classify_floor_parlay_tier(snapshot_prop)
                snapshot_available.append(snapshot_prop)
                stat_results['snapshot'][stat]['total'] += 1
                update_bucket(team_results['snapshot'], team, hit)
                if hit:
                    stat_results['snapshot'][stat]['wins'] += 1

        if baseline_available:
            strategy = build_floor_parlay_plan(baseline_available)
            baseline_slates.append({
                'date': str(pd.Timestamp(slate_date).date()),
                'available': baseline_available,
                'ranked': strategy['ranked'],
                'anchor': strategy['anchor'],
                'rr_pool': strategy['rr_pool']
            })
        if snapshot_available:
            strategy = build_floor_parlay_plan(snapshot_available)
            snapshot_slates.append({
                'date': str(pd.Timestamp(slate_date).date()),
                'available': snapshot_available,
                'ranked': strategy['ranked'],
                'anchor': strategy['anchor'],
                'rr_pool': strategy['rr_pool']
            })

    baseline_summary = summarize_slates(baseline_slates, stat_results['baseline'])
    snapshot_summary = summarize_slates(snapshot_slates, stat_results['snapshot'])

    summary.update(snapshot_summary)
    summary['baseline'] = baseline_summary
    summary['snapshot_model'] = snapshot_summary
    summary['lift'] = {
        'tier1_win_rate': round(snapshot_summary['tier1_win_rate'] - baseline_summary['tier1_win_rate'], 1),
        'anchor_hit_rate': round(snapshot_summary['anchor_hit_rate'] - baseline_summary['anchor_hit_rate'], 1),
        'rr_pair_hit_rate': round(snapshot_summary['rr_pair_hit_rate'] - baseline_summary['rr_pair_hit_rate'], 1),
        'tier1_props': snapshot_summary['tier1_props'] - baseline_summary['tier1_props']
    }
    stat_comparison = compare_buckets(stat_results['baseline'], stat_results['snapshot'])
    team_comparison = compare_buckets(team_results['baseline'], team_results['snapshot'], min_total=25)
    for row in stat_comparison:
        row['stat'] = row.pop('key')
    for row in team_comparison:
        row['team'] = row.pop('key')
        row['is_playoff_team'] = row['team'] in POSTSEASON_TEAMS
    summary['stat_comparison'] = sorted(stat_comparison, key=lambda x: (x['lift'], x['snapshot_hit_rate']), reverse=True)
    summary['team_comparison'] = sorted(team_comparison, key=lambda x: (x['lift'], x['snapshot_hit_rate']), reverse=True)

    return summary


def build_cached_season_review(max_backtest_slates=3, force_refresh=False):
    version = _build_file_token(
        DATA_DIR / 'gamelogs' / 'NBA_GameLogs.csv',
        DATA_DIR / 'tracking' / 'NBA_PlayerAdvanced.csv',
        DATA_DIR / 'tracking' / 'NBA_PlayerSnapshot.csv',
        DATA_DIR / 'tracking' / 'NBA_Playoff_History.csv',
    ) + (int(max_backtest_slates or 0),)

    def _build():
        gamelogs = load_gamelogs()
        player_advanced = load_player_advanced()
        player_snapshot = load_player_snapshot()
        review = build_season_review(gamelogs, player_advanced)
        review['formula_backtest'] = build_formula_backtest(
            gamelogs,
            player_snapshot,
            max_slates=max_backtest_slates,
        )
        return review

    if force_refresh:
        return _build()
    return _get_disk_ttl_cached_value(
        'nba_season_review_page_v2',
        ttl_seconds=12 * 60 * 60,
        builder=_build,
        version=version,
    )


def normalize_props_market_data(df):
    df = df.rename(columns={k: v for k, v in PROP_COLUMN_ALIASES.items() if k in df.columns}).copy()

    for column in ['Line', 'OpenLine', 'CurrentLine', 'CloseLine', 'BetLine']:
        if column in df.columns:
            df[column] = pd.to_numeric(df[column], errors='coerce')

    for column in [
        'OpenOverOdds', 'OpenUnderOdds', 'OverOdds', 'UnderOdds',
        'CloseOverOdds', 'CloseUnderOdds', 'BetOverOdds', 'BetUnderOdds'
    ]:
        if column in df.columns:
            df[column] = pd.to_numeric(df[column], errors='coerce')

    if 'CurrentLine' not in df.columns and 'Line' in df.columns:
        df['CurrentLine'] = df['Line']
    if 'Line' not in df.columns and 'CurrentLine' in df.columns:
        df['Line'] = df['CurrentLine']

    for column in PROP_MARKET_COLUMNS:
        if column not in df.columns:
            df[column] = np.nan

    if 'Book' in df.columns:
        df['Book'] = df['Book'].fillna('Manual')

    return df

def generate_props_from_gamelogs():
    """Generate props from game logs - includes all stat categories"""
    gamelogs = load_gamelogs()
    if gamelogs.empty:
        return pd.DataFrame()
    props = []
    player_games = gamelogs.groupby('Player').size()
    qualified = player_games[player_games >= 10].index.tolist()
    
    for player in qualified:
        player_logs = gamelogs[gamelogs['Player'] == player]
        team = player_logs.iloc[0]['Team'] if 'Team' in player_logs.columns else ''
        
        # Generate props for all stat types
        for stat in ['PTS', 'REB', 'AST', '3PM', 'STL', 'BLK']:
            if stat not in player_logs.columns:
                continue
            avg = player_logs[stat].mean()
            if pd.isna(avg):
                continue
            
            # Use stat-specific minimums
            min_avg = MIN_AVG_FOR_PROPS.get(stat, 1)
            if avg < min_avg:
                continue
            
            # Calculate line based on floor multiplier
            multiplier = FLOOR_MULTIPLIERS.get(stat, 0.75)
            line = round(avg * multiplier * 2) / 2  # Round to nearest 0.5
            
            # Minimum line of 0.5
            if line >= 0.5:
                props.append({'Player': player, 'Team': team, 'Stat': stat, 'Line': line})
    
    return pd.DataFrame(props)

def load_injuries():
    """Load current injury report"""
    path = DATA_DIR / 'injuries' / 'NBA_Injuries.csv'
    manual_path = DATA_DIR / 'injuries' / 'NBA_Injuries_Manual.csv'
    frames = []
    if path.exists():
        frames.append(_load_cached_csv(path))
    if manual_path.exists():
        manual = _load_cached_csv(manual_path).copy()
        for col in ['Player', 'Team', 'Status', 'Reason', 'Updated', 'Active', 'ExpiresOn']:
            if col not in manual.columns:
                manual[col] = ''
        for col in ['Player', 'Team', 'Status', 'Reason', 'Updated', 'Active', 'ExpiresOn']:
            manual[col] = manual[col].fillna('').astype(str).str.strip()
        if not manual.empty:
            now = pd.Timestamp.now()
            updated_dt = pd.to_datetime(manual['Updated'], errors='coerce')
            expires_dt = pd.to_datetime(manual['ExpiresOn'], errors='coerce')
            active_flag = manual['Active'].str.lower().isin({'1', 'true', 'yes', 'y', 'active'})
            recent_flag = updated_dt >= (now - pd.Timedelta(days=3))
            unexpired_flag = expires_dt.isna() | (expires_dt >= now.normalize())
            manual = manual[unexpired_flag & (active_flag | recent_flag)].copy()
        if not manual.empty:
            frames.append(manual)
    if not frames:
        return pd.DataFrame()

    injuries = pd.concat(frames, ignore_index=True)
    required_cols = ['Player', 'Team', 'Status', 'Reason', 'Updated']
    for col in required_cols:
        if col not in injuries.columns:
            injuries[col] = ''
    injuries['Player'] = injuries['Player'].fillna('').astype(str).str.strip()
    injuries['Team'] = injuries['Team'].fillna('').astype(str).str.strip()
    injuries['Status'] = injuries['Status'].fillna('').astype(str).str.strip().str.upper()
    injuries['Reason'] = injuries['Reason'].fillna('').astype(str).str.strip()
    injuries['Updated'] = injuries['Updated'].fillna('').astype(str).str.strip()
    injuries = injuries[injuries['Player'] != ''].copy()
    injuries = injuries.drop_duplicates(subset=['Player'], keep='last').reset_index(drop=True)
    return injuries


def load_sport_injuries(sport_key='nba'):
    sport_key = str(sport_key or 'nba').strip().lower()
    if sport_key == 'nba':
        return load_injuries()

    sport_prefix = {
        'wnba': 'WNBA',
        'nfl': 'NFL',
        'cfb': 'NCAAF',
        'ncaaf': 'NCAAF',
        'mlb': 'MLB',
    }.get(sport_key, sport_key.upper())
    path = DATA_DIR / 'injuries' / f'{sport_prefix}_Injuries.csv'
    manual_path = DATA_DIR / 'injuries' / f'{sport_prefix}_Injuries_Manual.csv'
    frames = []
    for candidate in [path, manual_path]:
        if candidate.exists():
            try:
                frame = _load_cached_csv(candidate, default=pd.DataFrame())
            except Exception:
                frame = pd.DataFrame()
            if frame is not None and not frame.empty:
                frames.append(frame)
    if not frames:
        return pd.DataFrame(columns=['Player', 'Team', 'Status', 'Reason', 'Updated'])

    injuries = pd.concat(frames, ignore_index=True)
    for col in ['Player', 'Team', 'Status', 'Reason', 'Updated']:
        if col not in injuries.columns:
            injuries[col] = ''
    injuries['Player'] = injuries['Player'].fillna('').astype(str).str.strip()
    injuries['Team'] = injuries['Team'].fillna('').astype(str).str.strip()
    injuries['Status'] = injuries['Status'].fillna('').astype(str).str.strip().str.upper()
    injuries['Reason'] = injuries['Reason'].fillna('').astype(str).str.strip()
    injuries['Updated'] = injuries['Updated'].fillna('').astype(str).str.strip()
    injuries = injuries[injuries['Player'] != ''].copy()
    injuries = injuries.drop_duplicates(subset=['Player'], keep='last').reset_index(drop=True)
    return injuries


def build_injury_status_lookup(injuries_df=None):
    injuries_df = injuries_df if injuries_df is not None else load_injuries()
    if injuries_df is None or injuries_df.empty or 'Player' not in injuries_df.columns:
        return {}

    lookup = {}
    working = injuries_df.copy()
    for _, row in working.iterrows():
        player = str(row.get('Player') or '').strip()
        if not player:
            continue
        status = str(row.get('Status') or '').strip().upper()
        reason = str(row.get('Reason') or '').strip()
        updated = str(row.get('Updated') or '').strip()
        team = str(row.get('Team') or '').strip()
        short_label = {
            'QUESTIONABLE': 'GTD',
            'GTD': 'GTD',
            'DOUBTFUL': 'DOUBT',
            'OUT': 'OUT',
            'PROBABLE': 'PROB',
            'AVAILABLE': 'AVAIL',
        }.get(status, status or 'MED')
        severity = 'info'
        if status in {'OUT', 'DOUBTFUL'}:
            severity = 'high'
        elif status in {'QUESTIONABLE', 'GTD'}:
            severity = 'medium'
        elif status in {'PROBABLE'}:
            severity = 'low'
        payload = {
            'player': player,
            'team': team,
            'status': status,
            'short_label': short_label,
            'reason': reason,
            'updated': updated,
            'severity': severity,
        }
        lookup[player] = payload
        normalized = normalize_player_lookup_name(player)
        if normalized:
            lookup[normalized] = payload
        if ',' in player:
            last, first = [part.strip() for part in player.split(',', 1)]
            alt_name = f'{first} {last}'.strip()
            if alt_name:
                lookup[alt_name] = payload
                alt_normalized = normalize_player_lookup_name(alt_name)
                if alt_normalized:
                    lookup[alt_normalized] = payload
    return lookup


def annotate_prop_rows_with_injuries(rows, injuries_df=None):
    if not rows:
        return rows
    injury_lookup = build_injury_status_lookup(injuries_df)
    if not injury_lookup:
        return rows

    annotated = []
    for row in rows:
        updated = dict(row)
        player = str(updated.get('player') or updated.get('Player') or '').strip()
        normalized = normalize_player_lookup_name(player)
        injury = injury_lookup.get(player) or injury_lookup.get(normalized)
        updated['injury_status'] = ''
        updated['injury_reason'] = ''
        updated['injury_updated'] = ''
        updated['injury_short_label'] = ''
        updated['injury_severity'] = ''
        updated['has_injury_flag'] = False
        if not injury:
            annotated.append(updated)
            continue

        status = str(injury.get('status') or '').strip().upper()
        updated['injury_status'] = status
        updated['injury_reason'] = str(injury.get('reason') or '').strip()
        updated['injury_updated'] = str(injury.get('updated') or '').strip()
        updated['injury_short_label'] = str(injury.get('short_label') or status or 'MED').strip()
        updated['injury_severity'] = str(injury.get('severity') or '').strip()
        updated['has_injury_flag'] = True

        guardrail_tags = list(updated.get('guardrail_tags') or [])
        if 'MED ALERT' not in guardrail_tags:
            guardrail_tags.append('MED ALERT')
        if updated['injury_short_label'] and updated['injury_short_label'] not in guardrail_tags:
            guardrail_tags.append(updated['injury_short_label'])
        updated['guardrail_tags'] = guardrail_tags

        note_bits = []
        if status in {'QUESTIONABLE', 'GTD'}:
            note_bits.append('Game-time injury risk is active here.')
            if str(updated.get('play_verdict', 'PLAY') or 'PLAY').upper() == 'PLAY':
                updated['play_verdict'] = 'CONFLICTED'
                updated['play_verdict_note'] = 'Questionable / GTD status makes this a lean until active status is confirmed.'
        elif status in {'OUT', 'DOUBTFUL'}:
            note_bits.append(f'Current injury report status is {status}.')
            updated['play_verdict'] = 'PASS'
            updated['play_verdict_note'] = f'Injury status is {status}, so this should not be treated as a live play until status changes.'
        elif status == 'PROBABLE':
            note_bits.append('Player is on the injury report, but expected availability is stronger than a GTD tag.')

        if updated['injury_reason']:
            note_bits.append(updated['injury_reason'])
        if note_bits:
            injury_blurb = ' '.join(note_bits[:2]).strip()
            existing_note = str(updated.get('injury_context_note') or '').strip()
            updated['injury_context_note'] = f'{existing_note} {injury_blurb}'.strip() if existing_note else injury_blurb

        annotated.append(updated)
    return annotated

def load_return_overrides():
    """Load manual player-return overrides for healthy-but-back suppression cases."""
    path = DATA_DIR / 'injuries' / 'NBA_Return_Overrides.csv'
    if not path.exists():
        return pd.DataFrame(columns=['Player', 'Team', 'Status', 'Reason', 'Updated', 'Active', 'ExpiresOn'])

    overrides = _load_cached_csv(path).copy()
    for col in ['Player', 'Team', 'Status', 'Reason', 'Updated', 'Active', 'ExpiresOn']:
        if col not in overrides.columns:
            overrides[col] = ''
    for col in ['Player', 'Team', 'Status', 'Reason', 'Updated', 'Active', 'ExpiresOn']:
        overrides[col] = overrides[col].fillna('').astype(str).str.strip()

    if overrides.empty:
        return overrides

    now = pd.Timestamp.now()
    updated_dt = pd.to_datetime(overrides['Updated'], errors='coerce')
    expires_dt = pd.to_datetime(overrides['ExpiresOn'], errors='coerce')
    active_flag = overrides['Active'].str.lower().isin({'1', 'true', 'yes', 'y', 'active'})
    recent_flag = updated_dt >= (now - pd.Timedelta(days=5))
    unexpired_flag = expires_dt.isna() | (expires_dt >= now.normalize())

    overrides = overrides[unexpired_flag & (active_flag | recent_flag)].copy()
    if overrides.empty:
        return overrides

    overrides['Status'] = overrides['Status'].fillna('').astype(str).str.strip().str.upper()
    overrides = overrides[overrides['Player'] != ''].copy()
    return overrides.drop_duplicates(subset=['Player'], keep='last').reset_index(drop=True)

