def get_sort_params(default_by='confidence', default_dir='desc'):
    sort_by = request.args.get('sort_by', default_by).strip().lower()
    sort_dir = request.args.get('sort_dir', default_dir).strip().lower()
    if sort_dir not in {'asc', 'desc'}:
        sort_dir = default_dir
    return sort_by, sort_dir


def build_sort_link(base_path, current_params, target_sort):
    sort_by, sort_dir = target_sort
    params = {k: v for k, v in current_params.items() if v not in [None, '', []]}
    params['sort_by'] = sort_by
    params['sort_dir'] = sort_dir
    return f"{base_path}?{urlencode(params)}"


@app.context_processor
def inject_sort_helpers():
    return {'build_sort_link': build_sort_link}


def sort_prop_rows(rows, sort_by='confidence', sort_dir='desc'):
    reverse = sort_dir == 'desc'
    alpha_fields = {'player', 'team', 'stat', 'direction', 'game_day'}
    numeric_fields = {
        'line', 'avg', 'confidence', 'weighted_over_rate', 'weighted_under_rate',
        'over_rate', 'under_rate', 'projected_minutes', 'usage_pct', 'fair_price',
        'ev_pct', 'edge_pct', 'market_price', 'matchup_over_rate', 'matchup_under_rate',
        'matchup_games', 'over_streak', 'under_streak'
    }
    key = sort_by if sort_by in alpha_fields | numeric_fields else 'confidence'

    def sort_key(row):
        value = row.get(key)
        if key in alpha_fields:
            return str(value or '').lower()
        if value is None or (isinstance(value, float) and pd.isna(value)):
            return float('-inf') if reverse else float('inf')
        return value

    return sorted(rows, key=sort_key, reverse=reverse)

def get_current_nba_season():
    now = datetime.now()
    return f"{now.year}-{str(now.year + 1)[2:]}" if now.month >= 10 else f"{now.year - 1}-{str(now.year)[2:]}"

def postseason_only_enabled():
    value = request.args.get('postseason', '1')
    return str(value).lower() not in {'0', 'false', 'no', 'all'}

def get_current_playoff_focus_label():
    try:
        playoff_results = load_playoff_results()
    except Exception:
        playoff_results = pd.DataFrame()

    if playoff_results is None or playoff_results.empty or 'Round' not in playoff_results.columns:
        return 'Playoff 16', 'Playoffs', 'Final 16-team playoff bracket after the play-in closes.'

    rounds = (
        playoff_results['Round']
        .fillna('')
        .astype(str)
        .str.strip()
    )
    ranked_rounds = [
        (PLAYOFF_ROUND_ORDER.get(round_name, 0), round_name)
        for round_name in rounds
        if round_name in PLAYOFF_ROUND_ORDER
    ]
    if not ranked_rounds:
        return 'Playoff 16', 'Playoffs', 'Final 16-team playoff bracket after the play-in closes.'

    max_order, round_label = max(ranked_rounds, key=lambda item: item[0])
    short_map = {
        1: 'Round 1',
        2: 'Semis',
        3: 'Conf Finals',
        4: 'Finals',
    }
    description_map = {
        1: 'Current playoff slate is in the first round stage.',
        2: 'Current playoff slate is in the conference semifinals stage.',
        3: 'Current playoff slate is in the conference finals stage.',
        4: 'Current playoff slate is in the NBA Finals stage.',
    }
    return round_label, short_map.get(max_order, 'Playoffs'), description_map.get(max_order, 'Current playoff slate is active.')

def get_focus_mode_labels(postseason_only):
    today = sports_today_date()
    playoff_bracket_lock = datetime(2026, 4, 18).date()
    if postseason_only:
        if today < playoff_bracket_lock:
            return {
                'focus_mode_label': '20-Team Field',
                'focus_mode_short': 'Field',
                'focus_mode_description': 'Play-in plus playoff teams still alive as of April 17, 2026.',
                'regular_mode_label': 'Regular Mode',
                'focus_team_count': len(POSTSEASON_TEAMS)
            }
        focus_label, focus_short, focus_description = get_current_playoff_focus_label()
        return {
            'focus_mode_label': focus_label,
            'focus_mode_short': focus_short,
            'focus_mode_description': focus_description,
            'regular_mode_label': 'Regular Mode',
            'focus_team_count': 16
        }
    return {
        'focus_mode_label': '20-Team Field',
        'focus_mode_short': 'Field',
        'focus_mode_description': 'Regular-mode view across the full league and season data.',
        'regular_mode_label': 'Regular Mode',
        'focus_team_count': len(POSTSEASON_TEAMS)
    }

def get_team_filter(postseason_only, schedule=None):
    if not postseason_only:
        return None
    if schedule is None or getattr(schedule, 'empty', True):
        try:
            schedule = load_schedule()
        except Exception:
            schedule = pd.DataFrame()
    return get_active_playoff_team_filter(schedule) if schedule is not None else POSTSEASON_TEAMS

def normalize_team_for_filter(team):
    team = str(team or '').strip()
    if not team:
        return ''
    upper_team = team.upper()
    if upper_team in NBA_TEAM_ABBR_ALIASES:
        upper_team = NBA_TEAM_ABBR_ALIASES[upper_team]
    if upper_team in TEAM_ABBR_TO_NAME:
        return upper_team
    mapped = TEAM_NAME_TO_ABBR.get(team)
    if mapped:
        return mapped
    title_mapped = TEAM_NAME_TO_ABBR.get(team.title())
    if title_mapped:
        return title_mapped
    return upper_team

def team_in_filter(team, allowed_teams):
    return not allowed_teams or normalize_team_for_filter(team) in allowed_teams

def filter_teams_list(teams, allowed_teams):
    if not allowed_teams:
        return teams
    return [team for team in teams if normalize_team_for_filter(team) in allowed_teams]

def get_series_label(team_a, team_b):
    normalized_a = normalize_team_for_filter(team_a)
    normalized_b = normalize_team_for_filter(team_b)
    matchup = frozenset({normalized_a, normalized_b})
    if matchup in SERIES_LOOKUP:
        series = SERIES_LOOKUP[matchup]
        return series['label'], series['type']
    if normalized_a in POSTSEASON_TEAMS and normalized_b in POSTSEASON_TEAMS:
        return 'Postseason Matchup', 'postseason'
    return '', ''


def get_postseason_sample_context(team_a, team_b, postseason_only=False, playoff_gamelogs=None):
    context = {
        'mode': 'regular',
        'label': 'Regular-season baseline',
        'reason': 'No playoff override active.',
        'round_label': '',
    }
    if not postseason_only:
        return context

    series_label, _ = get_series_label(team_a, team_b)
    inferred_round = infer_dynamic_playoff_round(team_a, team_b)
    round_label = inferred_round or series_label or 'Postseason Matchup'
    context['round_label'] = round_label

    playoff_ready = playoff_gamelogs is not None and not getattr(playoff_gamelogs, 'empty', True)
    if 'ROUND 1' in str(round_label).upper() or 'PLAY-IN' in str(round_label).upper():
        context['reason'] = 'First-round playoff reads stay anchored to the regular season.'
        return context

    if playoff_ready and any(token in str(round_label).upper() for token in ['SEMIFINAL', 'FINAL']):
        context['mode'] = 'playoffs'
        context['label'] = 'Playoff sample'
        context['reason'] = 'Later-round playoff reads now lean on postseason performance first.'
    else:
        context['reason'] = 'Playoff round detected, but postseason sample is not ready yet.'
    return context


def select_matchup_gamelogs(gamelogs, playoff_gamelogs, team_a, team_b, postseason_only=False):
    context = get_postseason_sample_context(
        team_a,
        team_b,
        postseason_only=postseason_only,
        playoff_gamelogs=playoff_gamelogs,
    )
    if context['mode'] == 'playoffs' and playoff_gamelogs is not None and not getattr(playoff_gamelogs, 'empty', True):
        return playoff_gamelogs.copy(), context
    return gamelogs.copy(), context


def infer_dynamic_playoff_round(team_a, team_b):
    results = load_playoff_results()
    if results.empty or 'SeriesId' not in results.columns:
        return None

    team_a = normalize_team_for_filter(team_a)
    team_b = normalize_team_for_filter(team_b)
    max_completed_round = -1

    for series_id, series_df in results.groupby('SeriesId', dropna=False):
        if series_df.empty:
            continue
        round_name = str(series_df.iloc[0].get('Round', '')).strip()
        round_order = PLAYOFF_ROUND_ORDER.get(round_name)
        if round_order is None:
            continue

        participants = {
            normalize_team_for_filter(series_df.iloc[0].get('Away', '')),
            normalize_team_for_filter(series_df.iloc[0].get('Home', '')),
        }
        if team_a not in participants and team_b not in participants:
            continue

        unique_games = series_df[['Date', 'Away', 'Home']].drop_duplicates()
        if len(unique_games) < 4:
            continue

        summary = build_head_to_head_summary(pd.DataFrame(), *tuple(participants))
        if max(int(summary.get('team_a_wins', 0) or 0), int(summary.get('team_b_wins', 0) or 0)) < 4:
            continue

        if team_a in participants or team_b in participants:
            max_completed_round = max(max_completed_round, round_order)

    if max_completed_round < 0:
        return None
    return PLAYOFF_ROUND_LABELS.get(max_completed_round + 1)

def build_postseason_matchups(upcoming, gamelogs=None, schedule=None):
    def _profile_signal(profile):
        stats = profile.get('stats', []) if isinstance(profile, dict) else []
        attack_count = sum(1 for stat in stats if stat.get('verdict') == 'Attack')
        defense_count = sum(1 for stat in stats if stat.get('verdict') == 'Defense Edge')
        offense_team = str((profile or {}).get('offense_team', '')).strip()
        defense_team = str((profile or {}).get('defense_team', '')).strip()
        tags = []
        score = 0

        if attack_count >= 2 and offense_team:
            tags.append(f'{offense_team} offense live')
            score += 4
        if defense_count >= 2 and defense_team:
            tags.append(f'{defense_team} defense edge')
            score += 4
        if not tags and stats:
            tags.append('balanced profile')

        return {
            'attack_count': attack_count,
            'defense_count': defense_count,
            'tags': tags,
            'score': score,
            'summary': str((profile or {}).get('summary', '')).strip(),
        }

    postseason_matchups = []
    series_next_games = {}
    if schedule is not None and not getattr(schedule, 'empty', True):
        for series in build_active_series(schedule):
            series_next_games[series['id']] = series.get('next_game', {})

    for bucket_name in ['today', 'tomorrow', 'upcoming']:
        for game in upcoming.get(bucket_name, []):
            away_team = normalize_team_for_filter(game.get('Away', ''))
            home_team = normalize_team_for_filter(game.get('Home', ''))
            label, series_type = get_series_label(game['Away'], game['Home'])
            series = SERIES_LOOKUP.get(frozenset({away_team, home_team}), {})
            series_id = series.get('id')
            series_score = build_head_to_head_summary(
                gamelogs if gamelogs is not None else pd.DataFrame(),
                away_team,
                home_team,
                allow_regular_fallback=False,
            )
            matchup_logs, sample_context = select_matchup_gamelogs(
                gamelogs if gamelogs is not None else pd.DataFrame(),
                load_playoff_gamelogs(),
                away_team,
                home_team,
                postseason_only=True,
            )
            away_profile = build_team_vs_defense_profile(matchup_logs, away_team, home_team, sample_context['label'])
            home_profile = build_team_vs_defense_profile(matchup_logs, home_team, away_team, sample_context['label'])
            away_signal = _profile_signal(away_profile)
            home_signal = _profile_signal(home_profile)
            next_game = series_next_games.get(series_id, {}) if series_id else {}
            postseason_matchups.append({
                **game,
                'bucket': bucket_name,
                'series_label': label,
                'series_type': series_type,
                'series_id': series_id,
                'series_score': series_score,
                'series_status': series_score.get('status', ''),
                'last_result': (
                    f"Game {len(series_score.get('games', []))}: "
                    f"{game['Away']} {series_score['games'][-1]['team_a_score']}-"
                    f"{series_score['games'][-1]['team_b_score']} {game['Home']}"
                    if series_score.get('games') else ''
                ),
                'matchup_profiles': [away_profile, home_profile],
                'matchup_profile_tags': (away_signal['tags'] + home_signal['tags'])[:4],
                'matchup_profile_summary': away_signal['summary'] or home_signal['summary'] or '',
                'matchup_profile_score': away_signal['score'] + home_signal['score'],
                'sample_context': sample_context,
                'next_game_number': next_game.get('game_number'),
                'next_game_date': next_game.get('Date', ''),
            })
    return postseason_matchups


def build_matchup_lens_board(postseason_matchups, best_by_series, role_changes, top_plays):
    def _team_role_lookup(changes):
        lookup = {}
        for item in changes or []:
            team = str(item.get('team', '')).strip()
            if not team:
                continue
            team_items = lookup.setdefault(team, [])
            team_items.append(item)
        return lookup

    def _clean_driver_labels(notes):
        label_map = {
            'today slate': 'TODAY',
            'high total': 'HIGH TOTAL',
            'tight spread': 'TIGHT SPREAD',
            'tighter total': 'LOWER TOTAL',
            'wide spread': 'BLOWOUT RISK',
            'series pressure': 'SERIES PRESSURE',
            'tied series': 'TIED SERIES',
            'role shifts live': 'ROLE SHIFT',
            'strong matchup profile': 'MATCHUP EDGE',
            'clean matchup profile': 'MATCHUP LEAN',
        }
        return [label_map.get(str(note), str(note).upper()) for note in (notes or [])]

    def _game_context_score(game, role_lookup):
        score = 50
        notes = []
        tone = 'soft'
        market_total = game.get('market_total')
        market_spread = game.get('market_spread')
        matchup_profile_score = int(game.get('matchup_profile_score', 0) or 0)
        series_status = str(game.get('series_status', '') or '')
        bucket = str(game.get('bucket', '') or '')
        away = str(game.get('Away', '') or '')
        home = str(game.get('Home', '') or '')
        team_role_hits = len(role_lookup.get(away, [])) + len(role_lookup.get(home, []))

        if bucket == 'today':
            score += 6
            notes.append('today slate')
        elif bucket == 'tomorrow':
            score += 2

        if market_total is not None and not pd.isna(market_total):
            total_value = float(market_total)
            if total_value >= 224:
                score += 8
                notes.append('high total')
            elif total_value <= 214:
                score += 4
                notes.append('tighter total')

        if market_spread is not None and not pd.isna(market_spread):
            spread_value = abs(float(market_spread))
            if spread_value <= 4.5:
                score += 7
                notes.append('tight spread')
            elif spread_value >= 9:
                score -= 3
                notes.append('wide spread')

        if 'leads 3-' in series_status or 'leads 2-' in series_status:
            score += 6
            notes.append('series pressure')
        if 'Series tied' in series_status:
            score += 7
            notes.append('tied series')

        if team_role_hits:
            score += min(10, team_role_hits * 3)
            notes.append('role shifts live')

        if matchup_profile_score >= 8:
            score += 6
            notes.append('strong matchup profile')
        elif matchup_profile_score >= 4:
            score += 3
            notes.append('clean matchup profile')

        if score >= 68:
            tone = 'accent'
        elif score >= 60:
            tone = 'copper'
        elif score <= 46:
            tone = 'danger'
        elif market_total is not None and not pd.isna(market_total):
            tone = 'blue'

        return max(35, min(92, int(round(score)))), tone, notes

    role_lookup = _team_role_lookup(role_changes)
    cards = []

    for game in postseason_matchups[:4]:
        href = f"/series/{game['series_id']}?postseason=1" if game.get('series_id') else f"/matchup/{game['Away']}-{game['Home']}?postseason=1"
        title = f"{game['Away']} @ {game['Home']}"
        context_score, tone, score_notes = _game_context_score(game, role_lookup)
        summary_bits = []
        if game.get('series_status'):
            summary_bits.append(game['series_status'])
        if game.get('market_summary'):
            summary_bits.append(game['market_summary'])
        if game.get('matchup_profile_summary'):
            summary_bits.append(game['matchup_profile_summary'])
        if game.get('last_result'):
            summary_bits.append(game['last_result'])
        cleaned_drivers = dedupe_preserve_order(
            _clean_driver_labels(score_notes[:3]) +
            [str(tag).upper() for tag in (game.get('matchup_profile_tags') or [])[:2]]
        )[:3]
        cards.append({
            'type': 'Series Pressure',
            'tone': tone,
            'title': title,
            'kicker': game.get('series_label') or 'Postseason Matchup',
            'summary': ' | '.join(summary_bits[:2]) or 'Start here when you want the highest-context game on the board.',
            'context_score': context_score,
            'score_note': build_lens_explanation(cleaned_drivers),
            'context_drivers': cleaned_drivers,
            'href': href,
            'cta': 'Open Matchup',
        })

    for role in role_changes[:4]:
        role_drivers = [
            'INJURY SHIFT',
            str(role.get('injury_status', '')).upper(),
            f"{role.get('boost_pct', 0)}% BOOST",
        ]
        cards.append({
            'type': 'Role Shift',
            'tone': 'danger' if role.get('boost_pct', 0) >= 20 else 'blue',
            'title': f"{role['player']} {role['stat']}",
            'kicker': f"{role['team']} | {role['expected_shift']}",
            'summary': f"{role['injured_player']} ({role['injury_status']}) can create a {role['boost_pct']}% shift in this role.",
            'context_score': min(90, int(round(52 + float(role.get('boost_pct', 0))))),
            'score_note': 'injury-driven role change',
            'context_drivers': [driver for driver in role_drivers if driver],
            'href': "/injuries?postseason=1",
            'cta': 'Open Injury Hub',
        })

    if not cards:
        for play in top_plays[:4]:
            cards.append({
                'type': 'Context Play',
                'tone': 'soft',
                'title': f"{play['player']} {play['stat']} {play['line']}",
                'kicker': play['team'],
                'summary': f"{play['direction']} {round(play['hit_rate'])}% | Use the matchup pages to confirm the context behind this read.",
                'context_score': int(round(play.get('hit_rate', 0))),
                'score_note': 'fallback context play',
                'context_drivers': ['FALLBACK', str(play.get('direction', '')).upper(), f"{round(play.get('hit_rate', 0))}% HIT"],
                'href': f"/player/{quote(play['player'])}",
                'cta': 'Open Player',
            })

    cards = sorted(cards, key=lambda item: (item.get('type') != 'Series Pressure', -item.get('context_score', 0)))
    return cards[:8]


def get_active_playoff_team_filter(schedule, days=7):
    """Return only playoff teams that still appear on the active upcoming slate."""
    upcoming = get_upcoming_games(schedule, days=days, allowed_teams=POSTSEASON_TEAMS)
    active_teams = {
        normalize_team_for_filter(team)
        for team in (upcoming.get('all_teams', set()) or set())
        if normalize_team_for_filter(team)
    }
    return active_teams if active_teams else set(POSTSEASON_TEAMS)


def annotate_schedule_games(games, gamelogs=None, schedule=None):
    annotated = []
    series_next_games = {}
    if schedule is not None and not getattr(schedule, 'empty', True):
        for series in build_active_series(schedule):
            series_next_games[series['id']] = series.get('next_game', {})

    for game in games:
        away_team = normalize_team_for_filter(game.get('Away', ''))
        home_team = normalize_team_for_filter(game.get('Home', ''))
        label, series_type = get_series_label(game['Away'], game['Home'])
        series = SERIES_LOOKUP.get(frozenset({away_team, home_team}), {})
        series_id = series.get('id')
        series_score = build_head_to_head_summary(
            gamelogs if gamelogs is not None else pd.DataFrame(),
            away_team,
            home_team,
            allow_regular_fallback=False,
        )
        next_game = series_next_games.get(series_id, {}) if series_id else {}
        annotated.append({
            **game,
            'series_label': label,
            'series_type': series_type,
            'series_id': series_id,
            'series_status': series_score.get('status', ''),
            'last_result': (
                f"Game {len(series_score.get('games', []))}: "
                f"{game['Away']} {series_score['games'][-1]['team_a_score']}-"
                f"{series_score['games'][-1]['team_b_score']} {game['Home']}"
                if series_score.get('games') else ''
            ),
            'next_game_number': next_game.get('game_number'),
        })
    return annotated

def get_series_schedule_games(schedule, series_teams):
    if schedule.empty or 'Away' not in schedule.columns or 'Home' not in schedule.columns:
        return []

    normalized_series_teams = {normalize_team_for_filter(team) for team in series_teams}
    games = []
    for _, row in schedule.iterrows():
        away = str(row.get('Away', '')).strip()
        home = str(row.get('Home', '')).strip()
        normalized_away = normalize_team_for_filter(away)
        normalized_home = normalize_team_for_filter(home)
        if {normalized_away, normalized_home} != normalized_series_teams:
            continue
        games.append({
            'Away': away,
            'Home': home,
            'Date': str(row.get('Date', '')),
            'Time': str(row.get('Time', 'TBD'))
        })

    def sort_key(game):
        parsed = pd.to_datetime(game.get('Date', ''), errors='coerce')
        return (parsed if pd.notna(parsed) else pd.Timestamp.max, game.get('Time', 'TBD'))

    return sorted(games, key=sort_key)


def prune_completed_playoff_games(schedule_df):
    if schedule_df is None or schedule_df.empty or not {'Away', 'Home', 'Date'}.issubset(schedule_df.columns):
        return schedule_df

    completed_matchups = []
    for config in SERIES_CONFIG.values():
        if config.get('type') != 'playoff':
            continue
        team_a, team_b = config.get('teams', ('', ''))
        series_score = build_head_to_head_summary(pd.DataFrame(), team_a, team_b)
        team_a_wins = int(series_score.get('team_a_wins', 0) or 0)
        team_b_wins = int(series_score.get('team_b_wins', 0) or 0)
        if max(team_a_wins, team_b_wins) < 4:
            continue
        completed_matchups.append(
            {
                'teams': {normalize_team_for_filter(team_a), normalize_team_for_filter(team_b)},
            }
        )

    if not completed_matchups:
        return schedule_df

    keep_mask = []
    for _, row in schedule_df.iterrows():
        row_teams = {
            normalize_team_for_filter(row.get('Away', '')),
            normalize_team_for_filter(row.get('Home', '')),
        }
        remove_row = any(row_teams == item['teams'] for item in completed_matchups)
        keep_mask.append(not remove_row)

    return schedule_df.loc[keep_mask].reset_index(drop=True)

def get_series_id(team_a, team_b):
    normalized_a = normalize_team_for_filter(team_a)
    normalized_b = normalize_team_for_filter(team_b)
    series = SERIES_LOOKUP.get(frozenset({normalized_a, normalized_b}))
    return series['id'] if series else None

def resolve_series_config(series_id, schedule=None):
    series_id = str(series_id or '').strip()
    if not series_id:
        return None
    if series_id in SERIES_CONFIG:
        return SERIES_CONFIG[series_id]

    if schedule is None:
        schedule = load_schedule()
    for active_series in build_active_series(schedule):
        if str(active_series.get('id') or '').strip() != series_id:
            continue
        teams = tuple(active_series.get('teams') or ())
        if len(teams) != 2:
            return None
        return {
            'teams': teams,
            'label': active_series.get('label') or 'Postseason Matchup',
            'type': active_series.get('type') or 'postseason',
        }
    return None

def build_active_series(schedule):
    active = []
    today = sports_today_ts()
    known_matchups = set()

    for series_id, config in SERIES_CONFIG.items():
        known_matchups.add(frozenset({normalize_team_for_filter(config['teams'][0]), normalize_team_for_filter(config['teams'][1])}))
        if config.get('type') == 'playoff':
            series_score = build_head_to_head_summary(pd.DataFrame(), config['teams'][0], config['teams'][1])
            if max(int(series_score.get('team_a_wins', 0) or 0), int(series_score.get('team_b_wins', 0) or 0)) >= 4:
                continue
        games = annotate_series_games(get_series_schedule_games(schedule, config['teams']))
        upcoming_games = []
        for game in games:
            game_date = pd.to_datetime(game.get('Date', ''), errors='coerce')
            if pd.notna(game_date) and game_date >= today:
                upcoming_games.append(game)

        next_game = upcoming_games[0] if upcoming_games else (games[0] if games else None)
        if not next_game:
            continue

        active.append({
            'id': series_id,
            'label': config['label'],
            'type': config['type'],
            'teams': config['teams'],
            'next_game': next_game,
            'next_matchup': f"{next_game['Away']} @ {next_game['Home']}",
            'next_date': next_game.get('Date', ''),
            'next_time': next_game.get('Time', 'TBD')
        })

    if schedule is not None and not getattr(schedule, 'empty', True):
        seen_dynamic = set()
        for _, row in schedule.iterrows():
            away = str(row.get('Away', '')).strip()
            home = str(row.get('Home', '')).strip()
            normalized_away = normalize_team_for_filter(away)
            normalized_home = normalize_team_for_filter(home)
            if not normalized_away or not normalized_home:
                continue
            if normalized_away not in POSTSEASON_TEAMS or normalized_home not in POSTSEASON_TEAMS:
                continue
            matchup = frozenset({normalized_away, normalized_home})
            if matchup in known_matchups or matchup in seen_dynamic:
                continue

            game_date = pd.to_datetime(row.get('Date', ''), errors='coerce')
            if pd.notna(game_date) and game_date < today:
                continue

            seen_dynamic.add(matchup)
            team_names = [TEAM_ABBR_TO_NAME.get(normalized_away, away), TEAM_ABBR_TO_NAME.get(normalized_home, home)]
            inferred_round = infer_dynamic_playoff_round(normalized_away, normalized_home)
            if inferred_round:
                label = f"{inferred_round}: {team_names[0]} vs {team_names[1]}"
            else:
                label = f"Postseason Matchup: {team_names[0]} vs {team_names[1]}"
            active.append({
                'id': f"{normalized_away.lower()}-{normalized_home.lower()}",
                'label': label,
                'type': 'postseason',
                'teams': (normalized_away, normalized_home),
                'next_game': {
                    'Away': away,
                    'Home': home,
                    'Date': str(row.get('Date', '')),
                    'Time': str(row.get('Time', 'TBD')),
                },
                'next_matchup': f"{away} @ {home}",
                'next_date': str(row.get('Date', '')),
                'next_time': str(row.get('Time', 'TBD')),
            })

    def active_sort_key(item):
        parsed = pd.to_datetime(item.get('next_date', ''), errors='coerce')
        return (parsed if pd.notna(parsed) else pd.Timestamp.max, item.get('label', ''))

    return sorted(active, key=active_sort_key)


