def _american_implied_probability(odds):
    try:
        odds = float(odds)
    except (TypeError, ValueError):
        return None
    if pd.isna(odds) or odds == 0:
        return None
    if odds < 0:
        return abs(odds) / (abs(odds) + 100)
    return 100 / (odds + 100)


def _format_american_price(odds):
    try:
        odds = int(round(float(odds)))
    except (TypeError, ValueError):
        return ''
    return f"+{odds}" if odds > 0 else str(odds)


def _dashboard_best_prop_for_game(props_df, game_name):
    if props_df.empty or 'Game' not in props_df.columns or not game_name:
        return None
    normalized_game = re.sub(r'\s+', '', str(game_name).casefold())
    game_props = props_df[
        props_df['Game'].astype(str).map(lambda value: re.sub(r'\s+', '', value.casefold())) == normalized_game
    ].copy()
    if game_props.empty:
        return None

    best = None
    for _, row in game_props.iterrows():
        options = [
            ('OVER', row.get('OverOdds')),
            ('UNDER', row.get('UnderOdds')),
        ]
        for direction, odds in options:
            implied = _american_implied_probability(odds)
            if implied is None:
                continue
            candidate = {
                'player': str(row.get('Player') or '').strip() or 'Player prop',
                'stat': str(row.get('Stat') or '').strip() or 'Prop',
                'line': row.get('Line'),
                'direction': direction,
                'price': _format_american_price(odds),
                'implied': round(implied * 100, 1),
                'book': str(row.get('Book') or '').strip(),
            }
            if best is None or candidate['implied'] > best['implied']:
                best = candidate
    return best


def _dashboard_best_props_for_games(props_df, game_names):
    if props_df.empty or 'Game' not in props_df.columns or not game_names:
        return {'OVER': None, 'UNDER': None}

    normalized_games = {
        re.sub(r'\s+', '', str(game_name).casefold())
        for game_name in game_names
        if str(game_name or '').strip()
    }
    if not normalized_games:
        return {'OVER': None, 'UNDER': None}

    game_props = props_df[
        props_df['Game'].astype(str).map(lambda value: re.sub(r'\s+', '', value.casefold())).isin(normalized_games)
    ].copy()
    if game_props.empty:
        return {'OVER': None, 'UNDER': None}

    best = {'OVER': None, 'UNDER': None}
    for _, row in game_props.iterrows():
        for direction, odds in [('OVER', row.get('OverOdds')), ('UNDER', row.get('UnderOdds'))]:
            implied = _american_implied_probability(odds)
            if implied is None:
                continue
            candidate = {
                'player': str(row.get('Player') or '').strip() or 'Player prop',
                'stat': str(row.get('Stat') or '').strip() or 'Prop',
                'line': row.get('Line'),
                'direction': direction,
                'price': _format_american_price(odds),
                'implied': round(implied * 100, 1),
                'book': str(row.get('Book') or '').strip(),
                'matchup': str(row.get('Game') or '').strip(),
            }
            if best[direction] is None or candidate['implied'] > best[direction]['implied']:
                best[direction] = candidate
    return best


