def get_postseason_matchup_context(gamelogs, team, opponent, cache=None):
    if not team or not opponent:
        return {'series_label': '', 'series_type': '', 'series_id': None, 'series_score': build_head_to_head_summary(pd.DataFrame(), team or '', opponent or '', allow_regular_fallback=False)}

    cache_key = (team, opponent)
    if cache is not None and cache_key in cache:
        return cache[cache_key]

    series_label, series_type = get_series_label(team, opponent)
    context = {
        'series_label': series_label,
        'series_type': series_type,
        'series_id': get_series_id(team, opponent),
        'series_score': build_head_to_head_summary(gamelogs, team, opponent, allow_regular_fallback=False)
    }

    if cache is not None:
        cache[cache_key] = context
    return context

def get_player_pressure_profile(player_logs):
    profile = {
        'tier': 'rotation',
        'pressure_over_boost': 0,
        'pressure_under_boost': 0,
        'tags': []
    }

    if player_logs.empty:
        return profile

    logs = player_logs.copy()
    if 'Date' in logs.columns:
        logs = logs.sort_values('Date', ascending=False)

    mins = logs['MIN'].dropna() if 'MIN' in logs.columns else pd.Series(dtype=float)
    pts = logs['PTS'].dropna() if 'PTS' in logs.columns else pd.Series(dtype=float)
    ast = logs['AST'].dropna() if 'AST' in logs.columns else pd.Series(dtype=float)
    reb = logs['REB'].dropna() if 'REB' in logs.columns else pd.Series(dtype=float)

    min_avg = mins.head(10).mean() if not mins.empty else 0
    min_last_5 = mins.head(5).mean() if not mins.empty else 0
    min_std = mins.head(10).std() if len(mins.head(10)) >= 2 else 0
    pts_avg = pts.head(10).mean() if not pts.empty else 0
    ast_avg = ast.head(10).mean() if not ast.empty else 0
    reb_avg = reb.head(10).mean() if not reb.empty else 0
    involvement = pts_avg + (ast_avg * 1.5) + (reb_avg * 0.75)

    if min_avg >= 35 or involvement >= 33:
        profile['tier'] = 'star'
        profile['pressure_over_boost'] = 4
        profile['tags'].append('STAR ROLE')
    elif min_avg >= 30 or involvement >= 24:
        profile['tier'] = 'core'
        profile['pressure_over_boost'] = 3
        profile['tags'].append('CORE ROLE')
    elif min_avg < 22:
        profile['tier'] = 'bench'
        profile['pressure_under_boost'] = 3
        profile['tags'].append('LOW ROLE')
    else:
        profile['tags'].append('ROTATION')

    if min_last_5 >= min_avg + 2:
        profile['pressure_over_boost'] += 1
        profile['tags'].append('ROLE HOLD')
    elif min_avg and min_last_5 <= min_avg - 2:
        profile['pressure_under_boost'] += 1
        profile['tags'].append('ROLE SLIP')

    if pd.notna(min_std) and min_std <= 3 and min_avg >= 28:
        profile['pressure_over_boost'] += 1
        profile['tags'].append('MIN STABLE')
    elif pd.notna(min_std) and min_std >= 7:
        profile['pressure_under_boost'] += 1
        profile['tags'].append('VOLATILE')

    profile['tags'] = list(dict.fromkeys(profile['tags']))
    return profile

def get_playoff_defense_context(gamelogs, opponent, stat, cache=None, allowed_teams=None):
    empty = {'over_boost': 0, 'under_boost': 0, 'tags': []}
    if gamelogs.empty or not opponent or stat not in STAT_COLUMNS:
        return empty
    if allowed_teams and opponent not in allowed_teams:
        return empty

    cache_key = (opponent, stat)
    if cache is not None and cache_key in cache:
        return cache[cache_key]

    if 'Team' not in gamelogs.columns or stat not in gamelogs.columns or 'Opp' not in gamelogs.columns:
        return empty

    team_allowed = []
    for team in gamelogs['Team'].dropna().unique():
        opponents = gamelogs[gamelogs['Opp'] == team]
        if opponents.empty:
            continue
        allowed_avg = opponents[stat].dropna().mean()
        if pd.notna(allowed_avg):
            team_allowed.append((team, allowed_avg))

    if not team_allowed:
        return empty

    ranked = sorted(team_allowed, key=lambda item: item[1])
    teams = [team for team, _ in ranked]
    if opponent not in teams:
        return empty

    idx = teams.index(opponent)
    count = len(teams)
    context = {'over_boost': 0, 'under_boost': 0, 'tags': []}

    if idx <= max(1, count // 5):
        context['under_boost'] += 4
        context['tags'].append(f'TOUGH {stat} DEF')
    elif idx >= count - max(2, count // 5):
        context['over_boost'] += 4
        context['tags'].append(f'SOFT {stat} DEF')

    if cache is not None:
        cache[cache_key] = context
    return context


def build_team_vs_defense_profile(gamelogs, offense_team, defense_team, sample_label=''):
    profile = {
        'offense_team': offense_team,
        'defense_team': defense_team,
        'stats': [],
        'summary': 'No team-vs-defense sample loaded yet.',
        'sample_label': sample_label or 'Regular-season baseline',
    }
    if gamelogs.empty or 'Team' not in gamelogs.columns or 'Opp' not in gamelogs.columns:
        return profile

    stat_labels = {
        'PTS': 'Points',
        'REB': 'Rebounds',
        'AST': 'Assists',
        '3PM': '3PT Made'
    }
    game_keys = ['Date', 'Team', 'Opp'] if 'Date' in gamelogs.columns else ['Team', 'Opp']

    offense_logs = gamelogs[gamelogs['Team'] == offense_team].copy()
    if offense_logs.empty:
        return profile

    defense_allowed_logs = gamelogs[gamelogs['Opp'] == defense_team].copy()
    if defense_allowed_logs.empty:
        return profile

    for stat, label in stat_labels.items():
        if stat not in offense_logs.columns or stat not in defense_allowed_logs.columns:
            continue

        offense_game_avg = (
            offense_logs.groupby(game_keys)[stat].sum().dropna().mean()
            if not offense_logs.empty else None
        )
        defense_allowed_avg = (
            defense_allowed_logs.groupby(game_keys)[stat].sum().dropna().mean()
            if not defense_allowed_logs.empty else None
        )
        if pd.isna(offense_game_avg) or pd.isna(defense_allowed_avg):
            continue

        if defense_allowed_avg:
            edge_pct = round(((offense_game_avg - defense_allowed_avg) / defense_allowed_avg) * 100, 1)
        else:
            edge_pct = 0

        if edge_pct >= 6:
            verdict = 'Attack'
        elif edge_pct <= -6:
            verdict = 'Defense Edge'
        else:
            verdict = 'Neutral'

        profile['stats'].append({
            'stat': stat,
            'label': label,
            'offense_avg': round(float(offense_game_avg), 1),
            'defense_allowed': round(float(defense_allowed_avg), 1),
            'edge_pct': edge_pct,
            'verdict': verdict
        })

    if profile['stats']:
        attack_count = sum(1 for stat in profile['stats'] if stat['verdict'] == 'Attack')
        defense_count = sum(1 for stat in profile['stats'] if stat['verdict'] == 'Defense Edge')
        if attack_count > defense_count:
            profile['summary'] = f"{offense_team} offense leans better into the {defense_team} defense in this {profile['sample_label'].lower()}."
        elif defense_count > attack_count:
            profile['summary'] = f"{defense_team} defense has the sturdier edge in this {profile['sample_label'].lower()}."
        else:
            profile['summary'] = f"{offense_team} offense vs {defense_team} defense looks mostly balanced in this {profile['sample_label'].lower()}."

    return profile

def build_series_best_plays(props_df, gamelogs, schedule):
    if props_df.empty or gamelogs.empty or schedule.empty:
        return []

    active_series = build_active_series(schedule)
    defense_cache = {}
    series_cards = []

    for series in active_series:
        team_a, team_b = series['teams']
        forward_score = build_head_to_head_summary(gamelogs, team_a, team_b)
        reverse_score = build_head_to_head_summary(gamelogs, team_b, team_a)
        best_prop = None
        next_game = series.get('next_game', {})

        for _, prop in props_df.iterrows():
            player, stat, line = prop.get('Player', ''), prop.get('Stat', ''), prop.get('Line', 0)
            if pd.isna(player) or pd.isna(stat) or pd.isna(line):
                continue

            pl = gamelogs[gamelogs['Player'] == player]
            if len(pl) < 5 or stat not in pl.columns:
                continue

            team = pl.iloc[0].get('Team', '')
            if team not in {team_a, team_b}:
                continue

            opponent = team_b if team == team_a else team_a
            score = score_prop(
                pl,
                stat,
                line,
                player=player,
                team=team,
                opponent=opponent,
                gamelogs=gamelogs,
                projection_context={},
                scheduled_game={'site': ('away' if next_game.get('Away') == team else 'home' if next_game.get('Home') == team else None)},
                postseason_only=True,
                series_context={
                    'series_label': series['label'],
                    'series_type': series['type'],
                    'series_score': forward_score if team == team_a else reverse_score
                },
                defense_context=get_playoff_defense_context(gamelogs, opponent, stat, defense_cache, POSTSEASON_TEAMS),
            )
            best_play = score['best_play']
            playoff_adjustments = score['playoff_adjustments']
            if best_play['confidence'] < 75:
                continue

            support_note = 'Series support is strong enough to treat this as a clean playable angle.'
            if best_play['confidence'] < 84:
                support_note = 'Series context supports this, but it still needs line discipline.'
            if best_play['confidence'] < 78:
                support_note = 'Series read is leaning here, but it is better as support than a blind top play.'

            candidate = {
                'series_id': series['id'],
                'series_label': series['label'],
                'player': player,
                'team': team,
                'stat': stat,
                'line': line,
                'direction': best_play['direction'],
                'confidence': best_play['confidence'],
                'tags': playoff_adjustments['tags'],
                'support_note': support_note,
            }
            if not best_prop or candidate['confidence'] > best_prop['confidence']:
                best_prop = candidate

        if best_prop:
            series_cards.append(best_prop)

    deduped_cards = {}
    for card in series_cards:
        key = (
            str(card.get('series_id', '')).strip(),
            str(card.get('player', '')).strip().lower(),
            str(card.get('team', '')).strip().upper(),
            str(card.get('stat', '')).strip().upper(),
            float(card.get('line', 0) or 0),
            str(card.get('direction', '')).strip().upper(),
        )
        current = deduped_cards.get(key)
        if current is None or float(card.get('confidence', 0) or 0) > float(current.get('confidence', 0) or 0):
            deduped_cards[key] = card

    return sorted(deduped_cards.values(), key=lambda x: x['confidence'], reverse=True)[:8]

def get_team_record(gamelogs, team_abbr, sample_label=''):
    team_logs = gamelogs[gamelogs['Team'] == team_abbr]
    if team_logs.empty:
        return {
            'wins': 0, 'losses': 0, 'win_pct': 0, 'home_wins': 0, 'home_losses': 0,
            'away_wins': 0, 'away_losses': 0, 'last_5_wins': 0, 'home_ppg': 0, 'away_ppg': 0,
            'overall_ppg': 0, 'sample_label': sample_label or 'Regular-season baseline'
        }
    record = {'wins': 0, 'losses': 0, 'home_wins': 0, 'home_losses': 0, 'away_wins': 0, 'away_losses': 0, 'last_5_wins': 0}
    game_group_cols = ['Date']
    if 'Game_ID' in team_logs.columns:
        game_group_cols = ['Game_ID']
    if all(col in team_logs.columns for col in game_group_cols) and 'Result' in team_logs.columns:
        agg_map = {'Result': 'first'}
        if 'Matchup' in team_logs.columns:
            agg_map['Matchup'] = 'first'
        if 'PTS' in team_logs.columns:
            agg_map['PTS'] = 'sum'
        game_results = team_logs.groupby(game_group_cols, dropna=False).agg(agg_map).reset_index()
        if 'Date' not in game_results.columns and 'Date' in team_logs.columns:
            game_dates = team_logs.groupby(game_group_cols, dropna=False)['Date'].first().reset_index()
            game_results = game_results.merge(game_dates, on=game_group_cols, how='left')
        if 'Result' in game_results.columns:
            record['wins'] = int((game_results['Result'] == 'W').sum())
            record['losses'] = int((game_results['Result'] == 'L').sum())
            if 'Date' in game_results.columns:
                last_5 = game_results.sort_values('Date', ascending=False).head(5)
                record['last_5_wins'] = int((last_5['Result'] == 'W').sum())
            if 'Matchup' in game_results.columns:
                home_g = game_results[game_results['Matchup'].str.contains('vs.', na=False)]
                away_g = game_results[game_results['Matchup'].str.contains('@', na=False)]
                record['home_wins'] = int((home_g['Result'] == 'W').sum()) if not home_g.empty else 0
                record['home_losses'] = int((home_g['Result'] == 'L').sum()) if not home_g.empty else 0
                record['away_wins'] = int((away_g['Result'] == 'W').sum()) if not away_g.empty else 0
                record['away_losses'] = int((away_g['Result'] == 'L').sum()) if not away_g.empty else 0
    total_games = record['wins'] + record['losses']
    record['win_pct'] = record['wins'] / total_games if total_games > 0 else 0
    if 'Matchup' in game_results.columns and 'PTS' in game_results.columns:
        home_l = game_results[game_results['Matchup'].astype(str).str.contains('vs.', na=False)]
        away_l = game_results[game_results['Matchup'].astype(str).str.contains('@', na=False)]
        record['home_ppg'] = round(home_l['PTS'].mean(), 1) if not home_l.empty else 0
        record['away_ppg'] = round(away_l['PTS'].mean(), 1) if not away_l.empty else 0
        record['overall_ppg'] = round(game_results['PTS'].mean(), 1) if not game_results.empty else 0
    else:
        record['home_ppg'] = 0
        record['away_ppg'] = 0
        record['overall_ppg'] = 0
    record['sample_label'] = sample_label or 'Regular-season baseline'
    return record

def _build_player_split_row(label, split_logs):
    if split_logs is None or split_logs.empty:
        return None
    row = {
        'label': label,
        'gp': int(len(split_logs)),
        'min': round(pd.to_numeric(split_logs.get('MIN'), errors='coerce').dropna().mean(), 1) if 'MIN' in split_logs.columns else None,
        'fgm': round(pd.to_numeric(split_logs.get('FGM'), errors='coerce').dropna().mean(), 1) if 'FGM' in split_logs.columns else None,
        'fga': round(pd.to_numeric(split_logs.get('FGA'), errors='coerce').dropna().mean(), 1) if 'FGA' in split_logs.columns else None,
        'pts': round(pd.to_numeric(split_logs.get('PTS'), errors='coerce').dropna().mean(), 1) if 'PTS' in split_logs.columns else None,
        'reb': round(pd.to_numeric(split_logs.get('REB'), errors='coerce').dropna().mean(), 1) if 'REB' in split_logs.columns else None,
        'ast': round(pd.to_numeric(split_logs.get('AST'), errors='coerce').dropna().mean(), 1) if 'AST' in split_logs.columns else None,
    }
    return row


def build_player_splits(player_logs, team=None, upcoming_opponent=None):
    if player_logs is None or player_logs.empty:
        return []

    working = player_logs.copy()
    if 'Date' in working.columns:
        working['Date'] = pd.to_datetime(working['Date'], errors='coerce')

    sections = []

    if 'Matchup' in working.columns:
        home_logs = working[working['Matchup'].astype(str).str.contains('vs.', na=False)]
        road_logs = working[working['Matchup'].astype(str).str.contains('@', na=False)]
        location_rows = [row for row in [
            _build_player_split_row('Home', home_logs),
            _build_player_split_row('Road', road_logs),
        ] if row]
        if location_rows:
            sections.append({'title': 'Location', 'rows': location_rows})

    if 'Result' in working.columns:
        win_logs = working[working['Result'].astype(str).str.upper() == 'W']
        loss_logs = working[working['Result'].astype(str).str.upper() == 'L']
        result_rows = [row for row in [
            _build_player_split_row('Wins', win_logs),
            _build_player_split_row('Losses', loss_logs),
        ] if row]
        if result_rows:
            sections.append({'title': 'Result', 'rows': result_rows})

    if upcoming_opponent and 'Opp' in working.columns:
        opp_key = normalize_team_for_filter(upcoming_opponent)
        opp_logs = working[working['Opp'].astype(str).apply(normalize_team_for_filter) == opp_key]
        opp_row = _build_player_split_row(TEAM_ABBR_TO_NAME.get(opp_key, upcoming_opponent), opp_logs)
        if opp_row:
            sections.append({'title': 'Vs Upcoming Opponent', 'rows': [opp_row]})

    if 'Date' in working.columns:
        valid = working.dropna(subset=['Date']).copy()
        if not valid.empty:
            valid['MonthLabel'] = valid['Date'].dt.strftime('%B')
            month_order = list(dict.fromkeys(valid.sort_values('Date')['MonthLabel'].tolist()))
            month_rows = []
            for month in month_order:
                month_row = _build_player_split_row(month, valid[valid['MonthLabel'] == month])
                if month_row:
                    month_rows.append(month_row)
            if month_rows:
                sections.append({'title': 'Month', 'rows': month_rows})

    if 'Opp' in working.columns:
        valid = working.copy()
        valid['Conference'] = valid['Opp'].astype(str).apply(lambda value: NBA_TEAM_TO_CONFERENCE.get(normalize_team_for_filter(value), ''))
        conference_rows = []
        for label in ['Eastern', 'Western']:
            row = _build_player_split_row(label, valid[valid['Conference'] == label])
            if row:
                conference_rows.append(row)
        if conference_rows:
            sections.append({'title': 'Conference', 'rows': conference_rows})

        valid['Division'] = valid['Opp'].astype(str).apply(lambda value: NBA_TEAM_TO_DIVISION.get(normalize_team_for_filter(value), ''))
        division_rows = []
        division_order = ['Atlantic', 'Central', 'Southeast', 'Northwest', 'Pacific', 'Southwest']
        for label in division_order:
            row = _build_player_split_row(label, valid[valid['Division'] == label])
            if row:
                division_rows.append(row)
        if division_rows:
            sections.append({'title': 'Division', 'rows': division_rows})

    return sections


def _decision_stat_value(value, suffix=''):
    if value is None:
        return '-'
    try:
        if pd.isna(value):
            return '-'
    except Exception:
        pass
    try:
        numeric = float(value)
        if numeric.is_integer():
            return f"{int(numeric)}{suffix}"
        return f"{round(numeric, 1)}{suffix}"
    except Exception:
        text = str(value).strip()
        return text if text else '-'


def _average_column(rows_df, column):
    if rows_df is None or rows_df.empty or column not in rows_df.columns:
        return None
    values = pd.to_numeric(rows_df[column], errors='coerce').dropna()
    if values.empty:
        return None
    return round(float(values.mean()), 1)


def _find_upcoming_game_for_team(schedule, team, days=7):
    upcoming = get_upcoming_games(schedule, days=days) if schedule is not None else {}
    team_key = normalize_team_for_filter(team)
    for bucket in ['today', 'tomorrow', 'upcoming']:
        for game in upcoming.get(bucket, []) or []:
            away_team = normalize_team_for_filter(game.get('Away', ''))
            home_team = normalize_team_for_filter(game.get('Home', ''))
            if team_key in {away_team, home_team}:
                opponent = home_team if away_team == team_key else away_team
                return {
                    'bucket': bucket,
                    'opponent': opponent,
                    'game': game,
                    'is_home': home_team == team_key,
                }
    return {'bucket': '', 'opponent': '', 'game': {}, 'is_home': None}


def build_player_decision_context(
    player_name,
    team,
    sport_key,
    player_logs,
    player_context,
    factors,
    prop_analysis,
    selected_stat,
    selected_line,
    upcoming_game_context,
    split_sections,
    injury_info=None,
):
    sport_key = normalize_sport_access_key(sport_key or 'nba')
    sport_label = sport_key.upper()
    selected_prop = next(
        (prop for prop in prop_analysis or [] if str(prop.get('stat', '')).upper() == str(selected_stat).upper()),
        (prop_analysis or [{}])[0] if prop_analysis else {},
    )
    opponent = (upcoming_game_context or {}).get('opponent') or ''
    game = (upcoming_game_context or {}).get('game') or {}
    selected_floor = factors.get(f'{selected_stat}_FLOOR')
    selected_avg = factors.get(f'{selected_stat}_SEASON')
    role_note = f"Minutes {factors.get('MIN_AVG', '-')} avg, floor {factors.get('MIN_FLOOR', '-')}, ceiling {factors.get('MIN_CEIL', '-')}."
    if factors.get('MIN_CONSISTENCY'):
        role_note = f"{role_note} Role tag: {factors.get('MIN_CONSISTENCY')}."

    matchup_row = None
    for section in split_sections or []:
        if section.get('title') == 'Vs Upcoming Opponent' and section.get('rows'):
            matchup_row = section['rows'][0]
            break

    prop_tabs = []
    seen_stats = set()
    for prop in sorted(prop_analysis or [], key=lambda item: (str(item.get('stat')) != str(selected_stat), -float(item.get('confidence', 0) or 0))):
        stat = str(prop.get('stat') or '').upper()
        if not stat or stat in seen_stats:
            continue
        seen_stats.add(stat)
        prop_tabs.append({
            'stat': stat,
            'line': _decision_stat_value(prop.get('line')),
            'direction': str(prop.get('best_direction') or '').upper() or '-',
            'hit_rate': _decision_stat_value(prop.get('hit_rate'), '%'),
            'over_rate': _decision_stat_value(prop.get('over_rate'), '%'),
            'under_rate': _decision_stat_value(prop.get('under_rate'), '%'),
            'avg': _decision_stat_value(prop.get('avg')),
            'market': prop.get('market_summary') or prop.get('market_gate_note') or '',
            'grade': prop.get('grade') or '',
        })
        if len(prop_tabs) >= 6:
            break

    if not prop_tabs and selected_stat:
        prop_tabs.append({
            'stat': selected_stat,
            'line': _decision_stat_value(selected_line),
            'direction': '-',
            'hit_rate': '-',
            'over_rate': '-',
            'under_rate': '-',
            'avg': _decision_stat_value(selected_avg),
            'market': '',
            'grade': '',
        })

    sport_questions = {
        'nba': 'Does the role support the line tonight?',
        'wnba': 'Does the rotation and market depth support the line tonight?',
        'mlb': 'Does the matchup environment support the prop tonight?',
        'nfl': 'Does the game script support the needed volume?',
    }

    return {
        'sport_key': sport_key,
        'sport_label': sport_label,
        'question': sport_questions.get(sport_key, sport_questions['nba']),
        'tonight': [
            {
                'label': 'Tonight',
                'value': f"vs {team_display_name(opponent, sport_key=sport_key)}" if opponent else 'No listed game',
                'note': f"{game.get('Time', 'TBD')} | {'Home' if (upcoming_game_context or {}).get('is_home') else 'Road' if (upcoming_game_context or {}).get('is_home') is False else 'Site TBD'}",
            },
            {
                'label': 'Line vs Floor',
                'value': f"{selected_stat} {_decision_stat_value(selected_line)}",
                'note': f"Floor {_decision_stat_value(selected_floor)} | Avg {_decision_stat_value(selected_avg)}",
            },
            {
                'label': 'Role',
                'value': factors.get('MIN_CONSISTENCY') or 'Tracked',
                'note': role_note,
            },
            {
                'label': 'Market',
                'value': selected_prop.get('play_verdict') or selected_prop.get('market_gate') or 'Review',
                'note': selected_prop.get('market_summary') or selected_prop.get('rank_explanation') or 'Use current book count and line range before firing.',
            },
        ],
        'prop_tabs': prop_tabs,
        'matchup': [
            {
                'label': 'Vs This Defense',
                'value': f"{selected_stat} {_decision_stat_value(matchup_row.get(selected_stat.lower()) if matchup_row else None)}" if matchup_row else 'Limited sample',
                'note': f"{matchup_row.get('gp')} games vs upcoming opponent" if matchup_row else 'Opponent-specific player sample appears here when game logs exist.',
                'plan': 'Free',
            },
            {
                'label': 'Game Script',
                'value': selected_prop.get('volatility_flag') or 'Check spread',
                'note': selected_prop.get('volatility_note') or selected_prop.get('featured_risk_note') or 'Spread, total, and blowout risk should confirm the role.',
                'plan': 'Pro',
            },
            {
                'label': 'Role/Usage',
                'value': f"{player_context.get('current_team_games', '-')} team games",
                'note': f"Sample: {player_context.get('sample_label', 'current')}." + (f" Injury: {injury_info.get('short_label') or injury_info.get('status')}." if injury_info else ''),
                'plan': 'Pro',
            },
            {
                'label': 'Player vs Player',
                'value': 'Sharp layer',
                'note': 'Defender and direct matchup history belong behind the higher-value Sharp/Elite gate.',
                'plan': 'Sharp',
            },
        ],
    }


def build_team_decision_context(team, sport_key, team_logs, players, schedule=None, odds_df=None):
    sport_key = normalize_sport_access_key(sport_key or 'nba')
    sport_label = sport_key.upper()
    upcoming_context = _find_upcoming_game_for_team(schedule, team) if schedule is not None else {}
    opponent = upcoming_context.get('opponent') or ''
    game = upcoming_context.get('game') or {}
    market = {}
    if odds_df is not None and not odds_df.empty and game:
        market_lookup = build_game_market_lookup(odds_df)
        away = normalize_team_for_filter(game.get('Away', ''))
        home = normalize_team_for_filter(game.get('Home', ''))
        game_date = str(game.get('Date', '') or '')
        market = market_lookup.get((game_date, away, home)) or market_lookup.get(('any', away, home)) or {}

    leaders = sorted(players or [], key=lambda item: item.get('PTS', 0), reverse=True)[:3]
    leader_note = ' / '.join(f"{row.get('name')} {row.get('PTS', '-')}" for row in leaders) if leaders else 'No current rotation sample.'
    team_averages = {
        'pts': _average_column(team_logs, 'PTS'),
        'reb': _average_column(team_logs, 'REB'),
        'ast': _average_column(team_logs, 'AST'),
        'threes': _average_column(team_logs, '3PM'),
        'min': _average_column(team_logs, 'MIN'),
    }
    question_map = {
        'nba': 'What does this team do to prop and game-total decisions?',
        'wnba': 'What does this team do to prop decisions when rotation and market depth matter?',
        'mlb': 'Does this lineup pressure the opposing pitcher and total?',
        'nfl': 'What do scheme and game script do to position props?',
    }
    market_summary = format_game_market_summary(market, game.get('Home')) if market else ''
    environment = classify_prop_game_environment(
        market.get('total') if market else None,
        market.get('spread') if market else None,
        sport=sport_label,
    ) if market else {}

    return {
        'sport_key': sport_key,
        'sport_label': sport_label,
        'question': question_map.get(sport_key, question_map['nba']),
        'does': [
            {'label': 'Scoring Shape', 'value': _decision_stat_value(team_averages['pts']), 'note': 'Average player scoring output in the current roster sample.'},
            {'label': 'Ball Movement', 'value': _decision_stat_value(team_averages['ast']), 'note': 'Assist environment for guards, wings, and combo props.'},
            {'label': 'Glass', 'value': _decision_stat_value(team_averages['reb']), 'note': 'Rebound context for frontcourt and PRA decisions.'},
            {'label': 'Rotation Leaders', 'value': f"{len(players or [])} players", 'note': leader_note},
        ],
        'allows': [
            {'label': 'Position Defense', 'value': 'Matchup lens', 'note': 'Opponent position-defense rankings plug into this row as the defensive table matures.', 'plan': 'Free'},
            {'label': 'Roster Depth', 'value': 'Pro layer', 'note': 'Usage, injuries, and teammate-out bumps are Pro team-page context.', 'plan': 'Pro'},
            {'label': 'Team vs Player', 'value': 'Sharp layer', 'note': 'Inline player-vs-this-defense intersections belong here and on player pages.', 'plan': 'Sharp'},
        ],
        'tonight': [
            {
                'label': 'Opponent',
                'value': f"vs {team_display_name(opponent, sport_key=sport_key)}" if opponent else 'No listed game',
                'note': f"{game.get('Time', 'TBD')} | {'Home' if upcoming_context.get('is_home') else 'Road' if upcoming_context.get('is_home') is False else 'Site TBD'}",
            },
            {'label': 'Market', 'value': market_summary or 'No market yet', 'note': environment.get('note') or 'Total, spread, and book context appears here when odds are present.'},
            {'label': 'Volatility', 'value': environment.get('label') or 'Normal', 'note': 'Use this before trusting player volume, blowout-sensitive props, or totals.'},
        ],
    }

def build_tonights_card(postseason_matchups, top_plays, best_by_series=None):
    if not postseason_matchups:
        return []

    top_plays = [
        play for play in (top_plays or [])
        if str(play.get('play_verdict', 'PLAY')).upper() == 'PLAY'
    ]

    def attack_count(profile):
        return sum(1 for row in profile.get('stats', []) if row.get('verdict') == 'Attack')

    def defense_edge_count(profile):
        return sum(1 for row in profile.get('stats', []) if row.get('verdict') == 'Defense Edge')

    def format_pct(value):
        if value is None or pd.isna(value):
            return None
        return int(round(float(value)))

    def build_angle_reason(play):
        direction = str(play.get('direction', '') or '').upper()
        same_side_rate = play.get('live_line_over_rate') if direction == 'OVER' else play.get('live_line_under_rate')
        opposite_rate = play.get('live_line_under_rate') if direction == 'OVER' else play.get('live_line_over_rate')
        games = int(play.get('live_line_games', 0) or 0)
        current_run_side = str(play.get('current_run_side', '') or '').strip().lower()
        current_streak = int(play.get('current_streak', 0) or 0)
        move_label = str(play.get('move_label', '') or '').strip()
        book_count = int(play.get('book_count', 0) or 0)
        range_gap = play.get('range_gap')
        support_bits = []

        if same_side_rate is not None and games >= 3:
            support_bits.append(
                f"{direction.title()} hit {format_pct(same_side_rate)}% at this line in {games} {('playoff' if games != 1 else 'playoff')} games."
            )
        elif games >= 3 and opposite_rate is not None:
            support_bits.append(
                f"The opposite side has only landed {format_pct(opposite_rate)}% of the time across {games} games."
            )

        if current_streak >= 2 and current_run_side == direction.lower():
            support_bits.append(f"Current {current_run_side} run: {current_streak} straight.")
        elif current_streak >= 3 and current_run_side in {'over', 'under'}:
            support_bits.append(f"Recent {current_run_side} run is the main caution flag.")

        if move_label:
            support_bits.append(f"Market note: {move_label.lower()}.")
        elif book_count >= 2 and range_gap is not None and not pd.isna(range_gap) and float(range_gap) >= 0.5:
            support_bits.append(f"Books still disagree by {float(range_gap):g}, so line shopping matters.")

        guardrail_note = str(play.get('guardrail_note', '') or '').strip()
        if guardrail_note and ('conflicts' in guardrail_note.lower() or 'trim' in guardrail_note.lower()):
            support_bits.append(guardrail_note[:1].upper() + guardrail_note[1:])

        if not support_bits:
            market_note = str(play.get('market_view_note', '') or '').strip()
            public_note = str(play.get('public_trend_note', '') or '').strip()
            situations = [str(tag).strip() for tag in (play.get('tags') or []) if str(tag).strip()]
            if market_note:
                support_bits.append(market_note)
            elif public_note:
                support_bits.append(public_note)
            elif situations:
                support_bits.append(f"Support stack: {', '.join(situations[:2]).lower()}.")
            else:
                support_bits.append("Role, matchup, and current line history all support the angle.")

        return ' '.join(support_bits[:3]).strip()

    def team_play_priority(play):
        stat_priority = {'REB': 0, '3PM': 1, 'AST': 2, 'PTS': 3, 'STL': 4, 'BLK': 5}
        return (
            -float(play.get('hit_rate', 0) or 0),
            stat_priority.get(str(play.get('stat', '')).upper(), 9),
            str(play.get('player', ''))
        )

    deduped_games = {}
    for game in postseason_matchups:
        if game.get('bucket') != 'today':
            continue
        away = normalize_team_for_filter(game.get('Away', ''))
        home = normalize_team_for_filter(game.get('Home', ''))
        if not away or not home:
            continue
        key = game.get('series_id') or '-'.join(sorted([away, home]))
        current = deduped_games.get(key)
        current_has_market = bool(current and current.get('market_summary'))
        candidate_has_market = bool(game.get('market_summary'))
        if current is None or (candidate_has_market and not current_has_market):
            deduped_games[key] = game

    tonight_cards = []
    for game in deduped_games.values():
        away = normalize_team_for_filter(game.get('Away', ''))
        home = normalize_team_for_filter(game.get('Home', ''))
        if not away or not home:
            continue

        profiles = game.get('matchup_profiles') or []
        away_profile = next((profile for profile in profiles if normalize_team_for_filter(profile.get('offense_team', '')) == away), {})
        home_profile = next((profile for profile in profiles if normalize_team_for_filter(profile.get('offense_team', '')) == home), {})

        away_attack = attack_count(away_profile)
        home_attack = attack_count(home_profile)
        away_defense = defense_edge_count(away_profile)
        home_defense = defense_edge_count(home_profile)
        total = game.get('market_total')
        sample_context = game.get('sample_context') or {}
        sample_label = str(sample_context.get('label') or 'Loaded sample')
        sample_reason = str(sample_context.get('reason') or 'This is the active sample driving the matchup read.')
        round_label = str(sample_context.get('round_label') or game.get('series_label') or 'Tonight')

        if home_attack - away_attack >= 2:
            side_lean = home
            side_reason = f"{home} has the cleaner offensive matchup profile."
        elif away_attack - home_attack >= 2:
            side_lean = away
            side_reason = f"{away} has the cleaner offensive matchup profile."
        elif 'leans live' in str(home_profile.get('summary', '')).lower() and 'balanced' in str(away_profile.get('summary', '')).lower():
            side_lean = home
            side_reason = f"{home} has the cleaner scoring path, while {away} looks more balanced than explosive."
        elif 'leans live' in str(away_profile.get('summary', '')).lower() and 'balanced' in str(home_profile.get('summary', '')).lower():
            side_lean = away
            side_reason = f"{away} has the cleaner scoring path, while {home} looks more balanced than explosive."
        else:
            side_lean = "Tight game"
            side_reason = "Neither side owns a huge profile edge, so the pressure spots matter more."

        if total is not None and total >= 217:
            total_lean = "More open scoring environment"
            total_reason = "The loaded total and both offensive profiles point to a more playable scoring game."
        elif total is not None and total <= 214:
            total_lean = "Lower-scoring environment"
            total_reason = "The market and matchup shape both lean toward a tighter playoff game."
        elif away_attack >= 2 and home_attack >= 2:
            total_lean = "More open scoring environment"
            total_reason = "Both offenses have real paths, so this is the better game for action."
        elif away_defense + home_defense >= 2:
            total_lean = "Lower-scoring environment"
            total_reason = "At least one side has a real defensive clamp point, which can choke off pace."
        else:
            total_lean = "Mixed total environment"
            total_reason = "Some live offensive paths exist, but not enough for a clean game-total conviction."

        if total_lean == "Lower-scoring environment":
            avoid_note = "Avoid forcing too many points overs here."
        elif not game.get('market_summary'):
            avoid_note = "Refresh the game-line feed before treating any side or total number as final."
        else:
            avoid_note = "Avoid weak bench spikes and keep the card centered on role-backed angles."

        game_plays = []
        for play in top_plays:
            if not play.get('plays_today'):
                continue
            if normalize_team_for_filter(play.get('team', '')) not in {away, home}:
                continue
            game_plays.append(play)

        deduped_plays = {}
        for play in sorted(game_plays, key=team_play_priority):
            key = (
                str(play.get('player', '')).strip(),
                normalize_team_for_filter(play.get('team', '')),
                str(play.get('stat', '')).strip(),
                str(play.get('line', '')).strip(),
                str(play.get('direction', '')).strip(),
            )
            if key not in deduped_plays:
                deduped_plays[key] = {
                    'label': f"{play.get('player')} {play.get('stat')} {play.get('direction')} {play.get('line')}",
                    'player': play.get('player'),
                    'confidence': int(round(float(play.get('confidence', play.get('hit_rate', 0)) or 0))),
                    'reason': build_angle_reason(play),
                    'team': play.get('team'),
                    'direction': play.get('direction'),
                    'verdict': str(play.get('play_verdict', 'PLAY')).upper(),
                    'verdict_note': str(play.get('play_verdict_note', '') or '').strip(),
                    'weight_profile': str(play.get('weight_profile', 'regular') or 'regular'),
                    'series_game_number': int(play.get('series_game_number', 0) or 0),
                    'volatility_flag': str(play.get('volatility_flag', 'STABLE') or 'STABLE').upper(),
                    'market_gate': str(play.get('market_gate', 'CLEAR') or 'CLEAR').upper(),
                    'bet_tier': build_bet_tier(play),
                    'bet_tier_explanation': explain_bet_tier_label(build_bet_tier(play).get('label', '')),
                    'profile_explanation': explain_profile_stack(
                        play.get('weight_profile', 'regular'),
                        play.get('volatility_flag', 'STABLE'),
                        play.get('market_gate', 'CLEAR'),
                    ),
                    'market_summary': build_compact_prop_market_summary(
                        draftkings_line=play.get('draftkings_line'),
                        vegas_line=play.get('vegas_line'),
                        line_low=play.get('line_low'),
                        line_high=play.get('line_high'),
                        best_book=play.get('best_book', ''),
                        book_count=play.get('book_count', 0),
                        current_line=play.get('current_line', play.get('line')),
                    ),
                }

        angle_cards = list(deduped_plays.values())[:4]
        if not angle_cards and best_by_series and game.get('series_id'):
            for play in best_by_series:
                if play.get('series_id') != game.get('series_id'):
                    continue
                if float(play.get('confidence', 0) or 0) < 75:
                    continue
                angle_cards.append({
                    'label': f"{play.get('player')} {play.get('stat')} {play.get('direction')} {play.get('line')}",
                    'player': play.get('player'),
                    'confidence': int(round(float(play.get('confidence', 0) or 0))),
                    'reason': str(play.get('support_note') or 'Series shortlist fallback while the live prop board catches up.'),
                    'team': play.get('team'),
                    'direction': play.get('direction'),
                    'verdict': 'PLAY',
                    'verdict_note': 'Series shortlist fallback',
                    'bet_tier_explanation': 'Fallback shortlist means this angle is on the board for context, but it still needs live market confirmation.',
                    'profile_explanation': 'This fallback angle is leaning more on series context than on a fresh fully-loaded market profile.',
                    'market_summary': '',
                })
                if len(angle_cards) >= 2:
                    break

        driver_tags = []
        driver_tags.append(sample_label.upper())
        for tag in (game.get('matchup_profile_tags') or [])[:2]:
            if tag:
                driver_tags.append(str(tag).upper())
        if game.get('series_status'):
            driver_tags.append(str(game.get('series_status')).upper().replace('.', ''))
        if total is not None:
            driver_tags.append(f"TOTAL {total}")
        driver_tags = dedupe_preserve_order(driver_tags)[:4]

        tonight_cards.append({
            'title': f"{away} @ {home}",
            'series_status': game.get('series_status') or 'Tonight',
            'time': game.get('Time', ''),
            'series_label': game.get('series_label', 'Tonight'),
            'market_summary': game.get('market_summary') or 'Market feed waiting',
            'market_loaded': bool(game.get('market_summary')),
            'market_updated': str(game.get('market', {}).get('last_updated', '') or '').strip(),
            'sample_label': sample_label,
            'sample_reason': explain_sample_read(sample_label, sample_reason),
            'round_label': round_label,
            'side_lean': side_lean,
            'side_reason': side_reason,
            'total_lean': total_lean,
            'total_reason': total_reason,
            'avoid_note': avoid_note,
            'summary': game.get('matchup_profile_summary') or side_reason,
            'driver_tags': driver_tags,
            'driver_tag_details': [
                {'label': tag, 'meaning': explain_dashboard_label(tag)}
                for tag in driver_tags
            ],
            'angles': angle_cards,
            'href': f"/matchup/{away}-{home}?postseason=1",
            'series_href': f"/series/{game.get('series_id')}?postseason=1" if game.get('series_id') else f"/matchup/{away}-{home}?postseason=1",
            'tone': 'accent' if total_lean == 'More open scoring environment' else 'blue'
        })

    return sorted(
        tonight_cards,
        key=lambda card: (0 if card.get('market_loaded') else 1, card.get('title', ''))
    )


def build_nba_market_watch(props_df, upcoming, top_plays):
    if props_df is None or props_df.empty:
        return {'movers': [], 'splits': []}

    today_games = upcoming.get('today', []) if isinstance(upcoming, dict) else []
    today_teams = {
        normalize_team_for_filter(game.get('Away', ''))
        for game in today_games
        if normalize_team_for_filter(game.get('Away', ''))
    } | {
        normalize_team_for_filter(game.get('Home', ''))
        for game in today_games
        if normalize_team_for_filter(game.get('Home', ''))
    }
    if not today_teams:
        return {'movers': [], 'splits': []}

    game_context = {}
    for game in today_games:
        away = normalize_team_for_filter(game.get('Away', ''))
        home = normalize_team_for_filter(game.get('Home', ''))
        if not away or not home:
            continue
        market_spread = pd.to_numeric(pd.Series([game.get('market_spread')]), errors='coerce').iloc[0]
        away_spread = -float(market_spread) if pd.notna(market_spread) else None
        home_spread = float(market_spread) if pd.notna(market_spread) else None
        for team, opponent, spread in (
            (away, home, away_spread),
            (home, away, home_spread),
        ):
            game_context[team] = {
                'game_label': f'{away} @ {home}',
                'opponent': opponent,
                'game_total': game.get('market_total'),
                'team_spread': spread,
            }

    working = props_df.copy()
    if 'Team' not in working.columns:
        return {'movers': [], 'splits': []}
    working['Team'] = working['Team'].fillna('').astype(str).str.upper()
    working = working[working['Team'].isin(today_teams)].copy()
    if working.empty:
        return {'movers': [], 'splits': []}

    grouped_lookup = build_prop_market_groups(working)
    anchor = dedupe_props_to_anchor_book(working)
    if anchor.empty:
        return {'movers': [], 'splits': []}

    top_play_lookup = {}
    for play in top_plays or []:
        if not play.get('plays_today'):
            continue
        key = (
            str(play.get('player', '')).strip(),
            normalize_team_for_filter(play.get('team', '')),
            str(play.get('stat', '')).strip().upper(),
        )
        current = top_play_lookup.get(key)
        if current is None or float(play.get('hit_rate', 0) or 0) > float(current.get('hit_rate', 0) or 0):
            top_play_lookup[key] = play

    movers = []
    splits = []
    for _, row in anchor.iterrows():
        team = normalize_team_for_filter(row.get('Team', ''))
        if team not in today_teams:
            continue
        player = str(row.get('Player', '')).strip()
        stat = str(row.get('Stat', '')).strip().upper()
        play_ref = top_play_lookup.get((player, team, stat), {})
        direction = str(play_ref.get('direction', 'OVER')).strip().upper() or 'OVER'
        confidence = float(play_ref.get('hit_rate', 0) or 0)

        market_ctx = build_prop_multi_book_context(row, direction, grouped_lookup)
        current_line = pd.to_numeric(pd.Series([row.get('CurrentLine', row.get('Line'))]), errors='coerce').iloc[0]
        open_line = pd.to_numeric(pd.Series([row.get('OpenLine')]), errors='coerce').iloc[0]
        prior_line = pd.to_numeric(pd.Series([row.get('CloseLine')]), errors='coerce').iloc[0]
        opening_move = round(float(current_line) - float(open_line), 1) if pd.notna(current_line) and pd.notna(open_line) else None
        snapshot_move = round(float(current_line) - float(prior_line), 1) if pd.notna(current_line) and pd.notna(prior_line) else None
        line_low = market_ctx.get('line_low')
        line_high = market_ctx.get('line_high')
        range_gap = round(float(line_high) - float(line_low), 1) if line_low is not None and line_high is not None else None

        tone = 'blue'
        move_label = ''
        move_note = ''
        if snapshot_move is not None and abs(snapshot_move) >= 0.5:
            if snapshot_move < 0:
                move_label = 'Line down'
                tone = 'accent'
            else:
                move_label = 'Line up'
                tone = 'copper'
            moved_toward_play = None
            if confidence:
                moved_toward_play = (direction == 'OVER' and snapshot_move < 0) or (direction == 'UNDER' and snapshot_move > 0)
                move_note = 'The market moved toward the current model side.' if moved_toward_play else 'The market moved against the current model side.'
                tone = 'accent' if moved_toward_play else 'danger'
            else:
                move_note = 'Current number differs from the prior snapshot.'
        elif opening_move is not None and abs(opening_move) >= 0.5:
            move_label = 'Open shift'
            move_note = 'Current number has drifted from the opener.'
            tone = 'copper'
            moved_toward_play = None
        else:
            moved_toward_play = None

        move_teaching_note = build_market_move_teaching_note(
            direction,
            snapshot_move=snapshot_move,
            opening_move=opening_move,
            moved_toward_play=moved_toward_play,
        )
        split_teaching_note = build_market_split_teaching_note(
            book_count=market_ctx.get('book_count') or 0,
            range_gap=range_gap,
        )

        display = {
            'player': player,
            'team': team,
            'stat': stat,
            'line': round(float(current_line), 1) if pd.notna(current_line) else row.get('Line'),
            'direction': direction,
            'confidence': int(round(confidence)) if confidence else None,
            'open_line': round(float(open_line), 1) if pd.notna(open_line) else None,
            'current_line': round(float(current_line), 1) if pd.notna(current_line) else None,
            'prior_line': round(float(prior_line), 1) if pd.notna(prior_line) else None,
            'opening_move': opening_move,
            'snapshot_move': snapshot_move,
            'range_gap': range_gap,
            'book_count': int(market_ctx.get('book_count') or 0),
            'best_book': market_ctx.get('best_book'),
            'line_low': line_low,
            'line_high': line_high,
            'note': market_ctx.get('book_comparison_note') or '',
            'move_label': move_label,
            'move_note': move_note,
            'move_teaching_note': move_teaching_note,
            'tone': tone,
            'game_label': game_context.get(team, {}).get('game_label', ''),
            'opponent': game_context.get(team, {}).get('opponent', ''),
            'game_total': game_context.get(team, {}).get('game_total'),
            'team_spread': game_context.get(team, {}).get('team_spread'),
            'split_teaching_note': split_teaching_note,
        }

        if (snapshot_move is not None and abs(snapshot_move) >= 0.5) or (opening_move is not None and abs(opening_move) >= 0.5):
            movers.append(display)
        if display['book_count'] >= 2 and range_gap is not None and range_gap >= 0.5:
            splits.append(display)

    movers = sorted(
        movers,
        key=lambda item: (
            -(1 if item.get('confidence') is not None else 0),
            -float(item.get('confidence') or 0),
            -abs(float(item.get('snapshot_move') or item.get('opening_move') or 0)),
            str(item.get('player', ''))
        )
    )[:8]
    splits = sorted(
        splits,
        key=lambda item: (
            -(1 if item.get('confidence') is not None else 0),
            -float(item.get('confidence') or 0),
            -float(item.get('range_gap') or 0),
            -float(item.get('book_count') or 0),
            str(item.get('player', ''))
        )
    )[:8]

    # --- Synthesis layer ---
    synthesis = _build_market_watch_synthesis(movers, splits)
    return {'movers': movers, 'splits': splits, 'synthesis': synthesis}


def _build_market_watch_synthesis(movers, splits):
    """Derive pattern summary and action read from sorted mover/split lists."""
    from collections import Counter
    if not movers and not splits:
        return None

    all_items = movers + splits

    # Stat distribution
    stat_counts = Counter(item.get('stat', '') for item in all_items if item.get('stat'))
    top_stat = stat_counts.most_common(1)[0] if stat_counts else None

    # Move direction (movers only)
    move_values = [float(m.get('snapshot_move') or m.get('opening_move') or 0) for m in movers]
    ups = sum(1 for value in move_values if value > 0)
    downs = sum(1 for value in move_values if value < 0)

    # Most active game
    game_counts = Counter(item.get('game_label', '') for item in all_items if item.get('game_label'))
    top_game = game_counts.most_common(1)[0] if game_counts else None

    # Model alignment buckets
    aligned   = [m for m in movers if m.get('tone') == 'accent']
    conflicted = [m for m in movers if m.get('tone') == 'danger']

    # Pattern bullets
    pattern = []
    if top_stat and top_stat[1] > 1:
        pattern.append(f"{top_stat[1]} of {len(all_items)} reads are {top_stat[0]} props")
    if movers:
        if ups > downs:
            pattern.append(f"{ups} moved up, {downs} moved down")
        elif downs > ups:
            pattern.append(f"{downs} moved down, {ups} moved up")
        else:
            pattern.append("Movement split evenly up and down")
    if top_game:
        pattern.append(f"{top_game[0]} is carrying most movement")
    if aligned:
        pattern.append(f"{len(aligned)} mover{'s' if len(aligned) != 1 else ''} aligned with model")
    if conflicted:
        pattern.append(f"{len(conflicted)} mover{'s' if len(conflicted) != 1 else ''} moving against model")

    # Best candidate: highest confidence among aligned movers
    best_candidate = None
    best_score = -1
    for m in aligned:
        score = float(m.get('confidence') or 0) + abs(float(m.get('snapshot_move') or m.get('opening_move') or 0)) * 10
        if score > best_score:
            best_score = score
            best_candidate = m

    # Caution prop: first conflicted mover
    caution_prop = conflicted[0] if conflicted else None

    # Action guidance
    if aligned and not conflicted:
        action_summary = "Market and model are moving together. Confirm against floor and reliability before acting."
    elif conflicted and not aligned:
        action_summary = "Market is moving against the model. Do not chase these lines - wait for model confirmation."
    elif aligned and conflicted:
        action_summary = "Mixed signals tonight. Filter to aligned movers only and skip the conflicts."
    else:
        action_summary = "Movement is neutral tonight. Stick to floor anchors and avoid chasing line shifts."

    best_candidate_label = None
    if best_candidate:
        best_candidate_label = (
            f"{best_candidate['player']} {best_candidate['stat']} {best_candidate.get('direction','OVER')} "
            f"{best_candidate.get('line','')} - market and model agree"
        )

    caution_label = None
    if caution_prop:
        caution_label = (
            f"{caution_prop['player']} {caution_prop['stat']} - market moved against model"
        )

    return {
        'pattern': pattern,
        'action_summary': action_summary,
        'best_candidate': best_candidate_label,
        'caution': caution_label,
        'aligned_count': len(aligned),
        'conflicted_count': len(conflicted),
        'mover_count': len(movers),
        'split_count': len(splits),
    }


def build_market_move_teaching_note(direction, snapshot_move=None, opening_move=None, moved_toward_play=None):
    direction = str(direction or '').strip().upper()
    if snapshot_move is not None and abs(float(snapshot_move)) >= 0.5:
        if moved_toward_play is True:
            return (
                "Sharp lesson: books usually move toward a side when money or information agrees with it. "
                "The read may still be right, but the better number is already gone, so the edge is smaller now."
            )
        if moved_toward_play is False:
            return (
                "Sharp lesson: books usually move away from your side when money or information disagrees with it. "
                "That is a warning sign that your model needs a stronger cushion before this should stay playable."
            )
        if float(snapshot_move) > 0:
            return (
                "Sharp lesson: a higher live line usually means the market is pricing in a stronger over environment than it had earlier."
            )
        return (
            "Sharp lesson: a lower live line usually means the market is pricing in a weaker scoring/output environment than it had earlier."
        )

    if opening_move is not None and abs(float(opening_move)) >= 0.5:
        if direction in {'OVER', 'UNDER'}:
            return (
                "Sharp lesson: when the current number has drifted from the opener, books are telling you the first price was not the final truth. "
                "Always compare what the market is charging now versus what it charged first."
            )
        return (
            "Sharp lesson: movement from the opener usually means the market re-priced the prop after action or new information."
        )

    return ""


def build_market_split_teaching_note(book_count=0, range_gap=None):
    try:
        gap = float(range_gap) if range_gap is not None else None
    except Exception:
        gap = None
    books = int(book_count or 0)
    if books >= 2 and gap is not None and gap >= 0.5:
        return (
            "Sharp lesson: when books are spread across different numbers, the market has not fully settled yet. "
            "That usually means you should shop aggressively and trust the best number more than the average number."
        )
    if books <= 1:
        return (
            "Sharp lesson: a one-book line is weaker confirmation because you cannot see whether the rest of the market agrees."
        )
    return ""


def build_rank_explanation(play):
    play = play or {}
    direction = str(play.get('direction', '') or '').strip().upper()
    stat = str(play.get('stat', '') or '').strip().upper()
    situations = {str(tag).strip().upper() for tag in (play.get('situations') or []) if str(tag).strip()}
    weighted_rate = play.get('weighted_over_rate') if direction == 'OVER' else play.get('weighted_under_rate')
    live_line_games = int(play.get('live_line_games', 0) or 0)
    current_run_side = str(play.get('current_run_side', '') or '').strip().lower()
    current_streak = int(play.get('current_streak', 0) or 0)
    market_gate = str(play.get('market_gate', 'CLEAR') or 'CLEAR').upper()
    volatility_flag = str(play.get('volatility_flag', 'STABLE') or 'STABLE').upper()
    return_impact_pct = float(play.get('return_impact_pct', 0) or 0)
    move_label = str(play.get('move_label', '') or '').strip()
    range_gap = pd.to_numeric(pd.Series([play.get('range_gap')]), errors='coerce').iloc[0]
    public_trend_note = str(play.get('public_trend_note', '') or '').strip()

    if market_gate == 'HOLD':
        return "Ranked lower because the line moved against this side, so the market is asking for stronger proof before it should be trusted."
    if market_gate == 'SPLIT MARKET':
        return "Ranked lower because books are split on the number, so line shopping matters more than the average market read."
    if direction == 'OVER' and (return_impact_pct >= 6 or {'RETURN SQUEEZE', 'RETURN-', 'RETURN PRESSURE'} & situations):
        return "Ranked lower because a returning teammate can cut into this player's role, touches, or minutes."
    if direction == 'OVER' and {'ROLE DOWN', 'MIN-', 'ROLE FADE'} & situations:
        return "Ranked lower because the recent role or minutes trend is moving the wrong way for an over."
    if direction == 'UNDER' and {'ROLE UP', 'MIN+', 'ROLE SUPPORT'} & situations:
        return "Ranked lower because the player's role and minutes are improving, which makes the under less stable."
    if is_zero_required_under_play(play):
        return "Ranked cautiously because this under only cashes if the player records a literal zero, so one event breaks the bet."
    if live_line_games >= 4 and weighted_rate is not None and current_streak >= 2 and current_run_side == direction.lower():
        return f"Ranked here because this side has been landing consistently at this line and the current run still supports it."
    if live_line_games >= 4 and weighted_rate is not None:
        return f"Ranked here because the player has a solid hit rate at this number across a usable sample of recent games."
    if {'ROLE UP', 'MIN+', 'L5 SURGE'} & situations and direction == 'OVER':
        return "Ranked here because the player's role and minutes have been trending up, and recent form supports the over."
    if {'L5 FADE', 'COLD'} & situations and direction == 'UNDER':
        return "Ranked here because recent production has cooled off, which supports the under."
    if move_label:
        return f"Ranked here because the broader support is still intact, but the market note is {move_label.lower()}."
    if pd.notna(range_gap) and float(range_gap) >= 0.5:
        return "Ranked here, but the books are spread apart enough that you should trust the best number more than the average one."
    if public_trend_note:
        return public_trend_note
    return "Ranked here because the role, matchup, and recent sample all support this side more than the alternatives."


def build_novice_tag_sentence(play):
    play = play or {}
    situations = {str(tag).strip().upper() for tag in (play.get('situations') or []) if str(tag).strip()}
    market_gate = str(play.get('market_gate', 'CLEAR') or 'CLEAR').upper()
    volatility_flag = str(play.get('volatility_flag', 'STABLE') or 'STABLE').upper()
    direction = str(play.get('direction', '') or '').strip().upper()
    return_impact_pct = float(play.get('return_impact_pct', 0) or 0)

    parts = []
    if {'ROLE UP', 'MIN+'} & situations:
        parts.append("This player's role and minutes have been trending up")
    elif {'ROLE DOWN', 'MIN-'} & situations:
        parts.append("This player's role or minutes have been trending down")
    elif {'ROLE HOLD'} & situations:
        parts.append("This player's role has been stable lately")

    if {'L5 SURGE', 'HOT', 'STREAK+'} & situations:
        parts.append("recent form has been supportive")
    elif {'L5 FADE', 'COLD', 'STREAK-'} & situations:
        parts.append("recent form has been working against this angle")

    if direction == 'OVER' and return_impact_pct >= 6:
        parts.append("a returning teammate is a real cap on upside")

    if market_gate == 'CLEAR':
        parts.append("the market signal is clean")
    elif market_gate == 'SPLIT MARKET':
        parts.append("the market is split, so line shopping matters")
    elif market_gate == 'HOLD':
        parts.append("the market moved the wrong way, so caution is warranted")

    if volatility_flag == 'HIGH':
        parts.append("the stat is highly volatile")
    elif volatility_flag == 'ELEVATED':
        parts.append("the stat is a little more volatile than normal")

    if not parts:
        return "The role, trend, and market context are all fairly neutral, so this rank mostly comes from the underlying hit-rate sample."

    sentence = ', and '.join(parts[:2]) if len(parts) == 2 else ', '.join(parts[:-1]) + (', and ' + parts[-1] if len(parts) > 2 else parts[0])
    return sentence[:1].upper() + sentence[1:] + '.'


def build_featured_risk_note(play):
    play = play or {}
    situations = {str(tag).strip().upper() for tag in (play.get('situations') or []) if str(tag).strip()}
    market_gate = str(play.get('market_gate', 'CLEAR') or 'CLEAR').upper()
    volatility_flag = str(play.get('volatility_flag', 'STABLE') or 'STABLE').upper()
    range_gap = pd.to_numeric(pd.Series([play.get('range_gap')]), errors='coerce').iloc[0]
    return_impact_pct = float(play.get('return_impact_pct', 0) or 0)
    injury_status = str(play.get('injury_status', '') or '').strip().upper()

    if is_zero_required_under_play(play):
        return "This only wins if the player records a literal zero, so one assist, steal, or block kills the ticket."
    if injury_status in {'QUESTIONABLE', 'GTD', 'PROBABLE'}:
        return "This relies on the player being active and close to normal workload. Status or minutes changes would weaken the edge."
    if market_gate == 'SPLIT MARKET' or (pd.notna(range_gap) and float(range_gap) >= 0.5):
        return "The market is split, so the edge depends heavily on getting the best available number before the books settle."
    if market_gate == 'HOLD':
        return "The line moved against this side, which means the market is pushing back on the read."
    if return_impact_pct >= 6 or {'RETURN SQUEEZE', 'RETURN PRESSURE', 'RETURN-'} & situations:
        return "This relies on the current role holding. A returning teammate could cut minutes, touches, or usage enough to break the edge."
    if {'ROLE DOWN', 'MIN-', 'ROLE FADE'} & situations:
        return "This relies on the player holding current opportunity. Any dip in minutes or role would make the edge much thinner."
    if volatility_flag == 'HIGH':
        return "This stat is highly volatile, so one outlier game event can swing the result quickly."
    if volatility_flag == 'ELEVATED':
        return "This stat has more variance than a normal prop, so the edge is real but less stable than the raw score suggests."
    if 'LINE HISTORY CONFLICT' in situations or 'LINE HISTORY CAP' in situations:
        return "The recent support is there, but the longer line history still pushes back on this angle."
    return "This works best if the player's current role and game environment stay the same from open to tip."


def build_series_context_teaching_note(series_score, series_label='', series_type=''):
    series_score = series_score or {}
    series_type = str(series_type or '').strip().lower()
    if series_type not in {'playoff', 'play-in', 'postseason'}:
        return "Single-game matchup: treat the market and role context as more important than any old head-to-head history."

    team_a_wins = int(series_score.get('team_a_wins', 0) or 0)
    team_b_wins = int(series_score.get('team_b_wins', 0) or 0)
    games_played = team_a_wins + team_b_wins
    label = str(series_label or 'this series').strip()
    if games_played == 0:
        return f"Teaching note: {label} is just opening, so regular-season history matters less than current roles, injuries, and the opening market."
    if games_played == 1:
        return "Teaching note: after one playoff game, the first adjustment is usually about minutes, coverage, and rotation changes more than pure trend data."
    if games_played >= 4:
        return "Teaching note: once a series gets deeper, rotation patterns and coaching adjustments usually matter more than generic season-long averages."
    return "Teaching note: early in a series, use the current playoff sample as a guide, but keep checking whether the market and role context are still moving."


def annotate_teaching_fields(play):
    updated = dict(play or {})
    updated['rank_explanation'] = build_rank_explanation(updated)
    updated['novice_tag_sentence'] = build_novice_tag_sentence(updated)
    updated['featured_risk_note'] = build_featured_risk_note(updated)
    return updated


def annotate_teaching_fields_batch(rows):
    return [annotate_teaching_fields(row) for row in (rows or [])]


def build_featured_nba_top_plays(live_props, limit=20, min_confidence=70):
    deduped_top_plays = {}
    live_props = attach_promotion_signals_to_props(
        [dict(prop) for prop in (live_props or [])],
        sport='NBA',
        score_fields=('confidence',),
    )
    eligible_props = [
        p for p in live_props
        if float(p.get('confidence', 0) or 0) >= min_confidence
        and str(p.get('play_verdict', 'PLAY')).upper() == 'PLAY'
        and 'LINE HISTORY CAP' not in (p.get('guardrail_tags') or [])
    ]
    for play in eligible_props:
        row = {
            'player': play.get('player'),
            'team': play.get('team'),
            'stat': play.get('stat'),
            'line': play.get('line'),
            'direction': play.get('direction'),
            'hit_rate': float(play.get('confidence', 0) or 0),
            'confidence': float(play.get('confidence', 0) or 0),
            'plays_today': play.get('plays_today'),
            'plays_tomorrow': play.get('plays_tomorrow'),
            'tags': play.get('situations', []),
            'situations': play.get('situations', []),
            'guardrail_tags': play.get('guardrail_tags', []),
            'guardrail_note': play.get('guardrail_note', ''),
            'live_line_over_rate': play.get('live_line_over_rate'),
            'live_line_under_rate': play.get('live_line_under_rate'),
            'live_line_games': play.get('live_line_games'),
            'weighted_over_rate': play.get('weighted_over_rate'),
            'weighted_under_rate': play.get('weighted_under_rate'),
            'current_run_side': play.get('current_run_side'),
            'current_streak': play.get('current_streak'),
            'move_label': play.get('move_label', ''),
            'tone': play.get('tone', 'muted'),
            'book_count': play.get('book_count', 0),
            'range_gap': play.get('range_gap'),
            'open_line': play.get('open_line'),
            'current_line': play.get('current_line'),
            'prior_line': play.get('close_line'),
            'draftkings_line': play.get('draftkings_line'),
            'vegas_line': play.get('vegas_line'),
            'line_low': play.get('line_low'),
            'line_high': play.get('line_high'),
            'best_book': str(play.get('best_book', '') or '').strip(),
            'book_comparison_note': str(play.get('book_comparison_note', '') or '').strip(),
            'market_view_note': ((play.get('market_view') or {}).get('note', '') if isinstance(play.get('market_view'), dict) else ''),
            'public_trend_note': play.get('public_trend_note', ''),
            'play_verdict': str(play.get('play_verdict', 'PLAY')).upper(),
            'play_verdict_note': str(play.get('play_verdict_note', '') or '').strip(),
            'weight_profile': str(play.get('weight_profile', 'regular') or 'regular'),
            'component_weights': play.get('component_weights', {}) or {},
            'series_game_number': int(play.get('series_game_number', 0) or 0),
            'series_weight': float(play.get('series_weight', 0) or 0),
            'volatility_flag': str(play.get('volatility_flag', 'STABLE') or 'STABLE').upper(),
            'volatility_note': str(play.get('volatility_note', '') or '').strip(),
            'market_gate': str(play.get('market_gate', 'CLEAR') or 'CLEAR').upper(),
            'market_gate_note': str(play.get('market_gate_note', '') or '').strip(),
            'role_label': play.get('role_label'),
            'return_impact_pct': play.get('return_impact_pct'),
            'promotion_signal': play.get('promotion_signal', 'STANDARD'),
            'promotion_reason': play.get('promotion_reason', ''),
            'promotion_boost': play.get('promotion_boost', 0.0),
            'missed_winner_count': play.get('missed_winner_count', 0),
        }
        row['market_summary'] = build_compact_prop_market_summary(
            draftkings_line=row.get('draftkings_line'),
            vegas_line=row.get('vegas_line'),
            line_low=row.get('line_low'),
            line_high=row.get('line_high'),
            best_book=row.get('best_book'),
            book_count=row.get('book_count', 0),
            current_line=row.get('current_line', row.get('line')),
        )
        row['bet_tier'] = build_bet_tier(row)
        key = (
            str(row.get('player', '')).strip().lower(),
            normalize_team_for_filter(row.get('team', '')),
            str(row.get('stat', '')).strip().upper(),
            str(row.get('direction', '')).strip().upper(),
        )
        current = deduped_top_plays.get(key)
        if current is None:
            deduped_top_plays[key] = row
            continue
        current_score = float(current.get('hit_rate', 0) or 0)
        row_score = float(row.get('hit_rate', 0) or 0)
        if row_score > current_score:
            deduped_top_plays[key] = row
            continue
        if row_score == current_score:
            current_gap = float(current.get('range_gap', 0) or 0)
            row_gap = float(row.get('range_gap', 0) or 0)
            if row_gap > current_gap:
                deduped_top_plays[key] = row
    featured_rows = sorted(deduped_top_plays.values(), key=lambda x: x['hit_rate'], reverse=True)
    props_refresh_meta = get_props_refresh_meta(load_props())
    refresh_age_hours = props_refresh_meta.get('age_hours')
    if refresh_age_hours is not None and refresh_age_hours > 6:
        return []
    runtime = {
        'injury_context_age_hours': build_injury_context_age(load_injuries(), load_return_overrides()),
        'warning_history_map': build_warning_history_map('nba_contradictions'),
    }
    cleared_rows = []
    for row in featured_rows:
        candidate = dict(row)
        candidate['_is_featured'] = True
        audit = audit_props([candidate], runtime=runtime)
        if audit['failure_count'] == 0:
            row['featured_checked_at'] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            row['featured_source_age_hours'] = refresh_age_hours
            cleared_rows.append(annotate_teaching_fields(row))
    return cleared_rows[:limit]


def apply_nba_contradiction_board_guardrails(rows):
    if not rows:
        return []
    runtime = {
        'injury_context_age_hours': build_injury_context_age(load_injuries(), load_return_overrides()),
        'warning_history_map': build_warning_history_map('nba_contradictions'),
    }
    guarded_rows = []
    for row in rows:
        candidate = dict(row)
        candidate['_is_featured'] = False
        audit = audit_props([candidate], runtime=runtime)
        failures = audit.get('failures', []) or []
        if not failures:
            guarded_rows.append(row)
            continue

        updated = dict(row)
        failure_rules = [str(item.rule).strip() for item in failures if str(item.rule).strip()]
        failure_messages = [str(item.message).strip() for item in failures if str(item.message).strip()]
        fail_note = "Contradiction QC: " + " | ".join(failure_messages[:3])
        updated['contradiction_fail_rules'] = failure_rules
        updated['contradiction_fail_note'] = fail_note
        existing_tags = [str(tag).strip() for tag in (updated.get('guardrail_tags') or []) if str(tag).strip()]
        updated['guardrail_tags'] = list(dict.fromkeys(existing_tags + ['CONTRADICTION QC'] + failure_rules))
        updated['guardrail_note'] = fail_note
        updated['play_verdict'] = 'PASS'
        updated['play_verdict_note'] = fail_note
        updated['confidence'] = min(float(updated.get('confidence', 0) or 0), 59.9)
        updated['grade'] = get_grade(updated['confidence'])
        guarded_rows.append(updated)
    return guarded_rows


def _wnba_verdict_sort_rank(row):
    verdict = str((row or {}).get('play_verdict', 'PLAY') or 'PLAY').upper()
    return {'PLAY': 2, 'CONFLICTED': 1, 'PASS': 0}.get(verdict, 0)


def sort_wnba_rows_for_promotion(rows, score_field='market_confidence'):
    rows = list(rows or [])
    rows.sort(
        key=lambda item: (
            -_wnba_verdict_sort_rank(item),
            -float(item.get('promotion_boost') or 0),
            -float(item.get(score_field) or 0),
            -float(item.get('market_prob') or 0),
            -float(item.get('lean_gap') or 0),
            item.get('player') or '',
            item.get('stat') or '',
        )
    )
    return rows


def _mlb_verdict_sort_rank(row):
    verdict = str((row or {}).get('play_verdict', 'PLAY') or 'PLAY').upper()
    return {'PLAY': 2, 'CONFLICTED': 1, 'PASS': 0}.get(verdict, 0)


