def summarize_prop_market_watch(prop_row, direction, confidence_pct=0, grouped_lookup=None):
    market_ctx = build_prop_multi_book_context(prop_row, direction, grouped_lookup)
    current_line = pd.to_numeric(pd.Series([prop_row.get('CurrentLine', prop_row.get('current_line', prop_row.get('Line', prop_row.get('line'))))]), errors='coerce').iloc[0]
    open_line = pd.to_numeric(pd.Series([prop_row.get('OpenLine', prop_row.get('open_line'))]), errors='coerce').iloc[0]
    prior_line = pd.to_numeric(pd.Series([prop_row.get('CloseLine', prop_row.get('close_line'))]), errors='coerce').iloc[0]
    opening_move = round(float(current_line) - float(open_line), 1) if pd.notna(current_line) and pd.notna(open_line) else None
    snapshot_move = round(float(current_line) - float(prior_line), 1) if pd.notna(current_line) and pd.notna(prior_line) else None
    line_low = market_ctx.get('line_low', prop_row.get('line_low'))
    line_high = market_ctx.get('line_high', prop_row.get('line_high'))
    range_gap = round(float(line_high) - float(line_low), 1) if line_low is not None and line_high is not None else None

    tone = 'blue'
    move_label = ''
    move_note = ''
    if snapshot_move is not None and abs(snapshot_move) >= 0.5:
        if snapshot_move < 0:
            move_label = 'Line down'
            tone = 'accent'
        else:
            move_label = 'Line up'
            tone = 'copper'
        moved_toward_play = (str(direction).upper() == 'OVER' and snapshot_move < 0) or (str(direction).upper() == 'UNDER' and snapshot_move > 0)
        if confidence_pct:
            move_note = 'Moved toward the model side.' if moved_toward_play else 'Moved against the model side.'
            tone = 'accent' if moved_toward_play else 'danger'
        else:
            move_note = 'Current number differs from the prior snapshot.'
    elif opening_move is not None and abs(opening_move) >= 0.5:
        move_label = 'Open shift'
        move_note = 'Current number has drifted from the opener.'
        tone = 'copper'
        moved_toward_play = None
    else:
        moved_toward_play = None

    move_teaching_note = build_market_move_teaching_note(
        direction,
        snapshot_move=snapshot_move,
        opening_move=opening_move,
        moved_toward_play=moved_toward_play,
    )
    split_teaching_note = build_market_split_teaching_note(
        book_count=market_ctx.get('book_count', prop_row.get('book_count')) or 0,
        range_gap=range_gap,
    )

    return {
        'open_line': round(float(open_line), 1) if pd.notna(open_line) else None,
        'current_line': round(float(current_line), 1) if pd.notna(current_line) else None,
        'prior_line': round(float(prior_line), 1) if pd.notna(prior_line) else None,
        'opening_move': opening_move,
        'snapshot_move': snapshot_move,
        'move_label': move_label,
        'move_note': move_note,
        'move_teaching_note': move_teaching_note,
        'tone': tone,
        'book_count': int(market_ctx.get('book_count', prop_row.get('book_count')) or 0),
        'best_book': market_ctx.get('best_book', prop_row.get('best_book')),
        'line_low': line_low,
        'line_high': line_high,
        'range_gap': range_gap,
        'book_comparison_note': market_ctx.get('book_comparison_note') or prop_row.get('book_comparison_note') or '',
        'split_teaching_note': split_teaching_note,
    }


def build_matchup_market_watch(matchup_props):
    if not matchup_props:
        return {'movers': [], 'splits': []}

    movers = []
    splits = []
    for prop in matchup_props:
        watch = summarize_prop_market_watch(prop, prop.get('direction', 'OVER'), prop.get('confidence', 0))
        item = {
            'player': prop.get('player'),
            'team': prop.get('team'),
            'stat': prop.get('stat'),
            'line': prop.get('line'),
            'direction': prop.get('direction'),
            'confidence': int(round(float(prop.get('confidence', 0) or 0))) if prop.get('confidence') is not None else None,
            **watch,
        }
        if (watch.get('snapshot_move') is not None and abs(float(watch['snapshot_move'])) >= 0.5) or (watch.get('opening_move') is not None and abs(float(watch['opening_move'])) >= 0.5):
            movers.append(item)
        if watch.get('book_count', 0) >= 2 and watch.get('range_gap') is not None and float(watch['range_gap']) >= 0.5:
            splits.append(item)

    movers = sorted(movers, key=lambda item: (-float(item.get('confidence') or 0), -abs(float(item.get('snapshot_move') or item.get('opening_move') or 0)), str(item.get('player', ''))))[:5]
    splits = sorted(splits, key=lambda item: (-float(item.get('confidence') or 0), -float(item.get('range_gap') or 0), -float(item.get('book_count') or 0), str(item.get('player', ''))))[:5]
    return {'movers': movers, 'splits': splits}

def build_matchup_editorial(away, home, series_label, series_score, matchup_profiles, current_market, matchup_props):
    away_profile = next((profile for profile in matchup_profiles if normalize_team_for_filter(profile.get('offense_team', '')) == normalize_team_for_filter(away)), {})
    home_profile = next((profile for profile in matchup_profiles if normalize_team_for_filter(profile.get('offense_team', '')) == normalize_team_for_filter(home)), {})

    def attack_count(profile):
        return sum(1 for row in profile.get('stats', []) if row.get('verdict') == 'Attack')

    away_attack = attack_count(away_profile)
    home_attack = attack_count(home_profile)
    total = current_market.get('total') if current_market else None

    if home_attack - away_attack >= 2:
        side_lean = home
        side_reason = f"{home} has the cleaner offensive profile in this matchup."
    elif away_attack - home_attack >= 2:
        side_lean = away
        side_reason = f"{away} has the cleaner offensive profile in this matchup."
    elif 'leans live' in str(home_profile.get('summary', '')).lower() and 'balanced' in str(away_profile.get('summary', '')).lower():
        side_lean = home
        side_reason = f"{home} looks more likely to win with skill and shot creation, while {away} leans more physical."
    elif 'leans live' in str(away_profile.get('summary', '')).lower() and 'balanced' in str(home_profile.get('summary', '')).lower():
        side_lean = away
        side_reason = f"{away} looks more likely to win with skill and shot creation, while {home} leans more physical."
    else:
        side_lean = 'Tight game'
        side_reason = "Neither side owns a huge profile edge, so game script matters more than raw talent labels."

    if total is not None and not pd.isna(total) and float(total) >= 217:
        total_lean = 'More open scoring environment'
        total_reason = "The loaded total and profile shape both support a more playable scoring game."
    elif total is not None and not pd.isna(total) and float(total) <= 214:
        total_lean = 'Lower-scoring environment'
        total_reason = "The loaded total and matchup shape both lean toward a tighter playoff game."
    elif away_attack >= 2 and home_attack >= 2:
        total_lean = 'More open scoring environment'
        total_reason = "Both offenses have real paths, so this is the better game for pace and action."
    else:
        total_lean = 'Mixed total environment'
        total_reason = "There are some live scoring paths here, but not enough for a clean total read."

    angle_cards = []
    seen = set()
    for prop in matchup_props:
        key = (
            str(prop.get('player', '')).strip().lower(),
            str(prop.get('team', '')).strip().upper(),
            str(prop.get('stat', '')).strip().upper(),
            float(prop.get('line', 0) or 0),
            str(prop.get('direction', '')).strip().upper(),
        )
        if key in seen:
            continue
        seen.add(key)
        angle_cards.append({
            'label': f"{prop.get('player')} {prop.get('stat')} {prop.get('direction')} {prop.get('line')}",
            'player': prop.get('player'),
            'confidence': int(round(float(prop.get('confidence', 0) or 0))),
            'best_book': prop.get('best_book'),
            'book_count': prop.get('book_count'),
            'line_low': prop.get('line_low'),
            'line_high': prop.get('line_high'),
            'move_label': prop.get('move_label'),
            'open_line': prop.get('open_line'),
            'current_line': prop.get('current_line'),
        })
        if len(angle_cards) >= 3:
            break

    if total_lean == 'Lower-scoring environment':
        avoid_note = "Avoid forcing too many points overs in a game like this."
    elif not current_market:
        avoid_note = "Refresh the line feed before trusting any side or total number as final."
    else:
        avoid_note = "Avoid random bench spikes and keep the card centered on role-backed angles."

    driver_tags = []
    if series_label:
        driver_tags.append(series_label.upper())
    if series_score and series_score.get('status'):
        driver_tags.append(str(series_score.get('status')).upper().replace('.', ''))
    if total is not None and not pd.isna(total):
        driver_tags.append(f"TOTAL {float(total):g}")
    for tag in [away_profile.get('summary', ''), home_profile.get('summary', '')]:
        text = str(tag).strip()
        if text:
            driver_tags.append(text)
    cleaned_tags = []
    for tag in driver_tags:
        if tag and tag not in cleaned_tags:
            cleaned_tags.append(tag)

    market_watch = build_matchup_market_watch(matchup_props)

    return {
        'side_lean': side_lean,
        'side_reason': side_reason,
        'total_lean': total_lean,
        'total_reason': total_reason,
        'angles': angle_cards,
        'avoid_note': avoid_note,
        'driver_tags': cleaned_tags[:4],
        'market_updated': str(current_market.get('last_updated', '') or '').strip() if current_market else '',
        'market_watch': market_watch,
    }


def build_matchup_decision_cards(matchup_props):
    def usable(prop):
        return str(prop.get('play_verdict', 'PLAY') or 'PLAY').upper() == 'PLAY'

    def score(prop):
        return (
            float(prop.get('confidence') or 0),
            float(prop.get('book_count') or 0),
            float(prop.get('matchup_games') or 0),
        )

    def card(prop, label):
        if not prop:
            return None
        direction = str(prop.get('direction') or '').upper()
        return {
            'label': label,
            'player': prop.get('player'),
            'team': prop.get('team'),
            'stat': prop.get('stat'),
            'line': prop.get('line'),
            'direction': direction,
            'confidence': int(round(float(prop.get('confidence') or 0))),
            'market': prop.get('market_summary') or prop.get('book_comparison_note') or '',
            'note': prop.get('baseline_reason') or prop.get('public_trend_note') or prop.get('injury_context_note') or '',
            'tone': 'danger' if label == 'Avoid' else 'blue' if direction == 'UNDER' else 'accent',
        }

    playable = [prop for prop in matchup_props if usable(prop)]
    avoid_candidates = [
        prop for prop in matchup_props
        if not usable(prop)
        or str(prop.get('play_verdict', '')).upper() in {'PASS', 'CONFLICTED'}
        or float(prop.get('confidence') or 0) < 58
    ]
    best_over = max([prop for prop in playable if str(prop.get('direction')).upper() == 'OVER'], key=score, default=None)
    best_under = max([prop for prop in playable if str(prop.get('direction')).upper() == 'UNDER'], key=score, default=None)
    stabilizers = [
        prop for prop in playable
        if str(prop.get('direction')).upper() == 'UNDER'
        or str(prop.get('stat')).upper() in {'REB', 'AST', 'STL', 'BLK'}
    ]
    best_floor = max(stabilizers, key=score, default=None)
    avoid = max(avoid_candidates, key=score, default=None)

    return {
        'best_over': card(best_over, 'Best Over'),
        'best_under': card(best_under, 'Best Under'),
        'best_floor': card(best_floor, 'Best Stabilizer'),
        'avoid': card(avoid, 'Avoid'),
        'playable_count': len(playable),
        'avoid_count': len(avoid_candidates),
    }


def sports_today_ts():
    """'Today' for schedule/game-date buckets, as a normalized pd.Timestamp.

    Schedule rows are dated in the server's timezone (UTC), so anchor 'today' to
    server-local time to stay consistent with how games are dated in the schedule.
    """
    return pd.Timestamp(datetime.now().strftime('%Y-%m-%d'))


def sports_today_date():
    """'Today' for schedule/game-date buckets, as a date object."""
    return sports_today_ts().date()


def get_upcoming_games(schedule, days=7, allowed_teams=None):
    if schedule.empty or 'Date' not in schedule.columns:
        return {'today': [], 'tomorrow': [], 'upcoming': [], 'all_teams': set()}
    
    today = sports_today_ts()
    tomorrow = today + pd.Timedelta(days=1)
    upcoming_start = today + pd.Timedelta(days=2)
    upcoming_end = today + pd.Timedelta(days=max(days - 1, 2))
    
    games = {'today': [], 'tomorrow': [], 'upcoming': [], 'all_teams': set()}
    
    for _, row in schedule.iterrows():
        game_date_raw = row.get('Date', '')
        game_date = pd.to_datetime(game_date_raw, errors='coerce')
        away = str(row.get('Away', '')).strip()
        home = str(row.get('Home', '')).strip()
        time = str(row.get('Time', 'TBD'))
        
        if not away or not home or away == 'nan' or home == 'nan':
            continue
        if pd.isna(game_date):
            continue
        if allowed_teams and (not team_in_filter(away, allowed_teams) or not team_in_filter(home, allowed_teams)):
            continue
        
        normalized_date = game_date.normalize()
        game_info = {'Away': away, 'Home': home, 'Time': time, 'Date': normalized_date.strftime('%Y-%m-%d')}
        
        if normalized_date == today:
            games['today'].append(game_info)
            games['all_teams'].add(away)
            games['all_teams'].add(home)
        elif normalized_date == tomorrow:
            games['tomorrow'].append(game_info)
            games['all_teams'].add(away)
            games['all_teams'].add(home)
        elif upcoming_start <= normalized_date <= upcoming_end:
            games['upcoming'].append(game_info)
            games['all_teams'].add(away)
            games['all_teams'].add(home)

    for bucket_name in ['today', 'tomorrow', 'upcoming']:
        games[bucket_name].sort(key=lambda game: (game['Date'], game['Time'], game['Away'], game['Home']))
    
    return games


def format_game_day_label(date_str):
    game_date = pd.to_datetime(date_str, errors='coerce')
    if pd.isna(game_date):
        return date_str
    return f"{game_date.strftime('%a')} {game_date.month}/{game_date.day}"


def build_team_game_lookup(upcoming):
    lookup = {}
    for bucket_name in ['today', 'tomorrow', 'upcoming']:
        for game in upcoming.get(bucket_name, []):
            game_date = game.get('Date', '')
            day_label = format_game_day_label(game_date)
            away = game.get('Away', '')
            home = game.get('Home', '')
            time = game.get('Time', 'TBD')
            for team, opponent, site in [(away, home, 'away'), (home, away, 'home')]:
                if not team:
                    continue
                game_info = {
                    'bucket': bucket_name,
                    'date': game_date,
                    'label': day_label,
                    'opponent': opponent,
                    'site': site,
                    'time': time,
                    'matchup': f"{away} @ {home}",
                    'market': game.get('market', {}),
                    'market_summary': game.get('market_summary', ''),
                    'market_total': game.get('market_total'),
                    'market_spread': game.get('market_spread'),
                    'market_book': game.get('market_book')
                }
                team_keys = []
                normalized_team = normalize_team_for_filter(team)
                if team:
                    team_keys.append(str(team).strip())
                if normalized_team and normalized_team not in team_keys:
                    team_keys.append(normalized_team)
                full_team = TEAM_ABBR_TO_NAME.get(normalized_team, '')
                if full_team and full_team not in team_keys:
                    team_keys.append(full_team)

                normalized_opponent = normalize_team_for_filter(opponent)
                opponent_display = TEAM_ABBR_TO_NAME.get(normalized_opponent, opponent) if normalized_opponent else opponent
                for key in team_keys:
                    if key and key not in lookup:
                        lookup[key] = {
                            **game_info,
                            'opponent_abbr': normalized_opponent or opponent,
                            'opponent_display': opponent_display,
                            'opponent': opponent_display if key == normalized_team or key == full_team else normalized_opponent or opponent
                        }
    return lookup


def american_odds_to_implied_prob(american_odds):
    if american_odds in [None, '', 0] or pd.isna(american_odds):
        return None
    odds = float(american_odds)
    if odds > 0:
        return round(100 / (odds + 100), 4)
    return round(abs(odds) / (abs(odds) + 100), 4)


def prob_to_american_odds(probability):
    if probability is None:
        return None
    prob = float(probability)
    if prob <= 0 or prob >= 1:
        return None
    if prob >= 0.5:
        return int(round(-(prob / (1 - prob)) * 100))
    return int(round(((1 - prob) / prob) * 100))


def calculate_ev_percent(model_probability, american_odds):
    implied = american_odds_to_implied_prob(american_odds)
    if implied is None or model_probability is None:
        return None

    odds = float(american_odds)
    if odds > 0:
        profit_multiple = odds / 100
    else:
        profit_multiple = 100 / abs(odds)

    expected_value = (model_probability * profit_multiple) - (1 - model_probability)
    return round(expected_value * 100, 1)


def get_prop_market_price(prop_row, direction):
    direction_key = str(direction or '').upper()
    if direction_key == 'OVER':
        candidates = ['OverOdds', 'OverPrice', 'OddsOver', 'PriceOver']
    else:
        candidates = ['UnderOdds', 'UnderPrice', 'OddsUnder', 'PriceUnder']

    for column in candidates:
        if column in prop_row.index:
            value = prop_row.get(column)
            if pd.notna(value):
                return value
    return None


def get_prop_price_for_stage(prop_row, direction, stage='current'):
    direction_key = str(direction or '').upper()
    stage_key = str(stage or 'current').lower()
    if direction_key == 'OVER':
        mapping = {
            'open': ['OpenOverOdds'],
            'current': ['OverOdds', 'OverPrice', 'OddsOver', 'PriceOver'],
            'close': ['CloseOverOdds'],
            'bet': ['BetOverOdds']
        }
    else:
        mapping = {
            'open': ['OpenUnderOdds'],
            'current': ['UnderOdds', 'UnderPrice', 'OddsUnder', 'PriceUnder'],
            'close': ['CloseUnderOdds'],
            'bet': ['BetUnderOdds']
        }

    available_keys = set()
    if hasattr(prop_row, 'index'):
        available_keys = set(prop_row.index)
    elif isinstance(prop_row, dict):
        available_keys = set(prop_row.keys())

    for column in mapping.get(stage_key, []):
        if column in available_keys:
            value = prop_row.get(column)
            if pd.notna(value):
                return value
    return None


def get_prop_market_context(prop_row, direction, model_probability):
    current_price = get_prop_price_for_stage(prop_row, direction, 'current')
    open_price = get_prop_price_for_stage(prop_row, direction, 'open')
    close_price = get_prop_price_for_stage(prop_row, direction, 'close')
    bet_price = get_prop_price_for_stage(prop_row, direction, 'bet')

    current_line = pd.to_numeric(pd.Series([prop_row.get('CurrentLine', prop_row.get('Line'))]), errors='coerce').iloc[0]
    open_line = pd.to_numeric(pd.Series([prop_row.get('OpenLine')]), errors='coerce').iloc[0]
    close_line = pd.to_numeric(pd.Series([prop_row.get('CloseLine')]), errors='coerce').iloc[0]
    bet_line = pd.to_numeric(pd.Series([prop_row.get('BetLine')]), errors='coerce').iloc[0]

    implied_prob = american_odds_to_implied_prob(current_price)
    fair_price = prob_to_american_odds(model_probability)
    ev_pct = calculate_ev_percent(model_probability, current_price)
    edge_pct = round((model_probability - implied_prob) * 100, 1) if implied_prob is not None else None

    line_move = None
    if pd.notna(current_line) and pd.notna(open_line):
        line_move = round(float(current_line) - float(open_line), 1)

    clv_line = None
    if pd.notna(close_line) and pd.notna(bet_line):
        if str(direction or '').upper() == 'OVER':
            clv_line = round(float(close_line) - float(bet_line), 1)
        else:
            clv_line = round(float(bet_line) - float(close_line), 1)

    clv_price_pct = None
    close_implied = american_odds_to_implied_prob(close_price)
    bet_implied = american_odds_to_implied_prob(bet_price)
    if close_implied is not None and bet_implied is not None:
        clv_price_pct = round((close_implied - bet_implied) * 100, 1)

    model_prob_pct = round(float(model_probability) * 100, 1) if model_probability is not None else None
    market_gap_pct = round((model_prob_pct - (implied_prob * 100)), 1) if model_prob_pct is not None and implied_prob is not None else None

    market_view = {
        'label': 'No Market Price',
        'note': 'Model angle is there, but there is no live price to compare.',
        'tone': 'muted'
    }
    if model_prob_pct is not None and implied_prob is not None:
        if (ev_pct is not None and ev_pct <= -2) or (market_gap_pct is not None and market_gap_pct <= -5):
            market_view = {
                'label': 'Pass Despite Model',
                'note': 'The model may like the angle, but the current price is too sharp.',
                'tone': 'danger'
            }
        elif market_gap_pct is not None and market_gap_pct >= 8 and (ev_pct is None or ev_pct > 0):
            market_view = {
                'label': 'Model Strong vs Market',
                'note': 'The model is materially stronger than the book here. Best when the role and minutes are stable.',
                'tone': 'accent'
            }
        elif market_gap_pct is not None and market_gap_pct >= 3 and (ev_pct is None or ev_pct > 0):
            market_view = {
                'label': 'Slight Market Disagreement',
                'note': 'This lives in the gray area. The model is stronger than the book, but not by a huge margin.',
                'tone': 'copper'
            }
        elif market_gap_pct is not None and market_gap_pct <= -3:
            market_view = {
                'label': 'Market Sharper',
                'note': 'The book is less friendly than the model read. Better alt line or pass.',
                'tone': 'danger'
            }
        else:
            market_view = {
                'label': 'Aligned',
                'note': 'Model and market are mostly in line. Price matters more than narrative here.',
                'tone': 'blue'
            }

    return {
        'market_price': current_price,
        'open_price': open_price,
        'close_price': close_price,
        'bet_price': bet_price,
        'implied_prob': round(implied_prob * 100, 1) if implied_prob is not None else None,
        'fair_price': fair_price,
        'ev_pct': ev_pct,
        'edge_pct': edge_pct,
        'book': prop_row.get('Book', 'Manual'),
        'current_line': float(current_line) if pd.notna(current_line) else prop_row.get('Line'),
        'open_line': float(open_line) if pd.notna(open_line) else None,
        'close_line': float(close_line) if pd.notna(close_line) else None,
        'bet_line': float(bet_line) if pd.notna(bet_line) else None,
        'line_move': line_move,
        'clv_line': clv_line,
        'clv_price_pct': clv_price_pct,
        'model_prob': model_prob_pct,
        'market_gap_pct': market_gap_pct,
        'market_view': market_view
    }


def get_prop_market_group_key(prop_row):
    player = str(prop_row.get('Player', '') or '').strip()
    stat = str(prop_row.get('Stat', '') or '').strip()
    game = str(prop_row.get('Game', '') or '').strip()
    return (player, stat, game)


def build_prop_market_groups(props_df):
    groups = {}
    if props_df is None or props_df.empty:
        return groups
    group_cols = [col for col in ['Player', 'Stat', 'Game'] if col in props_df.columns]
    if len(group_cols) < 3:
        return groups
    for key, group in props_df.groupby(group_cols, dropna=False, sort=False):
        groups[key] = group.copy()
    return groups


def dedupe_props_to_anchor_book(props_df, preferred_books=None):
    if props_df is None or props_df.empty:
        return pd.DataFrame()
    preferred_books = preferred_books or ['DraftKings', 'Caesars', 'FanDuel', 'BetMGM']
    grouped = build_prop_market_groups(props_df)
    rows = []
    for _, group in grouped.items():
        selected = None
        if 'Book' in group.columns:
            book_lower = group['Book'].astype(str).str.lower()
            for preferred in preferred_books:
                matches = group[book_lower == preferred.lower()]
                if not matches.empty:
                    selected = matches.iloc[0]
                    break
        if selected is None:
            selected = group.iloc[0]
        rows.append(selected.to_dict())
    if not rows:
        return pd.DataFrame(columns=props_df.columns)
    return pd.DataFrame(rows)


def load_canonical_live_props(gamelogs=None, player_snapshot=None, current_team_overrides=None, preferred_books=None, require_fresh=True, max_age_hours=6):
    gamelogs = gamelogs if gamelogs is not None else load_gamelogs()
    player_snapshot = player_snapshot if player_snapshot is not None else load_player_snapshot()
    current_team_overrides = current_team_overrides if current_team_overrides is not None else load_current_team_overrides()
    raw_props, _ = load_live_props_feed(max_age_hours=max_age_hours, require_fresh=require_fresh)
    resolved_props = apply_current_team_context(raw_props, gamelogs, player_snapshot, current_team_overrides)
    return dedupe_props_to_anchor_book(resolved_props, preferred_books=preferred_books)


def build_multi_book_comparison_note(primary_book, vegas_line, primary_line, line_low, line_high, direction, best_book):
    notes = []
    primary_label = str(primary_book or 'Primary book').strip() or 'Primary book'
    if vegas_line is not None and primary_line is not None:
        try:
            delta = round(float(primary_line) - float(vegas_line), 1)
        except Exception:
            delta = 0
        if abs(delta) >= 0.5:
            if delta > 0:
                notes.append(f'{primary_label} is {abs(delta):g} higher than Caesars on this line.')
            else:
                notes.append(f'Caesars is {abs(delta):g} higher than {primary_label}.')
        else:
            notes.append(f'{primary_label} and Caesars are dealing basically the same line.')
    elif vegas_line is not None:
        notes.append('Caesars is loaded as the Vegas reference on this market.')
    else:
        notes.append(f'{primary_label} is loaded, but the Caesars reference is not available yet.')

    if line_low is not None and line_high is not None and line_high != line_low:
        notes.append(f'The market range is {line_low:g} to {line_high:g} across books.')

    if best_book:
        notes.append(f'Best {direction.lower()} price is currently at {best_book}.')
    return ' '.join(notes[:3]).strip()


def build_prop_multi_book_context(prop_row, direction, grouped_lookup=None):
    key = get_prop_market_group_key(prop_row)
    group = grouped_lookup.get(key) if grouped_lookup else None
    primary_book = str(prop_row.get('Book') or '').strip()
    primary_line = pd.to_numeric(pd.Series([prop_row.get('CurrentLine', prop_row.get('Line'))]), errors='coerce').iloc[0]

    if group is None or group.empty:
        draftkings_price = get_prop_price_for_stage(prop_row, direction, 'current')
        return {
            'book_count': 1 if primary_book else 0,
            'books': [primary_book] if primary_book else [],
            'primary_book': primary_book,
            'draftkings_line': round(float(primary_line), 1) if pd.notna(primary_line) else None,
            'draftkings_price': draftkings_price,
            'vegas_line': None,
            'vegas_price': None,
            'line_low': round(float(primary_line), 1) if pd.notna(primary_line) else None,
            'line_high': round(float(primary_line), 1) if pd.notna(primary_line) else None,
            'best_book': primary_book,
            'best_price': draftkings_price,
            'book_comparison_note': build_multi_book_comparison_note(primary_book, None, primary_line, primary_line, primary_line, direction, primary_book),
        }

    working = group.copy()
    for col in ['CurrentLine', 'Line', 'OverOdds', 'UnderOdds']:
        if col in working.columns:
            working[col] = pd.to_numeric(working[col], errors='coerce')

    vegas_rows = working[working['Book'].astype(str).str.lower() == 'caesars'] if 'Book' in working.columns else pd.DataFrame()
    vegas_line = None
    vegas_price = None
    if not vegas_rows.empty:
        vegas_row = vegas_rows.iloc[0]
        vegas_line = vegas_row.get('CurrentLine') if pd.notna(vegas_row.get('CurrentLine')) else vegas_row.get('Line')
        vegas_price = get_prop_price_for_stage(vegas_row, direction, 'current')

    draftkings_rows = working[working['Book'].astype(str).str.lower() == 'draftkings'] if 'Book' in working.columns else pd.DataFrame()
    draftkings_line = None
    draftkings_price = None
    if not draftkings_rows.empty:
        draftkings_row = draftkings_rows.iloc[0]
        draftkings_line = draftkings_row.get('CurrentLine') if pd.notna(draftkings_row.get('CurrentLine')) else draftkings_row.get('Line')
        draftkings_price = get_prop_price_for_stage(draftkings_row, direction, 'current')

    line_candidates = []
    for col in ['CurrentLine', 'Line']:
        if col in working.columns:
            for candidate in working[col].dropna().tolist():
                try:
                    line_candidates.append(float(candidate))
                except Exception:
                    continue
    line_low = min(line_candidates) if line_candidates else None
    line_high = max(line_candidates) if line_candidates else None

    direction_key = str(direction or '').upper()
    best_book = primary_book
    best_price = get_prop_price_for_stage(prop_row, direction, 'current')
    if direction_key == 'OVER' and 'OverOdds' in working.columns:
        priced = working[pd.notna(working['OverOdds'])]
        if not priced.empty:
            best_row = priced.sort_values('OverOdds', ascending=False).iloc[0]
            best_book = str(best_row.get('Book') or primary_book).strip()
            best_price = best_row.get('OverOdds')
    elif direction_key == 'UNDER' and 'UnderOdds' in working.columns:
        priced = working[pd.notna(working['UnderOdds'])]
        if not priced.empty:
            best_row = priced.sort_values('UnderOdds', ascending=False).iloc[0]
            best_book = str(best_row.get('Book') or primary_book).strip()
            best_price = best_row.get('UnderOdds')

    books = sorted([str(book).strip() for book in working['Book'].dropna().unique().tolist() if str(book).strip()]) if 'Book' in working.columns else []
    return {
        'book_count': len(books),
        'books': books,
        'primary_book': primary_book,
        'draftkings_line': round(float(draftkings_line), 1) if draftkings_line is not None and not pd.isna(draftkings_line) else (round(float(primary_line), 1) if pd.notna(primary_line) else None),
        'draftkings_price': draftkings_price,
        'vegas_line': round(float(vegas_line), 1) if vegas_line is not None and not pd.isna(vegas_line) else None,
        'vegas_price': vegas_price,
        'line_low': round(float(line_low), 1) if line_low is not None else None,
        'line_high': round(float(line_high), 1) if line_high is not None else None,
        'best_book': best_book,
        'best_price': best_price,
        'book_comparison_note': build_multi_book_comparison_note(primary_book, vegas_line, primary_line, line_low, line_high, direction, best_book),
    }


def get_player_projection_context(player_name, team, stat, player_logs, player_advanced, active_boosts=None, player_snapshot=None, return_impacts=None):
    context = {
        'projected_minutes': None,
        'minutes_delta': 0,
        'usage_pct': None,
        'ts_pct': None,
        'role_label': '',
        'projection_tags': [],
        'injury_boost_player': '',
        'injury_boost_status': '',
        'return_impact_pct': 0,
        'return_player': '',
        'return_status': '',
        'return_reason': '',
        'snapshot_consistency': None,
        'snapshot_tier': '',
        'snapshot_load_label': '',
        'snapshot_mins_trend': 0,
        'snapshot_stat_trend': 0,
        'snapshot_split_delta': 0,
        'snapshot_signal': ''
    }
    if player_logs.empty:
        return context

    if 'MIN' in player_logs.columns:
        mins = player_logs['MIN'].dropna()
        if not mins.empty:
            last_10 = mins.head(10).mean() if len(mins) >= 10 else mins.mean()
            last_5 = mins.head(5).mean() if len(mins) >= 5 else mins.mean()
            last_3 = mins.head(3).mean() if len(mins) >= 3 else mins.mean()
            projected = (last_10 * 0.2) + (last_5 * 0.4) + (last_3 * 0.4)
            season_minutes = mins.mean()
            context['projected_minutes'] = round(projected, 1)
            context['minutes_delta'] = round(projected - season_minutes, 1)
            if context['minutes_delta'] >= 2:
                context['projection_tags'].append('MIN UP')
            elif context['minutes_delta'] <= -2:
                context['projection_tags'].append('MIN DOWN')

    if not player_advanced.empty and 'Player' in player_advanced.columns:
        advanced_row = player_advanced[player_advanced['Player'] == player_name]
        if not advanced_row.empty:
            row = advanced_row.iloc[0]
            usage_pct = float(row.get('USG_PCT', 0)) * 100 if pd.notna(row.get('USG_PCT', 0)) else None
            ts_pct = float(row.get('TS_PCT', 0)) * 100 if pd.notna(row.get('TS_PCT', 0)) else None
            context['usage_pct'] = round(usage_pct, 1) if usage_pct is not None else None
            context['ts_pct'] = round(ts_pct, 1) if ts_pct is not None else None

            if usage_pct is not None:
                if usage_pct >= 28:
                    context['role_label'] = 'Primary'
                elif usage_pct >= 22:
                    context['role_label'] = 'Core'
                else:
                    context['role_label'] = 'Support'

    if active_boosts is not None and not active_boosts.empty:
        boosts = active_boosts[
            (active_boosts.get('Beneficiary') == player_name) &
            (active_boosts.get('Team') == team) &
            (active_boosts.get('Stat') == stat)
        ] if 'Beneficiary' in active_boosts.columns and 'Team' in active_boosts.columns and 'Stat' in active_boosts.columns else pd.DataFrame()
        if not boosts.empty:
            boost_row = boosts.iloc[0]
            boost_pct = float(boost_row.get('Boost_Pct', 0))
            context['injury_boost_player'] = str(boost_row.get('Key_Player_Out', '') or '')
            context['injury_boost_status'] = str(boost_row.get('Injury_Status', '') or '')
            if context['projected_minutes'] is not None:
                context['projected_minutes'] = round(context['projected_minutes'] + min(4, boost_pct / 8), 1)
            context['projection_tags'].append('INJ BOOST')

    if return_impacts is not None and not return_impacts.empty:
        suppressions = return_impacts[
            (return_impacts.get('Beneficiary') == player_name) &
            (return_impacts.get('Team') == team) &
            (return_impacts.get('Stat') == stat)
        ] if 'Beneficiary' in return_impacts.columns and 'Team' in return_impacts.columns and 'Stat' in return_impacts.columns else pd.DataFrame()
        if not suppressions.empty:
            suppression = suppressions.sort_values('Return_Impact_Pct', ascending=False).iloc[0]
            return_impact_pct = float(pd.to_numeric(suppression.get('Return_Impact_Pct', 0), errors='coerce') or 0)
            context['return_impact_pct'] = round(return_impact_pct, 1)
            context['return_player'] = str(suppression.get('Key_Player_Out', '') or '')
            context['return_status'] = str(suppression.get('Return_Status', '') or '')
            context['return_reason'] = str(suppression.get('Return_Reason', '') or '')
            if context['projected_minutes'] is not None and return_impact_pct > 0:
                if stat == 'AST':
                    minute_penalty = min(3.4, return_impact_pct / 8)
                elif stat in {'PTS', '3PM'}:
                    minute_penalty = min(2.6, return_impact_pct / 10)
                elif stat == 'REB':
                    minute_penalty = min(1.8, return_impact_pct / 16)
                else:
                    minute_penalty = min(1.2, return_impact_pct / 24)
                context['projected_minutes'] = round(max(0, context['projected_minutes'] - minute_penalty), 1)
            context['projection_tags'].append('RETURN RISK')
            if return_impact_pct >= 6:
                context['projection_tags'].append('RETURN-')

    snapshot_row = get_player_snapshot_row(player_snapshot, player_name, team)
    if snapshot_row is not None:
        stat_key = get_snapshot_stat_key(stat)
        consistency_score = snapshot_row.get('consistency_score')
        mins_trend = snapshot_row.get('mins_trend')
        stat_trend = snapshot_row.get(f'{stat_key}_pm_trend')
        split_delta = snapshot_row.get(f'split_core_delta_{stat_key}_10')
        snapshot_tier = snapshot_row.get('consistency_tier_10') or snapshot_row.get('consistency_tier') or ''
        load_label = snapshot_row.get('load_label_10') or snapshot_row.get('load_label_5') or ''

        if pd.notna(consistency_score):
            context['snapshot_consistency'] = round(float(consistency_score), 1)
        if pd.notna(mins_trend):
            context['snapshot_mins_trend'] = round(float(mins_trend), 3)
        if pd.notna(stat_trend):
            context['snapshot_stat_trend'] = round(float(stat_trend), 3)
        if pd.notna(split_delta):
            context['snapshot_split_delta'] = round(float(split_delta), 2)

        context['snapshot_tier'] = str(snapshot_tier).strip()
        context['snapshot_load_label'] = str(load_label).strip()

        signal_parts = []
        if context['snapshot_tier']:
            signal_parts.append(context['snapshot_tier'].replace(' Consistency', ''))
        if context['snapshot_load_label']:
            signal_parts.append(context['snapshot_load_label'])
        context['snapshot_signal'] = ' | '.join(signal_parts[:2])

        if context['snapshot_consistency'] is not None:
            if context['snapshot_consistency'] >= 82:
                context['projection_tags'].append('SNAP CONSIST+')
            elif context['snapshot_consistency'] <= 68:
                context['projection_tags'].append('SNAP CONSIST-')

        if context['snapshot_mins_trend'] >= 1:
            context['projection_tags'].append('SNAP MIN+')
            if context['projected_minutes'] is not None:
                context['projected_minutes'] = round(context['projected_minutes'] + min(1.5, context['snapshot_mins_trend'] * 0.35), 1)
        elif context['snapshot_mins_trend'] <= -1:
            context['projection_tags'].append('SNAP MIN-')
            if context['projected_minutes'] is not None:
                context['projected_minutes'] = round(max(0, context['projected_minutes'] + max(-1.5, context['snapshot_mins_trend'] * 0.35)), 1)

        if context['snapshot_stat_trend'] >= 0.05:
            context['projection_tags'].append('SNAP FORM+')
        elif context['snapshot_stat_trend'] <= -0.05:
            context['projection_tags'].append('SNAP FORM-')

        load_upper = context['snapshot_load_label'].upper()
        if 'HIGH' in load_upper or 'UP' in load_upper:
            context['projection_tags'].append('SNAP LOAD+')
        elif 'LOW' in load_upper or 'DOWN' in load_upper:
            context['projection_tags'].append('SNAP LOAD-')

    context['projection_tags'] = list(dict.fromkeys(context['projection_tags']))
    return context


def get_player_tracking_context(player_name, player_tracking, player_advanced):
    context = {
        'touches': None,
        'drives': None,
        'avg_speed': None,
        'distance_miles': None,
        'ts_pct': None,
        'ast_pct': None,
        'off_rating': None,
        'def_rating': None,
        'net_rating': None
    }

    if player_tracking is not None and not player_tracking.empty and 'Player' in player_tracking.columns:
        tracking_row = player_tracking[player_tracking['Player'] == player_name]
        if not tracking_row.empty:
            row = tracking_row.iloc[0]
            for src, key, digits in [
                ('TOUCHES', 'touches', 1),
                ('DRIVES', 'drives', 1),
                ('AVG_SPEED', 'avg_speed', 2),
                ('DIST_MILES', 'distance_miles', 1),
            ]:
                value = row.get(src)
                if pd.notna(value):
                    context[key] = round(float(value), digits)

    if player_advanced is not None and not player_advanced.empty and 'Player' in player_advanced.columns:
        advanced_row = player_advanced[player_advanced['Player'] == player_name]
        if not advanced_row.empty:
            row = advanced_row.iloc[0]
            for src, key, multiplier, digits in [
                ('TS_PCT', 'ts_pct', 100, 1),
                ('AST_PCT', 'ast_pct', 100, 1),
                ('OFF_RATING', 'off_rating', 1, 1),
                ('DEF_RATING', 'def_rating', 1, 1),
                ('NET_RATING', 'net_rating', 1, 1),
            ]:
                value = row.get(src)
                if pd.notna(value):
                    context[key] = round(float(value) * multiplier, digits)

    return context


def get_game_environment_adjustments(market, stat, site=None, role_label='', projected_minutes=None):
    adjustments = {
        'over_boost': 0,
        'under_boost': 0,
        'tags': [],
        'game_total': None,
        'team_spread': None,
        'game_environment': '',
        'market_summary': ''
    }
    if not market:
        return adjustments

    total = market.get('total')
    spread = market.get('spread')
    projected_minutes = projected_minutes or 0
    role_upper = str(role_label or '').upper()
    stat_upper = str(stat or '').upper()

    if total is not None and not pd.isna(total):
        total = float(total)
        adjustments['game_total'] = round(total, 1)
        if total >= 232:
            adjustments['tags'].append('PACE+')
            if stat_upper in {'PTS', 'AST', '3PM'}:
                adjustments['over_boost'] += 4
            elif stat_upper == 'REB':
                adjustments['over_boost'] += 2
        elif total >= 226:
            adjustments['tags'].append('GOOD TOTAL')
            if stat_upper in {'PTS', 'AST', '3PM'}:
                adjustments['over_boost'] += 2
        elif total <= 218:
            adjustments['tags'].append('PACE-')
            if stat_upper in {'PTS', 'AST', '3PM'}:
                adjustments['under_boost'] += 4
            elif stat_upper == 'REB':
                adjustments['under_boost'] += 2
        elif total <= 222:
            adjustments['tags'].append('LOW TOTAL')
            if stat_upper in {'PTS', 'AST', '3PM'}:
                adjustments['under_boost'] += 2

    if spread is not None and not pd.isna(spread):
        spread = float(spread)
        team_spread = spread if site == 'home' else -spread if site == 'away' else spread
        adjustments['team_spread'] = round(team_spread, 1)
        spread_abs = abs(team_spread)

        if spread_abs <= 4.5:
            adjustments['tags'].append('CLOSE SPREAD')
            if projected_minutes >= 26 or role_upper in {'PRIMARY', 'CORE'}:
                adjustments['over_boost'] += 2
        elif spread_abs >= 9:
            adjustments['tags'].append('BLOWOUT RISK')
            if stat_upper in {'PTS', 'AST', '3PM'} and (projected_minutes >= 28 or role_upper in {'PRIMARY', 'CORE'}):
                adjustments['under_boost'] += 3
            elif stat_upper == 'REB':
                adjustments['under_boost'] += 1

    summary_bits = []
    if adjustments['game_total'] is not None:
        summary_bits.append(f"O/U {adjustments['game_total']:g}")
    if adjustments['team_spread'] is not None:
        summary_bits.append(f"{adjustments['team_spread']:+g}")
    adjustments['game_environment'] = ' | '.join(summary_bits)
    adjustments['market_summary'] = format_game_market_summary(market)
    adjustments['tags'] = list(dict.fromkeys(adjustments['tags']))
    return adjustments


def get_projection_adjustments(projection_context, stat):
    adjustments = {'over_boost': 0, 'under_boost': 0, 'tags': []}
    minutes_delta = projection_context.get('minutes_delta', 0) or 0
    usage_pct = projection_context.get('usage_pct')
    ts_pct = projection_context.get('ts_pct')
    return_impact_pct = projection_context.get('return_impact_pct', 0) or 0
    snapshot_consistency = projection_context.get('snapshot_consistency')
    snapshot_mins_trend = projection_context.get('snapshot_mins_trend', 0) or 0
    snapshot_stat_trend = projection_context.get('snapshot_stat_trend', 0) or 0
    snapshot_load_label = (projection_context.get('snapshot_load_label') or '').upper()
    role_label = str(projection_context.get('role_label', '') or '').strip().upper()

    if minutes_delta >= 2:
        adjustments['over_boost'] += 3
        adjustments['tags'].append('PROJ MIN+')
    elif minutes_delta <= -2:
        adjustments['under_boost'] += 3
        adjustments['tags'].append('PROJ MIN-')

    if usage_pct is not None and stat in {'PTS', 'AST', '3PM'}:
        if usage_pct >= 27:
            adjustments['over_boost'] += 2
            adjustments['tags'].append('USG+')
        elif usage_pct <= 18:
            adjustments['under_boost'] += 2
            adjustments['tags'].append('USG-')

    if ts_pct is not None and stat in {'PTS', '3PM'}:
        if ts_pct >= 60:
            adjustments['over_boost'] += 1
            adjustments['tags'].append('EFF+')
        elif ts_pct <= 52:
            adjustments['under_boost'] += 1
            adjustments['tags'].append('EFF-')

    if snapshot_consistency is not None:
        if snapshot_consistency >= 80:
            adjustments['over_boost'] += 2
            adjustments['tags'].append('CONSIST+')
        elif snapshot_consistency <= 64:
            adjustments['under_boost'] += 1
            adjustments['tags'].append('CONSIST-')

    if snapshot_mins_trend >= 1:
        adjustments['over_boost'] += 1
        adjustments['tags'].append('TREND MIN+')
    elif snapshot_mins_trend <= -1.25:
        adjustments['under_boost'] += 1
        adjustments['tags'].append('TREND MIN-')

    if snapshot_stat_trend >= 0.04:
        adjustments['over_boost'] += 2
        adjustments['tags'].append('FORM+')
    elif snapshot_stat_trend <= -0.08:
        adjustments['under_boost'] += 1
        adjustments['tags'].append('FORM-')

    if stat in {'PTS', 'AST', '3PM'}:
        if 'HIGH' in snapshot_load_label or 'UP' in snapshot_load_label:
            adjustments['over_boost'] += 1
            adjustments['tags'].append('LOAD+')
        elif 'LOW' in snapshot_load_label or 'DOWN' in snapshot_load_label:
            adjustments['under_boost'] += 1
            adjustments['tags'].append('LOAD-')

    if return_impact_pct >= 4:
        if stat == 'AST':
            adjustments['under_boost'] += min(5, max(1, round(return_impact_pct / 5)))
        elif stat in {'PTS', '3PM'}:
            adjustments['under_boost'] += min(4, max(1, round(return_impact_pct / 6)))
        elif stat == 'REB':
            adjustments['under_boost'] += min(3, max(1, round(return_impact_pct / 8)))
        else:
            adjustments['under_boost'] += min(2, max(1, round(return_impact_pct / 10)))
        adjustments['tags'].append('RETURN-')
        if return_impact_pct >= 6 and role_label == 'SUPPORT':
            if stat == 'AST':
                adjustments['under_boost'] += 3
                adjustments['tags'].append('RETURN SQUEEZE')
            elif stat in {'PTS', '3PM'}:
                adjustments['under_boost'] += 2
                adjustments['tags'].append('RETURN SQUEEZE')
            elif stat == 'REB':
                adjustments['under_boost'] += 1
                adjustments['tags'].append('RETURN SQUEEZE')

    adjustments['tags'].extend(projection_context.get('projection_tags', []))
    adjustments['tags'] = list(dict.fromkeys(adjustments['tags']))
    return adjustments


def blend_stat_std_dev(stat, valid_logs, recent_logs, opponent_logs):
    stat = str(stat or '').upper()
    weighted_candidates = []

    def add_candidate(frame, weight):
        if frame is None or getattr(frame, 'empty', True) or stat not in frame.columns or len(frame) < 2:
            return
        std_value = pd.to_numeric(frame[stat], errors='coerce').dropna().std()
        if pd.notna(std_value) and float(std_value) > 0:
            weighted_candidates.append((float(std_value), float(weight)))

    add_candidate(valid_logs, 0.45)
    add_candidate(recent_logs, 0.35)
    add_candidate(opponent_logs, 0.20)

    min_std_map = {'PTS': 4.0, 'REB': 2.0, 'AST': 1.7, '3PM': 1.1, 'STL': 0.6, 'BLK': 0.6}
    fallback_std_map = {'PTS': 6.5, 'REB': 3.4, 'AST': 2.6, '3PM': 1.8, 'STL': 1.0, 'BLK': 1.0}
    min_std = float(min_std_map.get(stat, 1.0))
    fallback_std = float(fallback_std_map.get(stat, 1.5))

    if not weighted_candidates:
        return max(min_std, fallback_std)

    total_weight = sum(weight for _, weight in weighted_candidates) or 1.0
    blended_std = sum(std_value * weight for std_value, weight in weighted_candidates) / total_weight
    return max(min_std, blended_std)


def calculate_core_stat_baseline(stat, player_logs, line, projection_context=None, opponent=None, postseason_only=False):
    baseline = {
        'projected_value': None,
        'over_prob': None,
        'under_prob': None,
        'std_dev': None,
        'over_boost': 0,
        'under_boost': 0,
        'tags': [],
        'volume_type': None,
        'recent_volume': None,
        'season_volume': None,
        'volume_delta': None,
    }
    stat = str(stat or '').upper()
    if stat not in CORE_BASELINE_STATS:
        return baseline
    if player_logs.empty or stat not in player_logs.columns:
        return baseline

    working = player_logs.copy()
    if 'Date' in working.columns:
        working = working.sort_values('Date', ascending=False)

    valid = working[working[stat].notna()].copy()
    if valid.empty:
        return baseline

    recent_10 = valid.head(10)
    recent_5 = valid.head(5)
    opponent_logs = valid[valid['Opp'] == opponent].copy() if opponent and 'Opp' in valid.columns else pd.DataFrame()

    season_avg = float(valid[stat].mean())
    recent_10_avg = float(recent_10[stat].mean()) if not recent_10.empty else season_avg
    recent_5_avg = float(recent_5[stat].mean()) if not recent_5.empty else recent_10_avg
    opponent_avg = float(opponent_logs[stat].mean()) if len(opponent_logs) >= 2 else None

    projected_minutes = None
    if projection_context:
        projected_minutes = projection_context.get('projected_minutes')
    if projected_minutes is None and 'MIN' in valid.columns:
        mins = valid['MIN'].dropna()
        if not mins.empty:
            projected_minutes = float(mins.head(5).mean() if len(mins) >= 5 else mins.mean())

    per_min_projection = None
    if projected_minutes and 'MIN' in valid.columns:
        valid_mins = valid[(valid['MIN'].notna()) & (valid['MIN'] > 0)].copy()
        if not valid_mins.empty:
            valid_mins['STAT_PER_MIN'] = valid_mins[stat] / valid_mins['MIN']
            season_per_min = float(valid_mins['STAT_PER_MIN'].mean())
            recent_per_min = float(valid_mins.head(5)['STAT_PER_MIN'].mean()) if len(valid_mins) >= 5 else season_per_min
            blended_per_min = (season_per_min * 0.35) + (recent_per_min * 0.65)
            per_min_projection = projected_minutes * blended_per_min

    if opponent_avg is not None:
        projected = (season_avg * 0.15) + (recent_10_avg * 0.15) + (recent_5_avg * 0.25) + ((per_min_projection or recent_5_avg) * 0.20) + (opponent_avg * 0.25)
    else:
        projected = (season_avg * 0.25) + (recent_10_avg * 0.20) + (recent_5_avg * 0.30) + ((per_min_projection or recent_5_avg) * 0.25)

    recent_volume = None
    season_volume = None
    if stat == 'PTS' and 'FGA' in valid.columns:
        recent_volume = float(valid['FGA'].head(5).mean()) if valid['FGA'].head(5).notna().any() else None
        season_volume = float(valid['FGA'].mean()) if valid['FGA'].notna().any() else None
        baseline['volume_type'] = 'FGA'
        baseline['recent_volume'] = round(recent_volume, 1) if recent_volume is not None else None
        baseline['season_volume'] = round(season_volume, 1) if season_volume is not None else None
        if recent_volume is not None and season_volume is not None and season_volume > 0:
            volume_delta = max(-0.08, min((recent_volume - season_volume) * 0.015, 0.08))
            baseline['volume_delta'] = round(recent_volume - season_volume, 1)
            projected *= (1 + volume_delta)
            if volume_delta >= 0.03:
                baseline['tags'].append('PTS BASE VOL+')
            elif volume_delta <= -0.03:
                baseline['tags'].append('PTS BASE VOL-')
    elif stat == 'AST':
        touches = projection_context.get('touches') if projection_context else None
        usage_pct = projection_context.get('usage_pct') if projection_context else None
        if touches is not None and not pd.isna(touches):
            touches = float(touches)
            if touches >= 60:
                projected += 0.35
                baseline['tags'].append('AST BASE TOUCH+')
            elif touches <= 38:
                projected -= 0.25
                baseline['tags'].append('AST BASE TOUCH-')
        if usage_pct is not None and not pd.isna(usage_pct):
            usage_pct = float(usage_pct)
            if usage_pct >= 26:
                projected += 0.2
                baseline['tags'].append('AST BASE USG+')
            elif usage_pct <= 17:
                projected -= 0.15
                baseline['tags'].append('AST BASE USG-')
    elif stat == 'REB':
        role_label = str((projection_context or {}).get('role_label', '')).upper()
        if projected_minutes is not None:
            if projected_minutes >= 34:
                projected += 0.35
                baseline['tags'].append('REB BASE MIN+')
            elif projected_minutes <= 24:
                projected -= 0.3
                baseline['tags'].append('REB BASE MIN-')
        if role_label in {'CORE', 'PRIMARY'}:
            projected += 0.2
            baseline['tags'].append('REB BASE ROLE+')
    elif stat == '3PM':
        recent_volume = float(valid['3PA'].head(5).mean()) if '3PA' in valid.columns and valid['3PA'].head(5).notna().any() else None
        season_volume = float(valid['3PA'].mean()) if '3PA' in valid.columns and valid['3PA'].notna().any() else None
        baseline['volume_type'] = '3PA'
        baseline['recent_volume'] = round(recent_volume, 1) if recent_volume is not None else None
        baseline['season_volume'] = round(season_volume, 1) if season_volume is not None else None
        if recent_volume is not None and season_volume is not None and season_volume > 0:
            volume_delta = max(-0.10, min((recent_volume - season_volume) * 0.03, 0.10))
            baseline['volume_delta'] = round(recent_volume - season_volume, 1)
            projected *= (1 + volume_delta)
            if volume_delta >= 0.04:
                baseline['tags'].append('3PM BASE VOL+')
            elif volume_delta <= -0.04:
                baseline['tags'].append('3PM BASE VOL-')
        usage_pct = projection_context.get('usage_pct') if projection_context else None
        if usage_pct is not None and not pd.isna(usage_pct):
            usage_pct = float(usage_pct)
            if usage_pct >= 25:
                projected += 0.15
                baseline['tags'].append('3PM BASE USG+')
            elif usage_pct <= 16:
                projected -= 0.12
                baseline['tags'].append('3PM BASE USG-')
    elif stat == 'STL':
        role_label = str((projection_context or {}).get('role_label', '')).upper()
        touches = projection_context.get('touches') if projection_context else None
        if projected_minutes is not None:
            if projected_minutes >= 32:
                projected += 0.12
                baseline['tags'].append('STL BASE MIN+')
            elif projected_minutes <= 24:
                projected -= 0.12
                baseline['tags'].append('STL BASE MIN-')
        if role_label in {'CORE', 'PRIMARY'}:
            projected += 0.08
            baseline['tags'].append('STL BASE ROLE+')
        if touches is not None and not pd.isna(touches):
            touches = float(touches)
            if touches >= 58:
                projected += 0.05
                baseline['tags'].append('STL BASE TOUCH+')
            elif touches <= 34:
                projected -= 0.05
                baseline['tags'].append('STL BASE TOUCH-')
    elif stat == 'BLK':
        role_label = str((projection_context or {}).get('role_label', '')).upper()
        if projected_minutes is not None:
            if projected_minutes >= 30:
                projected += 0.14
                baseline['tags'].append('BLK BASE MIN+')
            elif projected_minutes <= 22:
                projected -= 0.14
                baseline['tags'].append('BLK BASE MIN-')
        if role_label in {'CORE', 'PRIMARY'}:
            projected += 0.10
            baseline['tags'].append('BLK BASE ROLE+')

    if projected_minutes is not None:
        if stat in {'PTS', 'AST', '3PM'}:
            if projected_minutes >= 34:
                baseline['tags'].append(f'{stat} BASE MIN+')
            elif projected_minutes <= 24:
                baseline['tags'].append(f'{stat} BASE MIN-')

    if len(opponent_logs) >= 3:
        opponent_hits = int((opponent_logs[stat] > line).sum())
        under_series_boost = {
            'PTS': 8,
            'AST': 6,
            'REB': 6,
            '3PM': 5,
            'STL': 4,
            'BLK': 4,
        }
        over_series_boost = {
            'PTS': 6,
            'AST': 5,
            'REB': 5,
            '3PM': 5,
            'STL': 4,
            'BLK': 4,
        }
        if opponent_hits == 0:
            baseline['under_boost'] += under_series_boost.get(stat, 4)
            baseline['tags'].append(f'{stat} BASE SERIES-')
            if stat == 'PTS' and recent_volume is not None and recent_volume <= max(8.5, line - 1):
                projected = min(projected, line - 0.75)
        elif opponent_hits == len(opponent_logs):
            baseline['over_boost'] += over_series_boost.get(stat, 4)
            baseline['tags'].append(f'{stat} BASE SERIES+')
            if stat == 'PTS' and recent_volume is not None and recent_volume >= max(10.5, line):
                projected = max(projected, line + 0.75)

    std_dev = blend_stat_std_dev(stat, valid, recent_10, opponent_logs)

    sample_size = len(opponent_logs) if postseason_only and len(opponent_logs) >= 2 else len(recent_10)
    dist = NormalDist(mu=projected, sigma=std_dev)
    over_prob = (1 - dist.cdf(float(line)))
    under_prob = dist.cdf(float(line))

    baseline['projected_value'] = round(projected, 1)
    baseline['std_dev'] = round(std_dev, 2)
    baseline['over_prob'] = stabilize_rate(over_prob * 100, sample_size)
    baseline['under_prob'] = stabilize_rate(under_prob * 100, sample_size)
    baseline['tags'] = list(dict.fromkeys(baseline['tags']))
    return baseline


def apply_core_baseline_override(stat, player_logs, line, projection_context, opponent, rate_context, postseason_only=False):
    baseline = {
        'projected_value': None,
        'over_prob': None,
        'under_prob': None,
        'std_dev': None,
        'over_boost': 0,
        'under_boost': 0,
        'tags': []
    }
    stat = str(stat or '').upper()
    if stat not in CORE_BASELINE_STATS:
        return rate_context, baseline

    baseline = calculate_core_stat_baseline(
        stat,
        player_logs,
        line,
        projection_context=projection_context,
        opponent=opponent,
        postseason_only=postseason_only
    )
    if baseline['over_prob'] is None or baseline['under_prob'] is None:
        return rate_context, baseline

    blended = dict(rate_context)
    baseline_weight = 0.65 if postseason_only else 0.55
    model_weight = 1 - baseline_weight
    blended['weighted_over'] = round((float(rate_context.get('weighted_over', 0) or 0) * model_weight) + (baseline['over_prob'] * baseline_weight), 1)
    blended['weighted_under'] = round((float(rate_context.get('weighted_under', 0) or 0) * model_weight) + (baseline['under_prob'] * baseline_weight), 1)
    blended['over_boost'] = float(rate_context.get('over_boost', 0) or 0) + baseline['over_boost']
    blended['under_boost'] = float(rate_context.get('under_boost', 0) or 0) + baseline['under_boost']
    blended['tags'] = list(dict.fromkeys(list(rate_context.get('tags', [])) + baseline['tags']))
    return blended, baseline


def build_baseline_reason(stat, direction, baseline, line):
    stat = str(stat or '').upper()
    direction = str(direction or '').upper()
    baseline = baseline or {}
    projected = baseline.get('projected_value')
    over_prob = baseline.get('over_prob')
    under_prob = baseline.get('under_prob')
    volume_type = baseline.get('volume_type')
    recent_volume = baseline.get('recent_volume')
    season_volume = baseline.get('season_volume')
    tags = [str(tag) for tag in baseline.get('tags', []) if tag]
    if projected is None or direction not in {'OVER', 'UNDER'}:
        return ''

    if any('SERIES-' in tag for tag in tags) and direction == 'UNDER':
        return f"Series avg {projected:g} is still below {line:g}."
    if any('SERIES+' in tag for tag in tags) and direction == 'OVER':
        return f"Series avg {projected:g} is clearing {line:g}."
    if any('VOL+' in tag for tag in tags):
        if stat == 'PTS':
            if recent_volume is not None and season_volume is not None:
                return f"Shot volume is up: {recent_volume:g} {volume_type or 'FGA'} lately vs {season_volume:g} season, and baseline projects {projected:g}."
            return f"Shot volume is up and baseline projects {projected:g}."
        if stat == '3PM':
            if recent_volume is not None and season_volume is not None:
                return f"Three-point volume is up: {recent_volume:g} {volume_type or '3PA'} lately vs {season_volume:g} season, and baseline projects {projected:g}."
            return f"Three-point volume is up and baseline projects {projected:g}."
    if any('VOL-' in tag for tag in tags):
        if stat == 'PTS':
            if recent_volume is not None and season_volume is not None:
                return f"Shot volume is down: {recent_volume:g} {volume_type or 'FGA'} lately vs {season_volume:g} season, and baseline only projects {projected:g}."
            return f"Shot volume is down and baseline only projects {projected:g}."
        if stat == '3PM':
            if recent_volume is not None and season_volume is not None:
                return f"Three-point volume is down: {recent_volume:g} {volume_type or '3PA'} lately vs {season_volume:g} season, and baseline only projects {projected:g}."
            return f"Three-point volume is down and baseline only projects {projected:g}."
    if any('TOUCH+' in tag for tag in tags):
        return f"Touch volume supports about {projected:g} assists."
    if any('TOUCH-' in tag for tag in tags):
        return f"Touch volume is light for this assist line."
    if any('ROLE+' in tag for tag in tags):
        if stat == 'REB':
            return f"Role and minutes support about {projected:g} rebounds."
        if stat == 'BLK':
            return f"Frontcourt role supports about {projected:g} blocks."
        if stat == 'STL':
            return f"Role and minutes support about {projected:g} steals."
    if any('MIN+' in tag for tag in tags):
        return f"Minutes support a baseline around {projected:g}."
    if any('MIN-' in tag for tag in tags):
        return f"Minutes pressure keeps the baseline near {projected:g}."
    if direction == 'OVER' and over_prob is not None:
        return f"Baseline projection is {projected:g} with {over_prob:g}% over support."
    if direction == 'UNDER' and under_prob is not None:
        return f"Baseline projection is {projected:g} with {under_prob:g}% under support."
    return f"Baseline projection is {projected:g} vs a {line:g} line."


def build_baseline_reason_tone(direction, baseline):
    direction = str(direction or '').upper()
    baseline = baseline or {}
    tags = [str(tag) for tag in baseline.get('tags', []) if tag]

    if any(tag.endswith('SERIES-') or tag.endswith('VOL-') or tag.endswith('TOUCH-') or tag.endswith('MIN-') for tag in tags):
        return 'under'
    if any(tag.endswith('SERIES+') or tag.endswith('VOL+') or tag.endswith('TOUCH+') or tag.endswith('ROLE+') or tag.endswith('MIN+') for tag in tags):
        return 'over'
    if direction == 'UNDER':
        return 'under'
    if direction == 'OVER':
        return 'over'
    return 'neutral'


def build_core_model_read(stat, direction, baseline, line):
    stat = str(stat or '').upper()
    direction = str(direction or '').upper()
    baseline = baseline or {}
    projected = baseline.get('projected_value')
    over_prob = baseline.get('over_prob')
    under_prob = baseline.get('under_prob')
    volume_type = baseline.get('volume_type')
    recent_volume = baseline.get('recent_volume')
    season_volume = baseline.get('season_volume')
    tags = [str(tag) for tag in baseline.get('tags', []) if tag]
    if projected is None and over_prob is None and under_prob is None:
        return ''

    parts = []
    if projected is not None:
        parts.append(f"Proj {projected:g}")
    if over_prob is not None:
        parts.append(f"O {over_prob:g}%")
    if under_prob is not None:
        parts.append(f"U {under_prob:g}%")
    if line is not None:
        parts.append(f"Line {line:g}")
    if volume_type and recent_volume is not None and season_volume is not None:
        parts.append(f"{volume_type} {recent_volume:g} vs {season_volume:g}")
    summary = " | ".join(parts)

    compact_tags = []
    for tag in tags[:4]:
        compact = (
            tag.replace('SERIES+', 'Series+')
            .replace('SERIES-', 'Series-')
            .replace('VOL+', 'Vol+')
            .replace('VOL-', 'Vol-')
            .replace('TOUCH+', 'Touch+')
            .replace('TOUCH-', 'Touch-')
            .replace('ROLE+', 'Role+')
            .replace('MIN+', 'Min+')
            .replace('MIN-', 'Min-')
        )
        compact_tags.append(compact)
    if compact_tags:
        summary = f"{summary} | {' | '.join(compact_tags)}"

    return summary


def build_core_volume_read(baseline):
    baseline = baseline or {}
    volume_type = baseline.get('volume_type')
    recent_volume = baseline.get('recent_volume')
    season_volume = baseline.get('season_volume')
    if not volume_type or recent_volume is None or season_volume is None:
        return ''

    delta = recent_volume - season_volume
    direction = 'up' if delta > 0.2 else 'down' if delta < -0.2 else 'flat'
    if direction == 'up':
        return f"{volume_type} trend: {recent_volume:g} lately vs {season_volume:g} season."
    if direction == 'down':
        return f"{volume_type} trend: {recent_volume:g} lately vs {season_volume:g} season."
    return f"{volume_type} trend: {recent_volume:g} lately, basically in line with {season_volume:g} season."


def build_core_debug_lines(stat, direction, baseline, line):
    stat = str(stat or '').upper()
    direction = str(direction or '').upper()
    baseline = baseline or {}
    projected = baseline.get('projected_value')
    over_prob = baseline.get('over_prob')
    under_prob = baseline.get('under_prob')
    volume_type = baseline.get('volume_type')
    recent_volume = baseline.get('recent_volume')
    season_volume = baseline.get('season_volume')
    tags = [str(tag) for tag in baseline.get('tags', []) if tag]
    delta = None
    if projected is not None and line is not None:
        delta = projected - line

    lines = [
        {'label': 'Stat', 'value': stat or '-'},
        {'label': 'Play', 'value': direction or '-'},
        {'label': 'Line', 'value': f'{line:g}' if line is not None else '-'},
        {'label': 'Projection', 'value': f'{projected:g}' if projected is not None else '-'},
        {'label': 'Delta', 'value': f'{delta:+g}' if delta is not None else '-'},
        {'label': 'Over Prob', 'value': f'{over_prob:g}%' if over_prob is not None else '-'},
        {'label': 'Under Prob', 'value': f'{under_prob:g}%' if under_prob is not None else '-'},
        {'label': 'Recent Volume', 'value': f'{recent_volume:g} {volume_type}' if recent_volume is not None and volume_type else '-'},
        {'label': 'Season Volume', 'value': f'{season_volume:g} {volume_type}' if season_volume is not None and volume_type else '-'},
        {'label': 'Tags', 'value': ', '.join(tags) if tags else '-'},
        {'label': 'Reason Tone', 'value': build_baseline_reason_tone(direction, baseline)},
    ]
    return lines


def build_public_trend_note(player_logs, stat, line, direction, postseason_only=False):
    if player_logs is None or getattr(player_logs, 'empty', True):
        return ''
    if stat not in player_logs.columns:
        return ''
    working = player_logs.copy()
    if 'Date' in working.columns:
        working['Date'] = pd.to_datetime(working['Date'], errors='coerce')
        working = working.sort_values('Date', ascending=False)
    values = pd.to_numeric(working[stat], errors='coerce').dropna()
    if values.empty:
        return ''

    stat_upper = str(stat or '').upper()
    direction = str(direction or '').upper()
    stat_labels = {
        'PTS': 'points',
        'REB': 'rebounds',
        'AST': 'assists',
        '3PM': 'threes',
        'STL': 'steals',
        'BLK': 'blocks',
    }
    stat_label = stat_labels.get(stat_upper, stat_upper.lower())
    sample_n = min(len(values), 3 if stat_upper in {'STL', 'BLK'} else 4)
    recent = values.head(sample_n)
    if recent.empty:
        return ''

    sample_label = f"last {sample_n} playoff games" if postseason_only else f"last {sample_n} games"
    recent_avg = round(float(recent.mean()), 1)
    if sample_n == 1:
        sample_label = "last game"

    def _streak(match_fn):
        streak = 0
        for value in recent:
            if match_fn(float(value)):
                streak += 1
            else:
                break
        return streak

    if line is not None:
        line_value = float(line)
        full_over_streak = calculate_streak(working, stat, line_value)
        full_under_streak = calculate_under_streak(working, stat, line_value)
        if direction == 'OVER' and full_over_streak >= 3:
            return f"Cleared {line:g} in {full_over_streak} straight."
        if direction == 'UNDER' and full_under_streak >= 3:
            return f"Stayed under {line:g} in {full_under_streak} straight."
        if direction == 'OVER' and full_under_streak >= 3:
            return f"Current under run is the caution flag: {full_under_streak} straight below {line:g}."
        if direction == 'UNDER' and full_over_streak >= 3:
            return f"Current over run is the caution flag: {full_over_streak} straight above {line:g}."
        over_streak = _streak(lambda value: value > line_value)
        under_streak = _streak(lambda value: value < line_value)
        if direction == 'OVER' and over_streak >= min(3, sample_n):
            return f"Cleared {line:g} in {over_streak} straight."
        if direction == 'UNDER' and under_streak >= min(3, sample_n):
            return f"Stayed under {line:g} in {under_streak} straight."
        if direction == 'OVER':
            relation = 'above' if recent_avg > line_value else 'near' if abs(recent_avg - line_value) <= 0.3 else 'below'
        else:
            relation = 'below' if recent_avg < line_value else 'near' if abs(recent_avg - line_value) <= 0.3 else 'above'

        if relation == 'near':
            note = f"Averaging {recent_avg:g} {stat_label} over the {sample_label}, right around {line:g}."
        else:
            note = f"Averaging {recent_avg:g} {stat_label} over the {sample_label}, {relation} {line:g}."
        if direction == 'UNDER' and line_value <= 0.5 and stat_upper in {'AST', 'STL', 'BLK'}:
            note = f"{note} Needs a literal zero to cash."
        return note

    return f"Averaging {recent_avg:g} {stat_label} over the {sample_label}."


def is_zero_required_under_play(prop):
    if not prop:
        return False
    direction = str((prop or {}).get('direction', '') or '').strip().upper()
    stat = str((prop or {}).get('stat', '') or '').strip().upper()
    line_value = pd.to_numeric(pd.Series([(prop or {}).get('line')]), errors='coerce').iloc[0]
    return (
        direction == 'UNDER'
        and stat in {'AST', 'STL', 'BLK'}
        and pd.notna(line_value)
        and float(line_value) <= 0.5
    )


def build_injury_context_note(stat, direction, projection_context):
    projection_context = projection_context or {}
    stat = str(stat or '').upper()
    direction = str(direction or '').upper()
    return_impact_pct = float(projection_context.get('return_impact_pct', 0) or 0)
    return_player = str(projection_context.get('return_player', '') or '').strip()
    injury_boost_player = str(projection_context.get('injury_boost_player', '') or '').strip()
    injury_boost_status = str(projection_context.get('injury_boost_status', '') or '').strip().upper()

    if return_impact_pct >= 6 and return_player:
        if stat == 'AST':
            return f"{return_player} being back in the mix may cut creation touches."
        if stat in {'PTS', '3PM'}:
            return f"{return_player} being back in the mix may trim shot volume."
        if stat == 'REB':
            return f"{return_player} being back in the mix may squeeze the rebound role."
        return f"{return_player} being back in the mix can tighten this role."

    if injury_boost_player and injury_boost_status in {'OUT', 'DOUBTFUL'}:
        if stat == 'AST':
            return f"{injury_boost_player} being out can open more playmaking chances."
        if stat in {'PTS', '3PM'}:
            return f"{injury_boost_player} being out can leave more scoring usage behind."
        if stat == 'REB':
            return f"{injury_boost_player} being out can leave extra rebounding work."
        return f"{injury_boost_player} being out can open more opportunity here."

    return ''


def build_core_baseline_fields(stat, direction, baseline, line, projection_context=None):
    baseline = baseline or {}
    projected_value = baseline.get('projected_value')
    over_prob = baseline.get('over_prob')
    under_prob = baseline.get('under_prob')
    reason = build_baseline_reason(stat, direction, baseline, line)
    tone = build_baseline_reason_tone(direction, baseline)
    model_read = build_core_model_read(stat, direction, baseline, line)
    volume_read = build_core_volume_read(baseline)
    injury_note = build_injury_context_note(stat, direction, projection_context)
    return {
        'injury_context_note': injury_note,
        'baseline_reason': reason,
        'baseline_reason_tone': tone,
        'core_volume_read': volume_read,
        'core_model_read': model_read,
        'core_debug_lines': build_core_debug_lines(stat, direction, baseline, line),
        'core_projected_value': projected_value,
        'core_baseline_over_prob': over_prob,
        'core_baseline_under_prob': under_prob,
    }


def build_rank_driver_chips(prop):
    prop = prop or {}
    situations = {str(tag).strip().upper() for tag in (prop.get('situations') or []) if tag}
    stat = str(prop.get('stat', '') or '').upper()
    tier = str(prop.get('tier', '') or '').strip()
    chips = []
    seen = set()

    def add(label, tone='soft'):
        key = str(label).strip().upper()
        if not key or key in seen or len(chips) >= 3:
            return
        seen.add(key)
        chips.append({'label': label, 'tone': tone})

    projected_minutes = prop.get('projected_minutes')
    edge_pct = float(prop.get('edge_pct', 0) or 0)
    market_gap_pct = prop.get('market_gap_pct')
    touches = prop.get('touches')
    drives = prop.get('drives')
    ts_pct = prop.get('ts_pct')
    snapshot_consistency = prop.get('snapshot_consistency')
    return_impact_pct = prop.get('return_impact_pct')
    market_calibration_tags = {str(tag).strip().upper() for tag in (prop.get('market_calibration_tags') or []) if tag}

    if tier == 'Tier 3':
        if {'VOLATILE', 'ROLE SLIP', 'ROLE DOWN'} & situations:
            add('VOL-', 'danger')
        if projected_minutes is not None and float(projected_minutes) <= 24:
            add('MIN-', 'danger')
        if market_gap_pct is not None and float(market_gap_pct) <= -3:
            add('MKT-', 'danger')

    if {'STAR ROLE', 'CORE ROLE'} & situations:
        add('ROLE+', 'accent')
    if {'MIN STABLE', 'MIN UP', 'SNAP MIN+', 'ROLE HOLD'} & situations or (projected_minutes is not None and float(projected_minutes) >= 34):
        add('MIN+', 'blue')
    if edge_pct >= 8 or (market_gap_pct is not None and float(market_gap_pct) >= 8):
        add('EDGE+', 'accent')
    elif edge_pct >= 4:
        add('EDGE', 'copper')
    if stat in {'PTS', 'AST', '3PM'} and touches is not None and float(touches) >= 60:
        add('TCH+', 'soft')
    if stat in {'PTS', 'AST'} and drives is not None and float(drives) >= 8:
        add('DRV+', 'copper')
    if stat in {'PTS', '3PM'} and ts_pct is not None and float(ts_pct) >= 58:
        add('TS+', 'blue')
    if snapshot_consistency is not None and float(snapshot_consistency) >= 80:
        add('STABLE', 'soft')
    if return_impact_pct is not None and float(return_impact_pct) >= 10:
        add('RET-', 'danger')
    if 'SERIES UNDER' in situations:
        add('SERIES-', 'danger')
    if 'SERIES OVER' in situations:
        add('SERIES+', 'accent')
    if {'VOLATILE', 'ROLE SLIP', 'ROLE DOWN'} & situations:
        add('VOL-', 'danger')
    if projected_minutes is not None and float(projected_minutes) <= 24:
        add('MIN-', 'danger')
    if market_gap_pct is not None and float(market_gap_pct) <= -3:
        add('MKT-', 'danger')
    if {'WIDE RANGE', 'VEGAS GAP', 'LOW BOOK COUNT', 'THIN MARKET'} & market_calibration_tags:
        add('MKT-', 'danger')
    if {'MARKET CONFIRMED', 'LINE TIGHT'} & market_calibration_tags:
        add('MKT+', 'accent')

    if not chips:
        if tier == 'Tier 1':
            add('BUILD+', 'accent')
        elif tier == 'Tier 2':
            add('RR OK', 'copper')
        else:
            add('WATCH', 'soft')
    return chips


def build_method_supports(prop):
    prop = prop or {}
    supports = []
    seen = set()

    def add(label, tone='soft', note=''):
        key = str(label).strip().upper()
        if not key or key in seen or len(supports) >= 3:
            return
        seen.add(key)
        supports.append({
            'label': label,
            'tone': tone,
            'note': (str(note or '').strip()),
        })

    edge_pct = float(prop.get('edge_pct', 0) or 0)
    book_count = int(prop.get('book_count', 0) or 0)
    line_low = prop.get('line_low')
    line_high = prop.get('line_high')
    public_trend_note = str(prop.get('public_trend_note', '') or '').strip()
    injury_context_note = str(prop.get('injury_context_note', '') or '').strip()
    game_environment = str(prop.get('game_environment', '') or '').strip()
    baseline_reason = str(prop.get('baseline_reason', '') or '').strip()
    projected_minutes = prop.get('projected_minutes')
    snapshot_consistency = prop.get('snapshot_consistency')
    situations = {str(tag).strip().upper() for tag in (prop.get('situations') or []) if tag}
    direction = str(prop.get('direction', '') or '').upper()
    market_calibration_note = str(prop.get('market_calibration_note', '') or '').strip()

    range_exists = (
        line_low is not None and
        line_high is not None and
        float(line_low) != float(line_high)
    )
    if edge_pct > 0 or book_count > 1 or range_exists:
        add(
            'Market Edge',
            'accent',
            market_calibration_note or prop.get('book_comparison_note') or prop.get('market_view', {}).get('note') or 'Books are not fully aligned on this number yet.'
        )

    if public_trend_note:
        add('Trends', 'copper', public_trend_note)

    matchup_note = injury_context_note or game_environment or baseline_reason
    if matchup_note:
        add('Matchup Lens', 'blue', matchup_note)

    floor_ready = (
        direction == 'OVER' and
        projected_minutes is not None and float(projected_minutes) >= 28 and
        snapshot_consistency is not None and float(snapshot_consistency) >= 75
    ) or ({'MIN STABLE', 'ROLE HOLD', 'CORE ROLE', 'STAR ROLE'} & situations)
    if floor_ready:
        add('Floor Play', 'soft', 'Stable role and minutes keep this play from leaning only on a hot streak.')

    if not supports:
        add('Market Edge', 'soft', 'Start with the price, then confirm the trend and matchup support it.')
    return supports


def recalibrate_live_market_confidence(base_confidence, multi_book_context=None):
    context = multi_book_context or {}
    confidence = float(base_confidence or 0)
    penalties = 0.0
    bonuses = 0.0
    notes = []
    tags = []

    book_count = int(context.get('book_count', 0) or 0)
    line_low = context.get('line_low')
    line_high = context.get('line_high')
    dk_line = context.get('draftkings_line')
    vegas_line = context.get('vegas_line')

    range_span = None
    if line_low is not None and line_high is not None:
        try:
            range_span = abs(float(line_high) - float(line_low))
        except Exception:
            range_span = None

    vegas_gap = None
    if dk_line is not None and vegas_line is not None:
        try:
            vegas_gap = abs(float(dk_line) - float(vegas_line))
        except Exception:
            vegas_gap = None

    if book_count <= 1:
        penalties += 4
        notes.append('single-book market')
        tags.append('LOW BOOK COUNT')
    elif book_count == 2:
        penalties += 2
        notes.append('thin market')
        tags.append('THIN MARKET')
    elif book_count >= 3:
        bonuses += 1
        tags.append('MARKET CONFIRMED')

    if range_span is not None:
        if range_span >= 1.0:
            penalties += 4
            notes.append('wide line split')
            tags.append('WIDE RANGE')
        elif range_span >= 0.5:
            penalties += 2
            notes.append('some line disagreement')
            tags.append('LINE SPLIT')
        elif range_span == 0:
            bonuses += 1
            tags.append('LINE TIGHT')

    if vegas_gap is not None:
        if vegas_gap >= 1.0:
            penalties += 3
            notes.append('DK vs Vegas gap')
            tags.append('VEGAS GAP')
        elif vegas_gap >= 0.5:
            penalties += 1.5
            notes.append('small DK vs Vegas gap')

    adjusted = confidence - penalties + bonuses
    adjusted = max(50.0, min(99.0, adjusted))

    if penalties <= 0 and bonuses >= 2:
        note = 'Books are lining up cleanly on this number.'
    elif notes:
        note = 'Confidence trimmed for ' + ', '.join(notes[:2]) + '.'
    else:
        note = 'Market looks reasonably aligned.'

    return {
        'raw_confidence': round(confidence, 1),
        'confidence': round(adjusted, 1),
        'note': note,
        'tags': tags[:3],
    }


def apply_live_method_market_guardrails(prop):
    prop = dict(prop or {})
    confidence = float(prop.get('confidence', 0) or 0)
    original_confidence = confidence
    notes = []
    tags = []

    market_tags = {str(tag).strip().upper() for tag in (prop.get('market_calibration_tags') or []) if tag}
    method_labels = {str(item.get('label', '')).strip() for item in (prop.get('method_supports') or []) if isinstance(item, dict)}
    weighted_over = float(prop.get('weighted_over_rate', prop.get('over_rate', 0)) or 0)
    weighted_under = float(prop.get('weighted_under_rate', prop.get('under_rate', 0)) or 0)
    direction = str(prop.get('direction', '') or '').upper()
    weighted_hit_rate = weighted_over if direction == 'OVER' else weighted_under
    edge_pct = float(prop.get('edge_pct', 0) or 0)
    baseline_over = prop.get('core_baseline_over_prob')
    baseline_under = prop.get('core_baseline_under_prob')
    baseline_value = baseline_over if direction == 'OVER' else baseline_under
    baseline_hit_rate = float(baseline_value or 0)
    severe_market = bool({'WIDE RANGE', 'VEGAS GAP', 'LOW BOOK COUNT', 'THIN MARKET'} & market_tags)
    split_market = bool({'WIDE RANGE', 'VEGAS GAP', 'LINE SPLIT'} & market_tags)
    trends_only = bool(method_labels == {'Trends'})
    support_count = len(method_labels)
    book_count = int(prop.get('book_count', 0) or 0)
    range_gap = pd.to_numeric(pd.Series([prop.get('range_gap')]), errors='coerce').iloc[0]
    weak_evidence = weighted_hit_rate < 58 and baseline_hit_rate < 58
    thin_edge = edge_pct < 2
    live_line_over_rate = prop.get('live_line_over_rate')
    live_line_under_rate = prop.get('live_line_under_rate')
    live_line_games = int(prop.get('live_line_games', 0) or 0)
    stat = str(prop.get('stat', '') or '').upper()
    live_line_hit_rate = None
    live_line_opp_rate = None
    if direction == 'OVER':
        live_line_hit_rate = float(live_line_over_rate or 0) if live_line_over_rate is not None else None
        live_line_opp_rate = float(live_line_under_rate or 0) if live_line_under_rate is not None else None
    elif direction == 'UNDER':
        live_line_hit_rate = float(live_line_under_rate or 0) if live_line_under_rate is not None else None
        live_line_opp_rate = float(live_line_over_rate or 0) if live_line_over_rate is not None else None
    current_run_side = str(prop.get('current_run_side', '') or '').strip().lower()
    current_streak = int(prop.get('current_streak', 0) or 0)
    situations = {str(tag).strip().upper() for tag in (prop.get('situations') or []) if tag}
    run_conflicts = (
        (direction == 'OVER' and current_run_side == 'under') or
        (direction == 'UNDER' and current_run_side == 'over')
    )
    strong_role_fade = bool({'ROLE DOWN', 'SHOT VOL-', 'MIN-', 'L5 FADE', 'COLD'} & situations)
    strong_role_support = bool({'ROLE UP', 'SHOT VOL+', 'MIN+', 'L5 SURGE', 'HOT'} & situations)
    return_squeeze = 'RETURN SQUEEZE' in situations or 'RETURN-' in situations
    return_impact_pct = float(prop.get('return_impact_pct', 0) or 0)
    volatile_stat = stat in VOLATILE_PROP_STATS
    zero_required_under = is_zero_required_under_play(prop)
    volatility_flag = str(prop.get('volatility_flag', 'STABLE') or 'STABLE').upper()
    volatility_note = str(prop.get('volatility_note', '') or '').strip()
    volatility_penalty = float(prop.get('volatility_penalty', 0) or 0)
    current_line = pd.to_numeric(pd.Series([prop.get('current_line', prop.get('line'))]), errors='coerce').iloc[0]
    open_line = pd.to_numeric(pd.Series([prop.get('open_line')]), errors='coerce').iloc[0]
    prior_line = pd.to_numeric(pd.Series([prop.get('prior_line')]), errors='coerce').iloc[0]
    opening_move = round(float(current_line) - float(open_line), 1) if pd.notna(current_line) and pd.notna(open_line) else None
    snapshot_move = round(float(current_line) - float(prior_line), 1) if pd.notna(current_line) and pd.notna(prior_line) else None
    move_against_side = False
    effective_move = snapshot_move if snapshot_move is not None else opening_move
    if effective_move is not None:
        if direction == 'OVER' and float(effective_move) > 0:
            move_against_side = True
        elif direction == 'UNDER' and float(effective_move) < 0:
            move_against_side = True
    market_gate = 'CLEAR'
    market_gate_note = 'Market context is not blocking the play.'

    if severe_market and confidence >= 80:
        confidence = min(confidence, 79.4)
        notes.append('top-end confidence capped in a messy market')
        tags.append('NO LOCK MARKET')
    elif split_market:
        confidence -= 2.0
        notes.append('split market trimmed')
        tags.append('MARKET TRIM')

    if volatility_flag == 'HIGH':
        confidence -= max(8.0, volatility_penalty)
        notes.append(volatility_note or 'high volatility suspends blind trust in the recent sample')
        tags.append('VOLATILITY HIGH')
    elif volatility_flag == 'ELEVATED':
        confidence -= max(4.0, min(6.0, volatility_penalty))
        notes.append(volatility_note or 'elevated volatility trims conviction')
        tags.append('VOLATILITY WATCH')

    if move_against_side and effective_move is not None and abs(float(effective_move)) >= 1.5:
        market_gate = 'HOLD'
        confidence = min(confidence, 56.4)
        notes.append(f"market moved {abs(float(effective_move)):.1f} points against this side")
        tags.append('MARKET HOLD')
        market_gate_note = 'Line moved materially against the model side. Review before promoting.'
    elif split_market and pd.notna(range_gap) and stat in {'STL', 'BLK', '3PM'} and float(range_gap) >= 1.0:
        market_gate = 'SPLIT MARKET'
        confidence = min(confidence, 59.4)
        notes.append('low-count stat has a full-point book split')
        tags.append('MARKET SPLIT')
        market_gate_note = 'Books disagree by a full point on a volatile stat. Confirm the exact book line before using this play.'
    elif split_market and pd.notna(range_gap) and float(range_gap) >= 2.0:
        market_gate = 'SPLIT MARKET'
        confidence = min(confidence, 61.4)
        notes.append('wide book disagreement requires manual review')
        tags.append('MARKET SPLIT')
        market_gate_note = 'Books are too far apart on this number to treat it as clean.'

    if trends_only:
        confidence -= 4.0
        notes.append('trends-only support')
        tags.append('TRENDS ONLY')
    elif weak_evidence and thin_edge:
        confidence -= 4.0
        notes.append('thin evidence behind the play')
        tags.append('THIN EVIDENCE')
    elif support_count <= 1:
        confidence -= 1.5
        notes.append('thin method support')
        tags.append('THIN SUPPORT')
    elif {'Market Edge', 'Matchup Lens'} <= method_labels or {'Floor Play', 'Matchup Lens'} <= method_labels:
        confidence += 1.0
        tags.append('STACKED SUPPORT')

    if volatile_stat:
        if live_line_games < 10 or support_count <= 1:
            confidence -= 5.0
            notes.append('volatile stat needs deeper support')
            tags.append('VOLATILE STAT')
        elif weighted_hit_rate < 64:
            confidence -= 3.0
            notes.append('volatile stat is not clearing a strong enough edge')
            tags.append('VOLATILE EDGE')

    if zero_required_under:
        confidence = min(confidence, 68.4)
        notes.append('under only cashes if the player records a literal zero')
        tags.append('ZERO REQUIRED')
        if volatile_stat:
            notes.append('one event kills a zero-required volatile under')
            tags.append('FRAGILE UNDER')
        prop['situations'] = list(dict.fromkeys(list(prop.get('situations', []) or []) + ['ZERO REQUIRED', 'FRAGILE UNDER' if volatile_stat else '']))

    if live_line_games >= 12 and live_line_hit_rate is not None and live_line_opp_rate is not None:
        if live_line_hit_rate <= 30 and live_line_opp_rate >= 70:
            confidence = min(confidence, 67.4)
            notes.append(f"season-long line history strongly opposes this side ({live_line_games} games)")
            tags.append('LINE HISTORY CAP')
        elif live_line_hit_rate <= 40 and live_line_opp_rate >= 60:
            confidence -= 8.0
            notes.append(f"full-team line history leans the other way ({live_line_games} games)")
            tags.append('LINE HISTORY CONFLICT')
        elif live_line_hit_rate >= 65 and live_line_opp_rate <= 35:
            confidence += 1.0
            tags.append('LINE HISTORY CONFIRMED')

    if run_conflicts and current_streak >= 4:
        confidence = min(confidence, 54.4)
        notes.append(f"recent playoff reality fully conflicts with this side ({current_streak} straight)")
        tags.append('RUN TAKEOVER')
    elif run_conflicts and current_streak >= 3:
        confidence = min(confidence, 58.4)
        notes.append(f"current {current_run_side} streak conflicts with this side ({current_streak} straight)")
        tags.append('RUN CONFLICT')
    elif run_conflicts and current_streak >= 2:
        confidence -= 6.0
        notes.append(f"recent {current_run_side} trend trims the play")
        tags.append('RUN TRIM')
    elif current_streak >= 3:
        tags.append('RUN CONFIRMED')

    if direction == 'OVER' and strong_role_fade:
        confidence -= 6.0
        notes.append('role fade pressure trims the over')
        tags.append('ROLE FADE')
    elif direction == 'OVER' and return_squeeze and return_impact_pct >= 6:
        confidence -= 10.0
        notes.append('returning starter risk trims the over')
        tags.append('RETURN PRESSURE')
    elif direction == 'UNDER' and strong_role_support:
        confidence -= 4.0
        notes.append('role support trims the under')
        tags.append('ROLE SUPPORT')

    clean_under_stack = (
        direction == 'UNDER' and
        weighted_under >= 66 and
        live_line_hit_rate is not None and live_line_hit_rate >= 75 and
        current_run_side == 'under' and current_streak >= 3 and
        edge_pct >= 10 and
        book_count >= 3 and
        {'MARKET CONFIRMED', 'LINE TIGHT'} & market_tags
    )
    if clean_under_stack:
        confidence += 4.0
        notes.append('clean under stack confirmed')
        tags.append('UNDER STACK')

    if weak_evidence and confidence >= 78:
        confidence = min(confidence, 77.4)
        notes.append('evidence ceiling applied')
        tags.append('EVIDENCE CAP')
    if direction == 'OVER' and return_squeeze and return_impact_pct >= 6 and confidence >= 70:
        confidence = min(confidence, 66.4)
        notes.append('return squeeze cap applied')
        tags.append('RETURN CAP')

    play_verdict = 'PLAY'
    play_verdict_note = ''
    severe_conflict = bool({'RUN TAKEOVER', 'RUN CONFLICT'} & set(tags)) and strong_role_fade and direction == 'OVER'
    line_conflict = 'LINE HISTORY CONFLICT' in tags or 'LINE HISTORY CAP' in tags
    if severe_conflict or (run_conflicts and current_streak >= 4):
        play_verdict = 'PASS'
        confidence = min(confidence, 54.4)
        play_verdict_note = 'Recent playoff trend and role/context both push against forcing this side.'
    elif market_gate == 'HOLD':
        play_verdict = 'PASS'
        play_verdict_note = market_gate_note
    elif direction == 'OVER' and return_squeeze and return_impact_pct >= 6:
        play_verdict = 'CONFLICTED'
        confidence = min(confidence, 66.4)
        play_verdict_note = 'Returning-starter risk is strong enough that this over should stay a lean, not a featured play.'
    elif (line_conflict and run_conflicts and current_streak >= 2) or confidence < 60:
        play_verdict = 'CONFLICTED'
        confidence = min(confidence, 59.4)
        play_verdict_note = 'The trend is real, but the broader support stack is still too mixed to force a bet.'
    elif market_gate == 'SPLIT MARKET':
        play_verdict = 'CONFLICTED'
        play_verdict_note = market_gate_note
    elif zero_required_under:
        play_verdict = 'CONFLICTED'
        play_verdict_note = 'Zero-required under: this only cashes if the player records a literal zero, so one event kills the ticket.'
    elif volatile_stat and confidence < 64:
        play_verdict = 'CONFLICTED'
        play_verdict_note = 'Volatile stat family with too little clean support.'

    confidence = max(50.0, min(99.0, confidence))
    prop['confidence'] = round(confidence, 1)
    prop['is_lock'] = bool(prop.get('is_lock') and confidence >= 80 and not severe_market and not trends_only)
    prop['grade'] = get_grade(prop['confidence'])
    prop['guardrail_note'] = '; '.join(notes) if notes else 'support stack looks clean.'
    priority_guardrail_tags = []
    for priority_tag in ['ZERO REQUIRED', 'FRAGILE UNDER', 'MARKET HOLD', 'MARKET SPLIT', 'RUN TAKEOVER', 'RUN CONFLICT']:
        if priority_tag in tags and priority_tag not in priority_guardrail_tags:
            priority_guardrail_tags.append(priority_tag)
    for tag in tags:
        if tag not in priority_guardrail_tags:
            priority_guardrail_tags.append(tag)
    prop['guardrail_tags'] = priority_guardrail_tags[:3]
    if round(original_confidence, 1) != prop['confidence']:
        prop['guardrail_adjustment'] = round(prop['confidence'] - original_confidence, 1)
    else:
        prop['guardrail_adjustment'] = 0.0
    prop['play_verdict'] = play_verdict
    prop['play_verdict_note'] = play_verdict_note
    prop['market_gate'] = market_gate
    prop['market_gate_note'] = market_gate_note
    return prop


def score_floor_parlay_candidate(prop):
    weighted_over = prop.get('weighted_over_rate', prop.get('over_rate', 0)) or 0
    weighted_under = prop.get('weighted_under_rate', prop.get('under_rate', 0)) or 0
    confidence = prop.get('confidence', 0) or 0
    edge = prop.get('edge_pct', 0) or 0
    ev = prop.get('ev_pct', 0) or 0
    book_count = int(prop.get('book_count', 0) or 0)
    market_tags = {str(tag).strip().upper() for tag in (prop.get('market_calibration_tags') or []) if tag}
    method_count = len(normalize_method_labels(prop.get('method_supports') or prop.get('method_labels') or []))
    situations = {str(tag).strip().upper() for tag in (prop.get('situations') or []) if tag}

    score = confidence
    score += max(edge, 0) * 1.8
    score += max(ev, 0) * 0.35

    if prop.get('direction') == 'OVER':
        score += weighted_over * 0.12
    else:
        score += weighted_under * 0.12

    if method_count >= 2:
        score += 3
    if book_count >= 3:
        score += 2
    if {'MARKET CONFIRMED', 'LINE TIGHT'} & market_tags:
        score += 2
    if {'WIDE RANGE', 'VEGAS GAP', 'LOW BOOK COUNT', 'THIN MARKET'} & market_tags:
        score -= 5
    if 'VOLATILE' in situations or 'ROLE SLIP' in situations or 'ROLE DOWN' in situations:
        score -= 6
    player_model = str(prop.get('player_model_accuracy') or '').upper()
    player_reliability = str(prop.get('player_reliability') or '').upper()
    if player_model == 'OVERVALUED':
        score -= 8
    elif player_model == 'UNDERVALUED':
        score += 4
    if player_reliability in {'ANCHOR', 'WATCH'}:
        score += 3
    elif player_reliability == 'AVOID':
        score -= 5

    return round(score, 1)


def calculate_build_quality_score(prop):
    direction = prop.get('direction')
    if direction not in {'OVER', 'UNDER'}:
        return 0

    confidence = float(prop.get('confidence', 0) or 0)
    edge = float(prop.get('edge_pct', 0) or 0)
    ev = prop.get('ev_pct')
    weighted_over = float(prop.get('weighted_over_rate', prop.get('over_rate', 0)) or 0)
    weighted_under = float(prop.get('weighted_under_rate', prop.get('under_rate', 0)) or 0)
    situations = {str(tag).strip().upper() for tag in (prop.get('situations') or []) if tag}
    market_tags = {str(tag).strip().upper() for tag in (prop.get('market_calibration_tags') or []) if tag}
    method_count = len(normalize_method_labels(prop.get('method_supports') or prop.get('method_labels') or []))
    book_count = int(prop.get('book_count', 0) or 0)
    weighted_hit_rate = weighted_over if direction == 'OVER' else weighted_under

    score = (confidence * 0.62) + (weighted_hit_rate * 0.18)
    score += min(max(edge, 0), 12) * 0.85

    if ev is not None:
        score += min(max(float(ev), -8), 12) * 0.30

    if method_count >= 2:
        score += 3
    if book_count >= 3:
        score += 2
    if {'MARKET CONFIRMED', 'LINE TIGHT'} & market_tags:
        score += 2
    if {'WIDE RANGE', 'VEGAS GAP', 'LOW BOOK COUNT', 'THIN MARKET'} & market_tags:
        score -= 5

    if {'VOLATILE', 'ROLE SLIP', 'ROLE DOWN', 'MIN-'} & situations:
        score -= 10
    if {'L5 FADE', 'COLD'} & situations:
        score -= 5

    return round(max(0, min(score, 99)), 1)


def classify_floor_parlay_tier(prop):
    build_score = prop.get('build_quality_score')
    if build_score is None:
        build_score = calculate_build_quality_score(prop)

    if build_score >= 79:
        return 'Tier 1'
    if build_score >= 67:
        return 'Tier 2'
    return 'Tier 3'


def _promotion_lookup_key(player='', sport='', stat='', direction=''):
    return (
        str(player or '').strip().lower(),
        str(sport or '').strip().upper(),
        str(stat or '').strip().upper(),
        str(direction or '').strip().upper(),
    )


def _build_live_promotion_signal_context():
    cache_key = 'live_promotion_signal_context'
    cache_version = _build_file_token(
        DATA_DIR / 'tracking' / 'NBA_AllPropResults.csv',
        DATA_DIR / 'tracking' / 'WNBA_AllPropResults.csv',
        DATA_DIR / 'tracking' / 'MLB_AllPropResults.csv',
        DATA_DIR / 'tracking' / 'NFL_AllPropResults.csv',
        DATA_DIR / 'tracking' / 'NBA_CandidateArchive.csv',
        DATA_DIR / 'tracking' / 'CandidateArchive.csv',
    )
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry:
        cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
        if cached_age <= 900 and cached_entry.get('version') == cache_version:
            return cached_entry['value']

    disk_cache_key = f'disk::{cache_key}'
    disk_hit, disk_value = _read_disk_ttl_cached_value(disk_cache_key, version=cache_version)
    if disk_hit:
        RUNTIME_TTL_CACHE[cache_key] = {
            'created_at': datetime.now(timezone.utc),
            'value': disk_value,
            'version': cache_version,
        }
        return disk_value

    try:
        results_df = load_all_prop_results_for_review_service()
        player_profiles = build_player_hit_profiles_service(results_df)
        bucket_frequency = build_missed_winner_bucket_frequency_service(results_df, lookback_days=7)
    except Exception:
        player_profiles = []
        bucket_frequency = {}

    profile_lookup = {
        _promotion_lookup_key(
            row.get('player'),
            row.get('sport'),
            row.get('stat'),
            row.get('direction'),
        ): row
        for row in player_profiles
    }
    value = {
        'profiles': profile_lookup,
        'bucket_frequency': bucket_frequency,
    }
    _write_disk_ttl_cached_value(disk_cache_key, 900, value, version=cache_version)
    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': value,
        'version': cache_version,
    }
    return value


def _promotion_boost_for_signal(signal):
    signal = str(signal or '').strip().upper()
    if signal == 'PROMOTE HARD':
        return 4.5
    if signal == 'PROMOTE':
        return 2.5
    if signal == 'SURFACE':
        return 1.0
    if signal == 'HOLD':
        return -8.0
    return 0.0


def attach_promotion_signals_to_props(props, sport='NBA', score_fields=None):
    if not props:
        return props
    score_fields = tuple(score_fields or ('confidence', 'market_confidence', 'method_score', 'build_quality_score'))
    sport = str(sport or '').strip().upper()
    context = _build_live_promotion_signal_context()
    profile_lookup = context.get('profiles') or {}
    bucket_frequency = context.get('bucket_frequency') or {}

    for prop in props:
        prop_sport = str(prop.get('sport') or sport or '').strip().upper()
        player = str(prop.get('player') or prop.get('Player') or '').strip()
        stat = str(prop.get('stat') or prop.get('Stat') or prop.get('stat_type') or '').strip().upper()
        direction = str(prop.get('direction') or prop.get('play') or prop.get('Direction') or '').strip().upper()
        if direction not in {'OVER', 'UNDER'}:
            prop['promotion_signal'] = 'STANDARD'
            prop['promotion_reason'] = 'No over/under direction available for promotion scoring.'
            prop['promotion_boost'] = 0.0
            continue

        profile = profile_lookup.get(_promotion_lookup_key(player, prop_sport, stat, direction))
        if not profile:
            profile = {
                'player': player,
                'sport': prop_sport,
                'stat': stat,
                'direction': direction,
                'reliability': prop.get('player_reliability') or prop.get('historical_reliability') or '',
                'resolved': prop.get('player_resolved') or prop.get('historical_resolved') or 0,
                'hit_rate': prop.get('player_hit_rate') or prop.get('historical_hit_rate'),
            }

        signal = calculate_promotion_signal_service(profile, bucket_frequency)
        signal_name = signal.get('signal', 'STANDARD')
        boost = _promotion_boost_for_signal(signal_name)
        play_verdict = str(prop.get('play_verdict') or prop.get('verdict') or '').strip().upper()
        if boost > 0 and play_verdict == 'PASS':
            boost = 0.0
        if boost > 0 and any(str(tag).strip().upper() == 'PASS' for tag in prop.get('guardrail_tags') or []):
            boost = 0.0

        prop['promotion_signal'] = signal_name
        prop['promotion_reason'] = signal.get('reason', '')
        prop['promotion_action'] = signal.get('action', '')
        prop['promotion_boost'] = round(boost, 1)
        prop['missed_winner_count'] = int(signal.get('missed_count', 0) or 0)
        prop['missed_winner_a_plus_count'] = int(signal.get('bucket_a_plus', 0) or 0)
        prop['missed_winner_avg_grade'] = signal.get('bucket_avg_grade')
        prop['promotion_last_seen'] = signal.get('last_seen', '')

        if signal_name != 'STANDARD':
            tags = list(prop.get('promotion_tags') or [])
            if signal_name not in tags:
                tags.append(signal_name)
            prop['promotion_tags'] = tags

        if boost:
            for field in score_fields:
                raw_value = prop.get(field)
                numeric = pd.to_numeric(raw_value, errors='coerce')
                if pd.notna(numeric):
                    prop[field] = round(max(0.0, min(float(numeric) + boost, 99.0)), 1)
    return props


def attach_floor_reliability_to_props(props, sport='NBA'):
    if not props:
        return props
    try:
        floor_index = load_floor_play_index_service()
        buckets = build_floor_reliability_table_service(floor_index)
        player_profiles = build_player_hit_profiles_service(floor_index)
    except Exception:
        buckets = []
        player_profiles = []
    lookup = {
        (row.get('sport'), row.get('stat'), row.get('direction')): row
        for row in buckets
    }
    player_lookup = {
        (
            str(row.get('player') or '').strip().lower(),
            str(row.get('sport') or '').strip().upper(),
            str(row.get('stat') or '').strip().upper(),
            str(row.get('direction') or '').strip().upper(),
        ): row
        for row in player_profiles
    }
    sport = str(sport or 'NBA').strip().upper() or 'NBA'
    for prop in props:
        key = (
            str(prop.get('sport') or sport).strip().upper(),
            str(prop.get('stat') or '').strip().upper(),
            str(prop.get('direction') or '').strip().upper(),
        )
        bucket = lookup.get(key)
        if bucket:
            prop['floor_reliability'] = bucket.get('floor_reliability')
            prop['floor_reliability_note'] = f"{bucket.get('resolved_count', 0)} resolved at {bucket.get('hit_rate')}%"
            prop['floor_parlay_eligible'] = bool(bucket.get('parlay_eligible'))
        else:
            prop['floor_reliability'] = 'SMALL SAMPLE'
            prop['floor_reliability_note'] = 'No resolved floor bucket sample yet'
            prop['floor_parlay_eligible'] = False
        player_key = (
            str(prop.get('player') or '').strip().lower(),
            key[0],
            key[1],
            key[2],
        )
        player_profile = player_lookup.get(player_key)
        if player_profile:
            prop['player_reliability'] = player_profile.get('reliability')
            prop['player_model_accuracy'] = player_profile.get('model_accuracy')
            prop['player_hit_rate'] = player_profile.get('hit_rate')
            prop['player_resolved'] = player_profile.get('resolved')
            prop['player_profile_note'] = f"{player_profile.get('resolved', 0)} resolved at {player_profile.get('hit_rate')}%"
        else:
            prop['player_reliability'] = ''
            prop['player_model_accuracy'] = ''
            prop['player_hit_rate'] = None
            prop['player_resolved'] = 0
            prop['player_profile_note'] = ''
    return attach_promotion_signals_to_props(
        props,
        sport=sport,
        score_fields=('confidence', 'build_quality_score', 'strategy_score'),
    )


def build_parlay_handoff_context(available):
    player = str(request.args.get('player') or '').strip()
    stat = str(request.args.get('stat') or '').strip().upper()
    direction = str(request.args.get('direction') or '').strip().upper()
    sport = str(request.args.get('sport') or request.args.get('league') or 'NBA').strip().upper() or 'NBA'
    line = str(request.args.get('line') or '').strip()
    source = str(request.args.get('source') or '').strip()
    if not player and not stat and not direction:
        return None

    line_num = pd.to_numeric(pd.Series([line]), errors='coerce').iloc[0] if line else np.nan
    matched = None
    for prop in available or []:
        prop_player = str(prop.get('player') or '').strip()
        prop_stat = str(prop.get('stat') or '').strip().upper()
        prop_direction = str(prop.get('direction') or '').strip().upper()
        if player and prop_player.lower() != player.lower():
            continue
        if stat and prop_stat != stat:
            continue
        if direction and prop_direction != direction:
            continue
        if pd.notna(line_num):
            prop_line = pd.to_numeric(pd.Series([prop.get('line')]), errors='coerce').iloc[0]
            if pd.isna(prop_line) or abs(float(prop_line) - float(line_num)) > 0.001:
                continue
        matched = prop
        break

    if matched:
        return {
            'status': 'matched',
            'message': 'Matched this incoming leg to the live parlay board and preselected it.',
            'source': source or 'handoff',
            'leg': {
                'sport': str(matched.get('sport') or sport or 'NBA').strip().upper(),
                'player': matched.get('player'),
                'team': matched.get('team'),
                'stat': matched.get('stat'),
                'line': matched.get('line'),
                'direction': matched.get('direction'),
                'confidence': matched.get('confidence'),
                'matchup': matched.get('matchup'),
                'tier': matched.get('tier'),
            },
        }

    return {
        'status': 'needs_line',
        'message': (
            'This handoff came from a profile or streak bucket, but the current NBA parlay board could not find a live matching line. '
            'Use it as a watchlist signal until the matching market is loaded.'
        ),
        'source': source or 'handoff',
        'leg': {
            'sport': sport,
            'player': player,
            'team': '',
            'stat': stat,
            'line': line,
            'direction': direction,
            'confidence': request.args.get('confidence', ''),
            'matchup': request.args.get('matchup', ''),
            'tier': '',
        },
    }


def select_unique_props(props, limit, max_per_game=2):
    selected = []
    used_players = set()
    matchup_counts = {}

    for prop in props:
        player = prop.get('player')
        matchup = prop.get('matchup') or 'N/A'
        if player in used_players:
            continue
        if matchup != 'N/A' and matchup_counts.get(matchup, 0) >= max_per_game:
            continue
        selected.append(prop)
        used_players.add(player)
        if matchup != 'N/A':
            matchup_counts[matchup] = matchup_counts.get(matchup, 0) + 1
        if len(selected) >= limit:
            break
    return selected


def build_floor_parlay_plan(props):
    ranked = []
    for prop in props:
        prop_copy = dict(prop)
        prop_copy['strategy_score'] = score_floor_parlay_candidate(prop_copy)
        prop_copy['build_quality_score'] = calculate_build_quality_score(prop_copy)
        prop_copy['tier'] = classify_floor_parlay_tier(prop_copy)
        ranked.append(prop_copy)

    ranked = sorted(ranked, key=lambda x: (x['strategy_score'], x.get('confidence', 0)), reverse=True)
    has_reliability = any(str(p.get('floor_reliability') or '').strip() for p in ranked)
    eligible_ranked = [
        p for p in ranked
        if str(p.get('floor_reliability') or '').strip().upper() in {'ANCHOR', 'WATCH'}
        and str(p.get('player_model_accuracy') or '').strip().upper() != 'OVERVALUED'
    ] if has_reliability else ranked
    construction_ranked = eligible_ranked if eligible_ranked else ranked
    tier1 = [p for p in ranked if p['tier'] == 'Tier 1']
    tier2 = [p for p in ranked if p['tier'] == 'Tier 2']
    tier3 = [p for p in ranked if p['tier'] == 'Tier 3']
    eligible_tier1 = [p for p in construction_ranked if p['tier'] == 'Tier 1']
    eligible_tier2 = [p for p in construction_ranked if p['tier'] == 'Tier 2']
    eligible_tier3 = [p for p in construction_ranked if p['tier'] == 'Tier 3']

    anchor = select_unique_props(eligible_tier1, 4, max_per_game=2)
    rr_pool = select_unique_props(eligible_tier1 + eligible_tier2, 5, max_per_game=2)
    booster = select_unique_props(eligible_tier1 + eligible_tier2, 6, max_per_game=2)
    moonshot = select_unique_props(eligible_tier1 + eligible_tier2 + eligible_tier3, 8, max_per_game=2)

    slate_strength = evaluate_floor_slate_strength(construction_ranked, anchor, rr_pool)

    return {
        'ranked': ranked,
        'slate_strength': slate_strength,
        'tier_counts': {'tier1': len(tier1), 'tier2': len(tier2), 'tier3': len(tier3)},
        'floor_reliability_counts': {
            'anchor': sum(1 for p in ranked if str(p.get('floor_reliability') or '').upper() == 'ANCHOR'),
            'watch': sum(1 for p in ranked if str(p.get('floor_reliability') or '').upper() == 'WATCH'),
            'avoid': sum(1 for p in ranked if str(p.get('floor_reliability') or '').upper() == 'AVOID'),
            'eligible': len(eligible_ranked),
        },
        'anchor': anchor,
        'rr_pool': rr_pool,
        'booster': booster,
        'moonshot': moonshot,
        'budget': slate_strength['budget']
    }


def evaluate_floor_slate_strength(ranked, anchor, rr_pool):
    sample = ranked[:12]
    if not sample:
        return {
            'score': 0,
            'tier': 'Red Light',
            'badge': 'PASS',
            'accent': '#FF6B6B',
            'summary': 'No playable floor board yet. Save bankroll and wait for more edges.',
            'playbook': 'Pass or keep action to a tiny 2-leg test build only.',
            'bankroll_note': 'Keep 90%+ of your slate bankroll in reserve.',
            'components': [],
            'budget': [
                {'label': 'Hold Back', 'share': '90%', 'note': 'No reason to force action on a weak board'},
                {'label': 'Tiny 2-Leg Test', 'share': '10%', 'note': 'Only if you want a pulse-check ticket'},
            ],
        }

    top_sample = sample[:8]
    tier1 = [p for p in sample if p.get('tier') == 'Tier 1']
    tier2 = [p for p in sample if p.get('tier') == 'Tier 2']
    positive_ev = [max((p.get('ev_pct') or 0), 0) for p in top_sample]
    avg_positive_ev = round(sum(positive_ev) / len(top_sample), 1) if top_sample else 0
    stable_count = sum(
        1
        for p in top_sample
        if {'STAR ROLE', 'CORE ROLE', 'MIN STABLE', 'ROLE HOLD'} & set(p.get('situations', []))
    )
    avg_minutes = round(
        sum((p.get('projected_minutes') or 0) for p in top_sample) / len(top_sample), 1
    ) if top_sample else 0
    matchup_counts = Counter(
        p.get('matchup') for p in top_sample if p.get('matchup') and p.get('matchup') != 'N/A'
    )
    unique_matchups = len(matchup_counts)
    overlap_legs = sum(max(0, count - 1) for count in matchup_counts.values())
    anchor_ready = len(anchor) >= 4
    rr_ready = len(rr_pool) >= 4

    edge_points = min(34, len(tier1) * 7 + len(tier2) * 2)
    ev_points = min(18, avg_positive_ev * 2.2)
    stability_points = min(20, stable_count * 2.5 + max(avg_minutes - 24, 0) * 0.45)
    diversity_points = min(18, unique_matchups * 3 + (3 if rr_ready else 0))
    correlation_penalty = min(22, overlap_legs * 4 + max(matchup_counts.values(), default=0) - 1)
    readiness_bonus = (6 if anchor_ready else 0) + (4 if rr_ready else 0)

    raw_score = edge_points + ev_points + stability_points + diversity_points + readiness_bonus - correlation_penalty
    score = int(max(0, min(100, round(raw_score))))

    components = [
        {'label': 'Edge Depth', 'value': round(edge_points, 1), 'detail': f'{len(tier1)} Tier 1 / {len(tier2)} Tier 2 plays'},
        {'label': 'EV Quality', 'value': round(ev_points, 1), 'detail': f'Avg positive EV {avg_positive_ev}%'},
        {'label': 'Minutes Stability', 'value': round(stability_points, 1), 'detail': f'{stable_count} stable-role plays, {avg_minutes} avg mins'},
        {'label': 'Board Diversity', 'value': round(diversity_points, 1), 'detail': f'{unique_matchups} different matchups in the core pool'},
        {'label': 'Correlation Risk', 'value': -round(correlation_penalty, 1), 'detail': f'{overlap_legs} overlapping legs across matchups'},
    ]

    if score >= 78:
        return {
            'score': score,
            'tier': 'Blue Light',
            'badge': 'FULL FORMULA',
            'accent': '#4E78C2',
            'summary': 'Deep slate with enough edge and separation to run the full floor formula.',
            'playbook': 'Play the 4-leg anchor, make the round robin your core exposure, and add one controlled booster.',
            'bankroll_note': 'Normal-to-aggressive slate. This is when a booster ticket is justified.',
            'components': components,
            'budget': [
                {'label': 'Round Robin 2s/3s', 'share': '45%', 'note': 'Still the main bankroll driver'},
                {'label': '4-Leg Anchor', 'share': '30%', 'note': 'Strong enough to press the core ticket'},
                {'label': '5/6-Leg Booster', 'share': '20%', 'note': 'Use only if you keep matchup overlap clean'},
                {'label': '8-10 Leg Moonshot', 'share': '5%', 'note': 'Tiny upside flyer only'},
            ],
        }

    if score >= 62:
        return {
            'score': score,
            'tier': 'Green Light',
            'badge': 'ANCHOR + RR',
            'accent': '#6EA8A6',
            'summary': 'Healthy slate with enough Tier 1 quality to run the main formula without overextending.',
            'playbook': 'Use the 4-leg anchor and round robins. Keep the booster smaller or skip it.',
            'bankroll_note': 'Standard action slate. Let the RR carry most of the exposure.',
            'components': components,
            'budget': [
                {'label': 'Round Robin 2s/3s', 'share': '55%', 'note': 'Primary way to monetize the slate'},
                {'label': '4-Leg Anchor', 'share': '30%', 'note': 'Main parlay ticket'},
                {'label': '5/6-Leg Booster', 'share': '10%', 'note': 'Optional if the top 5 stay clean'},
                {'label': 'Hold Back', 'share': '5%', 'note': 'No need to force a moonshot'},
            ],
        }

    if score >= 45:
        return {
            'score': score,
            'tier': 'Yellow Light',
            'badge': 'RR ONLY',
            'accent': '#B87333',
            'summary': 'Playable board, but not deep enough to trust a full anchor-and-booster approach.',
            'playbook': 'Stay with 2-leg and 3-leg round robins. If you build an anchor, keep it tiny.',
            'bankroll_note': 'Reduce exposure and let combinations do the work instead of one big ticket.',
            'components': components,
            'budget': [
                {'label': 'Round Robin 2s/3s', 'share': '70%', 'note': 'Best format for a shallow slate'},
                {'label': 'Small 3/4-Leg Anchor', 'share': '20%', 'note': 'Only if the Tier 1 group is very clean'},
                {'label': 'Tiny Flyer', 'share': '10%', 'note': 'Optional upside only'},
            ],
        }

    return {
        'score': score,
        'tier': 'Red Light',
        'badge': 'PASS / TINY ACTION',
        'accent': '#FF6B6B',
        'summary': 'The board is too thin or too correlated to support a real parlay slate.',
        'playbook': 'Pass the slate, or at most take a tiny 2-leg test if you have to be involved.',
        'bankroll_note': 'This is a discipline day. Bankroll preservation matters more than action.',
        'components': components,
        'budget': [
            {'label': 'Hold Back', 'share': '80%', 'note': 'Save the bankroll for a stronger slate'},
            {'label': 'Tiny 2-Leg Test', 'share': '20%', 'note': 'Only if you want limited exposure'},
        ],
    }


def get_venue_split_context(player_logs, stat, line, game_site=None):
    context = {'over_boost': 0, 'under_boost': 0, 'tags': []}
    if not game_site or stat not in player_logs.columns or 'Matchup' not in player_logs.columns:
        return context

    site_key = str(game_site).lower().strip()
    if site_key not in {'home', 'away'}:
        return context

    valid = player_logs[player_logs[stat].notna()].copy()
    if valid.empty:
        return context

    home_games = valid[valid['Matchup'].astype(str).str.contains('vs.', regex=False, na=False)]
    away_games = valid[valid['Matchup'].astype(str).str.contains('@', regex=False, na=False)]
    site_games = home_games if site_key == 'home' else away_games

    if len(site_games) < 3:
        return context

    full_rates = calculate_over_under_rates(valid, stat, line)
    site_rates = calculate_over_under_rates(site_games, stat, line)

    if site_rates['over'] >= full_rates['over'] + 10:
        context['over_boost'] += 4
        context['tags'].append(f'{site_key.upper()} SPLIT+')
    elif site_rates['under'] >= full_rates['under'] + 10:
        context['under_boost'] += 4
        context['tags'].append(f'{site_key.upper()} SPLIT-')

    return context

# =============================================================================
# OVER/UNDER CALCULATIONS
# =============================================================================
def calculate_over_under_rates(player_logs, stat, line):
    if player_logs.empty or stat not in player_logs.columns:
        return {'over': 0, 'under': 0, 'push': 0}
    
    valid = player_logs[player_logs[stat].notna()]
    if valid.empty:
        return {'over': 0, 'under': 0, 'push': 0}
    
    total = len(valid)
    overs = (valid[stat] > line).sum()
    unders = (valid[stat] < line).sum()
    pushes = (valid[stat] == line).sum()
    
    return {
        'over': round((overs / total) * 100, 1),
        'under': round((unders / total) * 100, 1),
        'push': round((pushes / total) * 100, 1)
    }


def stabilize_rate(rate, sample_size, neutral_rate=50.0, stabilization_games=6):
    """Shrink tiny samples back toward neutral so short playoff runs don't read as false certainties."""
    if sample_size <= 0:
        return round(neutral_rate, 1)
    weight = min(sample_size, stabilization_games) / float(stabilization_games)
    stabilized = neutral_rate + ((float(rate) - neutral_rate) * weight)
    return round(stabilized, 1)


SOFT_BOOST_CAPS = {
    'PTS': 12.0,
    'REB': 14.0,
    'AST': 14.0,
    '3PM': 12.0,
    'STL': 10.0,
    'BLK': 10.0,
}

VOLATILE_PROP_STATS = {'STL', 'BLK', '3PM'}


def get_soft_boost_cap(stat):
    return float(SOFT_BOOST_CAPS.get(str(stat or '').upper(), 12.0))


def cap_soft_boosts(stat, over_boost, under_boost):
    cap = get_soft_boost_cap(stat)
    return {
        'cap': cap,
        'over': round(max(-cap, min(float(over_boost or 0), cap)), 1),
        'under': round(max(-cap, min(float(under_boost or 0), cap)), 1),
    }

def calculate_situational_factors(player_logs, player_name, team, opponent, gamelogs):
    factors = {
        'is_b2b': False,
        'b2b_drop': 0,
        'is_blowout_risk': False,
        'vs_elite_defense': {},
        'is_cold': False,
        'under_boost': 0,
        'over_boost': 0,
        'situations': []
    }
    
    if player_logs.empty:
        return factors
    
    # Back-to-back detection
    if 'Date' in player_logs.columns:
        player_logs_sorted = player_logs.sort_values('Date', ascending=False)
        dates = pd.to_datetime(player_logs_sorted['Date'], errors='coerce').dropna()
        if len(dates) >= 2:
            last_game = dates.iloc[0]
            today = sports_today_ts()
            days_since = (today - last_game).days
            if days_since <= 1:
                factors['is_b2b'] = True
                factors['situations'].append('B2B')
                factors['under_boost'] += 15
    
    # Check vs elite defense
    if opponent:
        for stat, teams in ELITE_DEFENSE.items():
            if opponent in teams:
                factors['vs_elite_defense'][stat] = True
    
    return factors

def normalize_confidence_rate(rate):
    if rate is None or pd.isna(rate):
        return 0
    rate = float(rate)
    if rate <= 50:
        return 50
    excess = max(rate - 50, 0)
    normalized = 52 + (excess * 0.58)
    if rate >= 70:
        normalized += (rate - 70) * 0.12
    if rate >= 80:
        normalized += (rate - 80) * 0.10
    if rate >= 90:
        normalized += (rate - 90) * 0.08

    if rate >= 96:
        cap = 90
    elif rate >= 92:
        cap = 88
    elif rate >= 88:
        cap = 85
    else:
        cap = 93
    return round(max(50, min(normalized, cap)), 1)


def build_play_signal(direction, adjusted_rate):
    adjusted_rate = round(float(adjusted_rate or 0), 1)
    return {
        'direction': direction,
        'confidence': normalize_confidence_rate(adjusted_rate),
        'qualifying_rate': adjusted_rate,
        'edge': round(adjusted_rate - 50, 1),
        'is_lock': adjusted_rate >= 80
    }


def get_best_play(over_rate, under_rate, under_boost, over_boost, line, avg):
    adjusted_over = over_rate + over_boost
    adjusted_under = under_rate + under_boost
    
    if adjusted_over >= 75 and adjusted_over > adjusted_under:
        return build_play_signal('OVER', adjusted_over)
    elif adjusted_under >= 75 and adjusted_under > adjusted_over:
        return build_play_signal('UNDER', adjusted_under)
    elif adjusted_over >= 70:
        return build_play_signal('OVER', adjusted_over)
    elif adjusted_under >= 70:
        return build_play_signal('UNDER', adjusted_under)
    else:
        if adjusted_over >= adjusted_under:
            return build_play_signal('OVER', adjusted_over)
        else:
            return build_play_signal('UNDER', adjusted_under)


def check_hard_signal_ceiling(stat, player_logs, line, opponent=None, postseason_only=False):
    stat = str(stat or '').upper()
    result = {'ceilings': {}, 'tags': [], 'note': ''}
    if not postseason_only or player_logs is None or getattr(player_logs, 'empty', True):
        return result
    if stat not in CORE_BASELINE_STATS or stat not in player_logs.columns or 'Opp' not in player_logs.columns:
        return result

    normalized_opponent = normalize_team_for_filter(opponent)
    if not normalized_opponent:
        return result

    opponent_logs = player_logs[player_logs['Opp'] == normalized_opponent].copy()
    if len(opponent_logs) < 3:
        return result

    stat_values = pd.to_numeric(opponent_logs[stat], errors='coerce').dropna()
    if len(stat_values) < 3:
        return result

    over_hits = int((stat_values > float(line)).sum())
    under_hits = int((stat_values < float(line)).sum())
    total_games = int(len(stat_values))
    over_ceiling_map = {'PTS': 62, 'REB': 64, 'AST': 63, '3PM': 62, 'STL': 61, 'BLK': 61}
    under_ceiling_map = {'PTS': 62, 'REB': 64, 'AST': 63, '3PM': 62, 'STL': 61, 'BLK': 61}

    if over_hits == 0:
        result['ceilings']['OVER'] = over_ceiling_map.get(stat, 62)
        result['tags'].append('HARD SERIES-')
        result['note'] = f"No over hits in {total_games} recent games vs {normalized_opponent}."
    if under_hits == 0:
        result['ceilings']['UNDER'] = under_ceiling_map.get(stat, 62)
        result['tags'].append('HARD SERIES+')
        if not result['note']:
            result['note'] = f"No under hits in {total_games} recent games vs {normalized_opponent}."
    return result


def apply_hard_signal_ceiling(best_play, ceiling_result):
    if not best_play:
        return best_play
    ceiling_result = ceiling_result or {}
    ceilings = ceiling_result.get('ceilings') or {}
    direction = str(best_play.get('direction', '')).upper()
    ceiling = ceilings.get(direction)
    if ceiling is None:
        return best_play

    adjusted = dict(best_play)
    adjusted['confidence'] = round(min(float(adjusted.get('confidence', 0) or 0), float(ceiling)), 1)
    adjusted['is_lock'] = False
    adjusted['hard_signal_ceiling'] = float(ceiling)
    adjusted['hard_signal_note'] = ceiling_result.get('note', '')
    adjusted['hard_signal_tags'] = list(ceiling_result.get('tags') or [])
    return adjusted


def resolve_core_baseline_conflict(stat, best_play, baseline):
    stat = str(stat or '').upper()
    baseline = baseline or {}
    if stat not in CORE_BASELINE_STATS:
        return best_play

    over_prob = baseline.get('over_prob')
    under_prob = baseline.get('under_prob')
    if over_prob is None or under_prob is None:
        return best_play

    over_prob = float(over_prob)
    under_prob = float(under_prob)
    gap = abs(over_prob - under_prob)
    stronger_rate = max(over_prob, under_prob)
    baseline_direction = 'OVER' if over_prob > under_prob else 'UNDER' if under_prob > over_prob else ''

    if not baseline_direction:
        return best_play
    if str(best_play.get('direction', '')).upper() == baseline_direction:
        return best_play
    if stronger_rate < 55 or gap < 8:
        return best_play

    signal = build_play_signal(baseline_direction, stronger_rate)
    signal['baseline_override'] = True
    signal['baseline_gap'] = round(gap, 1)
    return signal


def score_prop(
    player_logs,
    stat,
    line,
    *,
    player='',
    team='',
    opponent=None,
    gamelogs=None,
    projection_context=None,
    scheduled_game=None,
    postseason_only=False,
    series_context=None,
    defense_context=None,
):
    player_logs = player_logs if player_logs is not None else pd.DataFrame()
    projection_context = projection_context or {}
    scheduled_game = scheduled_game or {}
    stat = str(stat or '').upper()
    avg = round(float(pd.to_numeric(player_logs[stat], errors='coerce').dropna().mean()), 1) if not player_logs.empty and stat in player_logs.columns else 0

    ou_rates = calculate_over_under_rates(player_logs, stat, line)
    situations = calculate_situational_factors(player_logs, player, team, opponent, gamelogs if gamelogs is not None else pd.DataFrame())
    projection_adjustments = get_projection_adjustments(projection_context, stat)
    game_environment = get_game_environment_adjustments(
        scheduled_game.get('market', {}),
        stat,
        site=scheduled_game.get('site'),
        role_label=projection_context.get('role_label'),
        projected_minutes=projection_context.get('projected_minutes'),
    )

    if postseason_only:
        playoff_adjustments = calculate_postseason_adjustments(
            player_logs,
            stat,
            line,
            opponent=opponent,
            team=team,
            series_context=series_context,
            defense_context=defense_context,
            game_site=scheduled_game.get('site'),
        )
    else:
        playoff_adjustments = {
            'weighted_over': ou_rates['over'],
            'weighted_under': ou_rates['under'],
            'over_boost': 0,
            'under_boost': 0,
            'tags': [],
        }
    volatility_context = calculate_playoff_volatility_flag(player_logs, stat) if postseason_only else {
        'flag': 'STABLE',
        'minutes_delta': None,
        'stat_delta': None,
        'note': '',
        'penalty': 0.0,
    }

    playoff_adjustments, core_baseline = apply_core_baseline_override(
        stat,
        player_logs,
        line,
        projection_context,
        opponent,
        playoff_adjustments,
        postseason_only=postseason_only,
    )

    raw_over_boost = (
        float(situations.get('over_boost', 0) or 0) +
        float(playoff_adjustments.get('over_boost', 0) or 0) +
        float(projection_adjustments.get('over_boost', 0) or 0) +
        float(game_environment.get('over_boost', 0) or 0)
    )
    raw_under_boost = (
        float(situations.get('under_boost', 0) or 0) +
        float(playoff_adjustments.get('under_boost', 0) or 0) +
        float(projection_adjustments.get('under_boost', 0) or 0) +
        float(game_environment.get('under_boost', 0) or 0)
    )
    capped_boosts = cap_soft_boosts(stat, raw_over_boost, raw_under_boost)

    best_play = get_best_play(
        playoff_adjustments.get('weighted_over', ou_rates['over']),
        playoff_adjustments.get('weighted_under', ou_rates['under']),
        capped_boosts['under'],
        capped_boosts['over'],
        line,
        avg,
    )
    best_play = resolve_core_baseline_conflict(stat, best_play, core_baseline)
    hard_signal_ceiling = check_hard_signal_ceiling(
        stat,
        player_logs,
        line,
        opponent=opponent,
        postseason_only=postseason_only,
    )
    best_play = apply_hard_signal_ceiling(best_play, hard_signal_ceiling)

    combined_situations = (
        list(situations.get('situations', []) or []) +
        list(playoff_adjustments.get('tags', []) or []) +
        list(projection_adjustments.get('tags', []) or []) +
        list(game_environment.get('tags', []) or [])
    )
    if best_play.get('baseline_override'):
        combined_situations.append('BASELINE HOLD')
    combined_situations.extend(hard_signal_ceiling.get('tags', []))

    return {
        'avg': avg,
        'ou_rates': ou_rates,
        'situations': situations,
        'projection_adjustments': projection_adjustments,
        'game_environment': game_environment,
        'playoff_adjustments': playoff_adjustments,
        'volatility_context': volatility_context,
        'core_baseline': core_baseline,
        'best_play': best_play,
        'combined_situations': list(dict.fromkeys([tag for tag in combined_situations if tag])),
        'soft_boost_cap': capped_boosts['cap'],
        'raw_over_boost': round(raw_over_boost, 1),
        'raw_under_boost': round(raw_under_boost, 1),
        'capped_over_boost': capped_boosts['over'],
        'capped_under_boost': capped_boosts['under'],
        'hard_signal_ceiling': hard_signal_ceiling,
    }


def build_lock_reason(play, weighted_over_rate=None, weighted_under_rate=None):
    if not play.get('is_lock'):
        return ''
    direction = play.get('direction', '')
    confidence = play.get('confidence', 0)
    rate = weighted_over_rate if direction == 'OVER' else weighted_under_rate
    if rate is None:
        rate = confidence
    return f"Lock because adjusted {direction.lower()} rate is {round(rate, 1)}%, clearing the 80% lock threshold."


