def build_live_prop_runtime_context(postseason_only=False):
    schedule_path = DATA_DIR / 'schedules' / 'NBA_Schedule.csv'
    gamelog_path = DATA_DIR / 'gamelogs' / 'NBA_GameLogs.csv'
    props_path = DATA_DIR / 'props' / 'NBA_Props.csv'
    odds_path = DATA_DIR / 'odds' / 'NBA_Odds.csv'
    playoffs_path = DATA_DIR / 'gamelogs' / 'NBA_Playoff_GameLogs.csv'
    cache_version = _build_file_token(schedule_path, gamelog_path, props_path, odds_path, playoffs_path)

    def _build_runtime():
        gamelogs, schedule = load_gamelogs(), load_schedule()
        player_advanced = load_player_advanced()
        player_tracking = load_player_tracking()
        player_snapshot = load_player_snapshot()
        current_team_overrides = load_current_team_overrides()
        current_team_map = build_current_team_map(gamelogs, player_snapshot, current_team_overrides)
        playoff_gamelogs = load_playoff_gamelogs() if postseason_only else pd.DataFrame()
        team_filter = get_team_filter(postseason_only)
        upcoming = get_upcoming_games(schedule, days=7, allowed_teams=team_filter)
        game_odds = load_game_market_odds()
        market_lookup = build_game_market_lookup(game_odds)
        for bucket_name in ['today', 'tomorrow', 'upcoming']:
            upcoming[bucket_name] = attach_market_to_games(upcoming.get(bucket_name, []), market_lookup)
        team_game_lookup = build_team_game_lookup(upcoming)
        raw_props, refresh_meta = load_live_props_feed(require_fresh=True)
        resolved_props = apply_current_team_context(raw_props, gamelogs, player_snapshot, current_team_overrides)
        resolved_props = filter_props_to_active_slate(resolved_props, team_game_lookup)
        props_market_groups = build_prop_market_groups(resolved_props)
        props_df = dedupe_props_to_anchor_book(resolved_props)
        active_boosts = load_active_boosts()
        return_impacts = load_return_impacts()
        return {
            'gamelogs': gamelogs,
            'schedule': schedule,
            'player_advanced': player_advanced,
            'player_tracking': player_tracking,
            'player_snapshot': player_snapshot,
            'current_team_overrides': current_team_overrides,
            'current_team_map': current_team_map,
            'props_df': props_df,
            'props_market_groups': props_market_groups,
            'refresh_meta': refresh_meta,
            'active_boosts': active_boosts,
            'return_impacts': return_impacts,
            'game_odds': game_odds,
            'market_lookup': market_lookup,
            'playoff_gamelogs': playoff_gamelogs,
            'team_filter': team_filter,
            'upcoming': upcoming,
            'team_game_lookup': team_game_lookup,
        }

    return _get_disk_ttl_cached_value(
        cache_key=f'live_prop_runtime::{int(bool(postseason_only))}',
        ttl_seconds=43200,
        builder=_build_runtime,
        version=cache_version,
    )


def build_live_prop_request_context(postseason_only=False, include_ticket=False):
    date_filter = request.args.get('date')
    if not date_filter:
        date_filter = 'all'
    sample_mode = request.args.get('sample', 'current' if postseason_only else 'full').strip().lower()
    if sample_mode not in {'current', 'full'}:
        sample_mode = 'current' if postseason_only else 'full'
    sort_by, sort_dir = get_sort_params()
    context = {
        'date_filter': date_filter,
        'model_debug': request.args.get('model_debug', '').strip() == '1',
        'direction_filter': request.args.get('direction', 'all'),
        'team_query': request.args.get('team', '').strip().upper(),
        'player_query': request.args.get('player', '').strip(),
        'stat_query': request.args.get('stat', '').strip().upper(),
        'sample_mode': sample_mode,
        'sort_by': sort_by,
        'sort_dir': sort_dir,
    }
    if include_ticket:
        context['selected_ticket_id'] = request.args.get('ticket_id', '').strip()
    return context

# =============================================================================
# SHARP FACTORS
# =============================================================================
def calculate_sharp_factors(player_name, player_logs):
    factors = {}
    if player_logs.empty:
        return factors
    
    if 'Date' in player_logs.columns:
        player_logs = player_logs.copy()
        player_logs['Date'] = pd.to_datetime(player_logs['Date'], errors='coerce')
        player_logs = player_logs.sort_values('Date', ascending=False)
    
    # MINUTES
    if 'MIN' in player_logs.columns:
        mins = player_logs['MIN'].dropna()
        factors['MIN_AVG'] = round(mins.mean(), 1)
        factors['MIN_FLOOR'] = round(mins.min(), 0)
        factors['MIN_CEIL'] = round(mins.max(), 0)
        factors['MIN_STD'] = round(mins.std(), 1)
        factors['MIN_LAST5'] = round(mins.head(5).mean(), 1)
        if factors['MIN_STD'] <= 3: factors['MIN_CONSISTENCY'] = 'ELITE'
        elif factors['MIN_STD'] <= 5: factors['MIN_CONSISTENCY'] = 'GOOD'
        elif factors['MIN_STD'] <= 8: factors['MIN_CONSISTENCY'] = 'FAIR'
        else: factors['MIN_CONSISTENCY'] = 'VOLATILE'
    
    # HOME/AWAY
    if 'Matchup' in player_logs.columns:
        home_games = player_logs[player_logs['Matchup'].str.contains('vs.', na=False)]
        away_games = player_logs[player_logs['Matchup'].str.contains('@', na=False)]
        for stat in ['PTS', 'REB', 'AST', '3PM']:
            if stat in player_logs.columns:
                home_avg = home_games[stat].mean() if not home_games.empty else 0
                away_avg = away_games[stat].mean() if not away_games.empty else 0
                factors[f'{stat}_HOME'] = round(home_avg, 1) if pd.notna(home_avg) else 0
                factors[f'{stat}_AWAY'] = round(away_avg, 1) if pd.notna(away_avg) else 0
    
    # FORM
    for stat in ['PTS', 'REB', 'AST', '3PM']:
        if stat in player_logs.columns:
            season_avg = player_logs[stat].mean()
            last_5 = player_logs.head(5)[stat].mean()
            last_10 = player_logs.head(10)[stat].mean()
            factors[f'{stat}_SEASON'] = round(season_avg, 1) if pd.notna(season_avg) else 0
            factors[f'{stat}_L5'] = round(last_5, 1) if pd.notna(last_5) else 0
            factors[f'{stat}_L10'] = round(last_10, 1) if pd.notna(last_10) else 0
            if season_avg > 0:
                form_pct = ((last_5 - season_avg) / season_avg) * 100
                factors[f'{stat}_FORM'] = round(form_pct, 1)
                if form_pct >= 15: factors[f'{stat}_TREND'] = 'HOT'
                elif form_pct >= 5: factors[f'{stat}_TREND'] = 'UP'
                elif form_pct <= -15: factors[f'{stat}_TREND'] = 'COLD'
                elif form_pct <= -5: factors[f'{stat}_TREND'] = 'DOWN'
                else: factors[f'{stat}_TREND'] = 'STABLE'
    
    # WINS/LOSSES
    if 'Result' in player_logs.columns:
        wins = player_logs[player_logs['Result'] == 'W']
        losses = player_logs[player_logs['Result'] == 'L']
        factors['WIN_PCT'] = round((len(wins) / len(player_logs)) * 100, 1) if len(player_logs) > 0 else 0
        for stat in ['PTS', 'REB', 'AST', 'MIN']:
            if stat in player_logs.columns:
                factors[f'{stat}_IN_WINS'] = round(wins[stat].mean(), 1) if not wins.empty else 0
                factors[f'{stat}_IN_LOSSES'] = round(losses[stat].mean(), 1) if not losses.empty else 0
    
    # FLOOR/CEILING
    for stat in ['PTS', 'REB', 'AST']:
        if stat in player_logs.columns:
            values = player_logs[stat].dropna()
            if not values.empty:
                season_avg = values.mean()
                factors[f'{stat}_FLOOR'] = int(values.min())
                factors[f'{stat}_CEIL'] = int(values.max())
                factors[f'{stat}_P10'] = round(values.quantile(0.1), 1)
                factors[f'{stat}_P25'] = round(values.quantile(0.25), 1)
                factors[f'{stat}_RANGE'] = round(values.max() - values.min(), 1)

                if len(values) >= 5:
                    recent_line = round(season_avg * FLOOR_MULTIPLIERS.get(stat, 0.75) * 2) / 2
                    factors[f'{stat}_STREAK'] = calculate_streak(player_logs, stat, recent_line)

                if pd.notna(season_avg) and season_avg > 0:
                    hr_60_line = round(season_avg * 0.60 * 2) / 2
                    hr_70_line = round(season_avg * 0.70 * 2) / 2
                    hr_80_line = round(season_avg * 0.80 * 2) / 2

                    factors[f'{stat}_HR_60'] = calculate_hit_rate(player_logs, stat, hr_60_line)
                    factors[f'{stat}_HR_70'] = calculate_hit_rate(player_logs, stat, hr_70_line)
                    factors[f'{stat}_HR_80'] = calculate_hit_rate(player_logs, stat, hr_80_line)

                    safe_line = None
                    safe_hit_rate = 0
                    for multiplier in [x / 100 for x in range(50, 111, 5)]:
                        test_line = round(season_avg * multiplier * 2) / 2
                        hit_rate = calculate_hit_rate(player_logs, stat, test_line)
                        if hit_rate >= 85:
                            safe_line = test_line
                            safe_hit_rate = hit_rate

                    if safe_line is not None:
                        factors[f'{stat}_SAFE_LINE'] = safe_line
                        factors[f'{stat}_SAFE_HR'] = safe_hit_rate

                    if factors.get(f'{stat}_HR_80', 0) >= 85:
                        factors[f'{stat}_PREDICTABILITY'] = 'HIGH'
                    elif factors.get(f'{stat}_HR_60', 0) <= 65:
                        factors[f'{stat}_PREDICTABILITY'] = 'LOW'
                    else:
                        factors[f'{stat}_PREDICTABILITY'] = 'MED'
    
    return factors

# =============================================================================
# HELPERS
# =============================================================================
def calculate_hit_rate(player_logs, stat, line):
    if player_logs.empty or stat not in player_logs.columns: return 0
    valid = player_logs[player_logs[stat].notna()]
    return round((valid[stat] >= line).sum() / len(valid) * 100, 1) if not valid.empty else 0

def calculate_streak(player_logs, stat, line):
    if player_logs.empty or stat not in player_logs.columns: return 0
    if 'Date' in player_logs.columns:
        player_logs = player_logs.sort_values('Date', ascending=False)
    streak = 0
    for _, row in player_logs.iterrows():
        if pd.notna(row[stat]) and row[stat] >= line: streak += 1
        else: break
    return streak

def calculate_under_streak(player_logs, stat, line):
    if player_logs.empty or stat not in player_logs.columns: return 0
    if 'Date' in player_logs.columns:
        player_logs = player_logs.sort_values('Date', ascending=False)
    streak = 0
    for _, row in player_logs.iterrows():
        if pd.notna(row[stat]) and row[stat] < line: streak += 1
        else: break
    return streak

def calculate_streak_profile(player_logs, stat, line, min_streak=3):
    if player_logs.empty or stat not in player_logs.columns:
        return {
            'line': line,
            'games': 0,
            'over_count': 0,
            'over_lengths': [],
            'over_longest': 0,
            'over_avg_gap': None,
            'under_count': 0,
            'under_lengths': [],
            'under_longest': 0,
            'under_avg_gap': None,
            'current_label': 'No sample'
        }

    valid = player_logs[player_logs[stat].notna()].copy()
    if valid.empty:
        return {
            'line': line,
            'games': 0,
            'over_count': 0,
            'over_lengths': [],
            'over_longest': 0,
            'over_avg_gap': None,
            'under_count': 0,
            'under_lengths': [],
            'under_longest': 0,
            'under_avg_gap': None,
            'current_label': 'No sample'
        }

    if 'Date' in valid.columns:
        valid = valid.sort_values('Date', ascending=True)

    runs = []
    current_side = None
    current_len = 0
    start_idx = 0

    for idx, (_, row) in enumerate(valid.iterrows()):
        side = 'over' if row[stat] >= line else 'under'
        if side == current_side:
            current_len += 1
        else:
            if current_side is not None:
                runs.append({'side': current_side, 'length': current_len, 'start': start_idx, 'end': idx - 1})
            current_side = side
            current_len = 1
            start_idx = idx

    if current_side is not None:
        runs.append({'side': current_side, 'length': current_len, 'start': start_idx, 'end': len(valid) - 1})

    def summarize_runs(side_name):
        qualifying = [run for run in runs if run['side'] == side_name and run['length'] >= min_streak]
        lengths = [run['length'] for run in qualifying]
        gaps = []
        for prev, curr in zip(qualifying, qualifying[1:]):
            gaps.append(max(0, curr['start'] - prev['end'] - 1))
        return {
            'count': len(qualifying),
            'lengths': lengths,
            'longest': max(lengths) if lengths else 0,
            'avg_gap': round(sum(gaps) / len(gaps), 1) if gaps else None
        }

    over_summary = summarize_runs('over')
    under_summary = summarize_runs('under')
    current_over = calculate_streak(valid.sort_values('Date', ascending=False) if 'Date' in valid.columns else valid, stat, line)
    current_under = calculate_under_streak(valid.sort_values('Date', ascending=False) if 'Date' in valid.columns else valid, stat, line)

    if current_over > 0:
        current_label = f"Over {current_over}"
    elif current_under > 0:
        current_label = f"Under {current_under}"
    else:
        current_label = 'Flat'

    return {
        'line': line,
        'games': len(valid),
        'over_count': over_summary['count'],
        'over_lengths': over_summary['lengths'],
        'over_longest': over_summary['longest'],
        'over_avg_gap': over_summary['avg_gap'],
        'under_count': under_summary['count'],
        'under_lengths': under_summary['lengths'],
        'under_longest': under_summary['longest'],
        'under_avg_gap': under_summary['avg_gap'],
        'current_label': current_label
    }


def calculate_streak_follow_audit(player_logs, stat, line, thresholds=(3, 5)):
    if player_logs.empty or stat not in player_logs.columns:
        return {
            threshold: {
                'over': {'chances': 0, 'hits': 0, 'rate': None},
                'under': {'chances': 0, 'hits': 0, 'rate': None},
            }
            for threshold in thresholds
        }

    valid = player_logs[player_logs[stat].notna()].copy()
    if valid.empty:
        return {
            threshold: {
                'over': {'chances': 0, 'hits': 0, 'rate': None},
                'under': {'chances': 0, 'hits': 0, 'rate': None},
            }
            for threshold in thresholds
        }

    if 'Date' in valid.columns:
        valid = valid.sort_values('Date', ascending=True)

    audit = {
        threshold: {
            'over': {'chances': 0, 'hits': 0, 'rate': None},
            'under': {'chances': 0, 'hits': 0, 'rate': None},
        }
        for threshold in thresholds
    }

    previous_side = None
    previous_len = 0
    for _, row in valid.iterrows():
        value = row[stat]
        if previous_side is not None:
            for threshold in thresholds:
                if previous_len >= threshold:
                    bucket = audit[threshold][previous_side]
                    bucket['chances'] += 1
                    if previous_side == 'over' and value >= line:
                        bucket['hits'] += 1
                    elif previous_side == 'under' and value < line:
                        bucket['hits'] += 1

        side = 'over' if value >= line else 'under'
        if side == previous_side:
            previous_len += 1
        else:
            previous_side = side
            previous_len = 1

    for threshold in thresholds:
        for side in ['over', 'under']:
            chances = audit[threshold][side]['chances']
            hits = audit[threshold][side]['hits']
            audit[threshold][side]['rate'] = round((hits / chances) * 100, 1) if chances else None

    return audit

def build_market_reference_lookup(props_df):
    if props_df is None or props_df.empty or 'Player' not in props_df.columns or 'Stat' not in props_df.columns:
        return {}

    working = props_df.copy()
    for col in ['CurrentLine', 'Line']:
        if col in working.columns:
            working[col] = pd.to_numeric(working[col], errors='coerce')
    if 'LastUpdated' in working.columns:
        working['LastUpdated'] = pd.to_datetime(working['LastUpdated'], errors='coerce')

    lookup = {}
    for (player, stat), group in working.groupby(['Player', 'Stat'], dropna=False):
        if pd.isna(player) or pd.isna(stat):
            continue
        selected = None
        if 'Book' in group.columns:
            book_lower = group['Book'].astype(str).str.lower()
            for preferred in ['caesars', 'draftkings', 'fanduel', 'betmgm']:
                matches = group[book_lower == preferred]
                if not matches.empty:
                    if 'LastUpdated' in matches.columns:
                        matches = matches.sort_values('LastUpdated', ascending=False)
                    selected = matches.iloc[0]
                    break
        if selected is None:
            if 'LastUpdated' in group.columns:
                group = group.sort_values('LastUpdated', ascending=False)
            selected = group.iloc[0]

        line_value = selected.get('CurrentLine')
        if pd.isna(line_value):
            line_value = selected.get('Line')
        if pd.isna(line_value):
            continue

        book_name = str(selected.get('Book', '')).strip() or 'Market'
        lookup[(str(player).strip().lower(), str(stat).strip().upper())] = {
            'line': round(float(line_value), 1),
            'book': book_name,
            'source_label': 'Vegas' if book_name.lower() == 'caesars' else 'Market',
        }
    return lookup


def calculate_consistency_index(snapshot_score, floor_rate, market_best_rate, active_streaks, current_run_len, over_avg_gap, under_avg_gap):
    snapshot_component = float(snapshot_score) if snapshot_score is not None and not pd.isna(snapshot_score) else 55.0
    floor_component = float(floor_rate) if floor_rate is not None and not pd.isna(floor_rate) else 50.0
    market_component = float(market_best_rate) if market_best_rate is not None and not pd.isna(market_best_rate) else floor_component

    gap_values = [float(v) for v in [over_avg_gap, under_avg_gap] if v is not None and not pd.isna(v)]
    avg_gap = sum(gap_values) / len(gap_values) if gap_values else 6.0
    repeat_component = min(
        100.0,
        max(0.0, (active_streaks * 9.0) + (current_run_len * 8.0) + max(0.0, 20.0 - (avg_gap * 3.0)))
    )

    score = (
        (snapshot_component * 0.30) +
        (floor_component * 0.28) +
        (market_component * 0.22) +
        (repeat_component * 0.20)
    )
    return round(max(0.0, min(99.0, score)), 1)


def consistency_label(score):
    if score >= 85:
        return 'Elite'
    if score >= 76:
        return 'Strong'
    if score >= 68:
        return 'Solid'
    if score >= 60:
        return 'Fair'
    return 'Volatile'


def build_trend_board(gamelogs, current_team_map, props_df=None, player_snapshot=None, team_filter=None, sample_mode='current', stat_filter='all'):
    if gamelogs.empty or 'Player' not in gamelogs.columns:
        return []

    rows = []
    stat_pool = [stat_filter] if stat_filter in STAT_COLUMNS else STAT_COLUMNS
    market_reference_lookup = build_market_reference_lookup(props_df)
    snapshot_lookup = {}
    if player_snapshot is not None and not player_snapshot.empty and 'player_name' in player_snapshot.columns:
        snapshot_working = player_snapshot.copy()
        if 'last_game_date' in snapshot_working.columns:
            snapshot_working['last_game_date'] = pd.to_datetime(snapshot_working['last_game_date'], errors='coerce')
            snapshot_working = snapshot_working.sort_values('last_game_date', ascending=False)
        snapshot_lookup = {
            str(row.get('player_name', '')).strip().lower(): row
            for _, row in snapshot_working.iterrows()
            if str(row.get('player_name', '')).strip()
        }

    for player_name in sorted(gamelogs['Player'].dropna().unique()):
        full_logs = gamelogs[gamelogs['Player'] == player_name].copy()
        if full_logs.empty:
            continue
        current_team = current_team_map.get(player_name, full_logs.iloc[0]['Team'] if 'Team' in full_logs.columns else 'UNK')
        if team_filter and not team_in_filter(current_team, team_filter):
            continue

        player_logs = full_logs.copy()
        if sample_mode == 'current' and 'Team' in full_logs.columns:
            current_logs = full_logs[full_logs['Team'] == current_team].copy()
            if not current_logs.empty:
                player_logs = current_logs

        if 'Date' in player_logs.columns:
            player_logs['Date'] = pd.to_datetime(player_logs['Date'], errors='coerce')
            player_logs = player_logs.sort_values('Date', ascending=False)

        for stat in stat_pool:
            if stat not in player_logs.columns:
                continue
            valid = player_logs[player_logs[stat].notna()].copy()
            if len(valid) < 10:
                continue
            avg = valid[stat].mean()
            if avg < MIN_AVG_FOR_PROPS.get(stat, 1):
                continue

            floor_line = round(avg * FLOOR_MULTIPLIERS.get(stat, 0.75) * 2) / 2
            if floor_line < 0.5:
                floor_line = 0.5

            profile = calculate_streak_profile(player_logs, stat, floor_line, min_streak=3)
            follow_audit = calculate_streak_follow_audit(player_logs, stat, floor_line, thresholds=(3, 5))
            floor_rates = calculate_over_under_rates(valid, stat, floor_line)
            current_label = profile['current_label']
            current_run_len = 0
            current_run_side = 'flat'
            if current_label.startswith('Over '):
                current_run_side = 'over'
                current_run_len = int(current_label.split(' ')[1])
            elif current_label.startswith('Under '):
                current_run_side = 'under'
                current_run_len = int(current_label.split(' ')[1])

            follow_3 = follow_audit[3].get(current_run_side, {'chances': 0, 'hits': 0, 'rate': None}) if current_run_side in {'over', 'under'} else {'chances': 0, 'hits': 0, 'rate': None}
            follow_5 = follow_audit[5].get(current_run_side, {'chances': 0, 'hits': 0, 'rate': None}) if current_run_side in {'over', 'under'} else {'chances': 0, 'hits': 0, 'rate': None}

            market_reference = market_reference_lookup.get((str(player_name).strip().lower(), str(stat).strip().upper()), {})
            market_line = market_reference.get('line')
            market_source = market_reference.get('source_label', 'Floor')
            market_book = market_reference.get('book', '')
            market_rates = calculate_over_under_rates(valid, stat, market_line) if market_line is not None else {'over': None, 'under': None}
            market_over_hits = int((valid[stat] > market_line).sum()) if market_line is not None else 0
            market_under_hits = int((valid[stat] < market_line).sum()) if market_line is not None else 0
            market_pushes = int((valid[stat] == market_line).sum()) if market_line is not None else 0
            floor_hits = int((valid[stat] >= floor_line).sum())
            floor_misses = int((valid[stat] < floor_line).sum())
            active_streaks = int(profile['over_count'] + profile['under_count'])

            snapshot_row = snapshot_lookup.get(str(player_name).strip().lower())
            snapshot_consistency = None
            if snapshot_row is not None:
                score_value = snapshot_row.get('consistency_score')
                if pd.notna(score_value):
                    snapshot_consistency = round(float(score_value), 1)

            market_best_rate = None
            if market_line is not None:
                market_best_rate = max(market_rates.get('over') or 0, market_rates.get('under') or 0)

            consistency_index = calculate_consistency_index(
                snapshot_consistency,
                floor_rates.get('over'),
                market_best_rate,
                active_streaks,
                current_run_len,
                profile['over_avg_gap'],
                profile['under_avg_gap'],
            )

            rows.append({
                'player': player_name,
                'team': current_team,
                'stat': stat,
                'line': floor_line,
                'avg': round(avg, 1),
                'games': profile['games'],
                'over_rate': floor_rates['over'],
                'under_rate': floor_rates['under'],
                'over_count': profile['over_count'],
                'over_lengths': ', '.join(str(length) for length in profile['over_lengths']) if profile['over_lengths'] else '-',
                'over_longest': profile['over_longest'],
                'over_avg_gap': profile['over_avg_gap'],
                'under_count': profile['under_count'],
                'under_lengths': ', '.join(str(length) for length in profile['under_lengths']) if profile['under_lengths'] else '-',
                'under_longest': profile['under_longest'],
                'under_avg_gap': profile['under_avg_gap'],
                'current_label': current_label,
                'current_run_len': current_run_len,
                'current_run_side': current_run_side,
                'active_streaks': active_streaks,
                'follow_3_chances': follow_3.get('chances', 0),
                'follow_3_hits': follow_3.get('hits', 0),
                'follow_3_rate': follow_3.get('rate'),
                'follow_3_label': f"{'O' if current_run_side == 'over' else 'U'} {follow_3.get('hits', 0)}/{follow_3.get('chances', 0)}" if current_run_side in {'over', 'under'} and follow_3.get('chances', 0) else '-',
                'follow_5_chances': follow_5.get('chances', 0),
                'follow_5_hits': follow_5.get('hits', 0),
                'follow_5_rate': follow_5.get('rate'),
                'follow_5_label': f"{'O' if current_run_side == 'over' else 'U'} {follow_5.get('hits', 0)}/{follow_5.get('chances', 0)}" if current_run_side in {'over', 'under'} and follow_5.get('chances', 0) else '-',
                'market_line': market_line,
                'market_source': market_source,
                'market_book': market_book,
                'market_over_rate': market_rates.get('over'),
                'market_under_rate': market_rates.get('under'),
                'market_over_hits': market_over_hits,
                'market_under_hits': market_under_hits,
                'market_pushes': market_pushes,
                'floor_hits': floor_hits,
                'floor_misses': floor_misses,
                'floor_hit_rate': floor_rates.get('over'),
                'snapshot_consistency': snapshot_consistency,
                'consistency_index': consistency_index,
                'consistency_label': consistency_label(consistency_index),
                'sample_mode': sample_mode,
                'trend_score': round(
                    (profile['over_count'] * 3) + profile['over_longest'] +
                    (profile['under_count'] * 3) + profile['under_longest'] +
                    (6 - min(profile['over_avg_gap'], 6) if profile['over_avg_gap'] is not None else 0) +
                    (6 - min(profile['under_avg_gap'], 6) if profile['under_avg_gap'] is not None else 0),
                    1
                )
            })

    return rows


def build_trend_opportunity_history(gamelogs, current_team_map, team_filter=None, sample_mode='current', stat_filter='all', thresholds=(3, 5)):
    """Expanding-window trailing-streak scan behind /trend-board.

    Replaces a former per-window DataFrame.copy()/sort_values()/iterrows() walk
    (via calculate_streak_profile) with numpy arrays — validated row-for-row
    identical to that version. The caller only needs each window's *current* streak, and
    the backward scan stops at the first opposite-side game, so this is ~O(total
    games) instead of O(games^2) with pandas overhead — cold render drops from
    ~34s to a couple of seconds.
    """
    if gamelogs.empty or 'Player' not in gamelogs.columns:
        return []

    rows = []
    stat_pool = [stat_filter] if stat_filter in STAT_COLUMNS else STAT_COLUMNS

    for player_name in sorted(gamelogs['Player'].dropna().unique()):
        full_logs = gamelogs[gamelogs['Player'] == player_name]
        if full_logs.empty:
            continue
        current_team = current_team_map.get(player_name, full_logs.iloc[0]['Team'] if 'Team' in full_logs.columns else 'UNK')
        if team_filter and not team_in_filter(current_team, team_filter):
            continue

        player_logs = full_logs
        if sample_mode == 'current' and 'Team' in full_logs.columns:
            current_logs = full_logs[full_logs['Team'] == current_team]
            if not current_logs.empty:
                player_logs = current_logs

        if 'Date' in player_logs.columns:
            player_logs = player_logs.assign(Date=pd.to_datetime(player_logs['Date'], errors='coerce')).sort_values('Date', ascending=True)

        has_date = 'Date' in player_logs.columns
        has_opp = 'Opp' in player_logs.columns

        for stat in stat_pool:
            if stat not in player_logs.columns:
                continue
            valid = player_logs[player_logs[stat].notna()]
            if len(valid) < 11:
                continue
            vals = pd.to_numeric(valid[stat], errors='coerce').to_numpy(dtype='float64')
            if np.isnan(vals).any():  # mirror the legacy notna filter
                keep = ~np.isnan(vals)
                valid = valid.loc[keep]
                vals = vals[keep]
            n = len(vals)
            if n < 11:
                continue
            dates = valid['Date'].tolist() if has_date else None
            opps = valid['Opp'].tolist() if has_opp else None
            csum = np.cumsum(vals)
            mult = FLOOR_MULTIPLIERS.get(stat, 0.75)
            min_avg = MIN_AVG_FOR_PROPS.get(stat, 1)

            for idx in range(10, n):
                history_avg = csum[idx - 1] / idx  # == mean(vals[:idx])
                if history_avg < min_avg:
                    continue
                floor_line = round(float(history_avg) * mult * 2) / 2
                if floor_line < 0.5:
                    floor_line = 0.5

                over = bool(vals[idx - 1] >= floor_line)
                cnt = 0
                j = idx - 1
                if over:
                    while j >= 0 and vals[j] >= floor_line:
                        cnt += 1
                        j -= 1
                else:
                    while j >= 0 and vals[j] < floor_line:
                        cnt += 1
                        j -= 1

                if cnt < thresholds[0]:  # shorter than the smallest threshold -> no rows
                    continue

                streak_side = 'over' if over else 'under'
                current_value = vals[idx]
                continued = bool(current_value >= floor_line) if over else bool(current_value < floor_line)

                for threshold in thresholds:
                    if cnt < threshold:
                        continue
                    rows.append({
                        'player': player_name,
                        'team': current_team,
                        'stat': stat,
                        'threshold': int(threshold),
                        'side': streak_side,
                        'streak_len_before': int(cnt),
                        'line': round(float(floor_line), 1),
                        'history_avg': round(float(history_avg), 1),
                        'value': round(float(current_value), 1),
                        'continued': continued,
                        'date': (dates[idx] if dates is not None else None),
                        'opp': (opps[idx] if opps is not None else ''),
                        'sample_mode': sample_mode,
                    })

    return rows


def summarize_trend_opportunities(opportunity_rows):
    summary = {
        '3': {'chances': 0, 'hits': 0, 'rate': None, 'best_stat': '', 'best_stat_rate': None},
        '5': {'chances': 0, 'hits': 0, 'rate': None, 'best_stat': '', 'best_stat_rate': None},
    }
    if not opportunity_rows:
        return summary

    df = pd.DataFrame(opportunity_rows)
    if df.empty:
        return summary

    for threshold in [3, 5]:
        subset = df[df['threshold'] == threshold].copy()
        if subset.empty:
            continue
        chances = int(len(subset))
        hits = int(subset['continued'].astype(bool).sum())
        rate = round((hits / chances) * 100, 1) if chances else None
        summary[str(threshold)].update({
            'chances': chances,
            'hits': hits,
            'rate': rate,
        })

        stat_rows = []
        for stat, group in subset.groupby('stat'):
            group_chances = int(len(group))
            if group_chances < 2:
                continue
            group_hits = int(group['continued'].astype(bool).sum())
            group_rate = round((group_hits / group_chances) * 100, 1) if group_chances else None
            stat_rows.append((stat, group_rate, group_chances))
        if stat_rows:
            stat_rows = sorted(stat_rows, key=lambda item: (item[1], item[2]), reverse=True)
            best_stat, best_rate, _ = stat_rows[0]
            summary[str(threshold)]['best_stat'] = best_stat
            summary[str(threshold)]['best_stat_rate'] = best_rate

    return summary


def _serialize_team_filter(team_filter):
    if team_filter is None:
        return ''
    if isinstance(team_filter, (set, list, tuple)):
        return '|'.join(sorted(str(item).strip().upper() for item in team_filter if str(item).strip()))
    return str(team_filter).strip().upper()


def get_trend_opportunity_summary_cached(gamelogs, current_team_map, team_filter=None, sample_mode='current', stat_filter='all'):
    TREND_OPPORTUNITY_CACHE_DIR.mkdir(parents=True, exist_ok=True)
    stat_key = str(stat_filter or 'all').strip().lower() or 'all'
    team_key = _serialize_team_filter(team_filter)
    cache_name = f"{sample_mode}_{stat_key}_{(team_key or 'all').replace('|', '_')}.json"
    cache_path = TREND_OPPORTUNITY_CACHE_DIR / cache_name

    max_date = ''
    if gamelogs is not None and not gamelogs.empty and 'Date' in gamelogs.columns:
        try:
            max_date = str(pd.to_datetime(gamelogs['Date'], errors='coerce').max())
        except Exception:
            max_date = ''

    cache_meta = {
        'rows': int(len(gamelogs)) if gamelogs is not None else 0,
        'max_date': max_date,
        'sample_mode': sample_mode,
        'stat_filter': stat_key,
        'team_filter': team_key,
    }

    if cache_path.exists():
        try:
            payload = json.loads(cache_path.read_text(encoding='utf-8'))
            if payload.get('meta') == cache_meta:
                return payload.get('summary', {
                    '3': {'chances': 0, 'hits': 0, 'rate': None, 'best_stat': '', 'best_stat_rate': None},
                    '5': {'chances': 0, 'hits': 0, 'rate': None, 'best_stat': '', 'best_stat_rate': None},
                })
        except Exception:
            pass

    history_rows = build_trend_opportunity_history(
        gamelogs,
        current_team_map,
        team_filter=team_filter,
        sample_mode=sample_mode,
        stat_filter=stat_filter,
    )
    summary = summarize_trend_opportunities(history_rows)
    payload = {
        'meta': cache_meta,
        'summary': summary,
        'opportunity_count': len(history_rows),
        'updated_at': datetime.now().isoformat(timespec='seconds'),
    }
    cache_path.write_text(json.dumps(payload, indent=2), encoding='utf-8')
    return summary

def calculate_trend(player_logs, stat):
    if player_logs.empty or stat not in player_logs.columns: return 'FLAT', 0
    if 'Date' in player_logs.columns:
        player_logs = player_logs.sort_values('Date', ascending=False)
    valid = player_logs[player_logs[stat].notna()]
    if len(valid) < 10: return 'FLAT', 0
    last_5, prior_5 = valid.head(5)[stat].mean(), valid.iloc[5:10][stat].mean()
    if prior_5 == 0: return 'FLAT', 0
    pct = ((last_5 - prior_5) / prior_5) * 100
    if pct >= 15: return 'HOT', 10
    if pct >= 5: return 'UP', 5
    if pct <= -15: return 'COLD', -10
    if pct <= -5: return 'DOWN', -5
    return 'FLAT', 0

def calculate_postseason_adjustments(player_logs, stat, line, opponent=None, team=None, series_context=None, defense_context=None, game_site=None):
    weight_profile = get_postseason_weight_profile(series_context)
    adjustments = {
        'weighted_over': 0,
        'weighted_under': 0,
        'over_boost': 0,
        'under_boost': 0,
        'tags': [],
        'weight_profile': weight_profile.get('profile', 'regular'),
        'component_weights': {
            'line_history': round(weight_profile.get('line_history', 0) * 100),
            'role_usage': round(weight_profile.get('role_usage', 0) * 100),
            'opponent': round(weight_profile.get('opponent', 0) * 100),
            'streak': round(weight_profile.get('streak', 0) * 100),
            'market': round(weight_profile.get('market', 0) * 100),
        },
        'series_weight': round(weight_profile.get('series_weight', 0), 2),
        'series_game_number': int(weight_profile.get('game_number', 0) or 0),
    }
    if player_logs.empty or stat not in player_logs.columns:
        return adjustments
    if 'Date' in player_logs.columns:
        player_logs = player_logs.sort_values('Date', ascending=False)

    valid = player_logs[player_logs[stat].notna()]
    if valid.empty:
        return adjustments

    pressure_profile = get_player_pressure_profile(player_logs)
    adjustments['over_boost'] += pressure_profile['pressure_over_boost']
    adjustments['under_boost'] += pressure_profile['pressure_under_boost']
    adjustments['tags'].extend(pressure_profile['tags'])

    full_rates = calculate_over_under_rates(valid, stat, line)
    last_10_sample = valid.head(10)
    last_5_sample = valid.head(5)
    last_10_rates = calculate_over_under_rates(last_10_sample, stat, line) if len(valid) >= 10 else full_rates
    last_5_rates = calculate_over_under_rates(last_5_sample, stat, line) if len(valid) >= 5 else full_rates

    stabilized_full_over = stabilize_rate(full_rates['over'], len(valid))
    stabilized_full_under = stabilize_rate(full_rates['under'], len(valid))
    stabilized_last_10_over = stabilize_rate(last_10_rates['over'], len(last_10_sample))
    stabilized_last_10_under = stabilize_rate(last_10_rates['under'], len(last_10_sample))
    stabilized_last_5_over = stabilize_rate(last_5_rates['over'], len(last_5_sample))
    stabilized_last_5_under = stabilize_rate(last_5_rates['under'], len(last_5_sample))
    postseason_stage = classify_postseason_stage(series_context)

    sample_full_weight = float(weight_profile.get('sample_full', 0.3) or 0.3)
    sample_last_10_weight = float(weight_profile.get('sample_last_10', 0.3) or 0.3)
    sample_last_5_weight = float(weight_profile.get('sample_last_5', 0.4) or 0.4)

    if len(valid) >= 10:
        adjustments['weighted_over'] = round(
            stabilized_full_over * sample_full_weight +
            stabilized_last_10_over * sample_last_10_weight +
            stabilized_last_5_over * sample_last_5_weight,
            1
        )
        adjustments['weighted_under'] = round(
            stabilized_full_under * sample_full_weight +
            stabilized_last_10_under * sample_last_10_weight +
            stabilized_last_5_under * sample_last_5_weight,
            1
        )
    elif len(valid) >= 5:
        residual_full = sample_full_weight + sample_last_10_weight
        adjustments['weighted_over'] = round(stabilized_full_over * residual_full + stabilized_last_5_over * sample_last_5_weight, 1)
        adjustments['weighted_under'] = round(stabilized_full_under * residual_full + stabilized_last_5_under * sample_last_5_weight, 1)
    else:
        adjustments['weighted_over'] = stabilized_full_over
        adjustments['weighted_under'] = stabilized_full_under

    if last_5_rates['over'] >= full_rates['over'] + 12:
        adjustments['over_boost'] += 6
        adjustments['tags'].append('L5 SURGE')
    elif last_5_rates['under'] >= full_rates['under'] + 12:
        adjustments['under_boost'] += 6
        adjustments['tags'].append('L5 FADE')

    over_streak = calculate_streak(valid, stat, line)
    under_streak = calculate_under_streak(valid, stat, line)
    if over_streak >= 3:
        streak_boost = min(over_streak, 6)
        if postseason_stage == 'later_round':
            streak_boost += 2
        if postseason_stage == 'later_round' and over_streak >= 4:
            streak_boost += 4
            adjustments['tags'].append('RUN TAKEOVER')
        adjustments['over_boost'] += streak_boost
        adjustments['tags'].append('STREAK+')
    if under_streak >= 3:
        streak_boost = min(under_streak, 6)
        if postseason_stage == 'later_round':
            streak_boost += 2
        if postseason_stage == 'later_round' and under_streak >= 4:
            streak_boost += 4
            adjustments['tags'].append('RUN TAKEOVER')
        adjustments['under_boost'] += streak_boost
        adjustments['tags'].append('STREAK-')

    if stat == 'PTS':
        recent_fga = valid['FGA'].head(5).mean() if 'FGA' in valid.columns else np.nan
        recent_fta = valid['FTA'].head(5).mean() if 'FTA' in valid.columns else np.nan
        if pd.notna(recent_fga):
            if recent_fga >= max(11.5, line + 1.5):
                adjustments['over_boost'] += 4 if postseason_stage == 'later_round' else 3
                adjustments['tags'].append('SHOT VOL+')
            elif recent_fga <= max(7.5, line - 1.0):
                adjustments['under_boost'] += 6 if postseason_stage == 'later_round' else 4
                adjustments['tags'].append('SHOT VOL-')
        if pd.notna(recent_fta):
            if recent_fta >= 4:
                adjustments['over_boost'] += 1
                adjustments['tags'].append('FT PATH+')
            elif recent_fta <= 1.5:
                adjustments['under_boost'] += 1
                adjustments['tags'].append('FT PATH-')

    if 'MIN' in player_logs.columns:
        mins = player_logs['MIN'].dropna()
        if len(mins) >= 5:
            min_last_5 = mins.head(5).mean()
            min_season = mins.mean()
            min_std = mins.std()
            if pd.notna(min_last_5) and pd.notna(min_season):
                if min_last_5 >= min_season + 2 and (pd.isna(min_std) or min_std <= 5):
                    adjustments['over_boost'] += 4
                    adjustments['tags'].append('MIN+')
                elif min_last_5 <= min_season - 2:
                    adjustments['under_boost'] += 4
                    adjustments['tags'].append('MIN-')
        if len(mins) >= 8:
            min_last_3 = mins.head(3).mean()
            min_prior_5 = mins.iloc[3:8].mean()
            if pd.notna(min_last_3) and pd.notna(min_prior_5):
                if min_last_3 >= min_prior_5 + 3:
                    adjustments['over_boost'] += 6 if postseason_stage == 'later_round' else 5
                    adjustments['tags'].append('ROLE UP')
                elif min_last_3 <= min_prior_5 - 3:
                    adjustments['under_boost'] += 7 if postseason_stage == 'later_round' else 5
                    adjustments['tags'].append('ROLE DOWN')

    if opponent and 'Opp' in valid.columns:
        vs_opp = valid[valid['Opp'] == opponent]
        if len(vs_opp) >= 2:
            opp_rates = calculate_over_under_rates(vs_opp, stat, line)
            series_weight = float(weight_profile.get('series_weight', 0) or 0)
            context_boost_scale = 1.0 + min(0.75, series_weight)
            if opp_rates['over'] >= full_rates['over'] + 10:
                adjustments['over_boost'] += round(4 * context_boost_scale, 1)
                adjustments['tags'].append('VS OPP+')
            elif opp_rates['under'] >= full_rates['under'] + 10:
                adjustments['under_boost'] += round(4 * context_boost_scale, 1)
                adjustments['tags'].append('VS OPP-')
            if stat in CORE_BASELINE_STATS:
                opp_recent = vs_opp.head(3)
                if len(opp_recent) >= 2:
                    opp_hits = int((opp_recent[stat] > line).sum())
                    if opp_hits == 0:
                        series_under_boost = {'PTS': 8, 'AST': 6, 'REB': 6, '3PM': 5, 'STL': 4, 'BLK': 4}
                        adjustments['under_boost'] += round(series_under_boost.get(stat, 4) * context_boost_scale, 1)
                        adjustments['tags'].append('SERIES UNDER')
                    elif opp_hits == len(opp_recent):
                        series_over_boost = {'PTS': 6, 'AST': 5, 'REB': 5, '3PM': 5, 'STL': 4, 'BLK': 4}
                        adjustments['over_boost'] += round(series_over_boost.get(stat, 4) * context_boost_scale, 1)
                        adjustments['tags'].append('SERIES OVER')

    if defense_context:
        adjustments['over_boost'] += defense_context.get('over_boost', 0)
        adjustments['under_boost'] += defense_context.get('under_boost', 0)
        adjustments['tags'].extend(defense_context.get('tags', []))

    venue_context = get_venue_split_context(valid, stat, line, game_site)
    adjustments['over_boost'] += venue_context.get('over_boost', 0)
    adjustments['under_boost'] += venue_context.get('under_boost', 0)
    adjustments['tags'].extend(venue_context.get('tags', []))

    if series_context:
        series_type = series_context.get('series_type', '')
        series_score = series_context.get('series_score', {})
        games = series_score.get('games', [])
        team_wins = series_score.get('team_a_wins', 0)
        opp_wins = series_score.get('team_b_wins', 0)
        next_game_number = len(games) + 1
        series_weight = float(weight_profile.get('series_weight', 0) or 0)

        if series_type in {'playoff', 'play-in', 'postseason'}:
            adjustments['tags'].append(f'G{next_game_number}')

        if series_type == 'play-in':
            adjustments['over_boost'] += 3 + pressure_profile['pressure_over_boost']
            adjustments['under_boost'] += pressure_profile['pressure_under_boost']
            adjustments['tags'].append('WIN OR GO HOME')

        last_winner = series_score.get('last_winner')
        if last_winner and team and opponent:
            if last_winner == opponent:
                adjustments['over_boost'] += round(3 * (1 + series_weight * 0.5), 1)
                adjustments['tags'].append('BOUNCE BACK')
            elif last_winner == team and series_type == 'playoff':
                adjustments['tags'].append('KEEP EDGE')

        if team_wins < opp_wins:
            adjustments['over_boost'] += round((min(4, (opp_wins - team_wins) + 1) * (1 + series_weight * 0.5)) + pressure_profile['pressure_over_boost'], 1)
            adjustments['under_boost'] += pressure_profile['pressure_under_boost']
            adjustments['tags'].append('TRAILING')
        elif team_wins > opp_wins and team_wins >= 2:
            adjustments['under_boost'] += round((2 * (1 + series_weight * 0.35)) + pressure_profile['pressure_under_boost'], 1)
            adjustments['tags'].append('AHEAD')

        if series_type == 'playoff' and opp_wins >= 3 and team_wins < opp_wins:
            adjustments['over_boost'] += round((5 * (1 + series_weight * 0.35)) + pressure_profile['pressure_over_boost'], 1)
            adjustments['under_boost'] += pressure_profile['pressure_under_boost']
            adjustments['tags'].append('ELIMINATION')
        elif series_type == 'playoff' and team_wins >= 3 and team_wins > opp_wins:
            adjustments['over_boost'] += max(0, pressure_profile['pressure_over_boost'] - 1)
            adjustments['under_boost'] += pressure_profile['pressure_under_boost']
            adjustments['tags'].append('CLOSEOUT')

    # Deduplicate while keeping order for display
    adjustments['tags'] = list(dict.fromkeys(adjustments['tags']))
    return adjustments

def calculate_smart_score(hit_rate, streak, trend_bonus):
    return min(100, max(0, round(hit_rate + min(streak * 5, 25) + trend_bonus)))

def get_grade(score):
    if score >= 95: return 'A+'
    if score >= 90: return 'A'
    if score >= 85: return 'B+'
    if score >= 80: return 'B'
    if score >= 70: return 'C'
    return 'D'


def classify_postseason_stage(series_context=None):
    series_context = series_context or {}
    series_type = str(series_context.get('series_type', '') or '').strip().lower()
    series_label = str(series_context.get('series_label', '') or '').strip().lower()

    if series_type == 'play-in' or 'play-in' in series_label:
        return 'play_in'
    if 'first round' in series_label:
        return 'first_round'
    if any(token in series_label for token in ['semifinals', 'conference finals', 'finals']):
        return 'later_round'
    if series_type in {'playoff', 'postseason'}:
        return 'later_round'
    return 'regular'


def get_postseason_weight_profile(series_context=None):
    series_context = series_context or {}
    stage = classify_postseason_stage(series_context)
    series_score = series_context.get('series_score', {}) or {}
    game_number = int(len(series_score.get('games', []) or [])) + 1
    series_weight_map = {
        1: 0.00,
        2: 0.20,
        3: 0.45,
        4: 0.65,
        5: 0.80,
        6: 0.90,
        7: 0.95,
    }
    series_weight = series_weight_map.get(min(game_number, 7), 0.95)

    if stage == 'first_round' and game_number <= 2:
        return {
            'profile': 'r1_early',
            'line_history': 0.50,
            'role_usage': 0.18,
            'opponent': 0.12,
            'streak': 0.12,
            'market': 0.08,
            'sample_full': 0.25,
            'sample_last_10': 0.30,
            'sample_last_5': 0.45,
            'series_weight': series_weight,
            'game_number': game_number,
        }
    if stage == 'first_round':
        return {
            'profile': 'r1_late',
            'line_history': 0.47,
            'role_usage': 0.17,
            'opponent': 0.18,
            'streak': 0.12,
            'market': 0.06,
            'sample_full': 0.18,
            'sample_last_10': 0.30,
            'sample_last_5': 0.52,
            'series_weight': series_weight,
            'game_number': game_number,
        }
    if stage == 'later_round':
        series_label = str(series_context.get('series_label', '') or '').lower()
        profile = 'r2'
        line_history = 0.44
        role_usage = 0.16
        opponent = 0.22
        streak = 0.12
        market = 0.06
        sample_full = 0.12
        sample_last_10 = 0.24
        sample_last_5 = 0.64
        if 'conference finals' in series_label or 'finals' in series_label:
            profile = 'r3_r4'
            line_history = 0.41
            role_usage = 0.18
            opponent = 0.24
            streak = 0.11
            market = 0.06
            sample_full = 0.10
            sample_last_10 = 0.20
            sample_last_5 = 0.70
        return {
            'profile': profile,
            'line_history': line_history,
            'role_usage': role_usage,
            'opponent': opponent,
            'streak': streak,
            'market': market,
            'sample_full': sample_full,
            'sample_last_10': sample_last_10,
            'sample_last_5': sample_last_5,
            'series_weight': series_weight,
            'game_number': game_number,
        }
    return {
        'profile': 'regular',
        'line_history': 0.50,
        'role_usage': 0.18,
        'opponent': 0.12,
        'streak': 0.12,
        'market': 0.08,
        'sample_full': 0.30,
        'sample_last_10': 0.30,
        'sample_last_5': 0.40,
        'series_weight': series_weight,
        'game_number': game_number,
    }


def calculate_playoff_volatility_flag(player_logs, stat):
    stat = str(stat or '').upper()
    result = {
        'flag': 'STABLE',
        'minutes_delta': None,
        'stat_delta': None,
        'note': 'Role and recent usage look stable.',
        'penalty': 0.0,
    }
    if player_logs is None or getattr(player_logs, 'empty', True):
        return result

    working = player_logs.copy()
    if 'Date' in working.columns:
        working = working.sort_values('Date', ascending=False)
    valid = working[working[stat].notna()] if stat in working.columns else working
    if len(valid) < 5:
        result['note'] = 'Not enough recent playoff sample for a volatility read.'
        return result

    l2 = valid.head(2)
    prior3 = valid.iloc[2:5]
    if prior3.empty:
        result['note'] = 'Not enough prior sample for a volatility read.'
        return result

    stat_l2 = pd.to_numeric(l2.get(stat), errors='coerce').dropna().mean() if stat in valid.columns else np.nan
    stat_prior3 = pd.to_numeric(prior3.get(stat), errors='coerce').dropna().mean() if stat in valid.columns else np.nan
    minutes_l2 = pd.to_numeric(l2.get('MIN'), errors='coerce').dropna().mean() if 'MIN' in valid.columns else np.nan
    minutes_prior3 = pd.to_numeric(prior3.get('MIN'), errors='coerce').dropna().mean() if 'MIN' in valid.columns else np.nan

    stat_delta = None if pd.isna(stat_l2) or pd.isna(stat_prior3) else round(float(stat_l2 - stat_prior3), 1)
    minutes_delta = None if pd.isna(minutes_l2) or pd.isna(minutes_prior3) else round(float(minutes_l2 - minutes_prior3), 1)
    result['stat_delta'] = stat_delta
    result['minutes_delta'] = minutes_delta

    high_role_flip = False
    if minutes_delta is not None and abs(minutes_delta) >= 4:
        high_role_flip = True
    if stat in {'PTS', 'AST', 'REB'} and stat_delta is not None and abs(stat_delta) >= 4:
        high_role_flip = True
    if stat in {'STL', 'BLK', '3PM'} and stat_delta is not None and abs(stat_delta) >= 1.5:
        high_role_flip = True

    elevated = False
    if minutes_delta is not None and abs(minutes_delta) >= 2:
        elevated = True
    if stat in {'PTS', 'AST', 'REB'} and stat_delta is not None and abs(stat_delta) >= 2.5:
        elevated = True
    if stat in {'STL', 'BLK', '3PM'} and stat_delta is not None and abs(stat_delta) >= 1.0:
        elevated = True

    minute_phrase = None
    stat_phrase = None
    if minutes_delta is not None:
        minute_phrase = f"MIN {'up' if minutes_delta > 0 else 'down'} {abs(float(minutes_delta)):.1f} in the last 2 vs prior 3"
    if stat_delta is not None:
        stat_phrase = f"{stat} {'up' if stat_delta > 0 else 'down'} {abs(float(stat_delta)):.1f} in the last 2 vs prior 3"

    if high_role_flip:
        result['flag'] = 'HIGH'
        result['penalty'] = 10.0
        note_bits = [bit for bit in [minute_phrase, stat_phrase] if bit]
        if note_bits:
            result['note'] = '; '.join(note_bits[:2]) + '. Role direction looks unstable.'
        else:
            result['note'] = 'Recent role or output flipped sharply in the last two games.'
    elif elevated:
        result['flag'] = 'ELEVATED'
        result['penalty'] = 5.0
        note_bits = [bit for bit in [minute_phrase, stat_phrase] if bit]
        if note_bits:
            result['note'] = '; '.join(note_bits[:2]) + '. Enough movement to trim blind trend confidence.'
        else:
            result['note'] = 'Recent role or output is moving enough to question a blind trend follow.'
    return result


def build_bet_tier(play):
    verdict = str((play or {}).get('play_verdict', 'PLAY') or 'PLAY').upper()
    market_gate = str((play or {}).get('market_gate', 'CLEAR') or 'CLEAR').upper()
    volatility_flag = str((play or {}).get('volatility_flag', 'STABLE') or 'STABLE').upper()
    confidence = float((play or {}).get('confidence', 0) or 0)
    zero_required_under = is_zero_required_under_play(play)

    if verdict != 'PLAY' or market_gate == 'HOLD':
        return {'label': 'SKIP', 'note': 'Do not force this without cleaner support.'}
    if zero_required_under:
        return {'label': 'SKIP', 'note': 'Zero-required under: one event kills the ticket.'}
    if confidence >= 84 and market_gate == 'CLEAR' and volatility_flag == 'STABLE':
        return {'label': 'FULL UNIT', 'note': 'Clean support stack with no active gate.'}
    if confidence >= 72 and market_gate in {'CLEAR', 'SPLIT MARKET'}:
        return {'label': 'HALF UNIT', 'note': 'Playable, but something still needs respect.'}
    return {'label': 'SKIP', 'note': 'More monitor than attack right now.'}

