@app.route('/')
def frontpage():
    current_user = get_current_user()
    if current_user:
        return redirect(_resolve_post_auth_target(current_user, ''))
    postseason_only = postseason_only_enabled()
    snapshot_key = 'nba_command_center_postseason' if postseason_only else 'nba_command_center_regular'
    snapshot = load_runtime_snapshot(snapshot_key, max_age_minutes=720, allow_stale=True, stale_max_age_minutes=4320)
    nba_context = snapshot.get('payload') if snapshot else build_nba_command_center_context(postseason_only)
    sports_launch_cards = build_sports_launch_cards(
        postseason_only,
        upcoming=nba_context['upcoming'],
        total_props=nba_context['total_props'],
        total_players=len(nba_context['teams']),
        top_plays_count=len(nba_context['top_plays']),
        best_by_series_count=len(nba_context['best_by_series'])
    )
    sport_snapshots = build_cross_sport_dashboard_snapshots(postseason_only=postseason_only)
    cross_sport_top_props = build_cross_sport_top_props(sport_snapshots)
    phase2 = build_phase2_dashboard_context()
    run_status = load_run_status_context(limit=8)
    return render_template(
        'dashboard_overview.html',
        public_tour=True,
        sports_launch_cards=sports_launch_cards,
        sport_snapshots=sport_snapshots,
        cross_sport_top_props=cross_sport_top_props,
        nba_summary=nba_context['nba_summary'],
        phase2=phase2,
        run_status=run_status,
        postseason_only=postseason_only,
        active_page='home',
        bankroll='0.00',
    )

    snapshot_key = 'nba_command_center_postseason' if postseason_only else 'nba_command_center_regular'
    snapshot = load_runtime_snapshot(snapshot_key, max_age_minutes=720, allow_stale=True, stale_max_age_minutes=4320)
    if snapshot:
        payload = snapshot.get('payload') or {}
        upcoming = payload.get('upcoming') or {'today': [], 'tomorrow': [], 'upcoming': []}
        top_plays = (payload.get('top_plays') or [])[:5]
        teams = payload.get('teams') or []
        total_props = int(payload.get('total_props') or 0)
        best_by_series = payload.get('best_by_series') or []
        sports_launch_cards = build_sports_launch_cards(
            postseason_only,
            upcoming=upcoming,
            total_props=total_props,
            total_players=len(teams),
            top_plays_count=len(top_plays),
            best_by_series_count=len(best_by_series),
        )
        sport_snapshots = build_cross_sport_dashboard_snapshots(postseason_only=postseason_only)
        streak_heat = build_today_playable_hot_hands(sport_snapshots, limit=3)
        return render_template('frontpage.html',
            num_games_today=len(upcoming.get('today', [])),
            num_games_tomorrow=len(upcoming.get('tomorrow', [])),
            num_games_upcoming=len(upcoming.get('upcoming', [])),
            total_players=len(teams),
            total_props=total_props,
            top_plays=top_plays,
            upcoming=upcoming,
            upcoming_today=payload.get('upcoming_today') or upcoming.get('today', []),
            upcoming_tomorrow=payload.get('upcoming_tomorrow') or upcoming.get('tomorrow', []),
            upcoming_future=payload.get('upcoming_future') or upcoming.get('upcoming', []),
            postseason_only=postseason_only,
            postseason_matchups=payload.get('postseason_matchups') or [],
            best_by_series=best_by_series,
            role_changes=payload.get('role_changes') or [],
            sports_launch_cards=sports_launch_cards,
            sport_snapshots=sport_snapshots,
            streak_heat=streak_heat)

    gamelogs, schedule = load_gamelogs(), load_schedule()
    player_snapshot = load_player_snapshot()
    current_team_overrides = load_current_team_overrides()
    props = load_canonical_live_props(gamelogs, player_snapshot, current_team_overrides)
    game_odds = load_game_market_odds()
    market_lookup = build_game_market_lookup(game_odds)
    postseason_only = postseason_only_enabled()
    team_filter = get_team_filter(postseason_only, schedule)
    upcoming = get_upcoming_games(schedule, days=7, allowed_teams=team_filter)
    postseason_matchups = build_postseason_matchups(upcoming, gamelogs, schedule) if postseason_only else []
    upcoming_today = annotate_schedule_games(upcoming['today'], gamelogs, schedule) if postseason_only else upcoming['today']
    upcoming_tomorrow = annotate_schedule_games(upcoming['tomorrow'], gamelogs, schedule) if postseason_only else upcoming['tomorrow']
    upcoming_future = annotate_schedule_games(upcoming['upcoming'], gamelogs, schedule) if postseason_only else upcoming['upcoming']
    upcoming_today = attach_market_to_games(upcoming_today, market_lookup)
    upcoming_tomorrow = attach_market_to_games(upcoming_tomorrow, market_lookup)
    upcoming_future = attach_market_to_games(upcoming_future, market_lookup)
    postseason_matchups = attach_market_to_games(postseason_matchups, market_lookup) if postseason_matchups else []
    injuries = load_injuries() if postseason_only else pd.DataFrame()
    active_boosts = load_active_boosts() if postseason_only else pd.DataFrame()
    role_changes = build_role_change_candidates(injuries, active_boosts, team_filter, gamelogs) if postseason_only else []
    best_by_series = build_series_best_plays(props, gamelogs, schedule) if postseason_only else []
    
    total_players = gamelogs['Player'].nunique() if not gamelogs.empty and 'Player' in gamelogs.columns else 0
    top_plays = []
    live_board = build_live_props_board(
        filter_type=None,
        postseason_only=postseason_only,
        date_filter='today' if postseason_only else 'all',
        direction_filter='all',
        team_query='',
        player_query='',
        stat_query='',
        sample_mode='current' if postseason_only else 'full',
        model_debug=False,
        sort_by='confidence',
        sort_dir='desc',
    )
    live_props = live_board.get('props', [])
    if live_props:
        top_plays = build_featured_nba_top_plays(
            live_props,
            limit=5,
            min_confidence=75 if postseason_only else 70,
        )
        if top_plays:
            archive_version = _build_file_token(
                DATA_DIR / 'props' / 'NBA_Props.csv',
                DATA_DIR / 'odds' / 'NBA_Odds.csv',
            )
            if should_run_browse_archive(
                f'nba-featured-frontpage::{int(bool(postseason_only))}',
                cooldown_seconds=900,
                version=archive_version,
            ):
                archive_method_candidates(
                    'Featured Top Play',
                    top_plays[:40],
                    postseason_only=postseason_only,
                    sample_mode='current' if postseason_only else 'full',
                )

    sports_launch_cards = build_sports_launch_cards(
        postseason_only,
        upcoming=upcoming,
        total_props=len(props) if not props.empty else 0,
        total_players=total_players,
        top_plays_count=len(top_plays),
        best_by_series_count=len(best_by_series)
    )
    sport_snapshots = build_cross_sport_dashboard_snapshots(postseason_only=postseason_only)
    streak_heat = build_today_playable_hot_hands(sport_snapshots, limit=3)
    
    return render_template('frontpage.html', 
        num_games_today=len(upcoming['today']),
        num_games_tomorrow=len(upcoming['tomorrow']),
        num_games_upcoming=len(upcoming['upcoming']),
        total_players=total_players, 
        total_props=len(props) if not props.empty else 0,
        top_plays=top_plays,
        upcoming=upcoming,
        upcoming_today=upcoming_today,
        upcoming_tomorrow=upcoming_tomorrow,
        upcoming_future=upcoming_future,
        postseason_only=postseason_only,
        postseason_matchups=postseason_matchups,
        best_by_series=best_by_series,
        role_changes=role_changes,
        sports_launch_cards=sports_launch_cards,
        sport_snapshots=sport_snapshots,
        streak_heat=streak_heat)


def build_nba_command_center_context(postseason_only):
    cache_key = f'nba_command_center::{int(bool(postseason_only))}'
    cache_version = _build_file_token(
        DATA_DIR / 'schedules' / 'NBA_Schedule.csv',
        DATA_DIR / 'gamelogs' / 'NBA_GameLogs.csv',
        DATA_DIR / 'gamelogs' / 'NBA_Playoff_GameLogs.csv',
        DATA_DIR / 'tracking' / 'NBA_Playoff_Results.csv',
        DATA_DIR / 'props' / 'NBA_Props.csv',
        DATA_DIR / 'odds' / 'NBA_Odds.csv',
        DATA_DIR / 'injuries' / 'NBA_Injuries.csv',
    )
    cached_entry = RUNTIME_TTL_CACHE.get(cache_key)
    if cached_entry:
        cached_age = (datetime.now(timezone.utc) - cached_entry['created_at']).total_seconds()
        if cached_age <= 180 and cached_entry.get('version') == cache_version:
            return cached_entry['value']
    disk_cache_key = f'disk::{cache_key}'
    disk_hit, disk_context = _read_disk_ttl_cached_value(disk_cache_key, version=cache_version)
    if disk_hit:
        RUNTIME_TTL_CACHE[cache_key] = {
            'created_at': datetime.now(timezone.utc),
            'value': disk_context,
            'version': cache_version,
        }
        return disk_context

    gamelogs, schedule = load_gamelogs(), load_schedule()
    playoff_results = load_playoff_results()
    player_advanced = load_player_advanced()
    player_tracking = load_player_tracking()
    player_snapshot = load_player_snapshot()
    current_team_overrides = load_current_team_overrides()
    current_team_map = build_current_team_map(gamelogs, player_snapshot, current_team_overrides)
    props = load_canonical_live_props(gamelogs, player_snapshot, current_team_overrides)
    props_market_groups = build_prop_market_groups(props)
    props_anchor = dedupe_props_to_anchor_book(props)
    playoff_gamelogs = load_playoff_gamelogs() if postseason_only else pd.DataFrame()
    game_odds = load_game_market_odds()
    market_lookup = build_game_market_lookup(game_odds)
    team_filter = get_team_filter(postseason_only)
    mode_labels = get_focus_mode_labels(postseason_only)
    upcoming = get_upcoming_games(schedule, days=7, allowed_teams=team_filter)
    postseason_matchups = build_postseason_matchups(upcoming, gamelogs, schedule) if postseason_only else []
    upcoming_today = annotate_schedule_games(upcoming['today'], gamelogs, schedule) if postseason_only else upcoming['today']
    upcoming_tomorrow = annotate_schedule_games(upcoming['tomorrow'], gamelogs, schedule) if postseason_only else upcoming['tomorrow']
    upcoming_future = annotate_schedule_games(upcoming['upcoming'], gamelogs, schedule) if postseason_only else upcoming['upcoming']
    upcoming_today = attach_market_to_games(upcoming_today, market_lookup)
    upcoming_tomorrow = attach_market_to_games(upcoming_tomorrow, market_lookup)
    upcoming_future = attach_market_to_games(upcoming_future, market_lookup)
    postseason_matchups = attach_market_to_games(postseason_matchups, market_lookup) if postseason_matchups else []
    injuries = load_injuries()
    active_boosts = load_active_boosts()
    return_impacts = load_return_impacts()
    role_changes = build_role_change_candidates(injuries, active_boosts, team_filter, gamelogs) if postseason_only else []
    best_by_series = build_series_best_plays(props, gamelogs, schedule) if postseason_only else []
    defense_cache = {}
    teams = sorted(gamelogs['Team'].dropna().unique().tolist()) if not gamelogs.empty and 'Team' in gamelogs.columns else []
    teams = filter_teams_list(teams, team_filter)

    top_plays = []
    live_board = build_live_props_board(
        filter_type=None,
        postseason_only=postseason_only,
        date_filter='today' if postseason_only else 'all',
        direction_filter='all',
        team_query='',
        player_query='',
        stat_query='',
        sample_mode='current' if postseason_only else 'full',
        model_debug=False,
        sort_by='confidence',
        sort_dir='desc',
    )
    live_props = live_board.get('props', [])
    if live_props:
        top_plays = build_featured_nba_top_plays(live_props, limit=20, min_confidence=70)
        if top_plays:
            archive_version = _build_file_token(
                DATA_DIR / 'props' / 'NBA_Props.csv',
                DATA_DIR / 'odds' / 'NBA_Odds.csv',
            )
            if should_run_browse_archive(
                f'nba-featured-dashboard::{int(bool(postseason_only))}',
                cooldown_seconds=900,
                version=archive_version,
            ):
                archive_method_candidates(
                    'Featured Top Play',
                    top_plays[:40],
                    postseason_only=postseason_only,
                    sample_mode='current' if postseason_only else 'full',
                )

    if not top_plays and postseason_only and best_by_series:
        fallback_top_plays = []
        for play in best_by_series[:12]:
            fallback_top_plays.append({
                'player': play.get('player'),
                'team': play.get('team'),
                'stat': play.get('stat'),
                'line': play.get('line'),
                'direction': play.get('direction'),
                'hit_rate': float(play.get('confidence', 0) or 0),
                'confidence': float(play.get('confidence', 0) or 0),
                'plays_today': True,
                'plays_tomorrow': False,
                'tags': play.get('tags', []),
                'guardrail_tags': [],
                'guardrail_note': 'series shortlist fallback',
                'move_label': '',
                'tone': 'muted',
                'book_count': 0,
                'range_gap': None,
                'open_line': None,
                'current_line': play.get('line'),
                'prior_line': None,
                'draftkings_line': None,
                'vegas_line': None,
                'line_low': None,
                'line_high': None,
                'best_book': '',
                'book_comparison_note': '',
                'market_summary': '',
                'live_line_over_rate': None,
                'live_line_under_rate': None,
                'live_line_games': 0,
                'play_verdict': 'PLAY',
                'play_verdict_note': str(play.get('support_note') or 'Series shortlist fallback'),
            })
        top_plays = fallback_top_plays

    matchup_lens_board = build_matchup_lens_board(postseason_matchups, best_by_series, role_changes, top_plays)
    tonight_cards = build_tonights_card(postseason_matchups, top_plays, best_by_series=best_by_series) if postseason_only else []
    market_watch = build_nba_market_watch(
        props,
        {
            'today': upcoming_today,
            'tomorrow': upcoming_tomorrow,
            'upcoming': upcoming_future,
        },
        top_plays,
    )
    refresh_meta = get_props_refresh_meta(props)
    results_last_date = ''
    if not playoff_results.empty and 'Date' in playoff_results.columns:
        try:
            results_last_date = str(pd.to_datetime(playoff_results['Date'], errors='coerce').max().strftime('%Y-%m-%d'))
        except Exception:
            results_last_date = ''
    nba_data_pulse = {
        'schedule_source': 'Odds-backed live slate',
        'schedule_games': int(len(schedule)),
        'results_last_date': results_last_date or 'Unknown',
        'prop_books': int(refresh_meta.get('book_count', 0) or 0),
        'props_last_updated': refresh_meta.get('last_updated', 'Unknown'),
    }

    context = {
        'upcoming': upcoming,
        'upcoming_today': upcoming_today,
        'upcoming_tomorrow': upcoming_tomorrow,
        'upcoming_future': upcoming_future,
        'total_props': len(props),
        'teams': teams,
        'top_plays': top_plays,
        'postseason_only': postseason_only,
        'postseason_matchups': postseason_matchups,
        'matchup_lens_board': matchup_lens_board,
        'tonight_cards': tonight_cards,
        'market_watch': market_watch,
        'nba_data_pulse': nba_data_pulse,
        'best_by_series': best_by_series,
        'role_changes': role_changes,
        'nba_summary': {
            'focus_label': mode_labels['focus_mode_label'] if postseason_only else mode_labels['regular_mode_label'],
            'focus_copy': mode_labels['focus_mode_description'] if postseason_only else 'Full-league view across every NBA board and research tool.',
            'today_games': len(upcoming['today']),
            'tomorrow_games': len(upcoming['tomorrow']),
            'board_depth': len(props),
            'top_plays': len(top_plays),
            'series_angles': len(best_by_series),
            'lens_cards': len(matchup_lens_board),
            'tonight_cards': len(tonight_cards),
        }
    }
    RUNTIME_TTL_CACHE[cache_key] = {
        'created_at': datetime.now(timezone.utc),
        'value': context,
        'version': cache_version,
    }
    _write_disk_ttl_cached_value(disk_cache_key, 43200, context, version=cache_version)
    return context

