def build_nfl_dashboard_runtime_bundle():
    cache_version = _build_file_token(
        DATA_DIR / 'odds' / 'NFL_Odds.csv',
        DATA_DIR / 'props' / 'NFL_Props.csv',
        DATA_DIR / 'schedules' / 'NFL_Schedule.csv',
    )

    def _build_bundle():
        live_odds = load_nfl_game_market_odds()
        live_schedule = load_nfl_schedule()
        live_props, live_refresh_meta = load_nfl_live_props_feed(require_fresh=True)
        live_games = build_football_live_games(live_odds, live_schedule, date_filter='all')
        live_prop_rows = build_football_live_prop_board(
            live_props,
            live_odds,
            live_schedule,
            method_key='props',
            date_filter='all',
        )
        live_status = build_football_live_status('nfl', live_games, live_prop_rows, live_props, live_schedule, live_odds)
        history_status = build_football_history_status(build_football_history_lab('nfl'))
        return {
            'live_odds': live_odds,
            'live_schedule': live_schedule,
            'live_props': live_props,
            'live_refresh_meta': live_refresh_meta,
            'live_games': live_games,
            'live_prop_rows': live_prop_rows,
            'live_status': live_status,
            'history_status': history_status,
        }

    return _get_disk_ttl_cached_value(
        cache_key='nfl_dashboard_runtime',
        ttl_seconds=43200,
        builder=_build_bundle,
        version=cache_version,
    )


