def _render_football_method_page(sport_key, method_key):
    sport_key = str(sport_key or '').strip().lower()
    method_key = str(method_key or 'game_lines').strip().lower()
    postseason_only = postseason_only_enabled()
    sport_profile = get_sport_model_profile(sport_key)
    football_methods = get_football_method_modules(sport_key)
    method = next((item for item in football_methods if str(item.get('key', '')).strip().lower() == method_key), get_football_method_config(method_key))
    history_lab = build_football_history_lab(sport_key)
    current_season_context = build_ncaaf_current_season_context() if sport_key == 'ncaaf' else {}

    board = {}
    filter_state = {}
    method_view = {
        'method': method,
        'top_plays': [],
        'games': [],
        'summary_cards': [],
        'history_status': {},
        'live_games': [],
        'live_plays': [],
        'history_rows': [],
        'history_team_scorecards': [],
        'history_player_rows': [],
        'history_player_scorecards': [],
        'history_player_note': '',
        'history_prop_review': {},
        'history_insights': [],
        'game_line_board': {},
        'source': 'framework',
        'live_data_checked': False,
        'live_empty_reason': '',
        'live_refresh_meta': {},
    }
    if sport_key == 'nfl':
        board = load_nfl_floor_board()
        filter_state = build_nfl_filter_state(request.args, board)
        board = apply_nfl_board_filters(board, filter_state)
        method_view = build_nfl_method_view(board, method_key)
        method_view.update({'live_games': [], 'live_plays': [], 'source': 'workbook', 'history_status': {}, 'game_line_board': {}})

    sport_loaders = {
        'nfl': {
            'odds': load_nfl_game_market_odds,
            'schedule': load_nfl_schedule,
            'props': load_nfl_live_props_feed,
        },
        'ncaaf': {
            'odds': load_ncaaf_game_market_odds,
            'schedule': load_ncaaf_schedule,
            'props': load_ncaaf_live_props_feed,
        },
    }
    date_filter = request.args.get('date', 'all').strip().lower() or 'all'
    stat_filter = request.args.get('stat', '').strip()
    direction_filter = request.args.get('direction', 'all').strip().lower() or 'all'
    search_query = request.args.get('search', '').strip()

    live_config = sport_loaders.get(sport_key)
    if live_config:
        live_odds = live_config['odds']()
        live_schedule = live_config['schedule']()
        live_props, live_refresh_meta = live_config['props'](require_fresh=True)
        method_view['live_data_checked'] = True
        method_view['live_refresh_meta'] = live_refresh_meta
        if sport_key == 'nfl' and method_key in {'game_lines', 'totals'}:
            method_view['game_line_board'] = build_football_game_line_intelligence(
                sport_key,
                method_key,
                odds_df=live_odds,
                limit=20,
            )
        if method_key in {'game_lines', 'totals'}:
            live_games = build_football_live_game_method_board(
                method_key,
                live_odds,
                live_schedule,
                date_filter=date_filter,
                search_query=search_query,
                sport_key=sport_key,
            )
            if live_games:
                method_view['live_games'] = live_games
                method_view['source'] = 'live'
                _live_totals = [pd.to_numeric(game.get('total'), errors='coerce') for game in live_games]
                _valid_totals = [float(t) for t in _live_totals if pd.notna(t)]
                avg_total = round(sum(_valid_totals) / len(_valid_totals), 1) if _valid_totals else 0
                method_view['summary_cards'] = [
                    {'label': 'Matchups', 'value': len(live_games), 'note': 'live slate rows loaded'},
                    {'label': 'Book Source', 'value': len(sorted({str(game.get("book") or "").strip() for game in live_games if str(game.get("book") or "").strip()})), 'note': ', '.join(sorted({str(game.get("book") or "").strip() for game in live_games if str(game.get("book") or "").strip()})[:4]) or 'No books loaded'},
                    {'label': 'Avg Total', 'value': avg_total if avg_total else '-', 'note': 'live market total average'},
                ]
            elif not live_odds.empty or not live_schedule.empty:
                method_view['source'] = 'empty_live'
                method_view['live_empty_reason'] = 'Football feed files exist, but no live market rows were returned for the current window.'
        elif method_key in {'props', 'trends'} and live_refresh_meta.get('has_live_props'):
            live_plays = build_football_live_prop_board(
                live_props,
                live_odds,
                live_schedule,
                method_key=method_key,
                date_filter=date_filter,
                stat_filter=stat_filter,
                direction_filter=direction_filter,
                search_query=search_query,
                sport_key=sport_key,
            )
            if sport_key == 'ncaaf' and live_plays:
                guarded_featured = apply_cfb_contradiction_guardrails(live_plays[:12], featured=True)
                guarded_rest = apply_cfb_contradiction_guardrails(live_plays[12:], featured=False)
                live_plays = [
                    play for play in (guarded_featured + guarded_rest)
                    if not bool(play.get('is_contradiction_blocked'))
                ]
            if live_plays:
                method_view['live_plays'] = live_plays[:80]
                method_view['source'] = 'live'
                families = sorted({str(play.get('stat_family') or '').strip() for play in live_plays if str(play.get('stat_family') or '').strip()})
                method_view['summary_cards'] = [
                    {'label': 'Rows', 'value': len(live_plays), 'note': 'live football prop rows'},
                    {'label': 'Books', 'value': live_refresh_meta.get('book_count', 0), 'note': ', '.join(live_refresh_meta.get('books', [])[:4]) or 'No books loaded'},
                    {'label': 'Families', 'value': len(families), 'note': ', '.join(families[:3]) if families else 'No stat families loaded'},
                ]
                if sport_key == 'nfl':
                    sim_card = build_nfl_simulation_summary_card(method_view['live_plays'])
                    if sim_card:
                        method_view['summary_cards'].append(sim_card)
            elif not live_props.empty:
                method_view['source'] = 'empty_live'
                method_view['live_empty_reason'] = 'Football prop files exist, but no live prop rows were returned for the current window.'
        elif method_key in {'props', 'trends'} and (not live_props.empty or not live_odds.empty or not live_schedule.empty):
            method_view['source'] = 'empty_live'
            method_view['live_empty_reason'] = 'Football data files are present, but they only contain headers right now.'

    if method_key in {'game_lines', 'totals', 'trends'}:
        historical_rows = build_football_historical_market_rows(sport_key, method_key)
        if historical_rows:
            method_view['history_rows'] = historical_rows
            if sport_key == 'nfl':
                method_view['history_team_scorecards'] = build_nfl_historical_team_scorecards(historical_rows, method_key)
            if not method_view.get('summary_cards'):
                avg_fit = round(float(np.nanmean([row.get('fit_score', 0) for row in historical_rows])), 1)
                method_view['summary_cards'] = [
                    {'label': 'Historical Rows', 'value': len(historical_rows), 'note': 'ranked from prior-season streak patterns'},
                    {'label': 'Seasons', 'value': max(int(row.get('seasons') or 0) for row in historical_rows), 'note': 'multi-season trend window'},
                    {'label': 'Avg Fit', 'value': avg_fit, 'note': 'historical streak score'},
                ]

    if sport_key == 'nfl' and method_key in {'trends', 'props'}:
        historical_player_rows = build_nfl_historical_player_trend_rows(method_key)
        if historical_player_rows:
            historical_player_rows = attach_nfl_quant_insights_to_rows(historical_player_rows, default_direction='OVER')
            historical_player_rows = attach_promotion_signals_to_props(historical_player_rows, sport='NFL', score_fields=('fit_score',))
            method_view['history_player_rows'] = historical_player_rows
            method_view['history_player_scorecards'] = build_nfl_historical_player_scorecards(historical_player_rows)
            real_line_rows = sum(1 for row in historical_player_rows if str(row.get('line_source') or '').strip())
            if real_line_rows:
                method_view['history_player_note'] = 'Historical DraftKings player prop lines are now powering this board where archived lines exist; the proxy model only fills gaps when real line history is missing.'
            else:
                method_view['history_player_note'] = 'Proxy lines are derived from each player historical production so we can test continuation behavior before we have a full historical Vegas prop archive.'
            if not method_view.get('summary_cards'):
                avg_fit = round(float(np.nanmean([row.get('fit_score', 0) for row in historical_player_rows])), 1)
                method_view['summary_cards'] = [
                    {'label': 'Players', 'value': len(historical_player_rows), 'note': 'historical player hot-hand candidates'},
                    {'label': 'Season', 'value': historical_player_rows[0].get('season') or '-', 'note': 'latest historical season in view'},
                    {'label': 'Avg Fit', 'value': avg_fit, 'note': 'player continuation score'},
                ]
            sim_card = build_nfl_simulation_summary_card(historical_player_rows)
            if sim_card:
                method_view['summary_cards'].append(sim_card)

    if sport_key == 'nfl':
        method_view['history_prop_review'] = history_lab.get('prop_review', {})
        method_view['history_insights'] = build_nfl_historical_insights(
            history_lab,
            method_view.get('history_player_scorecards', []),
            method_key,
        )
    method_view['history_status'] = build_football_history_status(history_lab)

    page_title_map = {
        'nfl': 'NFL',
        'ncaaf': 'College Football',
    }
    return render_template(
        'football_method_board.html',
        sport_key=sport_key,
        sport_title=page_title_map.get(sport_key, sport_key.upper()),
        postseason_only=postseason_only,
        sport_profile=sport_profile,
        football_methods=football_methods,
        active_method=method_key,
        method=method,
        board=board,
        method_view=method_view,
        filter_state=filter_state,
        date_filter=date_filter,
        stat_filter=stat_filter,
        direction_filter=direction_filter,
        search_query=search_query,
        history_lab=history_lab,
        current_season_context=current_season_context,
    )


