@app.route('/season-review/team/<team>')
def team_season_review(team):
    gamelogs = load_gamelogs()
    player_advanced = load_player_advanced()
    player_snapshot = load_player_snapshot()
    current_team_overrides = load_current_team_overrides()
    current_team_map = build_current_team_map(gamelogs, player_snapshot, current_team_overrides)
    schedule = load_schedule()
    postseason_only = postseason_only_enabled()
    review = build_team_season_review(team.upper(), gamelogs, player_advanced, current_team_map)
    if not review:
        return render_error_page(404, 'Team review not found', 'That team review is not available yet.')
    team_filter = get_team_filter(postseason_only)
    upcoming = get_upcoming_games(schedule, days=7, allowed_teams=team_filter)
    team_game_lookup = build_team_game_lookup(upcoming)
    scheduled_game = team_game_lookup.get(team.upper(), {})

    current_matchup = None
    if scheduled_game:
        opponent = scheduled_game.get('opponent_abbr') or normalize_team_for_filter(scheduled_game.get('opponent'))
        opponent_display = scheduled_game.get('opponent_display') or scheduled_game.get('opponent')
        team_vs_opp = gamelogs[(gamelogs['Team'] == team.upper()) & (gamelogs['Opp'] == opponent)].copy()
        defense_reads = []
        for stat in ['PTS', 'REB', 'AST', '3PM']:
            context = get_playoff_defense_context(
                gamelogs, opponent, stat,
                allowed_teams=POSTSEASON_TEAMS if postseason_only else None
            )
            if context['tags']:
                defense_reads.append({
                    'stat': stat,
                    'tag': context['tags'][0],
                    'lean': 'over' if context['over_boost'] > context['under_boost'] else 'under'
                })

        matchup_angles = []
        if not team_vs_opp.empty:
            for player, player_logs in team_vs_opp.groupby('Player'):
                games = len(player_logs)
                if games < 2:
                    continue
                for stat, min_avg in [('PTS', 8), ('REB', 4), ('AST', 3), ('3PM', 1.2)]:
                    if stat not in player_logs.columns:
                        continue
                    avg = pd.to_numeric(player_logs[stat], errors='coerce').mean()
                    if pd.isna(avg) or avg < min_avg:
                        continue
                    floor_line = avg * 0.8
                    hit_rate = (pd.to_numeric(player_logs[stat], errors='coerce') >= floor_line).mean() * 100
                    if hit_rate < 60:
                        continue
                    matchup_angles.append({
                        'player': player,
                        'stat': stat,
                        'angle': f"{player} {stat} vs {opponent}",
                        'games': games,
                        'avg': round(float(avg), 1),
                        'floor_line': round(float(floor_line), 1),
                        'hit_rate': round(float(hit_rate), 1)
                    })
        matchup_angles = sorted(matchup_angles, key=lambda x: (x['hit_rate'], x['games'], x['avg']), reverse=True)[:4]

        series_label, series_type = get_series_label(team.upper(), opponent)
        current_matchup = {
            'opponent': opponent_display,
            'site': scheduled_game.get('site'),
            'label': scheduled_game.get('label'),
            'time': scheduled_game.get('time'),
            'matchup': scheduled_game.get('matchup'),
            'series_label': series_label,
            'series_type': series_type,
            'series_id': get_series_id(team.upper(), opponent),
            'series_score': build_head_to_head_summary(
                gamelogs,
                team.upper(),
                opponent,
                allow_regular_fallback=not postseason_only,
            ),
            'defense_reads': defense_reads[:2],
            'matchup_angles': matchup_angles
        }

    review['current_matchup'] = current_matchup
    return render_template('team_season_review.html', review=review, postseason_only=postseason_only)

@app.route('/schedule')
def schedule_page():
    schedule_df = load_schedule()
    odds_df = load_game_market_odds()
    market_lookup = build_game_market_lookup(odds_df)
    postseason_only = postseason_only_enabled()
    team_filter = get_team_filter(postseason_only)
    games_by_date = {}
    for _, game in schedule_df.iterrows():
        date = str(game.get('Date', 'Unknown'))
        away = str(game.get('Away', '')).strip()
        home = str(game.get('Home', '')).strip()
        if away and home and away != 'nan' and home != 'nan':
            if not team_in_filter(away, team_filter) or not team_in_filter(home, team_filter):
                continue
            if date not in games_by_date: games_by_date[date] = []
            market = market_lookup.get((date, away, home)) or market_lookup.get(('any', away, home)) or {}
            games_by_date[date].append({'Away': away, 'Home': home, 'Time': str(game.get('Time', 'TBD')), 'market': market, 'market_summary': format_game_market_summary(market, home)})
    return render_template('schedule.html', games_by_date=games_by_date, postseason_only=postseason_only)


