@app.route('/team/<team>')
def team(team):
    gamelogs = load_gamelogs()
    schedule = load_schedule()
    odds_df = load_game_market_odds()
    player_advanced = load_player_advanced()
    player_tracking = load_player_tracking()
    player_snapshot = load_player_snapshot()
    current_team_overrides = load_current_team_overrides()
    current_team_map = build_current_team_map(gamelogs, player_snapshot, current_team_overrides)
    current_players = [player for player, current_team in current_team_map.items() if current_team == team]
    team_logs = gamelogs[gamelogs['Player'].isin(current_players)] if not gamelogs.empty and current_players else (
        gamelogs[gamelogs['Team'] == team] if not gamelogs.empty and 'Team' in gamelogs.columns else pd.DataFrame()
    )
    advanced_lookup = {}
    if not player_advanced.empty and 'Player' in player_advanced.columns:
        advanced_lookup = (
            player_advanced.dropna(subset=['Player'])
            .drop_duplicates(subset=['Player'], keep='last')
            .set_index('Player')
            .to_dict('index')
        )
    tracking_lookup = {}
    if not player_tracking.empty and 'Player' in player_tracking.columns:
        tracking_lookup = (
            player_tracking.dropna(subset=['Player'])
            .drop_duplicates(subset=['Player'], keep='last')
            .set_index('Player')
            .to_dict('index')
        )
    player_stats = []
    for player in team_logs['Player'].unique() if not team_logs.empty else []:
        pl = team_logs[team_logs['Player'] == player]
        if len(pl) >= 3:
            stats = {'name': player, 'games': len(pl)}
            for col in ['PTS', 'REB', 'AST', '3PM', 'STL', 'BLK', 'TOV', 'MIN', 'FG_PCT']:
                if col in pl.columns:
                    avg = pl[col].mean()
                    if pd.isna(avg):
                        stats[col] = 0
                    elif col == 'FG_PCT':
                        stats[col] = round(avg * 100, 1)
                    else:
                        stats[col] = round(avg, 1)
            advanced_row = advanced_lookup.get(player, {})
            usg_pct = advanced_row.get('USG_PCT')
            if pd.notna(usg_pct):
                stats['USG_PCT'] = round(float(usg_pct) * 100, 1)
            tracking_row = tracking_lookup.get(player, {})
            touches = tracking_row.get('TOUCHES')
            drives = tracking_row.get('DRIVES')
            avg_speed = tracking_row.get('AVG_SPEED')
            if pd.notna(touches):
                stats['TOUCHES'] = round(float(touches), 1)
            if pd.notna(drives):
                stats['DRIVES'] = round(float(drives), 1)
            if pd.notna(avg_speed):
                stats['AVG_SPEED'] = round(float(avg_speed), 2)
            stats['STOCKS'] = round(stats.get('STL', 0) + stats.get('BLK', 0), 1)
            player_stats.append(stats)
    players_sorted = sorted(player_stats, key=lambda x: x.get('PTS', 0), reverse=True)
    team_decision_context = build_team_decision_context(
        team,
        'nba',
        team_logs,
        players_sorted,
        schedule=schedule,
        odds_df=odds_df,
    )
    return render_template('team.html', team=team, players=players_sorted, team_decision_context=team_decision_context)


@app.route('/raw-data')
def raw_data():
    postseason_only = postseason_only_enabled()
    sample_mode = request.args.get('sample', 'current').strip().lower()
    team_query = normalize_team_for_filter(request.args.get('team', '').strip())
    player_query = request.args.get('player', '').strip()
    stat_query = normalize_stat_filter(request.args.get('stat', 'PTS'))

    gamelogs = load_playoff_gamelogs() if postseason_only else load_gamelogs()
    base_gamelogs = load_gamelogs()
    current_team_overrides = load_current_team_overrides()
    player_snapshot = load_player_snapshot()
    current_team_map = build_current_team_map(base_gamelogs, player_snapshot, current_team_overrides)
    raw_props, refresh_meta = load_live_props_feed(require_fresh=True)
    resolved_props = apply_current_team_context(raw_props, base_gamelogs, player_snapshot, current_team_overrides)
    props_df = load_canonical_live_props(base_gamelogs, player_snapshot, current_team_overrides, require_fresh=True)
    props_market_groups = build_prop_market_groups(resolved_props)

    filtered = gamelogs.copy() if gamelogs is not None else pd.DataFrame()
    if filtered is None or filtered.empty:
        filtered = pd.DataFrame(columns=['Date', 'Player', 'Team', 'Opp', 'MIN', 'PTS', 'REB', 'AST', '3PM', 'STL', 'BLK', 'Result'])

    if 'Date' in filtered.columns:
        filtered['Date'] = pd.to_datetime(filtered['Date'], errors='coerce')

    if player_query and 'Player' in filtered.columns:
        filtered = filtered[filtered['Player'].astype(str).str.contains(player_query, case=False, na=False)].copy()
    if team_query and 'Team' in filtered.columns:
        filtered = filtered[filtered['Team'].astype(str).str.upper() == team_query].copy()

    if 'Date' in filtered.columns:
        filtered = filtered.sort_values('Date', ascending=False)

    if sample_mode == 'current' and player_query and not filtered.empty and 'Player' in filtered.columns and 'Team' in filtered.columns:
        narrowed_frames = []
        for player_name, player_group in filtered.groupby('Player', dropna=False):
            current_team = current_team_map.get(player_name)
            if current_team:
                team_rows = player_group[player_group['Team'].astype(str).str.upper() == current_team]
                narrowed_frames.append(team_rows if not team_rows.empty else player_group)
            else:
                narrowed_frames.append(player_group)
        if narrowed_frames:
            filtered = pd.concat(narrowed_frames, ignore_index=True)
            if 'Date' in filtered.columns:
                filtered = filtered.sort_values('Date', ascending=False)

    display_cols = [col for col in ['Date', 'Player', 'Team', 'Opp', 'Matchup', 'MIN', 'PTS', 'REB', 'AST', '3PM', 'STL', 'BLK', 'Result'] if col in filtered.columns]
    if display_cols:
        filtered = filtered[display_cols].copy()
    if 'Date' in filtered.columns:
        filtered['Date'] = pd.to_datetime(filtered['Date'], errors='coerce').dt.strftime('%Y-%m-%d')

    trajectory = {}
    prop_line_lookup = {}
    prop_book_lines = {}
    unique_players = []
    if not filtered.empty and 'Player' in filtered.columns:
        unique_players = [str(name).strip() for name in filtered['Player'].dropna().unique().tolist() if str(name).strip()]
    if player_query and len(unique_players) == 1 and not filtered.empty:
        resolved_player = unique_players[0]
        resolved_team = ''
        if 'Team' in filtered.columns:
            team_values = [str(team).strip().upper() for team in filtered['Team'].dropna().unique().tolist() if str(team).strip()]
            resolved_team = team_values[0] if team_values else ''
        player_props = props_df[props_df['Player'].astype(str).str.strip().str.lower() == resolved_player.strip().lower()].copy() if not props_df.empty and 'Player' in props_df.columns else pd.DataFrame()
        if resolved_team and not player_props.empty and 'Team' in player_props.columns:
            team_match = player_props[player_props['Team'].astype(str).str.strip().str.upper() == resolved_team].copy()
            if not team_match.empty:
                player_props = team_match
        if not player_props.empty and {'Stat', 'Line'}.issubset(player_props.columns):
            player_props = player_props.sort_values('LastUpdated', ascending=False) if 'LastUpdated' in player_props.columns else player_props
            for _, row in player_props.iterrows():
                stat_name = str(row.get('Stat', '') or '').strip().upper()
                line_value = pd.to_numeric(pd.Series([row.get('Line')]), errors='coerce').iloc[0]
                if stat_name and pd.notna(line_value) and stat_name not in prop_line_lookup:
                    prop_line_lookup[stat_name] = round(float(line_value), 1)
                if stat_name and stat_name not in prop_book_lines:
                    prop_book_lines[stat_name] = []

        selected_overlays = []
        if not player_props.empty:
            stat_match = player_props[player_props['Stat'].astype(str).str.strip().str.upper() == stat_query].copy()
            for _, prop_row in stat_match.iterrows():
                market_context = build_prop_multi_book_context(prop_row, 'OVER', props_market_groups)
                books = market_context.get('books') or []
                line_low = market_context.get('line_low')
                line_high = market_context.get('line_high')
                if line_low is not None and line_high is not None and line_low != line_high:
                    if not prop_book_lines.get(stat_query):
                        prop_book_lines[stat_query] = [{'book': 'Range', 'line': f"{line_low:g}-{line_high:g}", 'color': '#ffb800'}]
                color_map = {
                    'DraftKings': '#84d7d2',
                    'Caesars': '#ffb800',
                    'FanDuel': '#6ea2ff',
                    'BetMGM': '#ff8c42',
                }
                group = props_market_groups.get(get_prop_market_group_key(prop_row))
                if group is not None and not group.empty and 'Book' in group.columns:
                    working_group = group.copy()
                    for _, market_row in working_group.iterrows():
                        book = str(market_row.get('Book', '') or '').strip()
                        current_line = pd.to_numeric(pd.Series([market_row.get('CurrentLine', market_row.get('Line'))]), errors='coerce').iloc[0]
                        if not book or pd.isna(current_line):
                            continue
                        color = color_map.get(book, '#9fb3c8')
                        selected_overlays.append({'book': book, 'line': round(float(current_line), 1), 'color': color})
                    deduped_overlay_books = set()
                    cleaned_overlays = []
                    for overlay in selected_overlays:
                        key = (overlay['book'], overlay['line'])
                        if key in deduped_overlay_books:
                            continue
                        deduped_overlay_books.add(key)
                        cleaned_overlays.append(overlay)
                    selected_overlays = cleaned_overlays
                    if selected_overlays:
                        prop_book_lines[stat_query] = [
                            {'book': overlay['book'], 'line': overlay['line'], 'color': overlay['color']}
                            for overlay in selected_overlays
                        ]
        selected_line = prop_line_lookup.get(stat_query)
        trajectory = build_stat_trajectory(filtered, stat_query, line=selected_line, max_points=15, overlays=selected_overlays)

        if selected_line is not None and stat_query in filtered.columns:
            stat_series = pd.to_numeric(filtered[stat_query], errors='coerce')
            line_results = []
            for value in stat_series.tolist():
                if pd.isna(value):
                    line_results.append('')
                elif float(value) > float(selected_line):
                    line_results.append('OVER')
                elif float(value) < float(selected_line):
                    line_results.append('UNDER')
                else:
                    line_results.append('PUSH')
            filtered['SelectedLine'] = selected_line
            filtered['SelectedStatResult'] = line_results

    team_options = []
    if gamelogs is not None and not gamelogs.empty and 'Team' in gamelogs.columns:
        team_options = sorted([str(team).strip().upper() for team in gamelogs['Team'].dropna().unique().tolist() if str(team).strip()])

    return render_template(
        'raw_data.html',
        rows=filtered.head(250).to_dict('records'),
        row_count=int(len(filtered)),
        stat_options=RAW_DATA_STATS,
        selected_stat=stat_query,
        selected_team=team_query,
        selected_player=player_query,
        sample_mode=sample_mode,
        postseason_only=postseason_only,
        trajectory=trajectory,
        prop_line_lookup=prop_line_lookup,
        prop_book_lines=prop_book_lines,
        team_options=team_options,
        refresh_meta=refresh_meta,
    )


@app.route('/player/<player_name>')
def player(player_name):
    from urllib.parse import unquote
    player_name = unquote(player_name)
    ngs_context = build_ngs_player_context(player_name)
    statcast_context = build_statcast_player_context(player_name)
