    query_params = {}
    if team_query:
        query_params['team'] = team_query
    if player_query:
        query_params['player'] = player_query
    if stat_query:
        query_params['stat'] = stat_query
    query_params['sample'] = sample_mode
    if model_debug:
        query_params['model_debug'] = 1
