@app.route('/parlay/save', methods=['POST'])
def save_parlay():
    current_user = get_current_user()
    if not current_user:
        return jsonify({'ok': False, 'error': 'Sign in to save tickets.'}), 401
    payload = request.get_json(silent=True) or {}
    picks = payload.get('picks') or []
    if not picks:
        return jsonify({'ok': False, 'error': 'No picks selected.'}), 400

    sanitized_picks = []
    for pick in picks[:20]:
        method_labels = normalize_method_labels(pick.get('method_supports') or pick.get('method_labels') or [])
        sanitized_picks.append({
            'sport': str(pick.get('sport', pick.get('Sport', 'NBA'))).strip().upper() or 'NBA',
            'player': str(pick.get('player', '')).strip(),
            'team': str(pick.get('team', '')).strip(),
            'stat': str(pick.get('stat', '')).strip(),
            'line': pick.get('line'),
            'direction': str(pick.get('direction', '')).strip(),
            'confidence': float(pick.get('confidence', 0) or 0),
            'raw_confidence': float(pick.get('raw_confidence', pick.get('confidence', 0)) or 0),
            'matchup': str(pick.get('matchup', '')).strip(),
            'tier': str(pick.get('tier', '')).strip(),
            'method_labels': method_labels,
            'market_calibration_note': str(pick.get('market_calibration_note', '')).strip(),
            'market_calibration_tags': [str(tag).strip() for tag in (pick.get('market_calibration_tags') or []) if str(tag).strip()],
            'book_count': int(pick.get('book_count', 0) or 0),
            'book': str(pick.get('book', '')).strip(),
            'market_price': pick.get('market_price', pick.get('marketPrice')),
            'model_prob': pick.get('model_prob', pick.get('modelProb')),
            'ev_pct': pick.get('ev_pct', pick.get('evPct')),
            'historical_reliability': str(pick.get('historical_reliability', '')).strip(),
        })

    valid_picks = [pick for pick in sanitized_picks if pick['player'] and pick['stat'] and pick['direction']]
    if not valid_picks:
        return jsonify({'ok': False, 'error': 'No valid picks to save.'}), 400

    saved_at = datetime.now().strftime('%Y-%m-%d %I:%M %p')
    bankroll = float(payload.get('bankroll', 0) or 0)
    risk_pct = float(payload.get('risk_pct', 0) or 0)
    slate_budget = float(payload.get('slate_budget', 0) or 0)
    stake = float(payload.get('stake', slate_budget) or slate_budget or 0)
    avg_confidence = round(sum(pick['confidence'] for pick in valid_picks) / len(valid_picks), 1)
    tier1_count = sum(1 for pick in valid_picks if pick.get('tier') == 'Tier 1')
    label = str(payload.get('label', '')).strip() or f"{payload.get('mode', 'Parlay')} | {saved_at}"

    ticket = {
        'TicketId': datetime.now().strftime('%Y%m%d%H%M%S%f'),
        'UserId': current_user.get('user_id', ''),
        'UserEmail': current_user.get('email', ''),
        'SavedAt': saved_at,
        'Label': label,
        'Mode': str(payload.get('mode', 'Parlay Builder')).strip(),
        'DateFilter': str(payload.get('date_filter', 'all')).strip(),
        'DirectionFilter': str(payload.get('direction_filter', 'all')).strip(),
        'SampleMode': str(payload.get('sample_mode', 'current')).strip(),
        'LegCount': len(valid_picks),
        'Tier1Count': tier1_count,
        'AvgConfidence': avg_confidence,
        'Bankroll': bankroll,
        'RiskPct': risk_pct,
        'SlateBudget': slate_budget,
        'PostseasonOnly': 1 if payload.get('postseason_only') else 0,
        'Result': 'Pending',
        'ResultUpdatedAt': '',
        'Stake': stake,
        'Payout': 0,
        'ModelVersion': 'v2',
        'ConfidenceScale': 'native_v2',
        'PicksJson': json.dumps(valid_picks)
    }

    save_parlay_ticket(ticket)
    return jsonify({
        'ok': True,
        'message': f"Saved {len(valid_picks)}-leg ticket for review.",
        'saved_at': saved_at,
        'label': label,
        'ticket_id': ticket['TicketId']
    })


@app.route('/parlay/delete', methods=['POST'])
def delete_parlay():
    current_user = get_current_user()
    if not current_user:
        return jsonify({'ok': False, 'error': 'Sign in to manage saved tickets.'}), 401
    payload = request.get_json(silent=True) or {}
    ticket_id = str(payload.get('ticket_id', '')).strip()
    if not ticket_id:
        return jsonify({'ok': False, 'error': 'Missing ticket id.'}), 400
    deleted = delete_saved_parlay(ticket_id, user=current_user)
    if not deleted:
        return jsonify({'ok': False, 'error': 'Ticket not found.'}), 404
    return jsonify({'ok': True, 'message': 'Saved ticket deleted.'})


@app.route('/parlay/result', methods=['POST'])
def update_parlay_result():
    current_user = get_current_user()
    if not current_user:
        return jsonify({'ok': False, 'error': 'Sign in to manage saved tickets.'}), 401
    payload = request.get_json(silent=True) or {}
    ticket_id = str(payload.get('ticket_id', '')).strip()
    result = str(payload.get('result', '')).strip().title()
    if not ticket_id:
        return jsonify({'ok': False, 'error': 'Missing ticket id.'}), 400
    if result not in {'Pending', 'Win', 'Loss', 'Push'}:
        return jsonify({'ok': False, 'error': 'Invalid result.'}), 400
    updated = update_saved_parlay_result(ticket_id, result, user=current_user)
    if not updated:
        return jsonify({'ok': False, 'error': 'Ticket not found.'}), 404
    return jsonify({'ok': True, 'message': f'Result updated to {result}.'})


@app.route('/parlay/money', methods=['POST'])
def update_parlay_money():
    current_user = get_current_user()
    if not current_user:
        return jsonify({'ok': False, 'error': 'Sign in to manage saved tickets.'}), 401
    payload = request.get_json(silent=True) or {}
    ticket_id = str(payload.get('ticket_id', '')).strip()
    if not ticket_id:
        return jsonify({'ok': False, 'error': 'Missing ticket id.'}), 400
    stake = payload.get('stake')
    payout = payload.get('payout')
    try:
        stake = float(stake) if stake is not None and str(stake) != '' else None
        payout = float(payout) if payout is not None and str(payout) != '' else None
    except Exception:
        return jsonify({'ok': False, 'error': 'Stake and payout must be numeric.'}), 400
    updated = update_saved_parlay_money(ticket_id, stake=stake, payout=payout, user=current_user)
    if not updated:
        return jsonify({'ok': False, 'error': 'Ticket not found.'}), 404
    return jsonify({'ok': True, 'message': 'Ticket money updated.'})


