@app.route('/elite/bet-log', methods=['POST'])
def save_elite_bet_log():
    current_user = get_current_user()
    if not current_user:
        return redirect(url_for('login', next='/elite', gate='login_required', required='sharp'))

    form = request.form
    sport = str(form.get('sport', 'MLB')).strip().upper() or 'MLB'
    player = str(form.get('player', '')).strip()
    stat = str(form.get('stat', '')).strip()
    direction = str(form.get('direction', '')).strip().upper()
    line = str(form.get('line', '')).strip()
    matchup = str(form.get('matchup', '')).strip()
    book = str(form.get('book', '')).strip()
    result = str(form.get('result', 'Pending')).strip().title()
    if result not in {'Pending', 'Win', 'Loss', 'Push'}:
        result = 'Pending'
    try:
        confidence = float(form.get('confidence', 55) or 55)
    except Exception:
        confidence = 55.0
    try:
        stake = float(form.get('stake', 0) or 0)
    except Exception:
        stake = 0.0
    try:
        payout = float(form.get('payout', 0) or 0)
    except Exception:
        payout = 0.0
    try:
        market_price = int(float(form.get('price', 0) or 0))
    except Exception:
        market_price = None

    if not player or not stat or direction not in {'OVER', 'UNDER'} or not line:
        return redirect('/elite?status=bet_log_missing')

    saved_at = datetime.now().strftime('%Y-%m-%d %I:%M %p')
    pick = {
        'sport': sport,
        'player': player,
        'team': str(form.get('team', '')).strip(),
        'stat': stat,
        'line': line,
        'direction': direction,
        'confidence': confidence,
        'raw_confidence': confidence,
        'matchup': matchup,
        'tier': str(form.get('tier', 'Manual')).strip() or 'Manual',
        'method_labels': ['Elite Manual Log'],
        'market_calibration_tags': [],
        'book_count': 1 if book else 0,
        'book': book,
        'market_price': market_price,
        'historical_reliability': str(form.get('reliability', '')).strip(),
    }
    ticket = {
        'TicketId': datetime.now().strftime('%Y%m%d%H%M%S%f'),
        'UserId': current_user.get('user_id', ''),
        'UserEmail': current_user.get('email', ''),
        'SavedAt': saved_at,
        'Label': str(form.get('label', '')).strip() or f"{sport} Manual Bet | {player}",
        'Mode': 'Elite Manual Bet Log',
        'DateFilter': 'manual',
        'DirectionFilter': direction.lower(),
        'SampleMode': 'manual',
        'LegCount': 1,
        'Tier1Count': 1 if pick['tier'] == 'Tier 1' else 0,
        'AvgConfidence': confidence,
        'Bankroll': 0,
        'RiskPct': 0,
        'SlateBudget': stake,
        'PostseasonOnly': 0,
        'Result': result,
        'ResultUpdatedAt': saved_at if result != 'Pending' else '',
        'Stake': stake,
        'Payout': payout,
        'ModelVersion': 'elite_manual',
        'ConfidenceScale': 'manual',
        'PicksJson': json.dumps([pick]),
    }
    save_parlay_ticket(ticket)
    return redirect(f"/elite?status=bet_logged&ticket_id={ticket['TicketId']}")

def render_trends_board(stat):
    """Trend board showing recent hit and miss patterns by stat."""
    gamelogs, schedule = load_gamelogs(), load_schedule()
    props_df, refresh_meta = load_live_props_feed(require_fresh=True)
    direction = request.args.get('direction', 'over')
    postseason_only = postseason_only_enabled()
    playoff_gamelogs = load_playoff_gamelogs() if postseason_only else pd.DataFrame()
    team_filter = get_team_filter(postseason_only)
    upcoming = get_upcoming_games(schedule, days=7, allowed_teams=team_filter)
    team_game_lookup = build_team_game_lookup(upcoming)
    scope = request.args.get('scope', 'series' if postseason_only else 'overall')
    team_query = request.args.get('team', '').strip().upper()
    opponent_query = request.args.get('opponent', '').strip().upper()
    default_sort_dir = 'asc' if request.args.get('sort_by') in {'player', 'team', 'opponent'} else 'desc'
    sort_by = request.args.get('sort_by', 'display_rate')
    sort_dir = request.args.get('sort_dir', default_sort_dir)
    
    source_logs = playoff_gamelogs if postseason_only and not playoff_gamelogs.empty else gamelogs

    if source_logs.empty:
        return render_template(
            'heatmap.html',
            stat=stat,
            stat_name=STAT_LABELS.get(stat, stat),
            players=[],
            direction=direction,
            postseason_only=postseason_only,
            scope=scope,
            team_query=team_query,
            opponent_query=opponent_query,
            sort_by=sort_by,
            sort_dir=sort_dir,
            base_params={},
              teams=[],
              opponents=[],
              refresh_meta=refresh_meta,
              playoff_palette_active=postseason_only
          )
    
    # Get all players with this stat, not just those with props
    if stat in source_logs.columns:
        # Find players with reasonable averages for this stat
        min_avg = MIN_AVG_FOR_PROPS.get(stat, 1)
        player_avgs = source_logs.groupby('Player')[stat].mean()
        qualified_players = player_avgs[player_avgs >= min_avg].sort_values(ascending=False).head(100).index.tolist()
    else:
        qualified_players = []
    
    players_data = []
    for pn in qualified_players:
        pl = source_logs[source_logs['Player'] == pn].copy()
        if pl.empty or stat not in pl.columns: 
            continue
        if 'Date' in pl.columns:
            pl['Date'] = pd.to_datetime(pl['Date'], errors='coerce')
            pl = pl.sort_values('Date', ascending=False)
        
        team = pl.iloc[0].get('Team', 'UNK')
        if not team_in_filter(team, team_filter):
            continue
        if postseason_only and team not in team_game_lookup:
            continue
        
        # Calculate line - use prop line if exists, otherwise calculate
        stat_props = props_df[(props_df['Player'] == pn) & (props_df['Stat'] == stat)] if not props_df.empty and 'Stat' in props_df.columns else pd.DataFrame()
        if not stat_props.empty and 'Line' in stat_props.columns:
            line = float(stat_props.iloc[0]['Line'])
        else:
            avg = pl[stat].mean()
            line = round(avg * FLOOR_MULTIPLIERS.get(stat, 0.75) * 2) / 2
            if line < 0.5:
                line = 0.5
        
        valid = pl[pl[stat].notna()]
        if valid.empty: 
            continue
        
        avg = round(valid[stat].mean(), 1)
        ou_rates = calculate_over_under_rates(valid, stat, line)
        scheduled_game = team_game_lookup.get(team, {})
        opponent = scheduled_game.get('opponent')
        opponent_abbr = normalize_team_for_filter(opponent)

        valid_vs_opponent = pd.DataFrame()
        if opponent and 'Opp' in valid.columns:
            valid_vs_opponent = valid[
                valid['Opp'].apply(normalize_team_for_filter) == opponent_abbr
            ].copy()
        if scope == 'series' and valid_vs_opponent.empty:
            continue

        if scope == 'series':
            active_logs = valid_vs_opponent.copy()
            active_ou_rates = calculate_over_under_rates(active_logs, stat, line) if not active_logs.empty else {'over': 0.0, 'under': 0.0}
        else:
            active_logs = valid
            active_ou_rates = ou_rates
        
        # Build last 15 games - always show 15 slots, blank if no game
        last_15 = []
        game_count = 0
        for _, r in active_logs.iterrows():
            if game_count >= 15:
                break
            val = r[stat]
            if pd.notna(val):
                if direction == 'over':
                    last_15.append({'value': val, 'hit': val > line, 'played': True})
                else:
                    last_15.append({'value': val, 'hit': val < line, 'played': True})
            else:
                last_15.append({'value': None, 'hit': False, 'played': False})
            game_count += 1
        
        # Pad to 15 if needed
        while len(last_15) < 15:
            last_15.append({'value': None, 'hit': False, 'played': False})
        
        hit_rate = active_ou_rates['over'] if direction == 'over' else active_ou_rates['under']
        matchup_hit_rate = None
        if not valid_vs_opponent.empty:
            matchup_ou_rates = calculate_over_under_rates(valid_vs_opponent, stat, line)
            matchup_hit_rate = matchup_ou_rates['over'] if direction == 'over' else matchup_ou_rates['under']
        
        players_data.append({
            'name': pn, 'team': team, 'line': line, 'avg': avg, 
            'hit_rate': hit_rate, 'over_rate': ou_rates['over'], 'under_rate': ou_rates['under'], 
            'last_15': last_15, 'games_played': len(valid),
            'opponent': TEAM_ABBR_TO_NAME.get(opponent_abbr, opponent) if opponent_abbr else opponent,
            'matchup': scheduled_game.get('matchup', ''),
            'game_day': scheduled_game.get('label', ''),
            'matchup_hit_rate': matchup_hit_rate,
            'matchup_games': len(valid_vs_opponent),
            'scope': scope,
            'display_rate': matchup_hit_rate if scope == 'series' and matchup_hit_rate is not None else hit_rate
        })

    teams = sorted({p['team'] for p in players_data if p.get('team')})
    opponents = sorted({p['opponent'] for p in players_data if p.get('opponent')})

    if team_query:
        players_data = [p for p in players_data if p.get('team') == team_query]
    if opponent_query:
        players_data = [p for p in players_data if p.get('opponent') == opponent_query]

    reverse = sort_dir == 'desc'
    alpha_fields = {'player', 'team', 'opponent'}
    numeric_fields = {'line', 'avg', 'display_rate', 'over_rate', 'under_rate', 'matchup_games', 'games_played'}

    if sort_by in alpha_fields:
        key_map = {'player': 'name', 'team': 'team', 'opponent': 'opponent'}
        players_data = sorted(players_data, key=lambda x: str(x.get(key_map[sort_by], '') or ''), reverse=reverse)
    elif sort_by in numeric_fields:
        players_data = sorted(players_data, key=lambda x: x.get(sort_by) if x.get(sort_by) is not None else float('-inf'), reverse=reverse)
    else:
        players_data = sorted(
            players_data,
            key=lambda x: (
                x['display_rate'],
                x['matchup_games'],
                x['games_played']
            ),
            reverse=True
        )

    players_data = players_data[:100]
    base_params = {
        'direction': direction,
        'scope': scope,
        'postseason': 1 if postseason_only else 0,
        'team': team_query,
        'opponent': opponent_query
    }

    return render_template('heatmap.html', stat=stat, stat_name=STAT_LABELS.get(stat, stat), 
        players=players_data, direction=direction, postseason_only=postseason_only, scope=scope,
        team_query=team_query, opponent_query=opponent_query, sort_by=sort_by, sort_dir=sort_dir,
        base_params=base_params, teams=teams, opponents=opponents, refresh_meta=refresh_meta,
        playoff_palette_active=postseason_only)

