@app.route('/trend-board')
def trend_board():
    gamelogs = load_gamelogs()
    props_df, refresh_meta = load_live_props_feed(require_fresh=True)
    player_snapshot = load_player_snapshot()
    current_team_overrides = load_current_team_overrides()
    current_team_map = build_current_team_map(gamelogs, player_snapshot, current_team_overrides)
    postseason_only = postseason_only_enabled()
    team_filter = get_team_filter(postseason_only)
    stat_filter = request.args.get('stat', 'all').strip().upper()
    team_query = request.args.get('team', '').strip().upper()
    sample_mode = request.args.get('sample', 'current')
    sort_by = request.args.get('sort_by', 'consistency_index')
    default_sort_dir = 'asc' if sort_by in {'player', 'team', 'stat'} else 'desc'
    sort_dir = request.args.get('sort_dir', default_sort_dir)

    rows = build_trend_board(
        gamelogs,
        current_team_map,
        props_df=props_df,
        player_snapshot=player_snapshot,
        team_filter=team_filter,
        sample_mode=sample_mode,
        stat_filter=stat_filter
    )
    opportunity_summary = get_trend_opportunity_summary_cached(
        gamelogs,
        current_team_map,
        team_filter=team_query or team_filter,
        sample_mode=sample_mode,
        stat_filter=stat_filter
    )
    teams = sorted({row['team'] for row in rows if row.get('team')})

    if team_query:
        rows = [row for row in rows if row.get('team') == team_query]

    reverse = sort_dir == 'desc'
    alpha_fields = {'player', 'team', 'stat'}
    numeric_fields = {
        'line', 'avg', 'games', 'over_rate', 'under_rate',
        'over_count', 'over_longest', 'over_avg_gap',
        'under_count', 'under_longest', 'under_avg_gap',
        'current_run_len', 'trend_score', 'active_streaks',
        'market_line', 'market_over_rate', 'market_under_rate',
        'floor_hit_rate', 'snapshot_consistency', 'consistency_index'
    }

    if sort_by in alpha_fields:
        rows = sorted(rows, key=lambda x: str(x.get(sort_by, '') or ''), reverse=reverse)
    elif sort_by in numeric_fields:
        rows = sorted(rows, key=lambda x: x.get(sort_by) if x.get(sort_by) is not None else float('-inf'), reverse=reverse)
    else:
        rows = sorted(rows, key=lambda x: x.get('trend_score', 0), reverse=True)

    if should_auto_archive_candidates(
        postseason_only=postseason_only,
        sample_mode=sample_mode,
        date_filter='today',
        team_query=team_query,
        player_query='',
        stat_query=stat_filter if stat_filter != 'all' else '',
        model_debug=False,
    ) and should_run_browse_archive(
        f'nba-trends::{int(bool(postseason_only))}::{sample_mode}::{team_query}::{stat_filter}',
        cooldown_seconds=900,
        version=_build_file_token(
            DATA_DIR / 'props' / 'NBA_Props.csv',
            DATA_DIR / 'gamelogs' / 'NBA_GameLogs.csv',
            DATA_DIR / 'gamelogs' / 'NBA_Playoff_GameLogs.csv',
        ),
    ):
        archive_trend_candidates(
            rows,
            postseason_only=postseason_only,
            sample_mode=sample_mode,
        )

    base_params = {
        'postseason': 1 if postseason_only else 0,
        'stat': stat_filter.lower() if stat_filter != 'all' else 'all',
        'team': team_query,
        'sample': sample_mode
    }
    trend_meta = {
        'gamelog_rows': int(len(gamelogs)) if gamelogs is not None else 0,
        'row_count': int(len(rows)),
        'sample_mode': sample_mode,
        'scope_label': 'Playoff Field' if postseason_only else 'League-Wide',
        'props_rows': int(len(props_df)) if props_df is not None else 0,
        'opportunity_summary': opportunity_summary,
    }

    return render_template(
        'trend_board.html',
        rows=rows[:15],
        postseason_only=postseason_only,
        stat_filter=stat_filter,
        team_query=team_query,
        teams=teams,
        sample_mode=sample_mode,
        sort_by=sort_by,
        sort_dir=sort_dir,
        base_params=base_params,
        stat_options=STAT_COLUMNS,
        trend_meta=trend_meta
    )


