@app.route('/injuries')
def injuries_page():
    """Display current injuries and boost opportunities"""
    requested_sport = normalize_sport_access_key(request.args.get('sport', '').strip().lower())
    injuries = load_injuries()
    boosts = load_boosts()
    active_boosts = load_active_boosts()
    postseason_only = postseason_only_enabled()
    schedule = load_schedule()
    team_filter = get_active_playoff_team_filter(schedule) if postseason_only else get_team_filter(False)
    if requested_sport and requested_sport != 'nba':
        team_filter = set()
    
    injuries_by_team = {}
    filtered_injuries = injuries.copy()
    if not filtered_injuries.empty and team_filter:
        filtered_injuries = filtered_injuries[filtered_injuries['Team'].apply(lambda team: team_in_filter(team, team_filter))].copy()
    if not filtered_injuries.empty:
        for _, row in filtered_injuries.iterrows():
            team = row.get('Team', 'UNK')
            if not team_in_filter(team, team_filter):
                continue
            if team not in injuries_by_team:
                injuries_by_team[team] = []
            injuries_by_team[team].append({
                'player': row.get('Player', ''),
                'status': row.get('Status', ''),
                'reason': row.get('Reason', ''),
                'updated': row.get('Updated', '')
            })
    
    top_boosts = []
    if not active_boosts.empty:
        seen = set()
        for _, row in active_boosts.iterrows():
            if not team_in_filter(row.get('Team', ''), team_filter):
                continue
            key = (row['Beneficiary'], row['Stat'])
            if key in seen:
                continue
            seen.add(key)
            top_boosts.append({
                'beneficiary': row['Beneficiary'],
                'team': row['Team'],
                'stat': row['Stat'],
                'avg_with': row['Avg_With'],
                'avg_without': row['Avg_Without'],
                'boost_pct': row['Boost_Pct'],
                'injured_player': row['Key_Player_Out'],
                'injury_status': row.get('Injury_Status', 'OUT'),
                'injury_reason': row.get('Injury_Reason', '')
            })
            if len(top_boosts) >= 30:
                break
    
    role_cache_version = _build_file_token(
        DATA_DIR / 'injuries' / 'NBA_Injuries.csv',
        DATA_DIR / 'injuries' / 'NBA_Injuries_Manual.csv',
        DATA_DIR / 'injuries' / 'Active_Boost_Plays.csv',
        DATA_DIR / 'gamelogs' / 'NBA_GameLogs.csv',
    )
    role_cache_key = f"injury_role_changes::{requested_sport or 'nba'}::{int(bool(postseason_only))}"
    role_changes = _get_disk_ttl_cached_value(
        role_cache_key,
        43200,
        lambda: build_role_change_candidates(filtered_injuries, active_boosts, team_filter, load_gamelogs()),
        version=role_cache_version,
    )
    status_counts = filtered_injuries['Status'].value_counts().to_dict() if not filtered_injuries.empty else {}
    last_updated = filtered_injuries.iloc[0]['Updated'] if not filtered_injuries.empty and 'Updated' in filtered_injuries.columns else 'Unknown'
    
    return render_template('injuries.html',
        injuries_by_team=injuries_by_team,
        top_boosts=top_boosts,
        role_changes=role_changes,
        status_counts=status_counts,
        last_updated=last_updated,
        total_injuries=len(filtered_injuries),
        total_boosts=len(top_boosts),
        postseason_only=postseason_only,
        active_page='injuries',
        active_sport=requested_sport or 'nba',
    )

def prewarm_caches():
    """Best-effort warm of the heavy on-disk data caches.

    Parsing the large gamelog/prop CSVs is what makes the first request after a
    (re)start or data refresh slow (the per-process DATAFRAME_CACHE is lazy). Run
    this at server boot so a real visitor never pays that cold cost. Under gunicorn
    with preload_app=True it runs once in the master before workers fork, so every
    worker inherits the warm cache via copy-on-write. Never raises.
    """
    warmers = [
        ('nba_gamelogs', load_gamelogs),
        ('nba_schedule', load_schedule),
        ('mlb_gamelogs', load_mlb_gamelogs),
        ('wnba_gamelogs', load_wnba_gamelogs),
        ('nfl_gamelogs', load_nfl_gamelogs),
        ('injuries', load_injuries),
        ('nba_props', load_props),
        ('mlb_props', load_mlb_props),
        ('wnba_props', load_wnba_props),
    ]
    warmed = []
    for name, loader in warmers:
        try:
            loader()
            warmed.append(name)
        except Exception as exc:  # never let prewarm abort startup
            print(f"[PREWARM] {name} failed: {exc}")
    return warmed


